INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 22, 'Porque mi pueblo es necio; no me conocieron los hijos ignorantes y los no entendidos; sabios para mal hacer, y para bien hacer no supieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 23, 'Miré la tierra, y he aquí que estaba asolada y vacía; y los cielos, y no había en ellos luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 24, 'Miré los montes, y he aquí que temblaban, y todos los collados fueron destruídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 25, 'Miré, y no parecía hombre, y todas las aves del cielo se habían ido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 26, 'Miré, y he aquí el Carmelo desierto, y todas sus ciudades eran asoladas á la presencia de Jehová, á la presencia del furor de su ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 27, 'Porque así dijo Jehová: Toda la tierra será asolada; mas no haré consumación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 28, 'Por esto se enlutará la tierra, y los cielos arriba se oscurecerán, porque hablé, pensé, y no me arrepentí, ni me tornaré de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 29, 'Del estruendo de la gente de á caballo y de los flecheros huyó toda la ciudad; entráronse en las espesuras de los bosques, y subiéronse en peñascos; todas las ciudades fueron desamparadas, y no quedó en ellas morador alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 30, 'Y tú, destruída, ¿qué harás? Bien que te vistas de grana, aunque te adornes con atavíos de oro, aunque pintes con antimonio tus ojos, en vano te engalanas; menospreciáronte los amadores, buscarán tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 4, 31, 'Porque voz oí como de mujer que está de parto, angustia como de primeriza; voz de la hija de Sión que lamenta y extiende sus manos, diciendo: ¡Ay ahora de mí! que mi alma desmaya á causa de los matadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 1, 'DISCURRID por las plazas de Jerusalem, y mirad ahora, y sabed, y buscad en sus plazas si halláis hombre, si hay alguno que haga juicio, que busque verdad; y yo la perdonaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 2, 'Y si dijeren: Vive Jehová; por tanto jurarán mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 3, 'Oh Jehová, ¿no miran tus ojos á la verdad? Azotástelos, y no les dolió; consumístelos, y no quisieron recibir corrección; endurecieron sus rostros más que la piedra, no quisieron tornarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 4, 'Yo empero dije: Por cierto ellos son pobres, enloquecido han, pues no conocen el camino de Jehová, el juicio de su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 5, 'Irme he á los grandes, y hablaréles; porque ellos conocen el camino de Jehová, el juicio de su Dios. Ciertamente ellos también quebraron el yugo, rompieron las coyundas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 6, 'Por tanto, león del monte los herirá, destruirálos lobo del desierto, tigre acechará sobre sus ciudades; cualquiera que de ellas saliere, será arrebatado: porque sus rebeliones se han multiplicado, hanse aumentado sus deslealtades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 7, '¿Cómo te he de perdonar por esto? Sus hijos me dejaron, y juraron por lo que no es Dios. Saciélos, y adulteraron, y en casa de ramera se juntaron en compañías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 8, 'Como caballos bien hartos fueron á la mañana, cada cual relinchaba á la mujer de su prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 9, '¿No había de hacer visitación sobre esto? dijo Jehová. De una gente como ésta ¿no se había de vengar mi alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 10, 'Escalad sus muros, y destruid; mas no hagáis consumación: quitad las almenas de sus muros, porque no son de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 11, 'Porque resueltamente se rebelaron contra mí la casa de Israel y la casa de Judá, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 12, 'Negaron á Jehová, y dijeron: El no es, y no vendrá mal sobre nosotros, ni veremos cuchillo ni hambre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 13, 'Antes los profetas serán como viento, y no hay en ellos palabra; así se hará á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 14, 'Por tanto, así ha dicho Jehová Dios de los ejércitos: Porque hablasteis esta palabra, he aquí yo pongo en tu boca mis palabras por fuego, y á este pueblo por leños, y los consumirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 15, 'He aquí yo traigo sobre vosotros gente de lejos, oh casa de Israel, dice Jehová; gente robusta, gente antigua, gente cuya lengua ignorarás, y no entenderás lo que hablare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 16, 'Su aljaba como sepulcro abierto, todos valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 17, 'Y comerá tu mies y tu pan, que habían de comer tus hijos y tus hijas; comerá tus ovejas y tus vacas, comerá tus viñas y tus higueras; y tus ciudades fuertes en que tú confías, tornará en nada á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 18, 'Empero en aquellos días, dice Jehová, no os acabaré del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 19, 'Y será que cuando dijereis: ¿Por qué hizo Jehová el Dios nuestro con nosotros todas estas cosas? entonces les dirás: De la manera que me dejasteis á mí, y servisteis á dioses ajenos en vuestra tierra así serviréis á extraños en tierra ajena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 20, 'Denunciad esto en la casa de Jacob, y haced que esto se oiga en Judá, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 21, 'Oid ahora esto, pueblo necio y sin corazón, que tienen ojos y no ven, que tienen oídos y no oyen:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 22, '¿A mí no temeréis? dice Jehová; ¿no os amedrentaréis á mi presencia, que al mar por ordenación eterna, la cual no quebrantará, puse arena por término? Se levantarán tempestades, mas no prevalecerán; bramarán sus ondas, mas no lo pasarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 23, 'Empero este pueblo tiene corazón falso y rebelde; tornáronse y fuéronse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 24, 'Y no dijeron en su corazón: Temamos ahora á Jehová Dios nuestro, que da lluvia temprana y tardía en su tiempo; los tiempos establecidos de la siega nos guarda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 25, 'Vuestras iniquidades han estorbado estas cosas; y vuestros pecados apartaron de vosotros el bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 26, 'Porque fueron hallados en mi pueblo impíos; acechaban como quien pone lazos; pusieron trampa para tomar hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 27, 'Como jaula llena de pájaros, así están sus casas llenas de engaño: así se hicieron grandes y ricos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 28, 'Engordaron y pusiéronse lustrosos, y sobrepujaron los hechos del malo: no juzgaron la causa, la causa del huérfano; con todo hiciéronse prósperos, y la causa de los pobres no juzgaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 29, '¿No tengo de visitar sobre esto? dice Jehová; ¿y de tal gente no se vengará mi alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 30, 'Cosa espantosa y fea es hecha en la tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 5, 31, 'Los profetas profetizaron mentira, y los sacerdotes dirigían por manos de ellos; y mi pueblo así lo quiso. ¿Qué pues haréis á su fin?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 1, 'HUID, hijos de Benjamín, de en medio de Jerusalem, y tocad bocina en Tecoa, y alzad por señal humo sobre Beth-hacchêrem: porque del aquilón se ha visto mal, y quebrantamiento grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 2, 'A mujer hermosa y delicada comparé á la hija de Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 3, 'A ella vendrán pastores y sus rebaños; junto á ella en derredor pondrán sus tiendas; cada uno apacentará á su parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 4, 'Denunciad guerra contra ella: levantaos y subamos hacia el mediodía. ¡Ay de nosotros! que va cayendo ya el día, que las sombras de la tarde se han extendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 5, 'Levantaos, y subamos de noche, y destruyamos sus palacios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 6, 'Porque así dijo Jehová de los ejércitos: Cortad árboles, y extended baluarte junto á Jerusalem: esta es la ciudad que toda ella ha de ser visitada; violencia hay en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 7, 'Como la fuente nunca cesa de manar sus aguas, así nunca cesa de manar su malicia; injusticia y robo se oye en ella; continuamente en mi presencia, enfermedad y herida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 8, 'Corrígete, Jerusalem, porque no se aparte mi alma de ti, porque no te torne desierta, tierra no habitada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 9, 'Así dijo Jehová de los ejércitos: Del todo rebuscarán como á vid el resto de Israel: torna tu mano como vendimiador á los cestos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 10, '¿A quién tengo de hablar y amonestar, para que oigan? He aquí que sus orejas son incircuncisas, y no pueden escuchar; he aquí que la palabra de Jehová les es cosa vergonzosa, no la aman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 11, 'Por tanto estoy lleno de saña de Jehová, trabajado he por contenerme; derramaréla sobre los niños en la calle, y sobre la reunión de los jóvenes juntamente; porque el marido también será preso con la mujer, el viejo con el lleno de días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 12, 'Y sus casas serán traspasadas á otros, sus heredades y también sus mujeres; porque extenderé mi mano sobre los moradores de la tierra, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 13, 'Porque desde el más chico de ellos hasta el más grande de ellos, cada uno sigue la avaricia; y desde el profeta hasta el sacerdote, todos son engañadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 14, 'Y curan el quebrantamiento de la hija de mi pueblo con liviandad, diciendo, Paz, paz; y no hay paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 15, '¿Hanse avergonzado de haber hecho abominación? No por cierto, no se han avergonzado, ni aun saben tener vergüenza: por tanto caerán entre los que caerán; caerán cuando los visitaré, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 16, 'Así dijo Jehová: Paraos en los caminos, y mirad, y preguntad por las sendas antiguas, cuál sea el buen camino, y andad por él, y hallaréis descanso para vuestra alma. Mas dijeron: No andaremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 17, 'Desperté también sobre vosotros atalayas, que dijesen: Escuchad á la voz de la trompeta. Y dijeron ellos: No escucharemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 18, 'Por tanto oid, gentes, y conoce, oh conjunto de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 19, 'Oye, tierra. He aquí yo traigo mal sobre este pueblo, el fruto de sus pensamientos; porque no escucharon á mis palabras, y aborrecieron mi ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 20, '¿A qué viene para mí este incienso de Seba, y la buena caña olorosa de tierra lejana? Vuestros holocaustos no son á mi voluntad, ni vuestros sacrificios me dan gusto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 21, 'Por tanto Jehová dice esto: He aquí yo pongo á este pueblo tropiezos, y caerán en ellos los padres y los hijos juntamente, el vecino y su cercano perecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 22, 'Así ha dicho Jehová: He aquí que viene pueblo de tierra del aquilón, y gente grande se levantará de los cantones de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 23, 'Arco y escudo arrebatarán; crueles son, que no tendrán misericordia; sonará la voz de ellos como la mar, y montarán á caballo como hombres dispuestos para la guerra, contra ti, oh hija de Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 24, 'Su fama oimos, y nuestras manos se descoyuntaron; apoderóse de nosotros angustia, dolor como de mujer que pare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 25, 'No salgas al campo, ni andes por camino; porque espada de enemigo y temor hay por todas partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 26, 'Hija de mi pueblo, cíñete de saco, y revuélcate en ceniza; hazte luto como por hijo único, llanto de amarguras: porque presto vendrá sobre nosotros el destruidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 27, 'Por fortaleza te he puesto en mi pueblo, por torre: conocerás pues, y examinarás el camino de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 28, 'Todos ellos príncipes rebeldes, andan con engaño; son cobre y hierro: todos ellos son corruptores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 29, 'Quemóse el fuelle, del fuego se ha consumido el plomo: por demás fundió el fundidor, pues los malos no son arrancados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 6, 30, 'Plata desechada los llamarán, porque Jehová los desechó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 1, 'PALABRA que fué de Jehová á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 2, 'Ponte á la puerta de la casa de Jehová, y predica allí esta palabra, y di: Oid palabra de Jehová, todo Judá, los que entráis por estas puertas para adorar á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 3, 'Así ha dicho Jehová de los ejércitos, Dios de Israel: Mejorad vuestros caminos y vuestras obras, y os haré morar en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 4, 'No fiéis en palabras de mentira, diciendo: Templo de Jehová, templo de Jehová, templo de Jehová es éste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 5, 'Mas si mejorareis cumplidamente vuestros caminos y vuestras obras; si con exactitud hiciereis derecho entre el hombre y su prójimo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 6, 'Ni oprimiereis al peregrino, al huérfano, y á la viuda, ni en este lugar derramareis la sangre inocente, ni anduviereis en pos de dioses ajenos para mal vuestro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 7, 'Os haré morar en este lugar, en la tierra que dí á vuestros padres para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 8, 'He aquí vosotros os confiáis en palabras de mentira, que no aprovechan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 9, '¿Hurtando, matando, y adulterando, y jurando falso, é incensando á Baal, y andando tras dioses extraños que no conocisteis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 10, 'Vendréis y os pondréis delante de mí en esta casa sobre la cual es invocado mi nombre, y diréis: Librados somos: para hacer todas estas abominaciones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 11, '¿Es cueva de ladrones delante de vuestros ojos esta casa, sobre la cual es invocado mi nombre? He aquí que también yo veo, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 12, 'Andad empero ahora á mi lugar que fué en Silo, donde hice que morase mi nombre al principio, y ved lo que le hice por la maldad de mi pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 13, 'Ahora pues, por cuanto habéis vosotros hecho todas estas obras, dice Jehová, y bien que os hablé, madrugando para hablar, no oísteis, y os llamé, y no respondisteis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 14, 'Haré también á esta casa sobre la cual es invocado mi nombre, en la que vosotros confiáis, y á este lugar que dí á vosotros y á vuestros padres, como hice á Silo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 15, 'Que os echaré de mi presencia como eché á todos vuestros hermanos, á toda la generación de Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 16, 'Tú pues, no ores por este pueblo, ni levantes por ellos clamor ni oración, ni me ruegues; porque no te oiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 17, '¿No ves lo que estos hacen en las ciudades de Judá y en las calles de Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 18, 'Los hijos cogen la leña, y los padres encienden el fuego, y las mujeres amasan la masa, para hacer tortas á la reina del cielo y para hacer ofrendas á dioses ajenos, por provocarme á ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 19, '¿Provocaránme ellos á ira, dice Jehová, y no más bien obran ellos mismos para confusión de sus rostros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 20, 'Por tanto, así ha dicho el Señor Jehová: He aquí que mi furor y mi ira se derrama sobre este lugar, sobre los hombres, sobre los animales, sobre los árboles del campo, y sobre los frutos de la tierra; y encenderáse, y no se apagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 21, 'Así ha dicho Jehová de los ejércitos, Dios de Israel: Añadid vuestros holocaustos sobre vuestros sacrificios, y comed carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 22, 'Porque no hablé yo con vuestros padres, ni les mandé el día que los saqué de la tierra de Egipto, acerca de holocaustos y de víctimas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 23, 'Mas esto les mandé, diciendo: Escuchad mi voz, y seré á vosotros por Dios, y vosotros me seréis por pueblo; y andad en todo camino que os mandare, para que os vaya bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 24, 'Y no oyeron ni inclinaron su oído; antes caminaron en sus consejos, en la dureza de su corazón malvado, y fueron hacia atrás y no hacia adelante,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 25, 'Desde el día que vuestros padres salieron de la tierra de Egipto hasta hoy. Y os envié á todos los profetas mis siervos, cada día madrugando y enviándolos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 26, 'Mas no me oyeron ni inclinaron su oído; antes endurecieron su cerviz, é hicieron peor que sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 27, 'Tú pues les dirás todas estas palabras, mas no te oirán; aun los llamarás, y no te responderán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 28, 'Les dirás por tanto: Esta es la gente que no escuchó la voz de Jehová su Dios, ni tomó corrección; perdióse la fe, y de la boca de ellos fué cortada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 29, 'Trasquila tu cabello, y arrójalo, y levanta llanto sobre las alturas; porque Jehová ha aborrecido y dejado la nación de su ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 30, 'Porque los hijos de Judá han hecho lo malo ante mis ojos, dice Jehová; pusieron sus abominaciones en la casa sobre la cual mi nombre fué invocado, amancillándola.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 31, 'Y han edificado los altos de Topheth, que es en el valle del hijo de Hinnom, para quemar al fuego sus hijos y sus hijas, cosa que yo no les mandé, ni subió en mi corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 32, 'Por tanto, he aquí vendrán días, ha dicho Jehová, que no se diga más, Topheth, ni valle del hijo de Hinnom, sino Valle de la Matanza; y serán enterrados en Topheth, por no haber lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 33, 'Y serán los cuerpos muertos de este pueblo para comida de las aves del cielo y de las bestias de la tierra; y no habrá quien las espante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 7, 34, 'Y haré cesar de las ciudades de Judá, y de la calles de Jerusalem, voz de gozo y voz de alegría, voz de esposo y voz de esposa; porque la tierra será en desolación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 1, 'EN aquel tiempo, dice Jehová, sacarán los huesos de los reyes de Judá, y los huesos de sus príncipes, y los huesos de los sacerdotes, y los huesos de los profetas, y los huesos de los moradores de Jerusalem, fuera de sus sepulcros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 2, 'Y los esparcirán al sol, y á la luna, y á todo el ejército del cielo, á quien amaron, y á quienes sirvieron, y en pos de quienes anduvieron, y á quienes preguntaron, y á quienes se encorvaron. No serán recogidos, ni enterrados: serán por muladar sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 3, 'Y escogeráse la muerte antes que la vida por todo el resto que quedare de esta mala generación, en todos los lugares á donde los arrojaré yo á los que quedaren, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 4, 'Les dirás asimismo: Así ha dicho Jehová: ¿El que cae, no se levanta? ¿el que se desvía, no torna á camino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 5, '¿Por qué es este pueblo de Jerusalem rebelde con rebeldía perpetua? Abrazaron el engaño, no han querido volverse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 6, 'Escuché y oí; no hablan derecho, no hay hombre que se arrepienta de su mal, diciendo: ¿Qué he hecho? Cada cual se volvió á su carrera, como caballo que arremete con ímpetu á la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 7, 'Aun la cigüeña en el cielo conoce su tiempo, y la tórtola y la grulla y la golondrina guardan el tiempo de su venida; mas mi pueblo no conoce el juicio de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 8, '¿Cómo decís: Nosotros somos sabios, y la ley de Jehová es con nosotros? Ciertamente, he aquí que en vano se cortó la pluma, por demás fueron los escribas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 9, 'Los sabios se avergonzaron, espantáronse y fueron presos: he aquí que aborrecieron la palabra de Jehová; ¿y qué sabiduría tienen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 10, 'Por tanto daré á otros sus mujeres, y sus heredades á quien las posea: porque desde el chico hasta el grande cada uno sigue la avaricia, desde el profeta hasta el sacerdote todos hacen engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 11, 'Y curaron el quebrantamiento de la hija de mi pueblo con liviandad, diciendo: Paz, paz; y no hay paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 12, '¿Hanse avergonzado de haber hecho abominación? Por cierto no se han corrido de vergüenza, ni supieron avergonzarse; caerán por tanto entre los que cayeren, cuando los visitaré: caerán, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 13, 'Cortarélos de por junto, dice Jehová. No habrá uvas en la vid, ni higos en la higuera, y caeráse la hoja; y lo que les he dado pasará de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 14, '¿Sobre qué nos aseguramos? Juntaos, y entrémonos en las ciudades fuertes, y allí reposaremos: porque Jehová nuestro Dios nos ha hecho callar, y dádonos á beber bebida de hiel, porque pecamos contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 15, 'Esperamos paz, y no hubo bien; día de cura, y he aquí turbación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 16, 'Desde Dan se oyó el bufido de sus caballos: del sonido de los relinchos de sus fuertes tembló toda la tierra; y vinieron y devoraron la tierra y su abundancia, ciudad y moradores de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 17, 'Porque he aquí que yo envío sobre vosotros serpientes, basiliscos, contra los cuales no hay encantamiento; y os morderán, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 18, 'A causa de mi fuerte dolor mi corazón desfallece en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 19, 'He aquí voz del clamor de la hija de mi pueblo, que viene de la tierra lejana: ¿No está Jehová en Sión? ¿no está en ella su Rey? ¿Por qué me hicieron airar con sus imágenes de talla, con vanidades ajenas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 20, 'Pasóse la siega, acabóse el verano, y nosotros no hemos sido salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 21, 'Quebrantado estoy por el quebrantamiento de la hija de mi pueblo; entenebrecido estoy, espanto me ha arrebatado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 8, 22, '¿No hay bálsamo en Galaad? ¿no hay allí médico? ¿Por qué pues no hubo medicina para la hija de mi pueblo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 1, '¡OH si mi cabeza se tornase aguas, y mis ojos fuentes de aguas, para que llore día y noche los muertos de la hija de mi pueblo!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 2, '¡Oh quién me diese en el desierto un mesón de caminantes, para que dejase mi pueblo, y de ellos me apartase! Porque todos ellos son adúlteros, congregación de prevaricadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 3, 'E hicieron que su lengua, como su arco, tirase mentira; y no se fortalecieron por verdad en la tierra: porque de mal en mal procedieron, y me han desconocido, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 4, 'Guárdese cada uno de su compañero, ni en ningún hermano tenga confianza: porque todo hermano engaña con falacia, y todo compañero anda con falsedades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 5, 'Y cada uno engaña á su compañero, y no hablan verdad: enseñaron su lengua á hablar mentira, se ocupan de hacer perversamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 6, 'Tu morada es en medio de engaño; de muy engañadores no quisieron conocerme, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 7, 'Por tanto, así ha dicho Jehová de los ejércitos: He aquí que yo los fundiré, y los ensayaré; porque ¿cómo he de hacer por la hija de mi pueblo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 8, 'Saeta afilada es la lengua de ellos; engaño habla; con su boca habla paz con su amigo, y dentro de sí pone sus asechanzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 9, '¿No los tengo de visitar sobre estas cosas? dice Jehová. ¿De tal gente no se vengará mi alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 10, 'Sobre los montes levantaré lloro y lamentación, y llanto sobre las moradas del desierto; porque desolados fueron hasta no quedar quien pase, ni oyeron bramido de ganado: desde las aves del cielo y hasta las bestias de la tierra se trasportaron, y se fueron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 11, 'Y pondré á Jerusalem en montones, por moradas de culebras; y pondré las ciudades de Judá en asolamiento, que no quede morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 12, '¿Quién es varón sabio que entienda esto? ¿y á quién habló la boca de Jehová, para que pueda declararlo? ¿Por qué causa la tierra ha perecido, ha sido asolada como desierto, que no hay quien pase?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 13, 'Y dijo Jehová: Porque dejaron mi ley, la cual dí delante de ellos, y no obedecieron á mi voz, ni caminaron conforme á ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 14, 'Antes se fueron tras la imaginación de su corazón, y en pos de los Baales que les enseñaron sus padres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 15, 'Por tanto así ha dicho Jehová de los ejércitos, Dios de Israel: He aquí que á este pueblo yo les daré á comer ajenjos, y les daré á beber aguas de hiel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 16, 'Y los esparciré entre gentes que no conocieron ellos ni sus padres; y enviaré espada en pos de ellos, hasta que yo los acabe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 17, 'Así dice Jehová de los ejércitos: Considerad, y llamad plañideras que vengan; y enviad por las sabias que vengan:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 18, 'Y dense prisa, y levanten llanto sobre nosotros, y córranse nuestros ojos en lágrimas, y nuestros párpados en aguas se destilen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 19, 'Porque voz de endecha fué oída de Sión: ¡Cómo hemos sido destruídos! en gran manera hemos sido confundidos. ¿Por qué dejamos la tierra? ¿por qué nos han echado de sí nuestras moradas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 20, 'Oíd pues, oh mujeres, palabra de Jehová, y vuestro oído reciba la palabra de su boca; y enseñad endechas á vuestras hijas, y cada una á su amiga, lamentación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 21, 'Porque la muerte ha subido por nuestras ventanas, ha entrado en nuestros palacios; para talar los niños de las calles, los mancebos de las plazas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 22, 'Habla: Así ha dicho Jehová: Los cuerpos de los hombres muertos caerán como estiércol sobre la haz del campo, y como manojo tras el segador, que no hay quien lo recoja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 23, 'Así dijo Jehová: No se alabe el sabio en su sabiduría, ni en su valentía se alabe el valiente, ni el rico se alabe en sus riquezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 24, 'Mas alábese en esto el que se hubiere de alabar: en entenderme y conocerme, que yo soy Jehová, que hago misericordia, juicio, y justicia en la tierra: porque estas cosas quiero, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 25, 'He aquí que vienen días, dice Jehová, y visitaré sobre todo circuncidado, y sobre todo incircunciso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 9, 26, 'A Egipto, y á Judá, y á Edom, y á los hijos de Ammón y de Moab, y á todos los arrinconados en el postrer rincón, que moran en el desierto; porque todas las gentes tienen prepucio, y toda la casa de Israel tiene prepucio en el corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 1, 'OID la palabra que Jehová ha hablado sobre vosotros, oh casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 2, 'Así dijo Jehová: No aprendáis el camino de las gentes, ni de las señales del cielo tengáis temor, aunque las gentes las teman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 3, 'Porque las ordenanzas de los pueblos son vanidad: porque leño del monte cortaron, obra de manos de artífice con azuela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 4, 'Con plata y oro lo engalanan; con clavos y martillo lo afirman, para que no se salga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 5, 'Como palma lo igualan, y no hablan; son llevados, porque no pueden andar. No tengáis temor de ellos; porque ni pueden hacer mal, ni para hacer bien tienen poder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 6, 'No hay semejante á tí, oh Jehová; grande tú, y grande tu nombre en fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 7, '¿Quién no te temerá, oh Rey de las gentes? porque á tí compete ello; porque entre todos los sabios de las gentes, y en todos sus reinos, no hay semejante á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 8, 'Y todos se infatuarán, y entontecerán. Enseñanza de vanidades es el mismo leño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 9, 'Traerán plata extendida de Tarsis, y oro de Uphaz; obrará el artífice, y las manos del fundidor; vestiránlos de cárdeno y de púrpura: obra de peritos es todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 10, 'Mas Jehová Dios es la verdad; él es Dios vivo y Rey eterno: á su ira tiembla la tierra, y las gentes no pueden sufrir su saña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 11, 'Les diréis así: Los dioses que no hicieron los cielos ni la tierra, perezcan de la tierra y de debajo de estos cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 12, 'El que hizo la tierra con su potencia, el que puso en orden el mundo con su saber, y extendió los cielos con su prudencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 13, 'A su voz se da muchedumbre de aguas en el cielo, y hace subir las nubes de lo postrero de la tierra; hace los relámpagos con la lluvia, y saca el viento de sus depósitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 14, 'Todo hombre se embrutece y le falta ciencia; avergüéncese de su vaciadizo todo fundidor: porque mentira es su obra de fundición, y no hay espíritu en ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 15, 'Vanidad son, obra de escarnios: en el tiempo de su visitación perecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 16, 'No es como ellos la suerte de Jacob: porque él es el Hacedor de todo, é Israel es la vara de su herencia: Jehová de los ejércitos es su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 17, 'Recoge de las tierras tus mercaderías, la que moras en lugar fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 18, 'Porque así ha dicho Jehová: He aquí que esta vez arrojaré con honda los moradores de la tierra, y he de afligirlos, para que lo hallen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 19, '¡Ay de mí, por mi quebrantamiento! mi llaga es muy dolorosa. Yo empero dije: Ciertamente enfermedad mía es esta, y debo sufrirla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 20, 'Mi tienda es destruída, y todas mis cuerdas están rotas: mis hijos fueron sacados de mí, y perecieron: no hay ya más quien extienda mi tienda, ni quien levante mis cortinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 21, 'Porque los pastores se infatuaron, y no buscaron á Jehová: por tanto no prosperaron, y todo su ganado se esparció.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 22, 'He aquí que voz de fama viene, y alboroto grande de la tierra del aquilón, para tornar en soledad todas las ciudades de Judá, en morada de culebras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 23, 'Conozco, oh Jehová, que el hombre no es señor de su camino, ni del hombre que camina es ordenar sus pasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 24, 'Castígame, oh Jehová, mas con juicio; no con tu furor, porque no me aniquiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 10, 25, 'Derrama tu enojo sobre las gentes que no te conocen, y sobre las naciones que no invocan tu nombre: porque se comieron á Jacob, y lo devoraron, y le han consumido, y asolado su morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 1, 'PALABRA que fué de Jehová, á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 2, 'Oid las palabras de este pacto, y hablad á todo varón de Judá, y á todo morador de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 3, 'Y les dirás tú: Así dijo Jehová Dios de Israel: Maldito el varón que no obedeciere las palabras de este pacto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 4, 'El cual mandé á vuestros padres el día que los saqué de la tierra de Egipto, del horno de hierro, diciéndoles: Oid mi voz, y ejecutad aquéllas, conforme á todo lo que os mando, y me seréis por pueblo, y yo seré á vosotros por Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 5, 'Para que confirme el juramento que hice á vuestros padres, que les daría la tierra que corre leche y miel, como este día. Y respondí, y dije: Amén, oh Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 6, 'Y Jehová me dijo: Pregona todas estas palabras en las ciudades de Judá y en las calles de Jerusalem, diciendo: Oid las palabras de este pacto, y ponedlas por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 7, 'Porque con eficacia protesté a vuestros padres el día que los hice subir de la tierra de Egipto hasta el día de hoy, madrugando y protestando, diciendo: Oid mi voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 8, 'Mas no oyeron, ni inclinaron su oído, antes se fueron cada uno tras la imaginación de su corazón malvado: por tanto, traeré sobre ellos todas las palabras de este pacto, el cual mandé que cumpliesen, y no lo cumplieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 9, 'Y díjome Jehová: Conjuración se ha hallado en los varones de Judá, y en los moradores de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 10, 'Hanse vuelto á las maldades de sus primeros padres, los cuales no quisieron escuchar mis palabras, antes se fueron tras dioses ajenos para servirles; la casa de Israel y la casa de Judá invalidaron mi pacto, el cual había yo concertado con sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 11, 'Por tanto, así ha dicho Jehová: He aquí yo traigo sobre ellos mal del que no podrán salir; y clamarán á mi, y no los oiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 12, 'E irán las ciudades de Judá y los moradores de Jerusalem, y clamarán á los dioses á quienes queman ellos inciensos, los cuales no los podrán salvar en el tiempo de su mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 13, 'Porque según el número de tus ciudades fueron tus dioses, oh Judá; y según el número de tus calles, oh Jerusalem, pusisteis los altares de ignominia, altares para ofrecer sahumerios á Baal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 14, 'Tú pues, no ores por este pueblo, ni levantes por ellos clamor ni oración; porque yo no oiré el día que en su aflicción á mí clamaren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 15, '¿Qué tiene mi amado en mi casa, habiendo hecho abominaciones muchas? Y las carnes santas pasarán de sobre tí, porque en tu maldad te gloriaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 16, 'Oliva verde, hermosa en fruto y en parecer, llamó Jehová tu nombre. A la voz de gran palabra hizo encender fuego sobre ella, y quebraron sus ramas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 17, 'Pues Jehová de los ejércitos, que te plantó, ha pronunciado mal contra ti, á causa de la maldad de la casa de Israel y de la casa de Judá, que hicieron á sí mismos, provocándome á ira con incensar á Baal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 18, 'Y Jehová me lo hizo saber, y conocílo: entonces me hiciste ver sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 19, 'Y yo como cordero inocente que llevan á degollar, pues no entendía que maquinaban contra mí designios, diciendo: Destruyamos el árbol con su fruto, y cortémoslo de la tierra de los vivientes, y no haya más memoria de su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 20, 'Mas, oh Jehová de los ejércitos, que juzgas justicia, que sondas los riñones y el corazón, vea yo tu venganza de ellos: porque á ti he descubierto mi causa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 21, 'Por tanto, así ha dicho Jehová de los varones de Anathoth, que buscan tu alma, diciendo: No profetices en nombre de Jehová, y no morirás á nuestras manos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 22, 'Así pues ha dicho Jehová de los ejércitos: He aquí que yo los visito; los mancebos morirán á cuchillo; sus hijos y sus hijas morirán de hambre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 11, 23, 'Y no quedará resto de ellos: porque yo traeré mal sobre los varones de Anathoth, año de su visitación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 1, 'JUSTO eres tú, oh Jehová, aunque yo contigo dispute: hablaré empero juicios contigo. ¿Por qué es prosperado el camino de los impíos, y tienen bien todos los que se portan deslealmente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 2, 'Plantástelos, y echaron raíces; progresaron, é hicieron fruto; cercano estás tú en sus bocas, mas lejos de sus riñones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 3, 'Tu empero, oh Jehová, me conoces; vísteme, y probaste mi corazón para contigo: arráncalos como á ovejas para el degolladero, y señálalos para el día de la matanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 4, '¿Hasta cuándo estará desierta la tierra, y marchita la hierba de todo el campo? Por la maldad de los que en ella moran, faltaron los ganados, y las aves; porque dijeron: No verá él nuestras postrimerías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 5, 'Si corriste con los de á pié, y te cansaron, ¿cómo contenderás con los caballos? Y si en la tierra de paz estabas quieto, ¿cómo harás en la hinchazón del Jordán?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 6, 'Porque aun tus hermanos y la casa de tu padre, aun ellos se levantaron contra ti, aun ellos dieron voces en pos de ti. No los creas, cuando bien te hablaren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 7, 'He dejado mi casa, desamparé mi heredad, entregado he lo que amaba mi alma en manos de sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 8, 'Fué para mí mi heredad como león en breña: contra mí dió su voz; por tanto la aborrecí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 9, '¿Esme mi heredad ave de muchos colores? ¿no están contra ella aves en derredor? Venid, reuníos, vosotras todas las bestias del campo, venid á devorarla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 10, 'Muchos pastores han destruído mi viña, hollaron mi heredad, tornaron en desierto y soledad mi heredad preciosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 11, 'Fué puesta en asolamiento, y lloró sobre mí, asolada: fué asolada toda la tierra, porque no hubo hombre que mirase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 12, 'Sobre todos los lugares altos del desierto vinieron disipadores: porque la espada de Jehová devorará desde el un extremo de la tierra hasta el otro extremo: no habrá paz para ninguna carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 13, 'Sembraron trigo, y segarán espinas; tuvieron la heredad, mas no aprovecharon nada: se avergonzarán de vuestros frutos, á causa de la ardiente ira de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 14, 'Así dijo Jehová contra todos mis malos vecinos, que tocan la heredad que hice poseer á mi pueblo Israel: He aquí que yo los arrancaré de su tierra, y arrancaré de en medio de ellos la casa de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 15, 'Y será que, después que los hubiere arrancado, tornaré y tendré misericordia de ellos, y harélos volver cada uno á su heredad, y cada cual á su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 16, 'Y será que, si cuidadosamente aprendieren los caminos de mi pueblo, para jurar en mi nombre, diciendo, Vive Jehová, así como enseñaron á mi pueblo á jurar por Baal; ellos serán prosperados en medio de mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 12, 17, 'Mas si no oyeren, arrancaré á la tal gente, sacándola de raíz, y destruyendo, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 1, 'ASI me dijo Jehová: Ve, y cómprate un cinto de lino, y cíñelo sobre tus lomos, y no lo meterás en agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 2, 'Y compré el cinto conforme á la palabra de Jehová, y púselo sobre mis lomos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 3, 'Y fué á mí segunda vez palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 4, 'Toma el cinto que compraste, que está sobre tus lomos, y levántate, y ve al Eufrates, y escóndelo allá en la concavidad de una peña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 5, 'Fuí pues, y escondílo junto al Eufrates, como Jehová me mandó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 6, 'Y sucedió que al cabo de muchos días me dijo Jehová: Levántate, y ve al Eufrates, y toma de allí el cinto que te mandé escondieses allá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 7, 'Entonces fuí al Eufrates, y cavé, y tomé el cinto del lugar donde lo había escondido; y he aquí que el cinto se había podrido; para ninguna cosa era bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 8, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 9, 'Así ha dicho Jehová: Así haré podrir la soberbia de Judá, y la mucha soberbia de Jerusalem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 10, 'A este pueblo malo, que no quieren oir mis palabras, que andan en las imaginaciones de su corazón, y se fueron en pos de dioses ajenos para servirles, y para encorvarse á ellos; y vendrá á ser como este cinto, que para ninguna cosa es bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 11, 'Porque como el cinto se junta á los lomos del hombre, así hice juntar á mí toda la casa de Israel y toda la casa de Judá, dice Jehová, para que me fuesen por pueblo y por fama, y por alabanza y por honra: empero no escucharon.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 12, 'Les dirás pues esta palabra: Así ha dicho Jehová, Dios de Israel: Henchiráse de vino todo odre. Y ellos te dirán: ¿No sabemos que todo odre se henchirá de vino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 13, 'Entonces les has de decir: Así ha dicho Jehová: He aquí que yo lleno de embriaguez todos los moradores de esta tierra, y á los reyes de la estirpe de David que se sientan sobre su trono, y á los sacerdotes y profetas, y á todos los moradores de Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 14, 'Y quebrantarélos el uno con el otro, los padres con los hijos juntamente, dice Jehová: no perdonaré, ni tendré piedad ni misericordia, para no destruirlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 15, 'Escuchad y oid; no os elevéis: pues Jehová ha hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 16, 'Dad gloria á Jehová Dios vuestro, antes que haga venir tinieblas, y antes que vuestros pies tropiecen en montes de oscuridad, y esperéis luz, y os la torne sombra de muerte y tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 17, 'Mas si no oyereis esto, en secreto llorará mi alma á causa de vuestra soberbia; y llorando amargamente, se desharán mis ojos en lágrimas, porque el rebaño de Jehová fué cautivo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 18, 'Di al rey y á la reina: Humillaos, sentaos en tierra; porque la corona de vuestra gloria bajó de vuestras cabezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 19, 'Las ciudades del mediodía fueron cerradas, y no hubo quien las abriese: toda Judá fué trasportada, trasportada fué toda ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 20, 'Alzad vuestros ojos, y ved los que vienen del aquilón: ¿dónde está el rebaño que te fué dado, la grey de tu gloria?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 21, '¿Qué dirás cuando te visitará? porque tu los enseñaste á ser príncipes y cabeza sobre ti. ¿No te tomarán dolores como á mujer que pare?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 22, 'Cuando dijeres en tu corazón: ¿Por qué me ha sobrevenido esto? Por la enormidad de tu maldad fueron descubiertas tus faldas, fueron desnudos tus calcañares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 23, '¿Mudará el negro su pellejo, y el leopardo sus manchas? Así también podréis vosotros hacer bien, estando habituados á hacer mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 24, 'Por tanto yo los esparciré, como tamo que pasa, al viento del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 25, 'Esta es tu suerte, la porción de tus medidas de parte mía, dice Jehová; porque te olvidaste de mí, y confiaste en la mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 26, 'Yo pues descubriré también tus faldas delante de tu cara, y se manifestará tu ignominia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 13, 27, 'Tus adulterios, tus relinchos, la maldad de tu fornicación sobre los collados: en el mismo campo vi tus abominaciones. ¡Ay de ti, Jerusalem! ¿No serás al cabo limpia? ¿hasta cuándo todavía?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 1, 'PALABRA de Jehová que fué dada á Jeremías, con motivo de la sequía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 2, 'Enlutóse Judá, y sus puertas se despoblaron: oscureciéronse en tierra, y subió el clamor de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 3, 'Y los principales de ellos enviaron sus criados al agua: vinieron á las lagunas, y no hallaron agua: volviéronse con sus vasos vacíos; se avergonzaron, confundiéronse, y cubrieron sus cabezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 4, 'Porque se resquebrajó la tierra á causa de no llover en el país; confusos los labradores, cubrieron sus cabezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 5, 'Y aun las ciervas en los campos parían, y dejaban la cría, porque no había hierba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 6, 'Y los asnos monteses se ponían en los altos, aspiraban el viento como los chacales; sus ojos se ofuscaron, porque no había hierba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 7, 'Si nuestras iniquidades testifican contra nosotros, oh Jehová, haz por amor de tu nombre; porque nuestras rebeliones se han multiplicado, contra ti pecamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 8, 'Oh esperanza de Israel, Guardador suyo en el tiempo de la aflicción, ¿por qué has de ser como peregrino en la tierra, y como caminante que se aparta para tener la noche?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 9, '¿Por qué has de ser como hombre atónito, y como valiente que no puede librar? tú empero estás entre nosotros, oh Jehová, y sobre nosotros es invocado tu nombre; no nos desampares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 10, 'Así ha dicho Jehová á este pueblo: Así amaron moverse, ni detuvieron sus pies: por tanto, Jehová no los tiene en voluntad; acordaráse ahora de la maldad de ellos, y visitará sus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 11, 'Y díjome Jehová: No ruegues por este pueblo para bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 12, 'Cuando ayunaren, yo no oiré su clamor, y cuando ofrecieren holocausto y ofrenda, no lo aceptaré; antes los consumiré con cuchillo, y con hambre, y con pestilencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 13, 'Y yo dije: ¡Ah! ah! Señor Jehová! he aquí que los profetas les dicen: No veréis cuchillo, ni habrá hambre en vosotros, sino que en este lugar os daré paz verdadera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 14, 'Díjome entonces Jehová: Falso profetizan los profetas en mi nombre: no los envié, ni les mandé, ni les hablé: visión mentirosa, y adivinación, y vanidad, y engaño de su corazón os profetizan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 15, 'Por tanto así ha dicho Jehová sobre los profetas que profetizan en mi nombre, los cuales yo no envié, y que dicen, Cuchillo ni hambre no habrá en esta tierra: Con cuchillo y con hambre serán consumidos esos profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 16, 'Y el pueblo á quien profetizan, echado será en las calles de Jerusalem por hambre y por espada; y no habrá quien los entierre, ellos, y sus mujeres, y sus hijos, y sus hijas; y sobre ellos derramaré su maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 17, 'Decirles has, pues, esta palabra: Córranse mis ojos en lágrimas noche y día, y no cesen; porque de gran quebrantamiento es quebrantada la virgen hija de mi pueblo, de plaga muy recia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 18, 'Si salgo al campo, he aquí muertos á cuchillo; y si me entro en la ciudad, he aquí enfermos de hambre: porque también el profeta como el sacerdote anduvieron rodeando en la tierra, y no conocieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 19, '¿Has desechado enteramente á Judá? ¿ha aborrecido tu alma á Sión? ¿Por qué nos hiciste herir sin que nos quede cura? Esperamos paz, y no hubo bien; tiempo de cura, y he aquí turbación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 20, 'Reconocemos, oh Jehová, nuestra impiedad, la iniquidad de nuestros padres: porque contra ti hemos pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 21, 'Por amor de tu nombre no nos deseches, ni trastornes el trono de tu gloria: acuérdate, no invalides tu pacto con nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 14, 22, '¿Hay entre las vanidades de las gentes quien haga llover? ¿y darán los cielos lluvias? ¿No eres tú, Jehová, nuestro Dios? en ti pues esperamos; pues tú hiciste todas estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 1, 'Y DIJOME Jehová: Si Moisés y Samuel se pusieran delante de mí, mi voluntad no será con este pueblo: échalos de delante de mí, y salgan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 2, 'Y será que si te preguntaren: ¿A dónde saldremos? les dirás: Así ha dicho Jehová: El que á muerte, á muerte; y el que á cuchillo, á cuchillo; y el que á hambre, á hambre; y el que á cautividad, á cautividad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 3, 'Y enviaré sobre ellos cuatro géneros, dice Jehová: cuchillo para matar, y perros para despedazar, y aves del cielo y bestias de la tierra, para devorar y para disipar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 4, 'Y entregarélos á ser agitados por todos los reinos de la tierra, á causa de Manasés hijo de Ezechîas rey de Judá, por lo que hizo en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 5, 'Porque ¿quién tendrá compasión de ti, oh Jerusalem? ¿ó quién se entristecerá por tu causa? ¿ó quién ha de venir á preguntar por tu paz?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 6, 'Tú me dejaste, dice Jehová, atrás te volviste: por tanto yo extenderé sobre ti mi mano, y te destruiré; estoy cansado de arrepentirme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 7, 'Y aventélos con aventador hasta las puertas de la tierra; desahijé, desbaraté mi pueblo; no se tornaron de sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 8, 'Sus viudas se multiplicaron más que la arena de la mar; traje contra ellos destruidor á medio día sobre la madre y los hijos; sobre la ciudad hice que de repente cayesen terrores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 9, 'Enflaquecióse la que parió siete; llenóse de dolor su alma; su sol se le puso siendo aún de día; fué avergonzada y llena de confusión: y lo que de ella quedare, entregarélo á cuchillo delante de sus enemigos, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 10, '¡Ay de mí, madre mía, que me has engendrado hombre de contienda y hombre de discordia á toda la tierra! Nunca les dí á logro, ni lo tomé de ellos; y todos me maldicen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 11, 'Dijo Jehová: De cierto tus reliquias serán en bien; de cierto haré que el enemigo te salga á recibir en el tiempo trabajoso, y en el tiempo de angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 12, '¿Quebrará el hierro al hierro de la parte de aquilón, y al bronce?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 13, 'Tus riquezas y tus tesoros daré á saco sin ningún precio, por todos tus pecados, y en todos tus términos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 14, 'Y te haré pasar á tus enemigos en tierra que no conoces: porque fuego se ha encendido en mi furor, y arderá sobre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 15, 'Tú lo sabes, oh Jehová; acuérdate de mí, y visítame, y véngame de mis enemigos. No me tomes en la prolongación de tu enojo: sabes que por amor de ti sufro afrenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 16, 'Halláronse tus palabras, y yo las comí; y tu palabra me fué por gozo y por alegría de mi corazón: porque tu nombre se invocó sobre mí, oh Jehová Dios de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 17, 'No me senté en compañia de burladores, ni me engreí á causa de tu profecía; sentéme solo, porque me llenaste de desabrimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 18, '¿Por qué fué perpetuo mi dolor, y mi herida desahuciada no admitió cura? ¿Serás para mí como cosa ilusoria, como aguas que no son estables?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 19, 'Por tanto así dijo Jehová: Si te convirtieres, yo te repondré, y delante de mí estarás; y si sacares lo precioso de lo vil, serás como mi boca. Conviértanse ellos á ti, y tú no te conviertas á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 20, 'Y te daré para este pueblo por fuerte muro de bronce, y pelearán contra ti, y no te vencerán: porque yo estoy contigo para guardarte y para defenderte, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 15, 21, 'Y librarte he de la mano de los malos, y te redimiré de la mano de los fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 2, 'No tomarás para ti mujer, ni tendrás hijos ni hijas en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 3, 'Porque así ha dicho Jehová acerca de los hijos y de las hijas que nacieren en este lugar, y de sus madres que los parieren, y de los padres que los engendraren en esta tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 4, 'De dolorosas enfermedades morirán; no serán plañidos ni enterrados: serán por muladar sobre la haz de la tierra: y con cuchillo y con hambre serán consumidos, y sus cuerpos serán para comida de las aves del cielo y de las bestias de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 5, 'Porque así ha dicho Jehová: No entres en casa de luto, ni vayas á lamentar, ni los consueles: porque yo he quitado mi paz de este pueblo, dice Jehová, mi misericordia y piedades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 6, 'Y morirán en esta tierra grandes y chicos: no se enterrarán, ni los plañirán, ni se arañarán, ni se mesarán por ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 7, 'Ni por ellos partirán pan por luto, para consolarlos de sus muertos; ni les darán á beber vaso de consolaciones por su padre ó por su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 8, 'Asimismo no entres en casa de convite, para sentarte con ellos á comer ó á beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 9, 'Porque así ha dicho Jehová de los ejércitos, Dios de Israel: He aquí que yo haré cesar en este lugar, delante de vuestros ojos y en vuestros días, toda voz de gozo y toda voz de alegría, toda voz de esposo y toda voz de esposa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 10, 'Y acontecerá que cuando anunciares á este pueblo todas estas cosas, te dirán ellos: ¿Por qué habló Jehová sobre nosotros este mal tan grande? ¿y qué maldad es la nuestra, ó qué pecado es el nuestro, que cometiéramos contra Jehová nuestro Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 11, 'Entonces les dirás: Porque vuestros padres me dejaron, dice Jehová, y anduvieron en pos de dioses ajenos, y los sirvieron, y á ellos se encorvaron, y me dejaron á mí, y no guardaron mi ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 12, 'Y vosotros habéis hecho peor que vuestros padres; porque he aquí que vosotros camináis cada uno tras la imaginación de su malvado corazón, no oyéndome á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 13, 'Por tanto, yo os haré echar de esta tierra á tierra que ni vosotros ni vuestros padres habéis conocido, y allá serviréis á dioses ajenos de día y de noche; porque no os mostraré clemencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 14, 'Empero he aquí, vienen días, dice Jehová, que no se dirá más: Vive Jehová, que hizo subir á los hijos de Israel de tierra de Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 15, 'Sino: Vive Jehová, que hizo subir á los hijos de Israel de la tierra del aquilón, y de todas las tierras á donde los había arrojado: y volverélos á su tierra, la cual dí á sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 16, 'He aquí que yo envío muchos pescadores, dice Jehová, y los pescarán; y después enviaré muchos cazadores, y los cazarán de todo monte, y de todo collado, y de las cavernas de los peñascos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 17, 'Porque mis ojos están sobre todos sus caminos, los cuales no se me ocultaron, ni su maldad se esconde de la presencia de mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 18, 'Mas primero pagaré al doble su iniquidad y su pecado; porque contaminaron mi tierra con los cuerpos muertos de sus abominaciones, y de sus abominaciones llenaron mi heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 19, 'Oh Jehová, fortaleza mía, y fuerza mía, y refugio mío en el tiempo de la aflicción; á ti vendrán gentes desde los extremos de la tierra, y dirán: Ciertamente mentira poseyeron nuestros padres, vanidad, y no hay en ellos provecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 20, '¿Ha de hacer el hombre dioses para sí? mas ellos no son dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 16, 21, 'Por tanto, he aquí, les enseñaré de esta vez, enseñarles he mi mano y mi fortaleza, y sabrán que mi nombre es Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 1, 'EL pecado de Judá escrito está con cincel de hierro, y con punta de diamante: esculpido está en la tabla de su corazón, y en los lados de vuestros altares;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 2, 'Cuando sus hijos se acuerdan de sus altares y de sus bosques, junto á los árboles verdes y en los collados altos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 3, '¡Oh mi montaña! tu hacienda en el campo y todos tus tesoros daré á saco, por el pecado de tus altos en todos tus términos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 4, 'Y habrá en ti cesación de tu heredad, la cual yo te dí, y te haré servir á tus enemigos en tierra que no conociste; porque fuego habéis encendido en mi furor, para siempre arderá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 5, 'Así ha dicho Jehová: Maldito el varón que confía en el hombre, y pone carne por su brazo, y su corazón se aparta de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 6, 'Pues será como la retama en el desierto, y no verá cuando viniere el bien; sino que morará en las securas en el desierto, en tierra despoblada y deshabitada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 7, 'Bendito el varón que se fía en Jehová, y cuya confianza es Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 8, 'Porque él será como el árbol plantado junto á las aguas, que junto á la corriente echará sus raices, y no verá cuando viniere el calor, sino que su hoja estará verde; y en el año de sequía no se fatigará, ni dejará de hacer fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 9, 'Engañoso es el corazón más que todas las cosas, y perverso; ¿quién lo conocerá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 10, 'Yo Jehová, que escudriño el corazón, que pruebo los riñones, para dar á cada uno según su camino, según el fruto de sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 11, 'Como la perdiz que cubre lo que no puso, es el que allega riquezas, y no con justicia; en medio de sus días las dejará, y en su postrimería será insipiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 12, 'Trono de gloria, excelso desde el principio, es el lugar de nuestro santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 13, '¡Oh Jehová, esperanza de Israel! todos los que te dejan, serán avergonzados; y los que de mí se apartan, serán escritos en el polvo; porque dejaron la vena de aguas vivas, á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 14, 'Sáname, oh Jehová, y seré sano; sálvame, y seré salvo: porque tú eres mi alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 15, 'He aquí que ellos me dicen: ¿Dónde está la palabra de Jehová? venga ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 16, 'Mas yo no me entrometí á ser pastor en pos de ti, ni deseé día de calamidad, tú lo sabes. Lo que de mi boca ha salido, fué en tu presencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 17, 'No me seas tú por espanto: esperanza mía eres tú en el día malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 18, 'Avergüéncense los que me persiguen, y no me avergüence yo; asómbrense ellos, y yo no me asombre: trae sobre ellos día malo, y quebrántalos con doble quebrantamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 19, 'Así me ha dicho Jehová: Ve, y ponte á la puerta de los hijos del pueblo, por la cual entran y salen los reyes de Judá, y á todas las puertas de Jerusalem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 20, 'Y diles: Oid la palabra de Jehová, reyes de Judá, y todo Judá, y todos los moradores de Jerusalem que entráis por esta puertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 21, 'Así ha dicho Jehová: Guardaos por vuestras vidas, y no traigáis carga en el día del sábado, para meter por las puertas de Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 22, 'Ni saquéis carga de vuestras casas en el día del sábado, ni hagáis obra alguna: mas santificad el día del sábado, como mandé á vuestros padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 23, 'Mas ellos no oyeron, ni inclinaron su oído, antes endurecieron su cerviz, por no oir, ni recibir corrección.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 24, 'Será empero, si vosotros me obedeciereis, dice Jehová, no metiendo carga por las puertas de esta ciudad en el día del sábado, sino que santificaréis el día del sábado, no haciendo en él ninguna obra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 25, 'Que entrarán por las puertas de esta ciudad, en carros y en caballos, los reyes y los príncipes que se sientan sobre el trono de David, ellos y sus príncipes, los varones de Judá, y los moradores de Jerusalem: y esta ciudad será habitada para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 26, 'Y vendrán de las ciudades de Judá, y de los alrededores de Jerusalem, y de tierra de Benjamín, y de los campos, y del monte, y del austro, trayendo holocausto y sacrificio, y ofrenda é incienso, y trayendo sacrificio de alabanza á la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 17, 27, 'Mas si no me oyereis para santificar el día del sábado, y para no traer carga ni meterla por las puertas de Jerusalem en día de sábado, yo haré encender fuego en sus puertas, y consumirá los palacios de Jerusalem, y no se apagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 1, 'LA palabra que fué á Jeremías de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 2, 'Levántate, y vete á casa del alfarero, y allí te haré oir mis palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 3, 'Y descendí á casa del alfarero, y he aquí que él hacía obra sobre la rueda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 4, 'Y el vaso que él hacía de barro se quebró en la mano del alfarero; y tornó é hízolo otro vaso, según que al alfarero pareció mejor hacerlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 5, 'Entonces fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 6, '¿No podré yo hacer de vosotros como este alfarero, oh casa de Israel, dice Jehová? He aquí que como el barro en la mano del alfarero, así sois vosotros en mi mano, oh casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 7, 'En un instante hablaré contra gentes y contra reinos, para arrancar, y disipar, y destruir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 8, 'Empero si esas gentes se convirtieren de su maldad, de que habré hablado, yo me arrepentiré del mal que había pensado hacerles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 9, 'Y en un instante hablaré de la gente y del reino, para edificar y para plantar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 10, 'Pero si hiciere lo malo delante de mis ojos, no oyendo mi voz, arrepentiréme del bien que había determinado hacerle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 11, 'Ahora pues habla luego á todo hombre de Judá, y á los moradores de Jerusalem, diciendo: Así ha dicho Jehová: He aquí que yo dispongo mal contra vosotros, y trazo contra vosotros designios: conviértase ahora cada uno de su mal camino, y mejorad vuestros caminos y vuestras obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 12, 'Y dijeron: Es por demás: porque en pos de nuestras imaginaciones hemos de ir, y hemos de hacer cada uno el pensamiento de su malvado corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 13, 'Por tanto, así dijo Jehová: Preguntad ahora á las gentes, quién tal haya oído. Gran fealdad ha hecho la virgen de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 14, '¿Faltará la nieve del Líbano de la piedra del campo? ¿faltarán las aguas frías que corren de lejanas tierras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 15, 'Porque mi pueblo me ha olvidado, incensando á la vanidad, y hácenles tropezar en sus caminos, en las sendas antiguas, para que caminen por sendas, por camino no hollado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 16, 'Para poner su tierra en desolación, y en silbos perpetuos; todo aquel que pasare por ella se maravillará, y meneará su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 17, 'Como viento solano los esparciré delante del enemigo; mostraréles las espaldas, y no el rostro, en el día de su perdición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 18, 'Y dijeron: Venid, y tracemos maquinaciones contra Jeremías; porque la ley no faltará del sacerdote, ni consejo del sabio, ni palabra del profeta. Venid é hirámoslo de lengua, y no miremos á todas sus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 19, 'Oh Jehová, mira por mí, y oye la voz de los que contienden conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 20, '¿Dase mal por bien para que hayan cavado hoyo á mi alma? Acuérdate que me puse delante de ti para hablar bien por ellos, para apartar de ellos tu ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 21, 'Por tanto, entrega sus hijos á hambre, y hazlos derramar por medio de la espada; y queden sus mujeres sin hijos, y viudas; y sus maridos sean puestos á muerte, y sus jóvenes heridos á cuchillo en la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 22, 'Oigase clamor de sus casas, cuando trajeres sobre ellos ejército de repente: porque cavaron hoyo para prenderme, y á mis pies han escondido lazos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 18, 23, 'Mas tú, oh Jehová, conoces todo su consejo contra mí para muerte; no perdones su maldad, ni borres su pecado de delante de tu rostro: y tropiecen delante de ti; haz así con ellos en el tiempo de tu furor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 1, 'ASI dijo Jehová: Ve, y compra una vasija de barro de alfarero, y lleva contigo de los ancianos del pueblo, y de los ancianos de los sacerdotes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 2, 'Y saldrás al valle del hijo de Hinnom, que está á la entrada de la puerta oriental, y publicarás allí las palabras que yo te hablaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 3, 'Dirás pues: Oid palabra de Jehová, oh reyes de Judá, y moradores de Jerusalem. Así dice Jehová de los ejércitos, Dios de Israel: He aquí que yo traigo mal sobre este lugar, tal que quien lo oyere, le retiñan los oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 4, 'Porque me dejaron, y enajenaron este lugar, y ofrecieron en él perfumes á dioses ajenos, los cuales no habían ellos conocido, ni sus padres, ni los reyes de Judá; y llenaron este lugar de sangre de inocentes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 5, 'Y edificaron alto á Baal, para quemar con fuego sus hijos en holocaustos al mismo Baal; cosa que no les mandé, ni hablé, ni me vino al pensamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 6, 'Por tanto, he aquí vienen días, dice Jehová, que este lugar no se llamará más Topheth, ni Valle del hijo de Hinnom, sino Valle de la Matanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 7, 'Y desvaneceré el consejo de Judá y de Jerusalem en este lugar; y haréles caer á cuchillo delante de sus enemigos, y en las manos de los que buscan sus almas; y daré sus cuerpos para comida de las aves del cielo y de las bestias de la tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 8, 'Y pondré á esta ciudad por espanto y silbo: todo aquel que pasare por ella se maravillará, y silbará sobre todas sus plagas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 9, 'Y haréles comer la carne de sus hijos y la carne de sus hijas; y cada uno comerá la carne de su amigo, en el cerco y en el apuro con que los estrecharán sus enemigos y los que buscan sus almas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 10, 'Y quebrarás la vasija ante los ojos de los varones que van contigo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 11, 'Y les dirás: Así ha dicho Jehová de los ejércitos: Así quebrantaré á este pueblo y á esta ciudad, como quien quiebra un vaso de barro, que no puede más restaurarse; y en Topheth se enterrarán, porque no habrá otro lugar para enterrar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 12, 'Así haré á este lugar, dice Jehová, y á sus moradores, poniendo esta ciudad como Topheth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 13, 'Y las casas de Jerusalem, y las casas de los reyes de Judá, serán como el lugar de Topheth inmundas, por todas las casas sobre cuyos tejados ofrecieron perfumes á todo el ejército del cielo, y vertieron libaciones á dioses ajenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 14, 'Y volvió Jeremías de Topheth, á donde le envió Jehová á profetizar, y paróse en el atrio de la casa de Jehová, y dijo á todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 19, 15, 'Así ha dicho Jehová de los ejércitos, Dios de Israel: He aquí yo traigo sobre esta ciudad y sobre todas sus villas todo el mal que hablé contra ella: porque han endurecido su cerviz, para no oir mis palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 1, 'Y PASHUR sacerdote, hijo de Immer, que presidía por príncipe en la casa de Jehová, oyó á Jeremías que profetizaba estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 2, 'E hirió Pashur á Jeremías profeta, y púsole en el cepo que estaba á la puerta de Benjamín en lo alto, la cual conducía á la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 3, 'Y el día siguiente Pashur sacó á Jeremías del cepo. Díjole entonces Jeremías: Jehová no ha llamado tu nombre Pashur, sino Magormissabib.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 4, 'Porque así ha dicho Jehová: He aquí yo te pondré en espanto á ti, y á todos los que bien te quieren, y caerán por el cuchillo de sus enemigos, y tus ojos lo verán: y á todo Judá entregaré en mano del rey de Babilonia, y los trasportará á Babilonia, y herirálos á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 5, 'Entregaré asimismo toda la sustancia de esta ciudad, y todo su trabajo, y todas sus cosas preciosas; y daré todos los tesoros de los reyes de Judá en manos de sus enemigos, y los saquearán, y los tomarán, y llevaránlos á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 6, 'Y tú, Pashur, y todos los moradores de tu casa iréis cautivos, y entrarás en Babilonia, y allí morirás, y serás allá enterrado, tu, y todos los que bien te quieren, á los cuales has profetizado con mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 7, 'Alucinásteme, oh Jehová, y hállome frustrado: más fuerte fuiste que yo, y vencísteme: cada día he sido escarnecido; cada cual se burla de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 8, 'Porque desde que hablo, doy voces, grito, Violencia y destrucción: porque la palabra de Jehová me ha sido para afrenta y escarnio cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 9, 'Y dije: No me acordaré más de él, ni hablaré más en su nombre: empero fué en mi corazón como un fuego ardiente metido en mis huesos, trabajé por sufrirlo, y no pude.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 10, 'Porque oí la murmuración de muchos, temor de todas partes: Denunciad, y denunciaremos. Todos mis amigos miraban si claudicaría. Quizá se engañará, decían, y prevaleceremos contra él, y tomaremos de él nuestra venganza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 11, 'Mas Jehová está conmigo como poderoso gigante; por tanto los que me persiguen tropezarán, y no prevalecerán; serán avergonzados en gran manera, porque no prosperarán; tendrán perpetua confusión que jamás será olvidada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 12, 'Oh Jehová de los ejércitos, que sondas los justos, que ves los riñones y el corazón, vea yo tu venganza de ellos; porque á ti he descubierto mi causa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 13, 'Cantad á Jehová, load á Jehová: porque librado ha el alma del pobre de mano de los malignos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 14, 'Maldito el día en que nací: el día en que mi madre me parió no sea bendito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 15, 'Maldito el hombre que dió nuevas á mi padre, diciendo, Hijo varón te ha nacido, haciéndole alegrarse así mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 16, 'Y sea el tal hombre como las ciudades que asoló Jehová, y no se arrepintió: y oiga gritos de mañana, y voces al medio día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 17, 'Porque no me mató en el vientre, y mi madre me hubiera sido mi sepulcro, y su vientre concebimiento perpetuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 20, 18, '¿Para qué salí del vientre? ¿para ver trabajo y dolor, y que mis días se gastasen en afrenta?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 1, 'PALABRA que fué á Jeremías de Jehová, cuando el rey Sedechîas envió á él á Pashur hijo de Malchîas, y á Sephanías sacerdote, hijo de Maasías, que le dijesen:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 2, 'Pregunta ahora por nosotros á Jehová; porque Nabucodonosor rey de Babilonia hace guerra contra nosotros: quizá Jehová hará con nosotros según todas sus maravillas, y aquél se irá de sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 3, 'Y Jeremías les dijo: Diréis así á Sedechîas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 4, 'Así ha dicho Jehová Dios de Israel: He aquí yo vuelvo las armas de guerra que están en vuestras manos, y con que vosotros peleáis con el rey de Babilonia; y los Caldeos que os tienen cercados fuera de la muralla, yo los juntaré en medio de esta ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 5, 'Y pelearé contra vosotros con mano alzada y con brazo fuerte, y con furor, y enojo, é ira grande:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 6, 'Y heriré los moradores de esta ciudad; y los hombres y las bestias morirán de pestilencia grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 7, 'Y después, así dice Jehová, entregaré á Sedechîas rey de Judá, y á sus criados, y al pueblo, y á los que quedaren en la ciudad de la pestilencia, y del cuchillo, y del hambre, en mano de Nabucodonosor rey de Babilonia, y en mano de sus enemigos, y en mano de los que buscan sus almas; y él los herirá á filo de espada; no los perdonará, ni los recibirá á merced, ni tendrá de ellos misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 8, 'Y á este pueblo dirás: Así ha dicho Jehová: He aquí pongo delante de vosotros camino de vida y camino de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 9, 'El que se quedare en esta ciudad, morirá á cuchillo, ó de hambre, ó pestilencia: mas el que saliere, y se pasare á los Caldeos que os tienen cercados, vivirá, y su vida le será por despojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 10, 'Porque mi rostro he puesto contra esta ciudad para mal, y no para bien, dice Jehová: en mano del rey de Babilonia será entregada, y quemarála á fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 11, 'Y á la casa del rey de Judá dirás: Oid palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 12, 'Casa de David, así dijo Jehová: Juzgad de mañana juicio, y librad al oprimido de mano del opresor; porque mi ira no salga como fuego, y se encienda, y no haya quien apague, por la maldad de vuestras obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 13, 'He aquí yo contra ti, moradora del valle de la piedra de la llanura, dice Jehová: los que decís: ¿Quién subirá contra nosotros? ¿y quién entrará en nuestras moradas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 21, 14, 'Yo os visitaré conforme al fruto de vuestras obras, dice Jehová, y haré encender fuego en su breña, y consumirá todo lo que está alrededor de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 1, 'ASI dijo Jehová: Desciende á la casa del rey de Judá, y habla allí esta palabra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 2, 'Y di: Oye palabra de Jehová, oh rey de Judá que estás sentado sobre el trono de David, tú, y tus criados, y tu pueblo que entran por estas puertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 3, 'Así ha dicho Jehová: Haced juicio y justicia, y librad al oprimido de mano del opresor, y no engañéis, ni robéis al extranjero, ni al huérfano, ni á la viuda, ni derraméis sangre inocente en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 4, 'Porque si efectivamente hiciereis esta palabra, los reyes que en lugar de David se sientan sobre su trono, entrarán montados en carros y en caballos por las puertas de esta casa, ellos, y sus criados, y su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 5, 'Mas si no oyereis estas palabras, por mí he jurado, dice Jehová, que esta casa será desierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 6, 'Porque así ha dicho Jehová sobre la casa del rey de Judá: Galaad eres tú para mí, y cabeza del Líbano: empero de cierto te pondré en soledad, y ciudades deshabitadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 7, 'Y señalaré contra ti disipadores, cada uno con sus armas; y cortarán tus cedros escogidos, y los echarán en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 8, 'Y muchas gentes pasarán junto á esta ciudad, y dirán cada uno á su compañero: ¿Por qué lo hizo así Jehová con esta grande ciudad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 9, 'Y dirán: Porque dejaron el pacto de Jehová su Dios, y adoraron dioses ajenos, y les sirvieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 10, 'No lloréis al muerto, ni de él os condolezcáis: llorad amargamente por el que va; porque no volverá jamás, ni verá la tierra donde nació.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 11, 'Porque así ha dicho Jehová, de Sallum hijo de Josías, rey de Judá, que reina por Josías su padre, que salió de este lugar: No volverá acá más;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 12, 'Antes morirá en el lugar adonde lo trasportaren, y no verá más esta tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 13, '¡Ay del que edifica su casa y no en justicia, y sus salas y no en juicio, sirviéndose de su prójimo de balde, y no dándole el salario de su trabajo!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 14, 'Que dice: Edificaré para mí casa espaciosa, y airosas salas; y le abre ventanas, y la cubre de cedro, y la pinta de bermellón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 15, '¿Reinarás porque te cercas de cedro? ¿no comió y bebío tu padre, é hizo juicio y justicia, y entonces le fué bien?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 16, 'El juzgó la causa del afligido y del menesteroso, y entonces estuvo bien. ¿No es esto conocerme á mí? dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 17, 'Mas tus ojos y tu corazón no son sino á tu avaricia, y á derramar la sangre inocente, y á opresión, y á hacer agravio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 18, 'Por tanto así ha dicho Jehová, de Joacim hijo de Josías, rey de Judá: No lo llorarán, diciendo: ¡Ay hermano mío! y ¡ay hermana! ni lo lamentarán, diciendo: ¡Ay señor! ¡ay su grandeza!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 19, 'En sepultura de asno será enterrado, arrastrándole y echándole fuera de las puertas de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 20, 'Sube al Líbano, y clama, y en Basán da tu voz, y grita hacia todas partes; porque todos tus enamorados son quebrantados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 21, 'Hete hablado en tus prosperidades; mas dijiste: No oiré. Este fué tu camino desde tu juventud, que nunca oiste mi voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 22, 'A todos tus pastores pacerá el viento, y tus enamorados irán en cautiverio: entonces te avergonzarás y te confundirás á causa de toda tu malicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 23, 'Habitaste en el Líbano, hiciste tu nido en los cedros: ¡cómo gemirás cuando te vinieren dolores, dolor como de mujer que está de parto!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 24, 'Vivo yo, dice Jehová, que si Conías hijo de Joacím rey de Judá fuese anillo en mi mano diestra, aun de allí te arrancaré;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 25, 'Y te entregaré en mano de los que buscan tu alma, y en mano de aquellos cuya vista temes; sí, en mano de Nabucodonosor rey de Babilonia, y en mano de los Caldeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 26, 'Y hacerte he trasportar, á ti, y á tu madre que te parió, á tierra ajena en que no nacisteis; y allá moriréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 27, 'Y á la tierra á la cual levantan ellos su alma para tornar, allá no volverán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 28, '¿Es este hombre Conías un ídolo vil quebrado? ¿es vaso con quien nadie se deleita? ¿Por qué fueron arrojados, él y su generación, y echados á tierra que no habían conocido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 29, '¡Tierra, tierra, tierra! oye palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 22, 30, 'Así ha dicho Jehová: Escribid que será este hombre privado de generación, hombre á quien nada sucederá prósperamente en todos los días de su vida: porque ningún hombre de su simiente que se sentare sobre el trono de David, y que se enseñoreare sobre Judá, será jamás dichoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 1, '¡AY de los pastores que desperdician y derraman las ovejas de mi majada! dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 2, 'Por tanto, así ha dicho Jehová Dios de Israel á los pastores que apacientan mi pueblo: Vosotros derramasteis mis ovejas, y las espantasteis, y no las habéis visitado: he aquí yo visito sobre vosotros la maldad de vuestras obras, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 3, 'Y yo recogeré el resto de mis ovejas de todas las tierras adonde las eché, y harélas volver á sus moradas; y crecerán, y se multiplicarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 4, 'Y pondré sobre ellas pastores que las apacienten; y no temerán más, ni se asombrarán, ni serán menoscabadas, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 5, 'He aquí que vienen los días, dice Jehová, y despertaré á David renuevo justo, y reinará Rey, el cual será dichoso, y hará juicio y justicia en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 6, 'En sus días será salvo Judá, é Israel habitará confiado: y este será su nombre que le llamarán: JEHOVA, JUSTICIA NUESTRA.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 7, 'Por tanto, he aquí que vienen días, dice Jehová, y no dirán más: Vive Jehová que hizo subir los hijos de Israel de la tierra de Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 8, 'Sino: Vive Jehová que hizo subir y trajo la simiente de la casa de Israel de tierra del aquilón, y de todas las tierras adonde los había yo echado; y habitarán en su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 9, 'A causa de los profetas mi corazón está quebrantado en medio de mí, todos mis huesos tiemblan; estuve como hombre borracho, y como hombre á quien dominó el vino, delante de Jehová y delante de las palabras de su santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 10, 'Porque la tierra está llena de adúlteros: porque á causa del juramento la tierra está desierta; las cabañas del desierto se secaron; la carrera de ellos fué mala, y su fortaleza no derecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 11, 'Porque así el profeta como el sacerdote son fingidos: aun en mi casa hallé su maldad, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 12, 'Por tanto, como resbaladeros en oscuridad les será su camino: serán empujados, y caerán en él: porque yo traeré mal sobre ellos, año de su visitación, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 13, 'Y en los profetas de Samaria he visto desatinos: profetizaban en Baal, é hicieron errar á mi pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 14, 'Y en los profetas de Jerusalem he visto torpezas: cometían adulterios, y andaban en mentiras, y esforzaban las manos de los malos, para que ninguno se convirtiese de su malicia: fuéronme todos ellos como Sodoma, y sus moradores como Gomorra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 15, 'Por tanto, así ha dicho Jehová de los ejércitos contra aquellos profetas: He aquí que yo les hago comer ajenjos, y les haré beber aguas de hiel; porque de los profetas de Jerusalem salió la hipocresía sobre toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 16, 'Así ha dicho Jehová de los ejércitos: No escuchéis las palabras de los profetas que os profetizan: os hacen desvanecer; hablan visión de su corazón, no de la boca de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 17, 'Dicen atrevidamente á los que me irritan: Jehová dijo: Paz tendréis; y á cualquiera que anda tras la imaginación de su corazón, dijeron: No vendrá mal sobre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 18, 'Porque ¿quién estuvo en el secreto de Jehová, y vió, y oyó su palabra? ¿quién estuvo atento á su palabra, y oyó?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 19, 'He aquí que la tempestad de Jehová saldrá con furor; y la tempestad que está aparejada, caerá sobre la cabeza de los malos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 20, 'No se apartará el furor de Jehová, hasta tanto que haya hecho, y hasta tanto que haya cumplido los pensamientos de su corazón: en lo postrero de los días lo entenderéis cumplidamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 21, 'No envié yo aquellos profetas, y ellos corrían: yo no les hablé, y ellos profetizaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 22, 'Y si ellos hubieran estado en mi secreto, también hubieran hecho oir mis palabras á mi pueblo; y les hubieran hecho volver de su mal camino, y de la maldad de sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 23, '¿Soy yo Dios de poco acá, dice Jehová, y no Dios de mucho ha?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 24, '¿Ocultaráse alguno, dice Jehová, en escondrijos que yo no lo vea? ¿No hincho yo, dice Jehová, el cielo y la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 25, 'Yo he oído lo que aquellos profetas dijeron, profetizando mentira en mi nombre, diciendo: Soñé, soñé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 26, '¿Hasta cuándo será esto en el corazón de los profetas que profetizan mentira, y que profetizan el engaño de su corazón?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 27, '¿No piensan como hacen á mi pueblo olvidarse de mi nombre con sus sueños que cada uno cuenta á su compañero, al modo que sus padres se olvidaron de mi nombre por Baal?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 28, 'El profeta con quien fuere sueño, cuente sueño; y el con quien fuere mi palabra, cuente mi palabra verdadera. ¿Qué tiene que ver la paja con el trigo? dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 29, '¿No es mi palabra como el fuego, dice Jehová, y como martillo que quebranta la piedra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 30, 'Por tanto, he aquí yo contra los profetas, dice Jehová, que hurtan mis palabras cada uno de su más cercano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 31, 'He aquí yo contra los profetas, dice Jehová, que endulzan sus lenguas, y dicen: El ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 32, 'He aquí yo contra los que profetizan sueños mentirosos, dice Jehová y contáronlos, é hicieron errar á mi pueblo con sus mentiras y con sus lisonjas, y yo no los envié, ni les mandé; y ningún provecho hicieron á este pueblo, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 33, 'Y cuando te preguntare este pueblo, ó el profeta, ó el sacerdote, diciendo: ¿Qué es la carga de Jehová? les dirás: ¿Qué carga? Os dejaré, ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 34, 'Y el profeta, y el sacerdote, ó el pueblo, que dijere: Carga de Jehová; yo enviaré castigo sobre tal hombre y sobre su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 35, 'Así diréis cada cual á su compañero, y cada cual á su hermano: ¿Qué ha respondido Jehová, y qué habló Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 36, 'Y nunca más os vendrá á la memoria decir: Carga de Jehová: porque la palabra de cada uno le será por carga; pues pervertisteis las palabras del Dios viviente, de Jehová de los ejércitos, Dios nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 37, 'Así dirás al profeta: ¿Qué te respondió Jehová, y qué habló Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 38, 'Mas si dijereis: Carga de Jehová: por eso Jehová dice así: Porque dijisteis esta palabra, Carga de Jehová, habiendo enviado á deciros: No digáis, Carga de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 39, 'Por tanto, he aquí que yo os echaré en olvido, y os arrancaré de mi presencia, y á la ciudad que os dí á vosotros y á vuestros padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 23, 40, 'Y pondré sobre vosotros afrenta perpetua, y eterna confusión que nunca borrará el olvido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 1, 'MOSTROME Jehová, y he aquí dos cestas de higos puestas delante del templo de Jehová, después de haber trasportado Nabucodonosor rey de Babilonia á Jechônías hijo de Joacim, rey de Judá, y á los príncipes de Judá, y á los oficiales y herreros de Jerusalem, y haberlos llevado á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 2, 'La una cesta tenía higos muy buenos, como brevas; y la otra cesta tenía higos muy malos, que no se podían comer de malos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 3, 'Y díjome Jehová: ¿Qué ves tú, Jeremías? Y dije: Higos, higos buenos, muy buenos; y malos, muy malos, que de malos no se pueden comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 4, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 5, 'Así ha dicho Jehová Dios de Israel: Como á estos buenos higos, así conoceré la trasportación de Judá al cual eché de este lugar á tierra de Caldeos, para bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 6, 'Porque pondré mis ojos sobre ellos para bien, y volverélos á esta tierra; y los edificaré, y no los destruiré: plantarélos, y no los arrancaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 7, 'Y les daré corazón para que me conozcan, que yo soy Jehová: y me serán por pueblo, y yo les seré á ellos por Dios; porque se volverán á mí de todo su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 8, 'Y como los malos higos, que de malos no se pueden comer, así, ha dicho Jehová, daré á Sedechîas rey de Judá, y á sus príncipes, y al resto de Jerusalem que quedaron en esta tierra, y que moran en la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 9, 'Y darélos por escarnio, por mal á todos los reinos de la tierra: por infamia, y por ejemplo, y por refrán, y por maldición á todos los lugares adonde yo los arrojaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 24, 10, 'Y enviaré sobre ellos espada, hambre, y pestilencia, hasta que sean acabados de sobre la tierra que les dí á ellos y á sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 1, 'PALABRA que fué á Jeremías acerca de todo el pueblo de Judá en el año cuarto de Joacim hijo de Josías, rey de Judá, el cual es el año primero de Nabucodonosor rey de Babilonia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 2, 'La cual habló Jeremías profeta á todo el pueblo de Judá, y á todos los moradores de Jerusalem, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 3, 'Desde el año trece de Josías hijo de Amón, rey de Judá, hasta este día, que son veintitrés años, fué á mí palabra de Jehová, y os he hablado, madrugando y dando aviso; mas no oisteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 4, 'Y envió Jehová á vosotros todos sus siervos los profetas, madrugando y enviándolos; mas no oisteis, ni inclinasteis vuestro oído para escuchar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 5, 'Cuando decían: Volveos ahora de vuestro mal camino y de la maldad de vuestras obras, y morad en la tierra que os dió Jehová, á vosotros y á vuestros padres para siempre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 6, 'Y no vayáis en pos de dioses ajenos, sirviéndoles y encorvándoos á ellos, ni me provoquéis á ira con la obra de vuestras manos; y no os haré mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 7, 'Empero no me habéis oído, dice Jehová, para provocarme á ira con la obra de vuestras manos para mal vuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 8, 'Por tanto, así ha dicho Jehová de los ejércitos: Por cuanto no habéis oído mis palabras,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 9, 'He aquí enviaré yo, y tomaré todos los linajes del aquilón, dice Jehová, y á Nabucodonosor rey de Babilonia, mi siervo, y traerélos contra esta tierra, y contra sus moradores, y contra todas estas naciones en derredor; y los destruiré, y pondrélos por escarnio, y por silbo, y en soledades perpetuas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 10, 'Y haré que perezca de entre ellos voz de gozo y voz de alegría, voz de desposado y voz de desposada, ruido de muelas, y luz de lámpara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 11, 'Y toda esta tierra será puesta en soledad, en espanto; y servirán estas gentes al rey de Babilonia setenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 12, 'Y será que, cuando fueren cumplidos los setenta años, visitaré sobre el rey de Babilonia y sobre aquella gente su maldad, ha dicho Jehová, y sobre la tierra de los Caldeos; y pondréla en desiertos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 13, 'Y traeré sobre aquella tierra todas mis palabras que he hablado contra ella, con todo lo que está escrito en este libro, profetizado por Jeremías contra todas gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 14, 'Porque se servirán también de ellos muchas gentes, y reyes grandes; y yo les pagaré conforme á sus hechos, y conforme á la obra de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 15, 'Porque así me dijo Jehová Dios de Israel: Toma de mi mano el vaso del vino de este furor, y da á beber de él á todas las gentes á las cuales yo te envío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 16, 'Y beberán, y temblarán, y enloquecerán delante del cuchillo que yo envío entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 17, 'Y tomé el vaso de la mano de Jehová, y dí de beber á todas las gentes á las cuales me envió Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 18, 'A Jerusalem, á las ciudades de Judá, y á sus reyes, y á sus príncipes, para ponerlos en soledad, en escarnio, y en silbo, y en maldición, como este día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 19, 'A Faraón rey de Egipto, y á sus siervos, á sus príncipes, y á todo su pueblo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 20, 'Y á toda la mezcla de gente, y á todos los reyes de tierra de Hus, y á todos los reyes de tierra de Palestina, y á Ascalón, y Gaza, y Ecrón, y al residuo de Asdod;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 21, 'A Edom, y Moab, y á los hijos de Ammón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 22, 'Y á todos los reyes de Tiro, y á todos los reyes de Sidón, y á los reyes de las islas que están de ese lado de la mar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 23, 'Y á Dedán, y Tema, y Buz, y á todos los que están al cabo del mundo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 24, 'Y á todos los reyes de Arabia, y á todos los reyes de pueblos mezclados que habitan en el desierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 25, 'Y á todos los reyes de Zimri, y á todos los reyes de Elam, y á todos los reyes de Media;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 26, 'Y á todos los reyes del aquilón, los de cerca y los de lejos, los unos con los otros; y á todos los reinos de la tierra que están sobre la haz de la tierra: y el rey de Sesach beberá después de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 27, 'Les dirás, pues: Así ha dicho Jehová de los ejércitos, Dios de Israel: Bebed, y embriagaos, y vomitad, y caed, y no os levantéis delante del cuchillo que yo envío entre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 28, 'Y será que, si no quieren tomar el vaso de tu mano para beber, les dirás tú: Así ha dicho Jehová de los ejércitos: Habéis de beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 29, 'Porque he aquí, que á la ciudad sobre la cual es invocado mi nombre yo comienzo á hacer mal; ¿y vosotros seréis absueltos? No seréis absueltos: porque espada traigo sobre todos los moradores de la tierra, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 30, 'Tú pues, profetizarás á ellos todas estas palabras, y les dirás: Jehová bramará desde lo alto, y desde la morada de su santidad dará su voz: enfurecido bramará sobre su morada; canción de lagareros cantará contra todos los moradores de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 31, 'Llegó el estruendo hasta el cabo de la tierra; porque juicio de Jehová con las gentes: él es el Juez de toda carne; entregará los impíos á cuchillo, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 32, 'Así ha dicho Jehová de los ejércitos: He aquí que el mal sale de gente en gente, y grande tempestad se levantará de los fines de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 33, 'Y serán muertos de Jehová en aquel día desde el un cabo de la tierra hasta el otro cabo; no se endecharán, ni se recogerán, ni serán enterrados; como estiércol serán sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 34, 'Aullad, pastores, y clamad; y revolcaos en el polvo, mayorales del rebaño; porque cumplidos son vuestros días para ser vosotros degollados y esparcidos, y caeréis como vaso de codicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 35, 'Y acabaráse la huída de los pastores, y el escape de los mayorales del rebaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 36, '¡Voz de la grita de los pastores, y aullido de los mayorales del rebaño! porque Jehová asoló sus majadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 37, 'Y las majadas quietas serán taladas por el furor de la ira de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 25, 38, 'Dejó cual leoncillo su guarida; pues asolada fué la tierra de ellos por la ira del opresor, y por el furor de su saña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 1, 'EN el principio del reinado de Joacim hijo de Josías, rey de Judá, fué esta palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 2, 'Así ha dicho Jehová: Ponte en el atrio de la casa de Jehová, y habla á todas las ciudades de Judá, que vienen para adorar en la casa de Jehová, todas las palabras que yo te mandé les hablases; no retengas palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 3, 'Quizá oirán, y se tornarán cada uno de su mal camino; y arrepentiréme yo del mal que pienso hacerles por la maldad de sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 4, 'Les dirás pues: Así ha dicho Jehová: Si no me oyereis para andar en mi ley, la cual dí delante de vosotros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 5, 'Para atender á las palabras de mis siervos los profetas que yo os envío, madrugando en enviarlos, á los cuales no habéis oído;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 6, 'Yo pondré esta casa como Silo, y daré esta ciudad en maldición á todas las gentes de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 7, 'Y los sacerdotes, los profetas, y todo el pueblo, oyeron á Jeremías hablar estas palabras en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 8, 'Y fué que, acabando de hablar Jeremías todo lo que Jehová le había mandado que hablase á todo el pueblo, los sacerdotes y los profetas y todo el pueblo le echaron mano, diciendo: De cierto morirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 9, '¿Por qué has profetizado en nombre de Jehová, diciendo: Esta casa será como Silo, y esta ciudad será asolada hasta no quedar morador? Y juntóse todo el pueblo contra Jeremías en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 10, 'Y los príncipes de Judá oyeron estas cosas, y subieron de casa del rey á la casa de Jehová; y sentáronse en la entrada de la puerta nueva de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 11, 'Entonces hablaron los sacerdotes y los profetas á los príncipes y á todo el pueblo, diciendo: En pena de muerte ha incurrido este hombre; porque profetizó contra esta ciudad, como vosotros habéis oído con vuestros oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 12, 'Y habló Jeremías á todos los príncipes y á todo el pueblo, diciendo: Jehová me envió á que profetizase contra esta casa y contra esta ciudad, todas las palabras que habéis oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 13, 'Y ahora, mejorad vuestros caminos y vuestras obras, y oid la voz de Jehová vuestro Dios, y arrepentiráse Jehová del mal que ha hablado contra vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 14, 'En lo que á mí toca, he aquí estoy en vuestras manos: haced de mí como mejor y más recto os pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 15, 'Mas sabed de cierto que, si me matareis, sangre inocente echaréis sobre vosotros, y sobre esta ciudad, y sobre sus moradores: porque en verdad Jehová me envió á vosotros para que dijese todas estas palabras en vuestros oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 16, 'Y dijeron los príncipes y todo el pueblo á los sacerdotes y profetas. No ha incurrido este hombre en pena de muerte, porque en nombre de Jehová nuestro Dios nos ha hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 17, 'Entonces se levantaron ciertos de los ancianos de la tierra, y hablaron á toda la junta del pueblo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 18, 'Miqueas de Morasti profetizó en tiempo de Ezechîas rey de Judá, diciendo: Así ha dicho Jehová de los ejércitos: Sión será arada como campo, y Jerusalem vendrá á ser montones, y el monte del templo en cumbres de bosque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 19, '¿Matáronlo luego Ezechîas rey de Judá y todo Judá? ¿no temió á Jehová, y oró en presencia de Jehová, y Jehová se arrepintió del mal que había hablado contra ellos? ¿Haremos pues nosotros tan grande mal contra nuestras almas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 20, 'Hubo también un hombre que profetizaba en nombre de Jehová, Urías, hijo de Semaías de Chîriath-jearim, el cual profetizó contra esta ciudad y contra esta tierra, conforme á todas las palabras de Jeremías:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 21, 'Y oyó sus palabras el rey Joacim, y todos sus grandes, y todos sus príncipes, y el rey procuró de matarle; lo cual entendiendo Urías, tuvo temor, y huyó, y metióse en Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 22, 'Y el rey Joacim envió hombres á Egipto, á Elnathán hijo de Acbor, y otros hombres con él, á Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 23, 'Los cuales sacaron á Urías de Egipto, y lo trajeron al rey Joacim, é hiriólo á cuchillo, y echó su cuerpo en los sepulcros del vulgo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 26, 24, 'La mano empero de Ahicam hijo de Saphán era con Jeremías, porque no lo entregasen en las manos del pueblo para matarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 1, 'EN el principio del reinado de Joacim hijo de Josías, rey de Judá, fué de Jehová esta palabra á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 2, 'Jehová me ha dicho así: Hazte coyundas y yugos, y ponlos sobre tu cuello;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 3, 'Y los enviarás al rey de Edom, y al rey de Moab, y al rey de los hijos de Ammón, y al rey de Tiro, y al rey de Sidón, por mano de los embajadores que vienen á Jerusalem á Sedechîas, rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 4, 'Y les mandarás que digan á sus señores: Así ha dicho Jehová de los ejércitos, Dios de Israel: Así habéis de decir á vuestros señores:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 5, 'Yo hice la tierra, el hombre y las bestias que están sobre la haz de la tierra, con mi grande potencia y con mi brazo extendido, y díla á quien me plugo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 6, 'Y ahora yo he dado todas estas tierras en mano de Nabucodonosor rey de Babilonia, mi siervo, y aun las bestias del campo le he dado para que le sirvan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 7, 'Y todas las gentes le servirán á él, y á su hijo, y al hijo de su hijo, hasta que venga también el tiempo de su misma tierra; y le servirán muchas gentes y reyes grandes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 8, 'Y será, que la gente y el reino que no sirviere á Nabucodonosor rey de Babilonia, y que no pusiere su cuello debajo del yugo del rey de Babilonia, con espada y con hambre y con pestilencia visitaré á la tal gente, dice Jehová, hasta que los acabe yo por su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 9, 'Y vosotros no prestéis oído á vuestros profetas, ni á vuestros adivinos, ni á vuestros sueños, ni á vuestros agoreros, ni á vuestros encantadores, que os hablan diciendo: No serviréis al rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 10, 'Porque ellos os profetizan mentira, para haceros alejar de vuestra tierra, y para que yo os arroje y perezcáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 11, 'Mas la gente que sometiere su cuello al yugo del rey de Babilonia, y le sirviere, haréla dejar en su tierra, dice Jehová, y labrarála, y morará en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 12, 'Y hablé también á Sedechîas rey de Judá conforme á todas estas palabras, diciendo: Someted vuestros cuellos al yugo del rey de Babilonia, y servid á él y á su pueblo, y vivid.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 13, '¿Por qué moriréis, tú y tu pueblo, á cuchillo, de hambre, y pestilencia, según ha dicho Jehová á la gente que no sirviere al rey de Babilonia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 14, 'No oigáis las palabras de los profetas que os hablan, diciendo: No serviréis al rey de Babilonia; porque os profetizan mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 15, 'Porque yo no los envié, dice Jehová, y ellos profetizan falsamente en mi nombre, para que yo os arroje, y perezcáis, vosotros y los profetas que os profetizan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 16, 'También á los sacerdotes y á todo este pueblo hablé, diciendo: Así ha dicho Jehová: No oigáis las palabras de vuestros profetas que os profetizan diciendo: He aquí que los vasos de la casa de Jehová volverán de Babilonia ahora presto. Porque os profetizan mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 17, 'No los oigáis; servid al rey de Babilonia, y vivid: ¿por qué ha de ser desierta esta ciudad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 18, 'Y si ellos son profetas, y si es con ellos palabra de Jehová, oren ahora á Jehová de los ejércitos, que los vasos que han quedado en la casa de Jehová y en la casa del rey de Judá y en Jerusalem, no vayan á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 19, 'Porque así ha dicho Jehová de los ejércitos de aquellas columnas, y del mar, y de las basas, y del resto de los vasos que quedan en esta ciudad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 20, 'Que no quitó Nabucodonosor rey de Babilonia, cuando trasportó de Jerusalem á Babilonia á Jechônías hijo de Joacim, rey de Judá, y á todos los nobles de Judá y de Jerusalem:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 21, 'Así pues ha dicho Jehová de los ejércitos, Dios de Israel, acerca de los vasos que quedaron en la casa de Jehová, y en la casa del rey de Judá, y en Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 27, 22, 'A Babilonia serán trasportados, y allí estarán hasta el día en que yo los visitaré, dice Jehová; y después los haré subir, y restituirélos á este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 1, 'Y ACONTECIO en el mismo año, en el principio del reinado de Sedechîas rey de Judá, en el año cuarto, en el quinto mes, que Hananías, hijo de Azur, profeta que era de Gabaón, me habló en la casa de Jehová delante de los sacerdotes y de todo el pueblo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 2, 'Así habló Jehová de los ejércitos, Dios de Israel, diciendo: Quebranté el yugo del rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 3, 'Dentro de dos años de días tornaré á este lugar todos los vasos de la casa de Jehová, que Nabucodonosor, rey de Babilonia, llevó de este lugar para meterlos en Babilonia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 4, 'Y yo tornaré á este lugar á Jechônías hijo de Joacim, rey de Judá, y á todos los trasportados de Judá que entraron en Babilonia, dice Jehová; porque yo quebrantaré el yugo del rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 5, 'Entonces respondió Jeremías profeta á Hananías profeta, delante de los sacerdotes y delante de todo el pueblo que estaba en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 6, 'Y dijo Jeremías profeta: Amén, así lo haga Jehová. Confirme Jehová tus palabras, con las cuales profetizaste que los vasos de la casa de Jehová, y todos los trasportados, han de ser tornados de Babilonia á este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 7, 'Con todo eso, oye ahora esta palabra que yo hablo en tus oídos y en los oídos de todo el pueblo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 8, 'Los profetas que fueron antes de mí y antes de ti en tiempos pasados, profetizaron sobre muchas tierras y grandes reinos, de guerra, y de aflicción, y de pestilencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 9, 'El profeta que profetizó de paz, cuando sobreviniere la palabra del profeta, será conocido el profeta que Jehová en verdad lo envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 10, 'Entonces Hananías profeta quitó el yugo del cuello de Jeremías profeta, y quebrólo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 11, 'Y habló Hananías en presencia de todo el pueblo, diciendo: Así ha dicho Jehová: De esta manera quebraré el yugo de Nabucodonosor, rey de Babilonia, del cuello de todas las gentes dentro de dos años de días. Y fuése Jeremías su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 12, 'Y después que Hananías profeta quebró el yugo del cuello de Jeremías profeta, fué palabra de Jehová á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 13, 'Ve, y habla á Hananías, diciendo: Así ha dicho Jehová: Yugos de madera quebraste, mas en vez de ellos harás yugos de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 14, 'Porque así ha dicho Jehová de los ejércitos, Dios de Israel: Yugo de hierro puso sobre el cuello de todas estas gentes, para que sirvan á Nabucodonosor rey de Babilonia, y han de servirle; y aun también le he dado las bestias del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 15, 'Entonces dijo el profeta Jeremías á Hananías profeta: Ahora oye, Hananías; Jehová no te envió, y tú has hecho confiar á este pueblo en mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 16, 'Por tanto, así ha dicho Jehová: He aquí que yo te envío de sobre la haz de la tierra: morirás en este año, porque hablaste rebelión contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 28, 17, 'Y en el mismo año murió Hananías en el mes séptimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 1, 'Y ESTAS son las palabras de la carta que Jeremías profeta envió de Jerusalem á los ancianos que habían quedado de los trasportados, y á los sacerdotes y profetas, y á todo el pueblo que Nabucodonosor llevó cautivo de Jerusalem á Babilonia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 2, '(Después que salió el rey Jechônías y la reina, y los de palacio, y los príncipes de Judá y de Jerusalem, y los artífices, y los ingenieros de Jerusalem;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 3, 'Por mano de Elasa hijo de Saphán, y de Jemarías hijo de Hilcías, (los cuales envió Sedechîas rey de Judá á Babilonia, á Nabucodonosor rey de Babilonia,) diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 4, 'Así ha dicho Jehová de los ejércitos, Dios de Israel, á todos los de la cautividad que hice trasportar de Jerusalem á Babilonia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 5, 'Edificad casas, y morad; y plantad huertos, y comed del fruto de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 6, 'Casaos, y engendrad hijos é hijas; dad mujeres á vuestros hijos, y dad maridos á vuestras hijas, para que paran hijos é hijas; y multiplicaos ahí, y no os hagáis pocos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 7, 'Y procurad la paz de la ciudad á la cual os hice traspasar, y rogad por ella á Jehová; porque en su paz tendréis vosotros paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 8, 'Porque así ha dicho Jehová de los ejércitos, Dios de Israel: No os engañen vuestros profetas que están entre vosotros, ni vuestros adivinos; ni miréis á vuestros sueños que soñáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 9, 'Porque falsamente os profetizan ellos en mi nombre: no los envié, ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 10, 'Porque así dijo Jehová: Cuando en Babilonia se cumplieren los setenta años, yo os visitaré, y despertaré sobre vosotros mi buena palabra, para tornaros á este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 11, 'Porque yo sé los pensamientos que tengo acerca de vosotros, dice Jehová, pensamientos de paz, y no de mal, para daros el fin que esperáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 12, 'Entonces me invocaréis, é iréis y oraréis á mí, y yo os oiré:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 13, 'Y me buscaréis y hallaréis, porque me buscaréis de todo vuestro corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 14, 'Y seré hallado de vosotros, dice Jehová, y tornaré vuestra cautividad, y os juntaré de todas las gentes, y de todos los lugares adonde os arrojé, dice Jehová; y os haré volver al lugar de donde os hice ser llevados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 15, 'Mas habéis dicho: Jehová nos ha suscitado profetas en Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 16, 'Así empero ha dicho Jehová, del rey que está sentado sobre el trono de David, y de todo el pueblo que mora en esta ciudad, de vuestros hermanos que no salieron con vosotros en cautiverio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 17, 'Así ha dicho Jehová de los ejércitos: He aquí envío yo contra ellos cuchillo, hambre, y pestilencia, y pondrélos como los malos higos, que de malos no se pueden comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 18, 'Y perseguirélos con espada, con hambre y con pestilencia; y darélos por escarnio á todos los reinos de la tierra, por maldición y por espanto, y por silbo y por afrenta á todas la gentes á las cuales los habré arrojado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 19, 'Porque no oyeron mis palabras, dice Jehová, que les envié por mis siervos los profetas, madrugando en enviarlos; y no habéis escuchado, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 20, 'Oid pues palabra de Jehová, vosotros todos los trasportados que eché de Jerusalem á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 21, 'Así ha dicho Jehová de los ejércitos, Dios de Israel, acerca de Achâb hijo de Colías, y acerca de Sedechîas hijo de Maasías, quienes os profetizan en mi nombre falsamente: He aquí los entrego yo en mano de Nabucodonosor rey de Babilonia, y él los herirá delante de vuestro ojos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 22, 'Y todos los trasportados de Judá que están en Babilonia, tomarán de ellos maldición, diciendo: Póngate Jehová como á Sedechîas y como á Achâb, los cuales asó al fuego el rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 23, 'Porque hicieron maldad en Israel, y cometieron adulterio con las mujeres de sus prójimos, y falsamente hablaron en mi nombre palabra que no les mandé; lo cual yo sé, y soy testigo, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 24, 'Y á Semaías de Nehelam hablarás, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 25, 'Así habló Jehová de los ejércitos, Dios de Israel, diciendo: Por cuanto enviaste letras en tu nombre á todo el pueblo que está en Jerusalem, y á Sophonías sacerdote hijo de Maasías, y á todos los sacerdotes, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 26, 'Jehová te ha puesto por sacerdote en lugar de Joiada sacerdote, para que presidáis en la casa de Jehová sobre todo hombre furioso y profetizante, poniéndolo en el calabozo y en el cepo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 27, '¿Por qué pues no has ahora reprendido á Jeremías de Anathoth, que os profetiza falsamente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 28, 'Porque por eso nos envió á decir en Babilonia: Largo va el cautiverio: edificad casas, y morad; plantad huertos, y comed el fruto de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 29, 'Y Sophonías sacerdote había leído esta carta á oídos de Jeremías profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 30, 'Y fué palabra de Jehová á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 31, 'Envía á decir á toda la transmigración: Así ha dicho Jehová de Semaías de Nehelam: Porque os profetizó Semaías, y yo no lo envié, y os hizo confiar en mentira:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 29, 32, 'Por tanto, así ha dicho Jehová: He aquí que yo visito sobre Semaías de Nehelam, y sobre su generación: no tendrá varón que more entre este pueblo, ni verá aquel bien que haré yo á mi pueblo, dice Jehová: porque contra Jehová ha hablado rebelión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 1, 'PALABRA que fué á Jeremías de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 2, 'Así habló Jehová Dios de Israel, diciendo: Escríbete en un libro todas las palabras que te he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 3, 'Porque he aquí que vienen días, dice Jehová, en que tornaré la cautividad de mi pueblo Israel y Judá, ha dicho Jehová, y harélos volver á la tierra que dí á sus padres, y la poseerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 4, 'Estas pues son las palabras que habló Jehová acerca de Israel y de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 5, 'Porque así ha dicho Jehová: Hemos oído voz de temblor: espanto, y no paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 6, 'Preguntad ahora, y mirad si pare el varón: porque he visto que todo hombre tenía las manos sobre sus lomos, como mujer de parto, y hanse tornado pálidos todos los rostros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 7, '¡Ah, cuán grande es aquel día! tanto, que no hay otro semejante á él: tiempo de angustia para Jacob; mas de ella será librado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 8, 'Y será en aquel día, dice Jehová de los ejércitos, que yo quebraré su yugo de tu cuello, y romperé tus coyundas, y extraños no lo volverán más á poner en servidumbre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 9, 'Sino que servirán á Jehová su Dios, y á David su rey, el cual les levantaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 10, 'Tú pues, siervo mío Jacob, no temas, dice Jehová, ni te atemorices, Israel: porque he aquí que yo soy el que te salvo de lejos, y á tu simiente de la tierra de su cautividad; y Jacob tornará, y descansará y sosegará, y no habrá quien le espante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 11, 'Porque yo soy contigo, dice Jehová, para salvarte: y haré consumación en todas las gentes entre la cuales te esparcí; en ti empero no haré consumación, sino que te castigaré con juicio, y no te talaré del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 12, 'Porque así ha dicho Jehová: Desahuciado es tu quebrantamiento, y dificultosa tu llaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 13, 'No hay quien juzgue tu causa para salud: no hay para ti eficaces medicamentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 14, 'Todos tus enamorados te olvidaron; no te buscan; porque de herida de enemigo te herí, con azote de cruel, á causa de la muchedumbre de tu maldad, y de la multitud de tus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 15, '¿Por qué gritas á causa de tu quebrantamiento? Desahuciado es tu dolor: porque por la grandeza de tu iniquidad, y por tus muchos pecados te he hecho esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 16, 'Empero serán consumidos todos los que te consumen; y todos tus afligidores, todos irán en cautiverio; y hollados serán los que te hollaron, y á todos los que hicieron presa de ti daré en presa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 17, 'Mas yo haré venir sanidad para ti, y te sanaré de tus heridas, dice Jehová; porque Arrojada te llamaron, diciendo: Esta es Sión, á la que nadie busca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 18, 'Así ha dicho Jehová: He aquí yo hago tornar la cautividad de las tiendas de Jacob, y de sus tiendas tendré misericordia; y la ciudad será edificada sobre su collado, y el templo será asentado según su forma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 19, 'Y saldrá de ellos alabanza, y voz de gente que está en regocijo: y los multiplicaré, y no serán disminuídos; multiplicarélos, y no serán menoscabados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 20, 'Y serán sus hijos como de primero y su congregación delante de mí será confirmada; y visitaré á todos sus opresores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 21, 'Y de él será su fuerte, y de en medio de él saldrá su enseñoreador; y haréle llegar cerca, y acercaráse á mí: porque ¿quién es aquel que ablandó su corazón para llegarse á mí? dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 22, 'Y me seréis por pueblo, y yo seré vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 23, 'He aquí, la tempestad de Jehová sale con furor, la tempestad que se apareja; sobre la cabeza de los impíos reposará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 30, 24, 'No se volverá la ira del enojo de Jehová, hasta que haya hecho y cumplido los pensamientos de su corazón: en el fin de los días entenderéis esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 1, 'EN aquel tiempo, dice Jehová, yo seré por Dios á todos los linajes de Israel, y ellos me serán á mí por pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 2, 'Así ha dicho Jehová: Halló gracia en el desierto el pueblo, los que escaparon del cuchillo, yendo yo para hacer hallar reposo á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 3, 'Jehová se manifestó á mí ya mucho tiempo há, diciendo: Con amor eterno te he amado; por tanto te soporté con misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 4, 'Aun te edificaré, y serás edificada, oh virgen de Israel: todavía serás adornada con tus panderos, y saldrás en corro de danzantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 5, 'Aun plantarás viñas en los montes de Samaria: plantarán los plantadores, y harán común uso de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 6, 'Porque habrá día en que clamarán los guardas en el monte de Ephraim: Levantaos, y subamos á Sión, á Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 7, 'Porque así ha dicho Jehová: Regocijaos en Jacob con alegría, y dad voces de júbilo á la cabeza de gentes; haced oir, alabad, y decid: Oh Jehová, salva tu pueblo, el resto de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 8, 'He aquí yo los vuelvo de tierra del aquilón, y los juntaré de los fines de la tierra, y entre ellos ciegos y cojos, la mujer preñada y la parida juntamente; en grande compañía tornarán acá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 9, 'Irán con lloro, mas con misericordias los haré volver, y harélos andar junto á arroyos de aguas, por camino derecho en el cual no tropezarán: porque soy á Israel por padre, y Ephraim es mi primogénito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 10, 'Oid palabra de Jehová, oh gentes, y hacedlo saber en las islas que están lejos, y decid: El que esparció á Israel lo juntará y guardará, como pastor á su ganado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 11, 'Porque Jehová redimió á Jacob, redimiólo de mano del más fuerte que él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 12, 'Y vendrán, y harán alabanzas en lo alto de Sión, y correrán al bien de Jehová, al pan, y al vino, y al aceite, y al ganado de las ovejas y de las vacas; y su alma será como huerto de riego, ni nunca más tendrán dolor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 13, 'Entonces la virgen se holgará en la danza, los mozos y los viejos juntamente; y su lloro tornaré en gozo, y los consolaré, y los alegraré de su dolor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 14, 'Y el alma del sacerdote embriagaré de grosura, y será mi pueblo saciado de mi bien, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 15, 'Así ha dicho Jehová: Voz fué oída en Ramá, llanto y lloro amargo: Rachêl que lamenta por sus hijos, no quiso ser consolada acerca de sus hijos, porque perecieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 16, 'Así ha dicho Jehová: Reprime tu voz del llanto, y tus ojos de las lágrimas; porque salario hay para tu obra, dice Jehová, y volverán de la tierra del enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 17, 'Esperanza también hay para tu fin, dice Jehová, y los hijos volverán á su término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 18, 'Escuchando, he oído á Ephraim que se lamentaba: Azotásteme, y fuí castigado como novillo indómito: conviérteme y seré convertido; porque tú eres Jehová mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 19, 'Porque después que me convertí, tuve arrepentimiento, y después que me conocí, herí el muslo: avergoncéme, y confundíme, porque llevé la afrenta de mis mocedades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 20, '¿No es Ephraim hijo precioso para mí? ¿no es niño delicioso? pues desde que hablé de él, heme acordado de él constantemente. Por eso mis entrañas se conmovieron por él: apiadado, tendré de él misericordia, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 21, 'Establécete señales, ponte majanos altos; nota atentamente la calzada, el camino por donde viniste: vuélvete, virgen de Israel, vuélvete á estas tus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 22, '¿Hasta cuándo andarás errante, oh hija contumaz? porque Jehová criará una cosa nueva sobre la tierra: una hembra rodeará al varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 23, 'Así ha dicho Jehová de los ejércitos, Dios de Israel: Aun dirán esta palabra en la tierra de Judá y en sus ciudades, cuando yo convertiré su cautiverio: Jehová te bendiga, oh morada de justicia, oh monte santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 24, 'Y morarán allí Judá, y también en todas sus ciudades labradores, y los que van con rebaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 25, 'Porque habré embriagado el alma cansada, y henchido toda alma entristecida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 26, 'En esto me desperté, y vi, y mi sueño me fué sabroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 27, 'He aquí vienen días, dice Jehová, en que sembraré la casa de Israel y la casa de Judá de simiente de hombre y de simiente de animal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 28, 'Y será que, como tuve ciudado de ellos para arrancar y derribar, y trastornar y perder, y afligir, así tendré cuidado de ellos para edificar y plantar, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 29, 'En aquellos días no dirán más: Los padres comieron las uvas agraces, y los dientes de los hijos tienen la dentera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 30, 'Sino que cada cual morirá por su maldad; los dientes de todo hombre que comiere las uvas agraces, tendrán la dentera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 31, 'He aquí que vienen días, dice Jehová, en los cuales haré nuevo pacto con la casa de Jacob y la casa de Judá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 32, 'No como el pacto que hice con sus padres el día que tomé su mano para sacarlos de tierra de Egipto; porque ellos invalidaron mi pacto, bien que fuí yo un marido para ellos, dice Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 33, 'Mas éste es el pacto que haré con la casa de Israel después de aquellos días, dice Jehová: Daré mi ley en sus entrañas, y escribiréla en sus corazones; y seré yo á ellos por Dios, y ellos me serán por pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 34, 'Y no enseñará más ninguno á su prójimo, ni ninguno á su hermano, diciendo: Conoce á Jehová: porque todos me conocerán, desde el más pequeño de ellos hasta el más grande, dice Jehová: porque perdonaré la maldad de ellos, y no me acordaré más de su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 35, 'Así ha dicho Jehová, que da el sol para luz del día, las leyes de la luna y de las estrellas para luz de la noche; que parte la mar y braman sus ondas; Jehová de los ejércitos es su nombre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 36, 'Si estas leyes faltaren delante de mí, dice Jehová, también la simiente de Israel faltará para no ser nación delante de mí todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 37, 'Así ha dicho Jehová: Si los cielos arriba se pueden medir, y buscarse abajo los fundamentos de la tierra, también yo desecharé toda la simiente de Israel por todo lo que hicieron, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 38, 'He aquí que vienen días, dice Jehová, y la ciudad será edificada á Jehová, desde la torre de Hananeel hasta la puerta del rincón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 39, 'Y saldrá más adelante el cordel de la medida delante de él sobre el collado de Hareb, y rodeará á Goa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 31, 40, 'Y todo el valle de los cuerpos muertos y de la ceniza, y todas las llanuras hasta el arroyo de Cedrón, hasta la esquina de la puerta de los caballos al oriente, será santo á Jehová: no será arrancada, ni destruída más para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 1, 'PALABRA que fué á Jeremías, de Jehová el año décimo de Sedechîas rey de Judá, que fué el año décimo octavo de Nabucodonosor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 2, 'Y entonces el ejército del rey de Babilonia tenía cercada á Jerusalem; y el profeta Jeremías estaba preso en el patio de la cárcel que estaba en la casa del rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 3, 'Pues Sedechîas rey de Judá lo había preso, diciendo: ¿Por qué profetizas tú diciendo: Así ha dicho Jehová: He aquí yo entrego esta ciudad en mano del rey de Babilonia, y tomarála,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 4, 'Y Sedechîas rey de Judá no escapará de la mano de los Caldeos, sino que de cierto será entregado en mano del rey de Babilonia, y hablará con él boca á boca, y sus ojos verán sus ojos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 5, 'Y hará llevar á Sedechîas á Babilonia, y allá estará hasta que yo le visite, dice Jehová: si peleareis con los Caldeos, no os sucederá bien?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 6, 'Y dijo Jeremías: Palabra de Jehová fué á mí, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 7, 'He aquí que Hanameel, hijo de Sallum tu tío, viene á ti, diciendo: Cómprame mi heredad que está en Anathoth; porque tú tienes derecho á ella para comprarla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 8, 'Y vino á mí Hanameel, hijo de mi tío, conforme á la palabra de Jehová, al patio de la cárcel, y díjome: Compra ahora mi heredad que está en Anathoth, en tierra de Benjamín, porque tuyo es el derecho de la herencia, y á ti compete la redención: cómprala para ti. Entonces conocí que era palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 9, 'Y compré la heredad de Hanameel, hijo de mi tío, la cual estaba en Anathoth, y peséle el dinero: diecisiete siclos de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 10, 'Y escribí la carta, y selléla, é hice atestiguar á testigos, y pesé el dinero con balanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 11, 'Tomé luego la carta de venta, sellada según el derecho y costumbre, y el traslado abierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 12, 'Y dí la carta de venta á Baruch hijo de Nerías, hijo de Maasías, delante de Hanameel el hijo de mi tío, y delante de los testigos que habían suscrito en la carta de venta, delante de todos los Judíos que estaban en el patio de la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 13, 'Y dí orden á Baruch delante de ellos, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 14, 'Así ha dicho Jehová de los ejércitos, Dios de Israel: Toma estas cartas, esta carta de venta, la sellada, y ésta la carta abierta, y ponlas en un vaso de barro, para que se guarden muchos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 15, 'Porque así ha dicho Jehová de los ejércitos, Dios de Israel: Aun se comprarán casas, y heredades, y viñas en esta tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 16, 'Y después que dí la carta de venta á Baruch hijo de Nerías, oré á Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 17, '¡Oh Señor Jehová! he aquí que tú hiciste el cielo y la tierra con tu gran poder, y con tu brazo extendido, ni hay nada que sea difícil para ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 18, 'Que haces misericordia en millares, y vuelves la maldad de los padres en el seno de sus hijos después de ellos: Dios grande, poderoso, Jehová de los ejércitos es su nombre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 19, 'Grande en consejo, y magnífico en hechos: porque tus ojos están abiertos sobre todos los caminos de los hijos de los hombres, para dar á cada uno según sus caminos, y según el fruto de sus obras:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 20, 'Que pusiste señales y portentos en tierra de Egipto hasta este día, y en Israel, y entre los hombres; y te has hecho nombre cual es este día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 21, 'Y sacaste tu pueblo Israel de tierra de Egipto con señales y portentos, y con mano fuerte y brazo extendido, con terror grande;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 22, 'Y dísteles esta tierra, de la cual juraste á sus padres que se la darías, tierra que mana leche y miel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 23, 'Y entraron, y poseyéronla: mas no oyeron tu voz, ni anduvieron en tu ley; nada hicieron de lo que les mandaste hacer; por tanto has hecho venir sobre ellos todo este mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 24, 'He aquí que con arietes han acometido la ciudad para tomarla; y la ciudad va á ser entregada en mano de los Caldeos que pelean contra ella, á causa de la espada, y del hambre y de la pestilencia: ha pues venido á ser lo que tú dijiste, y he aquí tú lo estás viendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 25, '¡Oh Señor Jehová! ¿y me has tú dicho: Cómprate la heredad por dinero, y pon testigos; bien que la ciudad sea entregada en manos de los Caldeos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 26, 'Y fué palabra de Jehová á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 27, 'He aquí que yo soy Jehová, Dios de toda carne; ¿encubriráseme á mí alguna cosa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 28, 'Por tanto así ha dicho Jehová: He aquí voy á entregar esta ciudad en mano de los Caldeos, y en mano de Nabucodonosor rey de Babilonia, y la tomará:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 29, 'Y vendrán los Caldeos que combaten esta ciudad, y la pondrán á fuego, y la abrasarán, asimismo las casas sobre cuyas azoteas ofrecieron perfumes á Baal y derramaron libaciones á dioses ajenos, para provocarme á ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 30, 'Porque los hijos de Israel y los hijos de Judá no han hecho sino lo malo delante de mis ojos desde su juventud: porque los hijos de Israel no han hecho más que provocarme á ira con la obra de sus manos, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 31, 'Por manera que para enojo mío y para ira mía me ha sido esta ciudad, desde el día que la edificaron hasta hoy, para que la haga quitar de mi presencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 32, 'Por toda la maldad de los hijos de Israel y de los hijos de Judá, que han hecho para enojarme, ellos, sus reyes, sus príncipes, sus sacerdotes, y sus profetas, y los varones de Judá, y los moradores de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 33, 'Y volviéronme la cerviz, y no el rostro: y cuando los enseñaba, enseñaba, fbamadrugando y enseñando, no escucharon para recibir corrección:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 34, 'Antes asentaron sus abominaciones en la casa sobre la cual es invocado mi nombre, contaminándola.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 35, 'Y edificaron altares á Baal, los cuales están en el valle del hijo de Hinnom, para hacer pasar por el fuego sus hijos y sus hijas á Moloch, lo cual no les mandé, ni me vino al pensamiento que hiciesen esta abominación, para hacer pecar á Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 36, 'Y con todo, ahora así dice Jehová Dios de Israel, á esta ciudad, de la cual decís vosotros, Entregada será en mano del rey de Babilonia á cuchillo, á hambre, y á pestilencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 37, 'He aquí que yo los juntaré de todas las tierras á las cuales los eché con mi furor, y con mi enojo y saña grande; y los haré tornar á este lugar, y harélos habitar seguramente,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 38, 'Y me serán por pueblo, y yo seré á ellos por Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 39, 'Y daréles un corazón, y un camino, para que me teman perpetuamente, para que hayan bien ellos, y sus hijos después de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 40, 'Y haré con ellos pacto eterno, que no tornaré atrás de hacerles bien, y pondré mi temor en el corazón de ellos, para que no se aparten de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 41, 'Y alegraréme con ellos haciéndoles bien, y los plantaré en esta tierra en verdad, de todo mi corazón y de toda mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 42, 'Porque así ha dicho Jehová: Como traje sobre este pueblo todo este grande mal, así traeré sobre ellos todo el bien que acerca de ellos hablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 43, 'Y poseerán heredad en esta tierra de la cual vosotros decís: Está desierta, sin hombres y sin animales; es entregada en manos de los Caldeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 32, 44, 'Heredades comprarán por dinero, y harán carta, y la sellarán, y pondrán testigos, en tierra de Benjamín y en los contornos de Jerusalem, y en las ciudades de Judá: y en las ciudades de las montañas, y en las ciudades de las campiñas, y en las ciudades del mediodía: porque yo haré tornar su cautividad, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 1, 'Y FUÉ palabra de Jehová á Jeremías la segunda vez, estando él aún preso en el patio de la cárcel, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 2, 'Así ha dicho Jehová que la hizo, Jehová que la formó para afirmarla; Jehová es su nombre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 3, 'Clama á mí, y te responderé, y te enseñaré cosas grandes y dificultosas que tú no sabes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 4, 'Porque así ha dicho Jehová, Dios de Israel, acerca de las casas de esta ciudad, y de las casas de los reyes de Judá, derribadas con arietes y con hachas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 5, '(Porque vinieron para pelear con los Caldeos, para henchirlas de cuerpos de hombres muertos, á los cuales herí yo con mi furor y con mi ira, pues que escondí mi rostro de esta ciudad, a causa de toda su malicia:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 6, 'He aquí que yo le hago subir sanidad y medicina; y los curaré, y les revelaré abundancia de paz y de verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 7, 'Y haré volver la cautividad de Judá, y la cautividad de Israel, y edificarélos como al principio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 8, 'Y los limpiaré de toda su maldad con que pecaron contra mí; y perdonaré todos sus pecados con que contra mí pecaron, y con que contra mí se rebelaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 9, 'Y seráme á mí por nombre de gozo, de alabanza y de gloria, entre todas las gentes de la tierra, que habrán oído todo el bien que yo les hago; y temerán y temblarán de todo el bien y de toda la paz que yo les haré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 10, 'Así ha dicho Jehová: En este lugar, del cual decís que está desierto sin hombres y sin animales, en las ciudades de Judá y en las calles de Jerusalem, que están asoladas sin hombre y sin morador y sin animal, tiene de oirse aún,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 11, 'Voz de gozo y voz de alegría, voz de desposado y voz de desposada, voz de los que digan: Alabad á Jehová de los ejércitos, porque Jehová es bueno, porque para siempre es su misericordia; voz de los que traigan alabanza á la casa de Jehová. Porque tornaré á traer la cautividad de la tierra como al principio, ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 12, 'Así dice Jehová de los ejércitos: En este lugar desierto, sin hombre y sin animal, y en todas sus ciudades, aun habrá cabañas de pastores que hagan tener majada á ganados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 13, 'En las ciudades de las montañas, en las ciudades de los campos, y en las ciudades del mediodía, y en tierra de Benjamín, y alrededor de Jerusalem y en las ciudades de Judá, aun pasarán ganados por las manos de los contadores, ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 14, 'He aquí vienen días, dice Jehová, en que yo confirmaré la palabra buena que he hablado á la casa de Israel y á la casa de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 15, 'En aquellos días y en aquel tiempo haré producir á David Pimpollo de justicia, y hará juicio y justicia en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 16, 'En aquellos días Judá será salvo, y Jerusalem habitará seguramente, y esto es lo que la llamarán: Jehová, justicia nuestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 17, 'Porque así ha dicho Jehová: No faltará á David varón que se siente sobre el trono de la casa de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 18, 'Y de los sacerdotes y Levitas no faltará varón de mi presencia que ofrezca holocausto, y encienda presente, y que haga sacrificio todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 19, 'Y fué palabra de Jehová á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 20, 'Así ha dicho Jehová: Si pudieres invalidar mi concierto con el día y mi concierto con la noche, por manera que no haya día ni noche á su tiempo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 21, 'Podráse también invalidar mi pacto con mi siervo David, para que deje de tener hijo que reine sobre su trono, y con los Levitas y sacerdotes, mis ministros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 22, 'Como no puede ser contado el ejército del cielo, ni la arena de la mar se puede medir, así multiplicaré la simiente de David mi siervo, y los Levitas que á mí ministran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 23, 'Y fué palabra de Jehová á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 24, '¿No has echado de ver lo que habla este pueblo diciendo: Dos familias que Jehová escogiera ha desechado? y han tenido en poco mi pueblo, hasta no tenerlos más por nación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 25, 'Así ha dicho Jehová: Si no permaneciere mi concierto con el día y la noche, si yo no he puesto las leyes del cielo y la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 33, 26, 'También desecharé la simiente de Jacob, y de David mi siervo, para no tomar de su simiente quien sea señor sobre la simiente de Abraham, de Isaac, y de Jacob. Porque haré volver su cautividad, y tendré de ellos misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 1, 'PALABRA que fué á Jeremías de Jehová, (cuando Nabucodonosor rey de Babilonia, y todo su ejército, y todos los reinos de la tierra del señorío de su mano, y todos los pueblos, peleaban contra Jerusalem, y contra todas sus ciudades,) diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 2, 'Así ha dicho Jehová Dios de Israel: Ve, y habla á Sedechîas rey de Judá, y dile: Así ha dicho Jehová: He aquí entregaré yo esta ciudad en mano del rey de Babilonia, y la abrasaré con fuego:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 3, 'Y no escaparás tú de su mano, sino que de cierto serás preso, y en su mano serás entregado; y tus ojos verán los ojos del rey de Babilonia, y te hablará boca á boca, y en Babilonia entrarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 4, 'Con todo eso, oye palabra de Jehová, Sedechîas rey de Judá: Así ha dicho Jehová de ti: No morirás á cuchillo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 5, 'En paz morirás, y conforme á las quemas de tus padres, los reyes primeros que fueron antes de ti, así quemarán por ti, y te endecharán diciendo, ¡Ay, señor!; porque yo he hablado la palabra, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 6, 'Y habló Jeremías profeta á Sedechîas rey de Judá todas estas palabras en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 7, 'Y el ejército del rey de Babilonia peleaba contra Jerusalem, y contra todas las ciudades de Judá que habían quedado, contra Lachîs, y contra Azeca; porque de las ciudades fuertes de Judá éstas habían quedado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 8, 'Palabra que fué á Jeremías de Jehová, después que Sedechîas hizo concierto con todo el pueblo en Jerusalem, para promulgarles libertad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 9, 'Que cada uno dejase su siervo, y cada uno su sierva, hebreo y hebrea, libres; que ninguno usase de los Judíos su hermanos como de siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 10, 'Y como oyeron todos los príncipes, y todo el pueblo que habían venido en el concierto de dejar cada uno su siervo y cada uno su sierva libres, que ninguno usase más de ellos como de siervos, obedecieron, y dejáronlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 11, 'Mas después se arrepintieron, é hicieron tornar los siervos y las siervas que habían dejado libres, y sujetáronlos por siervos y por siervas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 12, 'Y fué palabra de Jehová á Jeremías, de parte de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 13, 'Así dice Jehová Dios de Israel: Yo hice pacto con vuestros padres el día que los saqué de tierra de Egipto, de casa de siervos, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 14, 'Al cabo de siete años dejaréis cada uno á su hermano hebreo que te fuere vendido; te servirá pues seis años, y lo enviarás libre de ti: mas vuestros padres no me oyeron, ni inclinaron su oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 15, 'Y vosotros os habíais hoy convertido, y hecho lo recto delante de mis ojos, anunciando cada uno libertad á su prójimo; y habíais hecho concierto en mi presencia, en la casa sobre la cual es invocado mi nombre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 16, 'Pero os habéis vuelto y profanado mi nombre, y habéis tornado á tomar cada uno su siervo y cada uno su sierva, que habíais dejado libres á su voluntad; y los habéis sujetado á seros siervos y siervas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 17, 'Por tanto, así ha dicho Jehová: Vosotros no me habéis oído en promulgar cada uno libertad á su hermano, y cada uno á su compañero: he aquí que yo os promulgo libertad, dice Jehová, á cuchillo y á pestilencia, y á hambre; y os pondré en remoción á todos los reinos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 18, 'Y entregaré á los hombres que traspasaron mi pacto, que no han llevado á efecto las palabras del pacto que celebraron en mi presencia dividiendo en dos partes el becerro y pasando por medio de ellas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 19, 'A los príncipes de Judá y á los príncipes de Jerusalem, á los eunucos y á los sacerdotes, y á todo el pueblo de la tierra, que pasaron entre las partes del becerro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 20, 'Entregarélos en mano de sus enemigos y en mano de los que buscan su alma; y sus cuerpos muertos serán para comida de las aves del cielo, y de las bestias de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 21, 'Y á Sedechîas rey de Judá, y á sus príncipes, entregaré en mano de sus enemigos, y en mano de los que buscan su alma, y en mano del ejército del rey de Babilonia, que se fueron de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 34, 22, 'He aquí, mandaré yo, dice Jehová, y harélos volver á esta ciudad, y pelearán contra ella, y la tomarán, y la abrasarán á fuego; y reduciré á soledad las ciudades de Judá, hasta no quedar morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 1, 'PALABRA que fué á Jeremías de Jehová en días de Joacim hijo de Josías, rey de Judá, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 2, 'Ve á casa de los Rechâbitas, y habla con ellos, é introdúcelos en la casa de Jehová, en una de las cámaras, y dales á beber vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 3, 'Tomé entonces á Jaazanías hijo de Jeremías, hijo de Habassinías, y á sus hermanos, y á todos sus hijos, y á toda la familia de los Rechâbitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 4, 'Y metílos en la casa de Jehová, en la cámara de los hijos de Hanán, hijo de Igdalías, varón de Dios, la cual estaba junto á la cámara de los príncipes, que estaba sobre la cámara de Maasías hijo de Sallum, guarda de los vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 5, 'Y puse delante de los hijos de la familia de los Rechâbitas tazas y copas llenas de vino, y díjeles: Bebed vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 6, 'Mas ellos dijeron: No beberemos vino; porque Jonadab hijo de Rechâb nuestro padre nos mandó, diciendo: No beberéis jamás vino vosotros ni vuestros hijos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 7, 'Ni edificaréis casa, ni sembraréis sementera, ni plantaréis viña, ni la tendréis: mas moraréis en tiendas todos vuestros días, para que viváis muchos días sobre la haz de la tierra donde vosotros peregrináis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 8, 'Y nosotros hemos obedecido á la voz de Jonadab nuestro padre, hijo de Rechâb, en todas las cosas que nos mandó, de no beber vino en todos nuestros días, nosotros, ni nuestras mujeres, ni nuestros hijos, ni nuestras hijas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 9, 'Y de no edificar casas para nuestra morada, y de no tener viña, ni heredad, ni sementera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 10, 'Moramos pues en tiendas, y hemos obedecido y hecho conforme á todas las cosas que nos mandó Jonadab nuestro padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 11, 'Sucedió, empero, que cuando Nabucodonosor rey de Babilonia subió á la tierra, dijimos: Venid, y entrémonos en Jerusalem, de delante del ejército de los Caldeos y de delante del ejército de los de Siria: y en Jerusalem nos quedamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 12, 'Y fué palabra de Jehová á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 13, 'Así ha dicho Jehová de los ejércitos, Dios de Israel: Ve, y di á los varones de Judá, y á los moradores de Jerusalem: ¿No recibiréis instrucción para obedecer á mis palabras? dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 14, 'Fué firme la palabra de Jonadab hijo de Rechâb, el cual mandó á sus hijos que no bebiesen vino, y no lo han bebido hasta hoy, por obedecer al mandamiento de su padre; y yo os he hablado á vosotros, madrugando, y hablando, y no me habéis oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 15, 'Y envié á vosotros á todos mis siervos los profetas, madrugando y enviándolos á decir: Tornaos ahora cada uno de su mal camino, y enmendad vuestras obras, y no vayáis tras dioses ajenos para servirles, y viviréis en la tierra que dí á vosotros y á vuestros padres: mas no inclinasteis vuestro oído, ni me oísteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 16, 'Ciertamente los hijos de Jonadab, hijo de Rechâb, tuvieron por firme el mandamiento que les dió su padre; mas este pueblo no me ha obedecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 17, 'Por tanto, así ha dicho Jehová Dios de los ejércitos, Dios de Israel: He aquí traeré yo sobre Judá y sobre todos los moradores de Jerusalem todo el mal que contra ellos he hablado: porque les hablé, y no oyeron; llamélos, y no han respondido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 18, 'Y dijo Jeremías á la familia de los Rechâbitas: Así ha dicho Jehová de los ejércitos, Dios de Israel: Porque obedecisteis al mandamiento de Jonadab vuestro padre, y guardasteis todos sus mandamientos, é hicisteis conforme á todas las cosas que os mandó;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 35, 19, 'Por tanto, así ha dicho Jehová de los ejércitos, Dios de Israel: No faltará varón de Jonadab, hijo de Rechâb, que esté en mi presencia todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 1, 'Y ACONTECIO en el cuarto año de Joacim hijo de Josías, rey de Judá, que fué esta palabra á Jeremías, de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 2, 'Tómate un rollo de libro, y escribe en él todas las palabras que te he hablado contra Israel y contra Judá, y contra todas las gentes, desde el día que comencé á hablarte, desde los días de Josías hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 3, 'Quizá oirá la casa de Judá todo el mal que yo pienso hacerles, para avolverse cada uno de su mal camino, y yo perdonaré su maldad y su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 4, 'Y llamó Jeremías á Baruch hijo de Nerías, y escribió Baruch de boca de Jeremías, en un rollo de libro, todas las palabras que Jehová le había hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 5, 'Después mandó Jeremías á Baruch, diciendo: Yo estoy preso, no puedo entrar en la casa de Jehova:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 6, 'Entra tú pues, y lee de este rollo que escribiste de mi boca, las palabras de Jehová en oídos del pueblo, en la casa de Jehová, el día del ayuno; y las leerás también en oídos de todo Judá que vienen de sus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 7, 'Quizá caerá oración de ellos en la presencia de Jehová, y tornaráse cada uno de su mal camino; porque grande es el furor y la ira que ha expresado Jehová contra este pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 8, 'Y Baruch hijo de Nerías hizo conforme á todas las cosas que le mandó Jeremías profeta, leyendo en el libro las palabras de Jehová en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 9, 'Y aconteció en el año quinto de Joacim hijo de Josías, rey de Judá, en el mes noveno, que promulgaron ayuno en la presencia de Jehová, á todo el pueblo de Jerusalem, y á todo el pueblo que venía de las ciudades de Judá á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 10, 'Y Baruch leyó en el libro las palabras de Jeremías en la casa de Jehová, en la cámara de Gemarías hijo de Saphán escriba, en el atrio de arriba, á la entrada de la puerta nueva de la casa de Jehová, en oídos del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 11, 'Y Michêas hijo de Gemarías, hijo de Saphán, habiendo oído del libro todas las palabras de Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 12, 'Descendió á la casa del rey, á la cámara del secretario, y he aquí que todos los príncipes estaban allí sentados, á saber: Elisama secretario, y Delaías hijo de Semeías, y Elnathán hijo de Achbor, y Gemarías hijo de Saphán, y Sedechîas hijo de Ananías, y todos los príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 13, 'Y contóles Michêas todas las palabras que había oído leyendo Baruch en el libro en oídos del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 14, 'Entonces enviaron todos los príncipes á Jehudí hijo de Nethanías, hijo de Selemías, hijo de Chusi, para que dijese á Baruch: Toma el rollo en que leíste á oídos del pueblo, y ven. Y Baruch, hijo de Nerías, tomó el rollo en su mano, y vino á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 15, 'Y dijéronle: Siéntate ahora, y léelo en nuestros oídos. Y leyó Baruch en sus oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 16, 'Y fué que, como oyeron todas aquellas palabras, cada uno se volvió espantado á su compañero, y dijeron á Baruch: Sin duda contaremos al rey todas estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 17, 'Preguntaron luego á Baruch, diciendo: Cuéntanos ahora cómo escribiste de boca de Jeremías todas estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 18, 'Y Baruch les dijo: El me dictaba de su boca todas estas palabras, y yo escribía con tinta en el libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 19, 'Entonces dijeron los príncipes á Baruch: Ve, y escóndete tú y Jeremías, y nadie sepa dónde estáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 20, 'Y entraron al rey al atrio, habiendo depositado el rollo en la cámara de Elisama secretario; y contaron en los oídos del rey todas estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 21, 'Y envió el rey á Jehudí á que tomase el rollo, el cual lo tomó de la cámara de Elisama secretario, y leyó en él Jehudí en oídos del rey, y en oídos de todos los príncipes que junto al rey estaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 22, 'Y el rey estaba en la casa de invierno en el mes noveno, y había un brasero ardiendo delante de él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 23, 'Y fué que, como Jehudí hubo leído tres ó cuatro planas, rasgólo con un cuchillo de escribanía, y echólo en el fuego que había en el brasero, hasta que todo el rollo se consumió sobre el fuego que en el brasero había.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 24, 'Y no tuvieron temor, ni rasgaron sus vestidos, el rey y todos sus siervos que oyeron todas estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 25, 'Y aunque Elnathán y Delaías y Gemarías rogaron al rey que no quemase aquel rollo, no los quiso oir:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 26, 'Antes mandó el rey á Jerameel hijo de Amelech, y á Seraías hijo de Azriel, y á Selemías hijo de Abdeel, que prendiesen á Baruch el escribiente y á Jeremías profeta; mas Jehová los escondió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 27, 'Y fué palabra de Jehová á Jeremías, después que el rey quemó el rollo, las palabras que Baruch había escrito de boca de Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 28, 'Vuelve á tomar otro rollo, y escribe en él todas las palabras primeras, que estaban en el primer rollo que quemó Joacim, el rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 29, 'Y dirás á Joacim rey de Judá: Así ha dicho Jehová: Tú quemaste este rollo, diciendo: ¿Por qué escribiste en él, diciendo: De cierto, vendrá el rey de Babilonia, y destruirá esta tierra, y hará que no queden en ella hombres ni animales?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 30, 'Por tanto, así ha dicho Jehová, en orden á Joacim rey de Judá: No tendrá quien se siente sobre el trono de David; y su cuerpo será echado al calor del día y al hielo de la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 31, 'Y visitaré sobre él, y sobre su simiente, y sobre sus siervos, su maldad; y traeré sobre ellos, y sobre los moradores de Jerusalem, y sobre los varones de Judá, todo el mal que les he dicho y no escucharon.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 36, 32, 'Y tomó Jeremías otro rollo, y diólo á Baruch hijo de Nerías escriba; y escribió en él de boca de Jeremías todas las palabras del libro que quemó en el fuego Joacim rey de Judá; y aun fueron añadidas sobre ellas muchas otras palabras semejantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 1, 'Y REINO el rey Sedechîas hijo de Josías, en lugar de Conías hijo de Joacim, al cual Nabucodonosor rey de Babilonia había constituído por rey en la tierra de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 2, 'Mas no obedeció él, ni sus siervos, ni el pueblo de la tierra á las palabras de Jehová, que dijo por el profeta Jeremías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 3, 'Y envió el rey Sedechîas á Jucal hijo de Selemías, y á Sephanías hijo de Maasías sacerdote, para que dijesen al profeta Jeremías: Ruega ahora por nosotros á Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 4, 'Y Jeremías entraba y salía en medio del pueblo; porque no lo habían puesto en la casa de la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 5, 'Y como el ejército de Faraón hubo salido de Egipto, y vino la fama de ellos á oídos de los Caldeos que tenían cercada á Jerusalem, partiéronse de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 6, 'Entonces fué palabra de Jehová á Jeremías profeta, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 7, 'Así ha dicho Jehová Dios de Israel: Diréis así al rey de Judá, que os envió á mí para que me preguntaseis: He aquí que el ejército de Faraón que había salido en vuestro socorro, se volvió á su tierra en Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 8, 'Y tornarán los Caldeos, y combatirán esta ciudad, y la tomarán, y la pondrán á fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 9, 'Así ha dicho Jehová: No engañéis vuestras almas, diciendo: Sin duda los Caldeos se han ido de nosotros: porque no se irán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 10, 'Porque aun cuando hirieseis todo el ejército de los Caldeos que pelean con vosotros, y quedasen de ellos hombres alanceados, cada uno se levantará de su tienda, y pondrán esta ciudad á fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 11, 'Y aconteció que, como el ejército de los Caldeos se fué de Jerusalem á causa del ejército de Faraón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 12, 'Salíase de Jerusalem Jeremías para irse á tierra de Benjamín, para apartarse de allí en medio del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 13, 'Y cuando fué á la puerta de Benjamín, estaba allí un prepósito que se llamaba Irías, hijo de Selemías hijo de Hananías, el cual prendió á Jeremías profeta, diciendo: Fnatú te retiras á los Caldeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 14, 'Y Jeremías dijo: Falso: no me retiro á los Caldeos. Mas él no lo escuchó, antes prendió Irías á Jeremías, y llevólo delante de los príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 15, 'Y los príncipes se airaron contra Jeremías, y azotáronle, y pusiéronle en prisión en la casa de Jonathán escriba, porque aquélla habían hecho casa de cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 16, 'Entró pues Jeremías en la casa de la mazmorra, y en las camarillas. Y habiendo estado allá Jeremías por muchos días,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 17, 'El rey Sedechîas envió, y sacóle; y preguntóle el rey escondidamente en su casa, y dijo: ¿Hay palabra de Jehová? Y Jeremías dijo: Hay. Y dijo más: En mano del rey de Babilonia serás entregado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 18, 'Dijo también Jeremías al rey Sedechîas: ¿En qué pequé contra ti, y contra tus siervos, y contra este pueblo, para que me pusieseis en la casa de la cárcel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 19, '¿Y dónde están vuestros profetas que os profetizaban, diciendo: No vendrá el rey de Babilonia contra vosotros, ni contra esta tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 20, 'Ahora pues, oye, te ruego, oh rey mi señor: caiga ahora mi súplica delante de ti, y no me hagas volver á casa de Jonathán escriba, porque no me muera allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 37, 21, 'Entonces dió orden el rey Sedechîas, y depositaron á Jeremías en el patio de la cárcel, haciéndole dar una torta de pan al día, de la plaza de los Panaderos, hasta que todo el pan de la ciudad se gastase. Y quedó Jeremías en el patio de la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 1, 'Y OYO Sephatías hijo de Mathán, y Gedalías hijo de Pashur, y Jucal hijo de Selemías, y Pashur hijo de Melchías, las palabras que Jeremías hablaba á todo el pueblo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 2, 'Así ha dicho Jehová: El que se quedare en esta ciudad morirá á cuchillo, ó de hambre, ó de pestilencia; mas el que saliere á los Caldeos vivirá, pues su vida le será por despojo, y vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 3, 'Así ha dicho Jehová: De cierto será entregada esta ciudad en mano del ejército del rey de Babilonia, y tomarála.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 4, 'Y dijeron los príncipes al rey: Muera ahora este hombre; porque de esta manera hace desmayar las manos de los hombres de guerra que han quedado en esta ciudad, y las manos de todo el pueblo, hablándoles tales palabras; porque este hombre no busca la paz de este pueblo, sino el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 5, 'Y dijo el rey Sedechîas: Helo ahí, en vuestras manos está; que el rey no podrá contra vosotros nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 6, 'Entonces tomaron ellos á Jeremías, é hiciéronlo echar en la mazmorra de Malchîas hijo de Amelech, que estaba en el patio de la cárcel; y metieron á Jeremías con sogas. Y en la mazmorra no había agua, sino cieno; y hundióse Jeremías en el cieno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 7, 'Y oyendo Ebed-melec, hombre etiope, eunuco que estaba en casa del rey, que habían puesto á Jeremías en la mazmorra, y estando sentado el rey á la puerta de Benjamín,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 8, 'Ebed-melec salió de la casa del rey, y habló al rey, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 9, 'Mi señor el rey, mal hicieron estos varones en todo lo que han hecho con Jeremías profeta, al cual hicieron echar en la mazmorra; porque allí se morirá de hambre, pues no hay más pan en la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 10, 'Entonces mandó el rey al mismo Ebed-melec Etiope, diciendo: Toma en tu poder treinta hombres de aquí, y haz sacar á Jeremías profeta de la mazmorra, antes que muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 11, 'Y tomó Ebed-melec en su poder hombres, y entró á la casa del rey al lugar debajo de la tesorería, y tomó de allí trapos viejos, traídos, viejos, y andrajosos, y echólos á Jeremías con sogas en la mazmorra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 12, 'Y dijo Ebed-melec Etiope á Jeremías: Pon ahora esos trapos viejos, traídos, y rotos, bajo los sobacos de tus brazos, debajo de las sogas. Y lo hizo así Jeremías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 13, 'De este modo sacaron á Jeremías con sogas, y subiéronlo de la mazmorra; y quedó Jeremías en el patio de la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 14, 'Después envió el rey Sedechîas, é hizo traer á sí á Jeremías profeta á la tercera entrada que estaba en la casa de Jehová. Y dijo el rey á Jeremías: Pregúntote una palabra, no me encubras ninguna cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 15, 'Y Jeremías dijo á Sedechîas: Si te lo denunciare, ¿no es verdad que me matarás? y si te diere consejo, no has de escucharme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 16, 'Y juró el rey Sedechîas en secreto á Jeremías, diciendo: Vive Jehová que nos hizo esta alma, que no te mataré, ni te entregaré en mano de estos varones que buscan tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 17, 'Entonces dijo Jeremías á Sedechîas: Así ha dicho Jehová Dios de los ejércitos, Dios de Israel: Si salieres luego á los príncipes del rey de Babilonia, tu alma vivirá, y esta ciudad no será puesta á fuego; y vivirás tú y tu casa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 18, 'Mas si no salieres á los príncipes del rey de Babilonia, esta ciudad será entregada en mano de los Caldeos, y la pondrán á fuego, y tú no escaparás de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 19, 'Y dijo el rey Sedechîas á Jeremías: Témome á causa de los Judíos que se han adherido á los Caldeos, que no me entreguen en sus manos y me escarnezcan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 20, 'Y dijo Jeremías: No te entregarán. Oye ahora la voz de Jehová que yo te hablo, y tendrás bien, y vivirá tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 21, 'Mas si no quisieres salir, esta es la palabra que me ha mostrado Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 22, 'Y he aquí que todas las mujeres que han quedado en casa del rey de Judá, serán sacadas á los príncipes del rey de Babilonia; y ellas mismas dirán: Te han engañado, y prevalecido contra ti tus amigos; atollaron en el cieno tus pies, se volvieron atrás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 23, 'Sacarán pues, todas tus mujeres y tus hijos á los Caldeos, y tú no escaparás de sus manos, sino que por mano del rey de Babilonia serás preso, y á esta ciudad quemará á fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 24, 'Y dijo Sedechîas á Jeremías: Nadie sepa estas palabras, y no morirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 25, 'Y si los príncipes oyeren que yo he hablado contigo, y vinieren á ti y te dijeren: Decláranos ahora qué hablaste con el rey, no nos lo encubras, y no te mataremos; asimismo qué te dijo el rey;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 26, 'Les dirás: Supliqué al rey que no me hiciese tornar á casa de Jonathán porque no me muriese allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 27, 'Y vinieron luego todos los príncipes á Jeremías, y preguntáronle: y él les respondió conforme á todo lo que el rey le había mandado. Con esto se dejaron de él, porque el negocio no se había oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 38, 28, 'Y quedó Jeremías en el patio de la cárcel hasta el día que fué tomada Jerusalem; y allí estaba cuando Jerusalem fué tomada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 1, 'EN el noveno año de Sedechîas rey de Judá, en el mes décimo, vino Nabucodonosor rey de Babilonia con todo su ejército contra Jerusalem, y cercáronla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 2, 'Y en el undécimo año de Sedechîas, en el mes cuarto, á los nueve del mes, fué rota la ciudad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 3, 'Y entraron todos los príncipes del rey de Babilonia, y asentaron á la puerta del medio: Nergal-sarezer, Samgar-nebo, Sarsechim, y Rabsaris, Nergal-sarezer, Rabmag, y todos los demás príncipes del rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 4, 'Y fué que viéndolos Sedechîas, rey de Judá, y todos los hombres de guerra, huyeron, y saliéronse de noche de la ciudad por el camino de la huerta del rey, por la puerta entre los dos muros: y salió el rey por el camino del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 5, 'Mas el ejército de los Caldeos los siguió, y alcanzaron á Sedechîas en los llanos de Jericó; y tomáronle, é hiciéronle subir á Nabucodonosor rey de Babilonia, á Ribla, en tierra de Hamath, y sentencióle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 6, 'Y degolló el rey de Babilonia los hijos de Sedechîas á su presencia en Ribla, haciendo asimismo degollar el rey de Babilonia á todos los nobles de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 7, 'Y sacó los ojos al rey Sedechîas, y aprisionóle con grillos para llevarle á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 8, 'Y los Caldeos pusieron á fuego la casa del rey y las casas del pueblo, y derribaron los muros de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 9, 'Y el resto del pueblo que había quedado en la ciudad, y los que se habían á él adherido, con todo el resto del pueblo que había quedado, trasportólos á Babilonia Nabuzaradán, capitán de la guardia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 10, 'Empero Nabuzaradán, capitán de la guardia, hizo quedar en tierra de Judá del vulgo de los pobres que no tenían nada, y dióles entonces viñas y heredades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 11, 'Y Nabucodonosor había ordenado á Nabuzaradán capitán de la guardia, acerca de Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 12, 'Tómale, y mira por él, y no le hagas mal ninguno; antes harás con él como él te dijere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 13, 'Envió por tanto Nabuzaradán capitán de la guardia, y Nabusazbán, Rabsaris, y Nergal-sarezer, y Rabmag, y todos los príncipes del rey de Babilonia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 14, 'Enviaron entonces, y tomaron á Jeremías del patio de la cárcel, y entregáronlo á Gedalías hijo de Ahicam, hijo de Saphán, para que lo sacase á casa: y vivió entre el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 15, 'Y había sido palabra de Jehová á Jeremías, estando preso en el patio de la cárcel, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 16, 'Ve, y habla á Ebed-melec Etiope, diciendo: Así ha dicho Jehová de los ejércitos, Dios de Israel: He aquí traigo yo mis palabras sobre esta ciudad para mal, y no para bien; y vendrán á ser en aquel día á presencia tuya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 17, 'Mas en aquel día yo te libraré, dice Jehová, y no serás entregado en mano de aquellos de quienes tú temes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 39, 18, 'Porque ciertamente te libraré, y no caerás á cuchillo, sino que tu vida te será por despojo, porque tuviste confianza en mí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 1, 'PALABRA que fué á Jeremías de Jehová, después que Nabuzaradán capitán de la guardia le envió desde Ramá, cuando le tomó estando atado con esposas entre toda la transmigración de Jerusalem y de Judá que iban cautivos á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 2, 'Tomó pues el capitán de la guardia á Jeremías, y díjole: Jehová tu Dios habló este mal contra este lugar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 3, 'Y halo traído y hecho Jehová según que había dicho: porque pecasteis contra Jehová, y no oísteis su voz, por eso os ha venido esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 4, 'Y ahora yo te he soltado hoy de las esposas que tenías en tus manos. Si te está bien venir conmigo á Babilonia, ven, y yo miraré por ti; mas si no te está bien venir conmigo á Babilonia, déjalo: mira, toda la tierra está delante de ti; ve á donde mejor y más cómodo te pareciere ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 5, 'Y aun no se había él vuelto, cuando le dijo: Vuélvete á Gedalías hijo de Ahicam, hijo de Saphán, al cual el rey de Babilonia ha puesto sobre todas las ciudades de Judá, y vive con él en medio del pueblo: ó ve á donde te pareciere más cómodo de ir. Y dióle el capitán de la guardia presentes y dones, y despidióle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 6, 'Fuése entonces Jeremías á Gedalías hijo de Ahicam, á Mizpa, y moró con él en medio del pueblo que había quedado en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 7, 'Y como oyeron todos los príncipes del ejército que estaba por el campo, ellos y sus hombres, que el rey de Babilonia había puesto á Gedalías hijo de Ahicam sobre la tierra, y que le había encomendado los hombres, y las mujeres, y los niños, y los pobres de la tierra, que no fueron trasportados á Babilonia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 8, 'Vinieron luego á Gedalías en Mizpa, es á saber, Ismael hijo de Nethanías, y Johanán y Jonathán hijos de Carea, y Seraías hijo de Tanhumeth, y los hijos de Ephi Netophatita, y Jezanías hijo de Maachâti, ellos y su hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 9, 'Y juróles Gedalías hijo de Ahicam, hijo de Saphán, á ellos y á sus hombres, diciendo: No tengáis temor de servir á los Caldeos: habitad en la tierra, y servid al rey de Babilonia, y tendréis bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 10, 'Y he aquí que yo habito en Mizpa, para estar delante de los Caldeos que vendrán á nosotros; mas vosotros, coged el vino, y el pan, y el aceite, y ponedlo en vuestros almacenes, y quedaos en vuestras ciudades que habéis tomado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 11, 'Asimismo todos los Judíos que estaban en Moab, y entre los hijos de Ammón, y en Edom, y los que estaban en todas las tierras, cuando oyeron decir como el rey de Babilonia había dejado algunos en la Judea, y que había puesto sobre ellos á Gedalías hijo de Ahicam, hijo de Saphán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 12, 'Todos estos Judíos tornaron entonces de todas las partes adonde habían sido echados, y vinieron á tierra de Judá, á Gedalías en Mizpa; y cogieron vino y muy muchos frutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 13, 'Y Johanán, hijo de Carea, y todos los príncipes de la gente de guerra que estaban en el campo, vinieron á Gedalías en Mizpa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 14, 'Y dijéronle: ¿No sabes de cierto como Baalis, rey de los hijos de Ammón, ha enviado á Ismael hijo de Nethanías, para matarte? Mas Gedalías hijo de Ahicam no los creyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 15, 'Entonces Johanán hijo de Carea habló á Gedalías en secreto, en Mizpa, diciendo: Yo iré ahora, y heriré á Ismael hijo de Nethanías, y hombre no lo sabrá: ¿por qué te ha de matar, y todos los Judíos que se han recogido á ti se derramarán, y perecerá el resto de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 40, 16, 'Pero Gedalías hijo de Ahicam dijo á Johanán hijo de Carea: No hagas esto, porque falso es lo que tú dices de Ismael.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 1, 'Y ACONTECIO en el mes séptimo, que vino Ismael hijo de Nethanías, hijo de Elisama, de la simiente real, y algunos príncipes del rey, y diez hombres con él, á Gedalías hijo de Ahicam en Mizpa; y comieron pan juntos allí en Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 2, 'Y levantóse Ismael hijo de Nethanías, y los diez hombres que con él estaban, é hirieron á cuchillo á Gedalías hijo de Ahicam, hijo de Saphán, matando así á aquel á quien el rey de Babilonia había puesto sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 3, 'Asimismo hirió Ismael á todos los Judíos que estaban con él, con Gedalías en Mizpa, y á los soldados Caldeos que allí se hallaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 4, 'Sucedió además, un día después que mató á Gedalías, cuando nadie lo sabía aún,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 5, 'Que venían unos hombres de Sichêm y de Silo y de Samaria, ochenta hombres, raída la barba, y rotas las ropas, y arañados y traían en sus manos ofrenda y perfume para llevar á la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 6, 'Y de Mizpa salióles al encuentro, llorando, Ismael hijo de Nethanías: y aconteció que como los encontró, díjoles: Venid á Gedalías, hijo de Ahicam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 7, 'Y fue que cuando llegaron al medio de la ciudad, Ismael hijo de Nethanías los degolló, y echólos en medio de un aljibe, él y los hombres que con él estaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 8, 'Mas entre aquellos fueron hallados diez hombres que dijeron á Ismael: No nos mates; porque tenemos en el campo tesoros de trigos, y cebadas, y aceite, y miel. Y dejólos, y no los mató entre sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 9, 'Y el aljibe en que echó Ismael todos los cuerpos de los hombres que hirió por causa de Gedalías, era el mismo que había hecho el rey Asa por causa de Baasa, rey de Israel: llenólo de muertos Ismael, hijo de Nethanías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 10, 'Después llevó Ismael cautivo á todo el resto del pueblo que estaba en Mizpa; á las hijas del rey, y á todo el pueblo que en Mizpa había quedado, el cual había Nabuzaradán capitán de la guardia encargado á Gedalías hijo de Ahicam. Llevólos pues cautivos Ismael hijo de Nethanías, y se fué para pasarse á los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 11, 'Y oyó Johanán hijo de Carea, y todos los príncipes de la gente de guerra que estaban con él, todo el mal que había hecho Ismael, hijo de Nethanías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 12, 'Entonces tomaron todos los hombres, y fueron á pelear con Ismael hijo de Nethanías, y halláronlo junto á Aguas-muchas, que es en Gabaón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 13, 'Y aconteció que como todo el pueblo que estaba con Ismael vió á Johanán hijo de Carea, y á todos los príncipes de la gente de guerra que estaban con él, se alegraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 14, 'Y todo el pueblo que Ismael había traído cautivo de Mizpa, tornáronse, y volvieron, y fuéronse á Johanán hijo de Carea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 15, 'Mas Ismael hijo de Nethanías se escapó delante de Johanán con ocho hombres, y se fué á los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 16, 'Y Johanán hijo de Carea, y todos los príncipes de la gente de guerra que con él estaban, tomaron todo el resto del pueblo que habían recobrado de Ismael hijo de Nethanías, de Mizpa, después que hirió á Gedalías hijo de Ahicam: hombres de guerra, y mujeres, y niños, y los eunucos que Johanán había hecho tornar de Gabaón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 17, 'Y fueron y habitaron en Geruth-chimham, que es cerca de Bethlehem, á fin de partir y meterse en Egipto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 41, 18, 'Por causa de los Caldeos: porque temían de ellos, por haber herido Ismael hijo de Nethanías á Gedalías hijo de Ahicam, al cual el rey de Babilonia había puesto sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 1, 'Y LLEGARONSE todos los oficiales de la gente de guerra, y Johanán hijo de Carea, y Jezanías hijo de Osaía, y todo el pueblo desde el menor hasta el mayor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 2, 'Y dijeron á Jeremías profeta: Caiga ahora nuestro ruego delante de ti, y ruega por nosotros á Jehová tu Dios, por todo este resto, (pues hemos quedado unos pocos de muchos, como nos ven tus ojos,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 3, 'Para que Jehová tu Dios nos enseñe camino por donde vayamos, y lo que hemos de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 4, 'Y Jeremías profeta les dijo: Ya he oído. He aquí que voy á orar á Jehová vuestro Dios, como habéis dicho; y será que todo lo que Jehová os respondiere, os enseñaré: no os reservaré palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 5, 'Y ellos dijeron á Jeremías: Jehová sea entre nosotros testigo de la verdad y de la lealtad, si no hiciéremos conforme á todo aquello para lo cual Jehová tu Dios te enviare á nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 6, 'Ora sea bueno, ora malo, á la voz de Jehová nuestro Dios, al cual te enviamos, obedeceremos; para que, obedeciendo á la voz de Jehová nuestro Dios, tengamos bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 7, 'Y aconteció que al cabo de diez días fué palabra de Jehová á Jeremías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 8, 'Y llamó á Johanán hijo de Carea, y á todos los oficiales de la gente de guerra que con él estaban, y á todo el pueblo desde el menor hasta el mayor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 9, 'Y díjoles: Así ha dicho Jehová Dios de Israel, al cual me enviasteis para que hiciese caer vuestros ruegos en su presencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 10, 'Si os quedareis quietos en esta tierra, os edificaré, y no os destruiré; os plantaré, y no os arrancaré: porque arrepentido estoy del mal que os he hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 11, 'No temáis de la presencia del rey de Babilonia, del cual tenéis temor; no temáis de su presencia, ha dicho Jehová, porque con vosotros estoy yo para salvaros y libraros de su mano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 12, 'Y os daré misericordias, y tendrá misericordia de vosotros, y os hará tornar á vuestra tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 13, 'Mas si dijereis: No moraremos en esta tierra, no obedeciendo así á la voz de Jehová vuestro Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 14, 'Y diciendo: No, antes nos entraremos en tierra de Egipto, en la cual no veremos guerra, ni oiremos sonido de trompeta, ni tendremos hambre de pan, y allá moraremos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 15, 'Ahora por eso, oid la palabra de Jehová, reliquias de Judá: Así ha dicho Jehová de los ejércitos, Dios de Israel: Si vosotros volviereis vuestros rostros para entrar en Egipto, y entrareis para peregrinar allá,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 16, 'Será que el cuchillo que teméis, os alcanzará allí en tierra de Egipto, y el hambre de que tenéis temor, allá en Egipto se os pegará; y allí moriréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 17, 'Será pues, que todos los hombres que tornaren sus rostros para entrarse en Egipto, para peregrinar allí, morirán á cuchillo, de hambre, y de pestilencia: no habrá de ellos quien quede vivo, ni quien escape delante del mal que traeré yo sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 18, 'Porque así ha dicho Jehová de los ejércitos, Dios de Israel: Como se derramó mi enojo y mi ira sobre los moradores de Jerusalem, así se derramará mi ira sobre vosotros, cuando entrareis en Egipto; y seréis por juramento y por espanto, y por maldición y por afrenta; y no veréis más este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 19, 'Jehová habló sobre vosotros, oh reliquias de Judá: No entréis en Egipto: sabed por cierto que os aviso hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 20, '¿Por qué hicisteis errar vuestras almas? porque vosotros me enviasteis á Jehová vuestro Dios, diciendo: Ora por nosotros á Jehová nuestro Dios; y conforme á todas las cosas que Jehová nuestro Dios dijere, háznoslo saber así, y lo pondremos por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 21, 'Y os lo he denunciado hoy, y no habéis obedecido á la voz de Jehová vuestro Dios, ni á todas las cosas por las cuales me envió á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 42, 22, 'Ahora pues sabed de cierto que á cuchillo, y de hambre y pestilencia, moriréis en el lugar donde deseasteis entrar para peregrinar allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 1, 'Y ACONTECIO que como Jeremías acabó de hablar á todo el pueblo todas las palabras de Jehová Dios de ellos, todas estas palabras por las cuales Jehová Dios de ellos le había enviado á ellos mismos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 2, 'Dijo Azarías hijo de Osaías, y Johanán hijo de Carea, y todos los varones soberbios dijeron á Jeremías: Mentira dices; no te ha enviado Jehová nuestro Dios para decir: No entréis en Egipto á peregrinar allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 3, 'Sino que Baruch hijo de Nerías te incita contra nosotros, para entregarnos en mano de los Caldeos, para matarnos y para hacernos trasportar á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 4, 'No obedeció pues Johanán hijo de Carea, y todos los oficiales de la gente de guerra, y todo el pueblo, á la voz de Jehová para quedarse en tierra de Judá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 5, 'Antes tomó Johanán hijo de Carea, y todos los oficiales de la gente de guerra, á todo el resto de Judá, que de todas las gentes adonde habían sido echados habían vuelto para morar en tierra de Judá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 6, 'A hombres, y mujeres, y niños, y á las hijas del rey, y á toda alma que había dejado Nabuzaradán capitán de la guardia con Gedalías hijo de Ahicam hijo de Saphán, y á Jeremías profeta, y á Baruch hijo de Nerías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 7, 'Y entraron en tierra de Egipto; porque no obedecieron á la voz de Jehová: y llegaron hasta Taphnes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 8, 'Y fué palabra de Jehová á Jeremías en Taphnes, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 9, 'Toma con tu mano piedras grandes, y cúbrelas de barro en un horno de ladrillos que está á la puerta de la casa de Faraón en Taphnes, á vista de hombres Judíos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 10, 'Y diles: Así ha dicho Jehová de los ejércitos, Dios de Israel: He aquí que yo envío, y tomaré á Nabucodonosor rey de Babilonia, mi siervo, y pondré su trono sobre estas piedras que he escondido, y tenderá su dosel sobre ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 11, 'Y vendrá, y herirá la tierra de Egipto: los que á muerte, á muerte, y los que á cautiverio, á cautiverio, y los que á cuchillo, á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 12, 'Y pondré fuego á las casas de los dioses de Egipto; y las quemará, y á ellos llevará cautivos; y él se vestirá la tierra de Egipto, como el pastor se viste su capa, y saldrá de allá en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 43, 13, 'Además, quebrará las estatuas de Beth-semes, que es en tierra de Egipto, y las casas de los dioses de Egipto quemará á fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 1, 'PALABRA que fué á Jeremías acerca de todos los Judíos que moraban en la tierra de Egipto, que moraban en Migdol, y en Taphnes, y en Noph, y en tierra de Pathros, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 2, 'Así ha dicho Jehová de los ejércitos, Dios de Israel: Vosotros habéis visto todo el mal que traje sobre Jerusalem y sobre todas las ciudades de Judá: y he aquí que ellas están el día de hoy asoladas, y ni hay en ellas morador;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 3, 'A causa de la maldad de ellos que cometieron para hacerme enojar, yendo á ofrecer sahumerios, honrando dioses ajenos que ellos no habían conocido, vosotros, ni vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 4, 'Y envié á vosotros á todos mis siervos los profetas, madrugando y enviándolos, diciendo: No hagáis ahora esta cosa abominable que yo aborrezco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 5, 'Mas no oyeron ni inclinaron su oído para convertirse de su maldad, para no ofrecer sahumerios á dioses ajenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 6, 'Derramóse por tanto mi saña y mi furor, y encendióse en las ciudades de Judá y en las calles de Jerusalem, y tornáronse en soledad y en destrucción, como hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 7, 'Ahora pues, así ha dicho Jehová de los ejércitos, Dios de Israel: ¿Por qué hacéis tan grande mal contra vuestras almas, para ser talados varón y mujer, niño y mamante, de en medio de Judá, sin que os quede residuo alguno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 8, 'Haciéndome enojar con las obras de vuestras manos, ofreciendo sahumerios á dioses ajenos en la tierra de Egipto, adonde habéis entrado para morar, de suerte que os acabéis, y seáis por maldición y por oprobio á todas las gentes de la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 9, '¿Os habéis olvidado de las maldades de vuestros padres, y de las maldades de los reyes de Judá, y de las maldades de sus mujeres, y de vuestras maldades, y de las maldades de vuestras mujeres, que hicieron en tierra de Judá y en las calles de Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 10, 'No se han morigerado hasta el día de hoy, ni han tenido temor, ni han caminado en mi ley, ni en mis estatutos que puse delante de vosotros y delante de vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 11, 'Por tanto, así ha dicho Jehová de los ejércitos, Dios de Israel: He aquí que yo pongo mi rostro en vosotros para mal, y para destruir á todo Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 12, 'Y tomaré el resto de Judá que pusieron sus rostros para entrar en tierra de Egipto para morar allí, y en tierra de Egipto serán todos consumidos, caerán á cuchillo, serán consumidos de hambre, á cuchillo y hambre morirán desde el más pequeño hasta el mayor; y serán por juramento, y por espanto, y por maldición, y por oprobio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 13, 'Pues visitaré á los que moran en tierra de Egipto, como visité á Jerusalem, con cuchillo, y con hambre, y con pestilencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 14, 'Y del resto de Judá que entraron en tierra de Egipto para morar allí, no habrá quien escape, ni quien quede vivo, para volver á la tierra de Judá, por la cual suspiran ellos por volver para habitar allí: porque no volverán sino los que escaparen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 15, 'Entonces todos los que sabían que sus mujeres habían ofrecido sahumerios á dioses ajenos, y todas las mujeres que estaban presentes, una gran concurrencia, y todo el pueblo que habitaba en tierra de Egipto, en Pathros, respondieron á Jeremías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 16, 'La palabra que nos has hablado en nombre de Jehová, no oímos de ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 17, 'Antes pondremos ciertamente por obra toda palabra que ha salido de nuestra boca, para ofrecer sahumerios á la reina del cielo, y derramándole libaciones, como hemos hecho nosotros y nuestros padres, nuestros reyes y nuestros príncipes, en las ciudades de Judá y en las plazas de Jerusalem, y fuimos hartos de pan, y estuvimos alegres, y no vimos mal alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 18, 'Mas desde que cesamos de ofrecer sahumerios á la reina del cielo, y de derramarle libaciones, nos falta todo, y á cuchillo y á hambre somos consumidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 19, 'Y cuando ofrecimos sahumerios á la reina del cielo, y le derramamos libaciones, ¿hicímosle nosotras tortas para tributarle culto, y le derramamos libaciones, sin nuestros maridos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 20, 'Y habló Jeremías á todo el pueblo, á los hombres y á las mujeres, y á todo el vulgo que le había respondido esto, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 21, '¿No se ha acordado Jehová, y no ha venido á su memoria el sahumerio que ofrecisteis en las ciudades de Judá, y en las plazas de Jerusalem, vosotros y vuestros padres, vuestros reyes y vuestros príncipes, y el pueblo de la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 22, 'Y no pudo sufrir más Jehová á causa de la maldad de vuestras obras, á causa de las abominaciones que habíais hecho: por tanto vuestra tierra fué en asolamiento, y en espanto, y en maldición, hasta no quedar morador, como hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 23, 'Porque ofrecisteis sahumerios, y pecasteis contra Jehová, y no obedecisteis á la voz de Jehová, ni anduvisteis en su ley, ni en sus estatutos, ni en sus testimonios: por tanto ha venido sobre vosotros este mal, como hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 24, 'Y dijo Jeremías á todo el pueblo, y á todas las mujeres: Oid palabra de Jehová, todos los de Judá que estáis en tierra de Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 25, 'Así ha hablado Jehová de los ejércitos, Dios de Israel, diciendo: Vosotros y vuestras mujeres proferisteis con vuestras bocas, y con vuestras manos lo ejecutasteis, diciendo: Cumpliremos efectivamente nuestros votos que hicimos, de ofrecer sahumerios á la reina del cielo y de derramarle libaciones: confirmáis á la verdad vuestros votos, y ponéis vuestros votos por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 26, 'Por tanto, oid palabra de Jehová, todo Judá que habitáis en tierra de Egipto: He aquí he jurado por mi grande nombre, dice Jehová, que mi nombre no será más invocado en toda la tierra de Egipto por boca de ningún hombre Judío, diciendo: Vive el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 27, 'He aquí que yo velo sobre ellos para mal, y no para bien; y todos los hombres de Judá que están en tierra de Egipto, serán consumidos á cuchillo y de hambre, hasta que perezcan del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 28, 'Y los que escaparen del cuchillo, volverán de tierra de Egipto á tierra de Judá, pocos hombres; sabrán pues todas las reliquias de Judá, que han entrado en Egipto á morar allí la palabra de quién ha de permanecer, si la mía, ó la suya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 29, 'Y esto tendréis por señal, dice Jehová, de que en este lugar os visito, para que sepáis que de cierto permanecerán mis palabras para mal sobre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 44, 30, 'Así ha dicho Jehová: He aquí que yo entrego á Farón Hophra rey de Egipto en mano de sus enemigos, y en mano de los que buscan su alma, como entregué á Sedechîas rey de Judá en mano de Nabucodonosor rey de Babilonia, su enemigo, y que buscaba su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 45, 1, 'PALABRA que habló Jeremías profeta á Baruch hijo de Nerías, cuando escribía en el libro estas palabras de boca de Jeremías, el año cuarto de Joacim hijo de Josías, rey de Judá, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 45, 2, 'Así ha dicho Jehová Dios de Israel, á ti, oh Baruch:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 45, 3, 'Tú dijiste: ¡Ay de mí ahora! porque me ha añadido Jehová tristeza sobre mi dolor; trabajé en mi gemido, y no he hallado descanso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 45, 4, 'Así le has de decir: Así ha dicho Jehová: He aquí que yo destruyo los que edifiqué, y arranco los que planté, y toda esta tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 45, 5, '¿Y tú buscas para ti grandezas? No busques; porque he aquí que yo traigo mal sobre toda carne, ha dicho Jehová, y á ti te daré tu vida por despojo en todos los lugares adonde fueres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 1, 'PALABRA de Jehová que fué á Jeremías profeta, contra las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 2, 'En orden á Egipto: contra el ejército de Faraón Nechâo rey de Egipto, que estaba cerca del río Eufrates en Carchêmis, al cual hirió Nabucodonosor rey de Babilonia el año cuarto de Joacim hijo de Josías, rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 3, 'Aparejad escudo y pavés, y venid á la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 4, 'Uncid caballos, y subid, vosotros los caballeros, y poneos con capacetes; limpiad las lanzas, vestíos de lorigas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 5, '¿Por qué los vi medrosos, tornando atrás? y sus valientes fueron deshechos, y huyeron á más huir sin volver á mirar atrás: miedo de todas partes, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 6, 'No huya el ligero, ni el valiente escape; al aquilón junto á la ribera del Eufrates tropezaron y cayeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 7, '¿Quién es éste que como río sube, y cuyas aguas se mueven como ríos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 8, 'Egipto como río se hincha, y las aguas se mueven como ríos, y dijo: Subiré, cubriré la tierra, destruiré la ciudad y los que en ella moran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 9, 'Subid, caballos, y alborotaos, carros; y salgan los valientes: los de Cus y los de Phut que toman escudo, y los de Lut que toman y entesan arco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 10, 'Mas ese día será á Jehová Dios de los ejércitos día de venganza, para vengarse de sus enemigos: y la espada devorará y se hartará, y se embriagará de la sangre de ellos: porque matanza será á Jehová, Dios de los ejércitos, en tierra del aquilón junto al río Eufrates.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 11, 'Sube á Galaad, y toma bálsamo, virgen hija de Egipto: por demás multiplicarás medicinas; no hay cura para ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 12, 'Las gentes oyeron tu afrenta, y tu clamor hinchió la tierra: porque fuerte se encontró con fuerte, y cayeron ambos juntos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 13, 'Palabra que habló Jehová á Jeremías profeta acerca de la venida de Nabucodonosor, rey de Babilonia, para herir la tierra de Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 14, 'Denunciad en Egipto, y haced saber en Migdol: haced saber también en Noph y en Taphnes; decid: Para, y apercíbete; porque espada ha de devorar tu comarca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 15, '¿Por qué ha sido derribado tu fuerte? no se pudo tener, porque Jehová lo rempujó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 16, 'Multiplicó los caídos, y cada uno cayó sobre su compañero, y dijeron: Levántate y volvámonos á nuestro pueblo, y á la tierra de nuestro nacimiento, de delante de la espada vencedora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 17, 'Allí gritaron: Faraón rey de Egipto, rey de revuelta: dejó pasar el tiempo señalado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 18, 'Vivo yo, dice el Rey, cuyo nombre es Jehová de los ejércitos, que como Tabor entre los montes, y como Carmelo en la mar, así vendrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 19, 'Hazte vasos de transmigración, moradora hija de Egipto; porque Noph será por yermo, y será asolada hasta no quedar morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 20, 'Becerra hermosa Egipto; mas viene destrucción, del aquilón viene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 21, 'Sus soldados también en medio de ella como engordados becerros: que también ellos se volvieron huyeron todos sin pararse: porque vino sobre ellos el día de su quebrantamiento, el tiempo de su visitación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 22, 'Su voz saldrá como de serpiente; porque con ejército vendrán, y con hachas vienen á ella como cortadores de leña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 23, 'Cortaron su bosque, dice Jehová, porque no podrán ser contados; porque serán más que langostas, ni tendrán número.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 24, 'Avergonzóse la hija de Egipto; entregada será en mano del pueblo del aquilón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 25, 'Jehová de los ejércitos, Dios de Israel, ha dicho: He aquí que yo visito el pueblo de Amón de No, y á Faraón y á Egipto, y á sus dioses y á sus reyes; así á Faraón como á los que en él confían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 26, 'Y entregarélos en mano de los que buscan su alma, y en mano de Nabucodonosor rey de Babilonia, y en mano de sus siervos: mas después será habitada como en los días pasados, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 27, 'Y tú no temas, siervo mío Jacob, y no desmayes, Israel; porque he aquí que yo te salvo de lejos, y á tu simiente de la tierra de su cautividad. Y volverá Jacob, y descansará y será prosperado, y no habrá quien lo espante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 46, 28, 'Tú, siervo mío Jacob, no temas, dice Jehová; porque yo soy contigo: porque haré consumación en todas las gentes á las cuales te habré echado; mas en ti no haré consumación, sino que te castigaré con juicio, y no te talaré del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 47, 1, 'PALABRA de Jehová que fué á Jeremías profeta acerca de los Palestinos, antes que Faraón hiriese á Gaza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 47, 2, 'Así ha dicho Jehová: He aquí que suben aguas del aquilón, y tornaranse en torrente, é inundarán la tierra y su plenitud, ciudades y moradores de ellas; y los hombres clamarán, y aullará todo morador de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 47, 3, 'Por el sonido de las uñas de sus fuertes, por el alboroto de sus carros, por el estruendo de sus ruedas, los padres no miraron á los hijos por la flaqueza de las manos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 47, 4, 'A causa del día que viene para destrucción de todos los Palestinos, para talar á Tiro, y á Sidón, á todo ayudador que quedó vivo: porque Jehová destruirá á los Palestinos, al resto de la isla de Caphtor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 47, 5, 'Sobre Gaza vino mesadura, Ascalón fué cortada, y el resto de su valle: ¿hasta cuándo te arañarás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 47, 6, 'Oh espada de Jehová, ¿hasta cuándo no reposarás? Métete en tu vaina, reposa y sosiega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 47, 7, '¿Cómo reposarás? pues que Jehová lo ha enviado contra Ascalón, y á la ribera de la mar, allí lo puso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 1, 'ACERCA de Moab. Así ha dicho Jehová de los ejércitos, Dios de Israel: ¡Ay de Nebo! que fué destruída, fué avergonzada; Chîriathaim fué tomada; fué confusa Misgab, y desmayó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 2, 'No se alabará ya más Moab; contra Hesbón maquinaron mal, diciendo: Venid, y quitémosla de entre las gentes. También tú, Madmén, serás cortada, espada irá tras ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 3, '¡Voz de clamor de Horonaim, destrucción y gran quebrantamiento!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 4, 'Moab fué quebrantada; hicieron que se oyese el clamor de sus pequeños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 5, 'Porque á la subida de Luhith con lloro subirá el que llora; porque á la bajada de Horonaim los enemigos oyeron clamor de quebranto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 6, 'Huid, salvad vuestra vida, y sed como retama en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 7, 'Pues por cuanto confiaste en tus haciendas, en tus tesoros, tú también serás tomada: y Chêmos saldrá en cautiverio, los sacerdotes y sus príncipes juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 8, 'Y vendrá destruidor á cada una de las ciudades, y ninguna ciudad escapará: arruinaráse también el valle, y será destruída la campiña, como ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 9, 'Dad alas á Moab, para que volando se vaya; pues serán desiertas sus ciudades hasta no quedar en ellas morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 10, 'Maldito el que hiciere engañosamente la obra de Jehová, y maldito el que detuviere su cuchillo de la sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 11, 'Quieto estuvo Moab desde su mocedad, y sobre sus heces ha estado él reposado, y no fué trasegado de vaso en vaso, ni nunca fué en cautiverio: por tanto quedó su sabor en él, y su olor no se ha trocado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 12, 'Por eso, he aquí que vienen días, ha dicho Jehová, en que yo le enviaré trasportadores que lo harán trasportar; y vaciarán sus vasos, y romperán sus odres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 13, 'Y avergonzaráse Moab de Chêmos, á la manera que la casa de Israel se avergonzó de Beth-el, su confianza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 14, '¿Cómo diréis: Somos valientes, y robustos hombres para la guerra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 15, 'Destruído fué Moab, y sus ciudades asoló, y sus escogidos mancebos descendieron al degolladero, ha dicho el Rey, cuyo nombre es Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 16, 'Cercano está el quebrantamiento de Moab para venir, y su mal se apresura mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 17, 'Compadeceos de él todos los que estáis alrededor suyo; y todos los que sabéis su nombre, decid: ¿Cómo se quebró la vara de fortaleza, el báculo de hermosura?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 18, 'Desciende de la gloria, siéntate en seco, moradora hija de Dibón; porque el destruidor de Moab subió contra ti, disipó tus fortalezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 19, 'Párate en el camino, y mira, oh moradora de Aroer: pregunta á la que va huyendo, y á la que escapó; dile: ¿Qué ha acontecido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 20, 'Avergonzóse Moab, porque fué quebrantado: aullad y clamad: denunciad en Arnón que Moab es destruído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 21, 'Y que vino juicio sobre la tierra de la campiña; sobre Holón, y sobre Jahzah, y sobre Mephaath,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 22, 'Y sobre Dibón, y sobre Nebo, y sobre Beth-diblathaim,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 23, 'Y sobre Chîriathaim, y sobre Beth-gamul, y sobre Beth-meon,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 24, 'Y sobre Chêrioth, y sobre Bosra, y sobre todas las ciudades de tierra de Moab, las de lejos y las de cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 25, 'Cortado es el cuerno de Moab, y su brazo quebrantado, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 26, 'Embriagadlo, porque contra Jehová se engrandeció; y revuélquese Moab sobre su vómito, y sea también él por escarnio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 27, '¿Y no te fué á ti Israel por escarnio, como si lo tomaran entre ladrones? porque desde que de él hablaste, tú te has movido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 28, 'Desamparad las ciudades, y habitad en peñascos, oh moradores de Moab; y sed como la paloma que hace nido detrás de la boca de la caverna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 29, 'Oído hemos la soberbia de Moab, que es muy soberbio: su hinchazón y su orgullo, y su altivez y la altanería de su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 30, 'Yo conozco, dice Jehová, su cólera; mas no tendrá efecto: sus mentiras no han de aprovechar le.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 31, 'Por tanto yo aullaré sobre Moab, y sobre todo Moab haré clamor, y sobre los hombres de Kir-heres gemiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 32, 'Con lloro de Jazer lloraré por ti, oh vid de Sibma: tus sarmientos pasaron la mar, llegaron hasta la mar de Jazer: sobre tu agosto y sobre tu vendimia vino destruidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 33, 'Y será cortada la alegría y el regocijo de los campos labrados, y de la tierra de Moab: y haré cesar el vino de los lagares: no pisarán con canción; la canción no será canción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 34, 'El clamor, desde Hesbón hasta Eleale; hasta Jaaz dieron su voz: desde Zoar hasta Horonaim, becerra de tres años: porque también las aguas de Nimrin serán destruídas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 35, 'Y haré cesar de Moab, dice Jehová, quien sacrifique en altar, y quien ofrezca sahumerio á sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 36, 'Por tanto, mi corazón resonará como flautas por causa de Moab, asimismo resonará mi corazón á modo de flautas por los hombres de Kir-heres: porque perecieron las riquezas que había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 37, 'Porque en toda cabeza habrá calva, y toda barba será raída; sobre todas manos rasguños, y sacos sobre todos los lomos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 38, 'Sobre todas las techumbres de Moab y en sus calles, todo él será llanto; porque yo quebranté á Moab como á vaso que no agrada, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 39, 'Aullad: ¡Cómo ha sido quebrantado! ¡cómo volvió la cerviz Moab, y fué avergonzado! Y fué Moab en escarnio y en espanto á todos los que están en sus alrededores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 40, 'Porque así ha dicho Jehová: He aquí que como águila volará, y extenderá sus alas á Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 41, 'Tomadas son las ciudades, y tomadas son las fortalezas; y será aquel día el corazón de los valientes de Moab como el corazón de mujer en angustias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 42, 'Y Moab será destruído para dejar de ser pueblo: porque se engrandeció contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 43, 'Miedo y hoyo y lazo sobre ti, oh morador de Moab, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 44, 'El que huyere del miedo, caerá en el hoyo; y el que saliere del hoyo, será preso del lazo: porque yo traeré sobre él, sobre Moab, año de su visitación, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 45, 'A la sombra de Hesbón se pararon los que huían de la fuerza; mas salió fuego de Hesbón, y llama de en medio de Sihón, y quemó el rincón de Moab, y la mollera de los hijos revoltosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 46, '¡Ay de ti, Moab! pereció el pueblo de Chêmos: porque tus hijos fueron presos para cautividad, y tus hijas para cautiverio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 48, 47, 'Empero haré tornar el cautiverio de Moab en lo postrero de los tiempos, dice Jehová. Hasta aquí es el juicio de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 1, 'DE los hijos de Ammón. Así ha dicho Jehová: ¿No tiene hijos Israel? ¿No tiene heredero? ¿Por qué tomó como por heredad el rey de ellos á Gad, y su pueblo habitó en sus ciudades?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 2, 'Por tanto, he aquí vienen días, ha dicho Jehová, en que haré oir en Rabba de los hijos de Ammón clamor de guerra; y será puesta en montón de asolamiento, y sus ciudades serán puestas á fuego, é Israel tomará por heredad á los que los tomaron á ellos, ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 3, 'Aulla, oh Hesbón, porque destruída es Hai; clamad, hijas de Rabba, vestíos de sacos, endechad, y rodead por los vallados, porque el rey de ellos fué en cautiverio, sus sacerdotes y sus príncipes juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 4, '¿Por qué te glorías de los valles? Tu valle se deshizo, oh hija contumaz, la que confía en sus tesoros, la que dice: ¿Quién vendrá contra mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 5, 'He aquí yo traigo sobre ti espanto, dice el Señor Jehová de los ejércitos, de todos tus alrededores; y seréis lanzados cada uno en derechura de su rostro, y no habrá quien recoja al errante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 6, 'Y después de esto haré tornar la cautividad de los hijos de Ammón, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 7, 'De Edom. Así ha dicho Jehová de los ejércitos: ¿No hay más sabiduría en Temán? ¿ha perecido el consejo en los sabios? ¿corrompióse su sabiduría?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 8, 'Huid, volveos, escondeos en simas para estar, oh moradores de Dedán; porque el quebrantamiento de Esaú traeré sobre él, al tiempo que lo tengo de visitar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 9, 'Si vendimiadores vinieran contra ti, ¿no dejarán rebuscos? Si ladrones de noche, tomarán lo que hubieren menester.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 10, 'Mas yo desnudaré á Esaú, descubriré sus escondrijos, y no podrá esconderse: será destruída su simiente, y sus hermanos, y sus vecinos; y no será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 11, 'Deja tus huérfanos, yo los criaré; y en mí se confiarán tus viudas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 12, 'Porque así ha dicho Jehová: He aquí que los que no estaban condenados á beber del cáliz, beberán ciertamente; ¿y serás tú absuelto del todo? No serás absuelto, sino que de cierto beberás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 13, 'Porque por mí he jurado, dice Jehová, que en asolamiento, en oprobio, en soledad, y en maldición, será Bosra; y todas su ciudades serán en asolamientos perpetuos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 14, 'La fama oí, que de Jehová había sido enviado mensajero á las gentes, diciendo: Juntaos, y venid contra ella, y levantaos á la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 15, 'Porque he aquí que pequeño te he puesto entre las gentes, menospreciado entre los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 16, 'Tu arrogancia te engañó, y la soberbia de tu corazón, tú que habitas en cavernas de peñas, que tienes la altura del monte: aunque alces como águila tu nido, de allí te haré descender, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 17, 'Y será Edom en asolamiento: todo aquel que pasare por ella se espantará, y silbará sobre todas sus plagas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 18, 'Como el trastornamiento de Sodoma y de Gomorra, y de sus ciudades vecinas, dice Jehová, no morará allí nadie, ni la habitará hijo de hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 19, 'He aquí que como león subirá de la hinchazón del Jordán contra la bella y robusta; porque muy pronto harélo correr de sobre ella, y al que fuere escogido la encargaré; porque ¿quién es semejante á mí? ¿y quién me emplazará? ¿y quién será aquel pastor que me podrá resistir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 20, 'Por tanto, oíd el consejo de Jehová, que ha acordado sobre Edom; y sus pensamientos, que ha resuelto sobre los moradores de Temán. Ciertamente los más pequeños del hato los arrastrarán, y destruirán sus moradas con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 21, 'Del estruendo de la caída de ellos la tierra tembló, y el grito de su voz se oyó en el mar Bermejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 22, 'He aquí que como águila subirá y volará, y extenderá sus alas sobre Bosra: y el corazón de los valientes de Edom será en aquel día como el corazón de mujer en angustias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 23, 'Acerca de Damasco. Confundióse Hamath, y Arphad, porque oyeron malas nuevas: derritiéronse en aguas de desmayo, no pueden sosegarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 24, 'Desmayóse Damasco, volvióse para huir, y tomóle temblor: angustia y dolores le tomaron, como de mujer que está de parto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 25, '¡Cómo dejaron á la ciudad de alabanza, ciudad de mi gozo!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 26, 'Por tanto, sus mancebos caerán en sus plazas, y todos los hombres de guerra morirán en aquel día, ha dicho Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 27, 'Y haré encender fuego en el muro de Damasco, y consumirá las casas de Ben-hadad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 28, 'De Cedar y de los reinos de Hasor, los cuales hirió Nabucodonosor rey de Babilonia. Así ha dicho Jehová: Levantaos, subid contra Cedar, y destruid los hijos de oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 29, 'Sus tiendas y su ganados tomarán: sus cortinas, y todos sus vasos, y sus camellos, tomarán para sí; y llamarán contra ellos miedo alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 30, 'Huid, trasponeos muy lejos, meteos en simas para estar, oh moradores de Hasor, dice Jehová; porque tomó consejo contra vosotros Nabucodonosor rey de Babilonia, y contra vosotros ha formado designio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 31, 'Levantaos, subid á gente pacífica, que vive confiadamente, dice Jehová, que ni tienen puertas ni cerrojos, que viven solitarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 32, 'Y serán sus camellos por presa, y la multitud de sus ganados por despojo; y esparcirélos por todos vientos, echados hasta el postrer rincón; y de todos sus lados les traeré su ruina, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 33, 'Y Hasor será morada de chacales, soledad para siempre: ninguno morará allí, ni la habitará hijo de hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 34, 'Palabra de Jehová que fué á Jeremías profeta acerca de Elam, en el principio del reinado de Sedechîas rey de Judá, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 35, 'Así ha dicho Jehová de los ejércitos: He aquí que yo quiebro el arco de Elam, principio de su fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 36, 'Y traeré sobre Elam los cuatro vientos de los cuatro puntos del cielo, y aventarélos á todos estos vientos; ni habrá gente adonde no vengan extranjeros de Elam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 37, 'Y haré que Elam se intimide delante de sus enemigos, y delante de los que buscan su alma; y traeré sobre ellos mal, y el furor de mi enojo, dice Jehová; y enviaré en pos de ellos espada hasta que los acabe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 38, 'Y pondré mi silla en Elam, y destruiré de allí rey y príncipe, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 49, 39, 'Mas acontecerá en lo postrero de los días, que haré tornar la cautividad de Elam, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 1, 'PALABRA que habló Jehová contra Babilonia, contra la tierra de los Caldeos, por mano de Jeremías profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 2, 'Denunciad en las gentes, y haced saber; levantad también bandera: publicad, y no encubráis: decid: Tomada es Babilonia, Bel es confundido, deshecho es Merodach; confundidas son sus esculturas, quebrados son sus ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 3, 'Porque subió contra ella gente del aquilón, la cual pondrá su tierra en asolamiento, y no habrá ni hombre ni animal que en ella more: moviéronse, se fueron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 4, 'En aquellos días y en aquel tiempo, dice Jehová, vendrán los hijos de Israel, ellos y los hijos de Judá juntamente; é irán andando y llorando, y buscarán á Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 5, 'Preguntarán por el camino de Sión, hacia donde volverán sus rostros, diciendo: Venid, y juntaos á Jehová con pacto eterno, que jamás se ponga en olvido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 6, 'Ovejas perdidas fueron mi pueblo: sus pastores las hicieron errar, por los montes las descarriaron: anduvieron de monte en collado, olvidáronse de sus majadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 7, 'Todos los que los hallaban, los comían; y decían sus enemigos: No pecaremos, porque ellos pecaron á Jehová morada de justicia, á Jehová, esperanza de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 8, 'Huid de en medio de Babilonia, y salid de la tierra de los Caldeos, y sed como los mansos delante del ganado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 9, 'Porque he aquí que yo suscito y hago subir contra Babilonia reunión de grandes pueblos de la tierra del aquilón; y desde allí se aparejarán contra ella, y será tomada: sus flechas como de valiente diestro, que no se tornará en vano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 10, 'Y la Caldea será para presa: todos los que la saquearen, saldrán hartos, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 11, 'Porque os alegrasteis, porque os gozasteis destruyendo mi heredad, porque os henchisteis como becerra de renuevos, y relinchasteis como caballos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 12, 'Vuestra madre se avergonzó mucho, afrentóse la que os engendró; he aquí será la postrera de las gentes: desierto, sequedad, y páramo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 13, 'Por la ira de Jehová no será habitada, sino que asolada será toda ella; todo hombre que pasare por Babilonia se asombrará, y silbará sobre todas sus plagas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 14, 'Apercibíos contra Babilonia alrededor, todos los que entesáis arco; tirad contra ella, no escatiméis las saetas: porque pecó contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 15, 'Gritad contra ella en derredor; dió su mano; caído han sus fundamentos, derribados son sus muros; porque venganza es de Jehová. Tomad venganza de ella; haced con ella como ella hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 16, 'Talad de Babilonia sembrador, y el que tiene hoz en tiempo de la siega: delante de la espada opresora cada uno volverá el rostro hacia su pueblo, cada uno huirá hacia su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 17, 'Ganado descarriado es Israel; leones lo amontonaron: el rey de Asiria lo devoró el primero; este Nabucodonosor rey de Babilonia lo deshuesó el postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 18, 'Por tanto, así ha dicho Jehová de los ejércitos, Dios de Israel: He aquí que yo visito al rey de Babilonia y á su tierra como visité al rey de Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 19, 'Y volveré á traer á Israel á su morada, y pacerá en el Carmelo y en Basán; y en el monte de Ephraim y de Galaad se hartará su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 20, 'En aquellos días y en aquel tiempo, dice Jehová, la maldad de Israel será buscada, y no parecerá; y los pecados de Judá, y no se hallarán: porque perdonaré á los que yo hubiere dejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 21, 'Sube contra la tierra de Merathaim, contra ella, y contra los moradores de Pekod: destruye y mata en pos de ellos, dice Jehová, y haz conforme á todo lo que yo te he mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 22, 'Estruendo de guerra en la tierra, y quebrantamiento grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 23, '¡Cómo fué cortado y quebrado el martillo de toda la tierra! ¡cómo se tornó Babilonia en desierto entre las gentes!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 24, 'Púsete lazos, y aun fuiste tomada, oh Babilonia, y tú no lo supiste: fuiste hallada, y aun presa, porque provocaste á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 25, 'Abrió Jehová tu tesoro, y sacó los vasos de su furor: porque esta es obra de Jehová, Dios de los ejércitos, en la tierra de los Caldeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 26, 'Venid contra ella desde el cabo de la tierra: abrid sus almacenes: hacedla montones, y destruidla: no le queden reliquias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 27, 'Matad todos sus novillos; vayan al matadero: ¡ay de ellos! que venido es su día, el tiempo de su visitación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 28, 'Voz de los que huyen y escapan de la tierra de Babilonia, para dar las nuevas en Sión de la venganza de Jehová nuestro Dios, de la venganza de su templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 29, 'Haced juntar sobre Babilonia flecheros, á todos los que entesan arco; asentad campo sobre ella alrededor; no escape de ella ninguno: pagadle según su obra; conforme á todo lo que ella hizo, haced con ella: porque contra Jehová se ensoberbeció, contra el Santo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 30, 'Por tanto sus mancebos caerán es sus plazas, y todos su hombres de guerra serán talados en aquel día, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 31, 'He aquí yo contra ti, oh soberbio, dice el Señor Jehová de los ejércitos: porque tu día es venido, el tiempo en que te visitaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 32, 'Y el soberbio tropezará y caerá, y no tendrá quien lo levante: y encenderé fuego en sus ciudades, y quemaré todos sus alrededores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 33, 'Así ha dicho Jehová de los ejércitos: Oprimidos fueron los hijos de Israel y los hijos de Judá juntamente: y todos los que los tomaron cautivos, se los retuvieron; no los quisieron soltar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 34, 'El redentor de ellos es el Fuerte; Jehová de los ejércitos es su nombre: de cierto abogará la causa de ellos, para hacer quietar la tierra, y turbar los moradores de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 35, 'Cuchillo sobre los Caldeos, dice Jehová, y sobre los moradores de Babilonia, y sobre sus príncipes, y sobre sus sabios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 36, 'Cuchillo sobre los adivinos, y se atontarán; cuchillo sobre sus valientes, y serán quebrantados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 37, 'Cuchillo sobre sus caballos, y sobre sus carros, y sobre todo el vulgo que está en medio de ella, y serán como mujeres: cuchillo sobre sus tesoros, y serán saqueados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 38, 'Sequedad sobre sus aguas, y secaránse: porque tierra es de esculturas, y en ídolos enloquecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 39, 'Por tanto, allí morarán bestias monteses con lobos, morarán también en ella pollos de avestruz: y no más será poblada para siempre, ni se habitará de generación en generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 40, 'Como en el trastornamiento de Dios á Sodoma y á Gomorra y á sus ciudades vecinas, dice Jehová, no morará allí hombre, ni hijo de hombre la habitará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 41, 'He aquí viene un pueblo del aquilón; y una nación grande, y muchos reyes se levantarán de los lados de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 42, 'Arco y lanza manejarán; serán crueles, y no tendrán compasión; su voz sonará como la mar, y montarán sobre caballos: apercibirse han como hombre á la pelea, contra ti, oh hija de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 43, 'Oyó su fama el rey de Babilonia, y sus manos se descoyuntaron: angustia le tomó, dolor como de mujer de parto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 44, 'He aquí que como león subirá de la hinchazón del Jordán á la morada fuerte: porque muy pronto le haré correr de sobre ella, y al que fuere escogido la encargaré: porque ¿quién es semejante á mí? ¿y quién me emplazará? ¿ó quién será aquel pastor que me podrá resistir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 45, 'Por tanto, oid el consejo de Jehová, que ha acordado sobre Babilonia, y sus pensamientos que ha formado sobre la tierra de los Caldeos: Ciertamente los más pequeños del hato los arrastrarán, y destruirán sus moradas con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 50, 46, 'Del grito de la toma de Babilonia la tierra tembló, y el clamor se oyó entre las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 1, 'ASI ha dicho Jehová: He aquí que yo levanto sobre Babilonia, y sobre sus moradores que se levantan contra mí, un viento destruidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 2, 'Y enviaré á Babilonia aventadores que la avienten, y vaciarán su tierra; porque serán contra ella de todas partes en el día del mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 3, 'Diré al flechero que entesa su arco, y al que se pone orgulloso con su loriga: No perdonéis á sus mancebos, destruid todo su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 4, 'Y caerán muertos en la tierra de los Caldeos, y alanceados en sus calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 5, 'Porque Israel y Judá no han enviudado de su Dios, Jehová de los ejércitos, aunque su tierra fué llena de pecado contra el Santo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 6, 'Huid de en medio de Babilonia, y librad cada uno su alma, porque no perezcáis á causa de su maldad: porque el tiempo es de venganza de Jehová; darále su pago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 7, 'Vaso de oro fué Babilonia en la mano de Jehová, que embriaga toda la tierra: de su vino bebieron las gentes; aturdiéronse por tanto las naciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 8, 'En un momento cayó Babilonia, y despedazóse: aullad sobre ella; tomad bálsamo para su dolor, quizá sanará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 9, 'Curamos á Babilonia, y no ha sanado: dejadla, y vámonos cada uno á su tierra; porque llegado ha hasta el cielo su juicio, y alzádose hasta las nubes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 10, 'Jehová sacó á luz nuestras justicias: venid, y contemos en Sión la obra de Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 11, 'Limpiad las saetas, embrazad los escudos: despertado ha Jehová el espíritu de los reyes de Media; porque contra Babilonia es su pensamiento para destruirla; porque venganza es de Jehová, venganza de su templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 12, 'Levantad bandera sobre los muros de Babilonia, reforzad la guardia, poned centinelas, disponed celadas; porque deliberó Jehová, y aun pondrá en efecto lo que ha dicho sobre los moradores de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 13, 'La que moras entre muchas aguas, rica en tesoros, venido ha tu fin, la medida de tu codicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 14, 'Jehová de los ejércitos juró por su vida, diciendo: Yo te llenaré de hombres como de langostas, y levantarán contra ti gritería.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 15, 'El es el que hizo la tierra con su fortaleza, el que afirmó el mundo con su sabiduría, y extendió los cielos con inteligencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 16, 'El que da con su voz muchedumbre de aguas del cielo, y hace subir las nubes de lo postrero de la tierra; él hace relámpagos con la lluvia, y saca el viento de sus tesoros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 17, 'Todo hombre se ha infatuado y es sin ciencia: avergüénzase todo artífice de la escultura, porque mentira es su vaciadizo, que no tiene espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 18, 'Vanidad son, obra de irrisiones; en el tiempo de su visitación perecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 19, 'No es como ellos la parte de Jacob: porque él es el Formador de todo; é Israel es la vara de su heredad: Jehová de los ejércitos es su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 20, 'Martillo me sois, y armas de guerra; y por medio de ti quebrantaré gentes, y por medio de ti desharé reinos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 21, 'Y por tu medio quebrantaré caballos y sus cabalgadores, y por medio de ti quebrantaré carros y los que en ellos suben;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 22, 'Asimismo por tu medio quebrantaré hombres y mujeres, y por medio de ti quebrantaré viejos y mozos, y por tu medio quebrantaré mancebos y vírgenes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 23, 'También quebrantaré por medio de ti al pastor y á su manada: quebrantaré por tu medio á labradores y sus yuntas; y duques y príncipes quebrantaré por medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 24, 'Y pagaré á Babilonia y á todos los moradores de Caldea, todo el mal de ellos que hicieron en Sión delante de vuestros ojos, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 25, 'He aquí yo contra ti, oh monte destruidor, dice Jehová, que destruiste toda la tierra; y extenderé mi mano sobre ti, y te haré rodar de las peñas, y te tornaré monte quemado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 26, 'Y nadie tomará de ti piedra para esquina, ni piedra para cimiento; porque perpetuos asolamientos serás, ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 27, 'Alzad bandera en la tierra, tocad trompeta en las naciones, apercibid gentes contra ella; juntad contra ella los reinos de Ararat, de Minni, y de Aschênaz; señalad contra ella capitán, haced subir caballos como langostas erizadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 28, 'Apercibid contra ella gentes; á reyes de Media, á sus capitanes, y á todos sus príncipes, y á toda la tierra de su señorío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 29, 'Y temblará la tierra, y afligiráse; porque confirmado es contra Babilonia todo el pensamiento de Jehová, para poner la tierra de Babilonia en soledad, y que no haya morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 30, 'Los valientes de Babilonia dejaron de pelear, estuviéronse en sus fuertes: faltóles su fortaleza, tornáronse como mujeres: encendiéronse sus casas, quebráronse sus cerrojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 31, 'Correo se encontrará con correo, mensajero se encontrará con mensajero, para noticiar al rey de Babilonia que su ciudad es tomada por todas partes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 32, 'Y los vados fueron tomados, y los carrizos fueron quemados á fuego, y consternáronse los hombres de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 33, 'Porque así ha dicho Jehová de los ejércitos, Dios de Israel: La hija de Babilonia es como parva; tiempo es ya de trillarla: de aquí á poco le vendrá el tiempo de la siega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 34, 'Comióme, desmenuzóme Nabucodonosor rey de Babilonia; paróme como vaso vacío, tragóme como dragón, hinchió su vientre de mis delicadezas, y echóme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 35, 'Sobre Babilonia la violencia contra mí y mi carne, dirá la moradora de Sión; y mi sangre sobre los moradores de Caldea, dirá Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 36, 'Por tanto, así ha dicho Jehová: He aquí que yo juzgo tu causa y haré tu venganza; y secaré su mar, y haré que quede seca su corriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 37, 'Y será Babilonia para montones, morada de chacales, espanto y silbo, sin morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 38, 'A una rugirán como leones; como cachorros de leones bramarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 39, 'En su calor les pondré sus banquetes; y haréles que se embriaguen, para que se alegren, y duerman eterno sueño, y no despierten, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 40, 'Hacerlos he traer como corderos al matadero, como carneros con cabritos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 41, '¡Cómo fué presa Sesach, y fué tomada la que era alabada por toda la tierra! ¡Cómo fué Babilonia por espanto entre las gentes!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 42, 'Subió la mar sobre Babilonia; de la multitud de sus ondas fué cubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 43, 'Sus ciudades fueron asoladas, la tierra seca y desierta, tierra que no morará en ella nadie, ni pasará por ella hijo de hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 44, 'Y visitaré á Bel en Babilonia, y sacaré de su boca lo que ha tragado: y no vendrán más á él gentes; y el muro de Babilonia caerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 45, 'Salid de en medio de ella, pueblo mío, y salvad cada uno su vida de la ira del furor de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 46, 'Y porque no desmaye vuestro corazón, y temáis á causa de la fama que se oirá por la tierra, en un año vendrá la fama, y después en otro año el rumor, y la violencia en la tierra, y el enseñoreador sobre el que enseñorea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 47, 'Por tanto, he aquí vienen días que yo visitaré las esculturas de Babilonia, y toda su tierra será avergonzada, y todos sus muertos caerán en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 48, 'Y los cielos y la tierra, y todo lo que está en ellos, darán alabanzas sobre Babilonia: porque del aquilón vendrán sobre ella destruidores, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 49, 'Pues que Babilonia fué causa que cayesen muertos de Israel, también de Babilonia caerán muertos de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 50, 'Los que escapasteis del cuchillo, andad, no os detengais; acordaos por muchos días de Jehová, y acordaos de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 51, 'Estamos avergonzados, porque oímos la afrenta: confusión cubrió nuestros rostros, porque vinieron extranjeros contra los santuarios de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 52, 'Por tanto, he aquí vienen días, dice Jehová, que yo visitaré sus esculturas, y en toda su tierra gemirán los heridos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 53, 'Si subiese Babilonia al cielo, y si fortaleciere en lo alto su fuerza, de mí vendrán á ella destruidores, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 54, '¡Sonido de grito de Babilonia, y quebrantamiento grande de la tierra de los Caldeos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 55, 'Porque Jehová destruye á Babilonia, y quitará de ella el mucho estruendo; y bramarán sus ondas, como muchas aguas será el sonido de la voz de ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 56, 'Porque vino destruidor contra ella, contra Babilonia, y sus valientes fueron presos, el arco de ellos fué quebrado: porque Jehová, Dios de retribuciones, dará la paga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 57, 'Y embriagaré sus príncipes y sus sabios, sus capitanes y sus nobles y sus fuertes; y dormirán sueño eterno y no despertarán, dice el Rey, cuyo nombre es Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 58, 'Así ha dicho Jehová de los ejércitos: El muro ancho de Babilonia será derribado enteramente, y sus altas puertas serán quemadas á fuego; y en vano trabajarán pueblos y gentes en el fuego, y se cansarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 59, 'Palabra que envió Jeremías profeta á Seraías hijo de Nerías, hijo de Maasías, cuando iba con Sedechîas rey de Judá á Babilonia, el cuarto año de su reinado. Y era Seraías el principal camarero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 60, 'Escribió pues Jeremías en un libro todo el mal que había de venir sobre Babilonia, todas las palabras que están escritas contra Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 61, 'Y dijo Jeremías á Seraías: Cuando llegares á Babilonia, y vieres y leyeres todas estas cosas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 62, 'Dirás: Oh Jehová, tú has dicho contra este lugar que lo habías de talar, hasta no quedar en él morador, ni hombre ni animal, sino que para siempre ha de ser asolado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 63, 'Y será que cuando acabares de leer este libro, le atarás una piedra, y lo echarás en medio del Eufrates:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 51, 64, 'Y dirás: Así será anegada Babilonia, y no se levantará del mal que yo traigo sobre ella; y serán rendidos. Hasta aquí son las palabras de Jeremías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 1, 'ERA Sedechîas de edad de veintiún años cuando comenzó á reinar, y reinó once años en Jerusalem. Su madre se llamaba Hamutal, hija de Jeremías, de Libna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 2, 'E hizo lo malo en los ojos de Jehová, conforme á todo lo que hizo Joacim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 3, 'Y á causa de la ira de Jehová contra Jerusalem y Judá, fué el llegar á echarlos de su presencia: y rebelóse Sedechîas contra el rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 4, 'Aconteció por tanto á los nueve años de su reinado, en el mes décimo, á los diez días del mes, que vino Nabucodonosor rey de Babilonia, él y todo su ejército, contra Jerusalem, y contra ella asentaron campo, y de todas partes edificaron contra ella baluartes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 5, 'Y estuvo cercada la ciudad hasta el undécimo año del rey Sedechîas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 6, 'En el mes cuarto, á los nueve del mes, prevaleció el hambre en la ciudad, hasta no haber pan para el pueblo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 7, 'Y fué entrada la ciudad, y todos los hombres de guerra huyeron, y saliéronse de la ciudad de noche por el camino de postigo de entre los dos muros, que había cerca del jardín del rey, y fuéronse por el camino del desierto, estando aún los Caldeos junto á la ciudad alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 8, 'Y el ejército de los Caldeos siguió al rey, y alcanzaron á Sedechîas en los llanos de Jericó; y esparcióse de él todo su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 9, 'Entonces prendieron al rey, e hiciéronle venir al rey de Babilonia, á Ribla en tierra de Hamath, donde pronunció contra él sentencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 10, 'Y degolló el rey de Babilonia á los hijos de Sedechîas delante de sus ojos, y también degolló á todos los príncipes de Judá en Ribla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 11, 'A Sedechîas empero sacó los ojos, y le aprisionó con grillos, é hízolo el rey de Babilonia llevar á Babilonia; y púsolo en la casa de la cárcel hasta el día en que murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 12, 'Y en el mes quinto, á los diez del mes, que era el año diecinueve del reinado de Nabucodonosor, rey de Babilonia, vino á Jerusalem Nabuzaradán, capitán de la guardia, que solía estar delante del rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 13, 'Y quemó la casa de Jehová, y la casa del rey, y todas las casas de Jerusalem; y abrasó con fuego todo grande edificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 14, 'Y todo el ejército de los Caldeos, que venía con el capitán de la guardia, destruyó todos los muros de Jerusalem en derredor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 15, 'E hizo trasportar Nabuzaradán, capitán de la guardia, los pobres del pueblo, y toda la otra gente vulgar que en la ciudad habían quedado, y los fugitivos que se habían huído al rey de Babilonia, y todo el resto de la multitud vulgar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 16, 'Mas de los pobres del país dejó Nabuzaradán, capitán de la guardia, para viñadores y labradores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 17, 'Y los Caldeos quebraron las columnas de bronce que estaban en la casa de Jehová, y las basas, y el mar de bronce que estaba en la casa de Jehová, y llevaron todo el metal á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 18, 'Lleváronse también los calderos, y los badiles, y los salterios, y las bacías, y los cazos, y todos los vasos de metal con que se servían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 19, 'Y las copas, é incensarios, y tazones, y ollas, y candeleros, y escudillas, y tazas: lo que de oro de oro, y lo que de plata de plata, se llevó el capitán de la guardia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 20, 'Las dos columnas, un mar, y doce bueyes de bronce que estaban debajo de las basas, que había hecho el rey Salomón en la casa de Jehová: no se podía pesar el metal de todos estos vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 21, 'Cuanto á las columnas, la altura de la columna era de dieciocho codos, y un hilo de doce codos la rodeaba: y su grueso era de cuatro dedos, y hueca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 22, 'Y el capitel de bronce que había sobre ella, era de altura de cinco codos, con una red y granadas en el capitel alrededor, todo de bronce; y lo mismo era lo de la segunda columna con sus granadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 23, 'Había noventa y seis granadas en cada orden: todas ellas eran ciento sobre la red alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 24, 'Tomó también el capitán de la guardia á Seraías principal sacerdote, y á Sophonías segundo sacerdote, y tres guardas del atrio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 25, 'Y de la ciudad tomó un eunuco que era capitán sobre los hombres de guerra, y siete hombres de los continuos del rey, que se hallaron en al ciudad; y al principal secretario de la milicia, que revistaba el pueblo de la tierra para la guerra; y sesenta hombres del vulgo del país, que se hallaron dentro de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 26, 'Tomólos pues Nabuzaradán, capitán de la guardia, y llevólos al rey de Babilonia á Ribla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 27, 'Y el rey de Babilonia los hirió, y los mató en Ribla en tierra de Hamath. Así fué Judá trasportado de su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 28, 'Este es el pueblo que Nabucodonosor hizo trasportar: En el año séptimo, tres mil veintitrés Judíos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 29, 'En el año dieciocho hizo Nabudonosor, trasportar de Jerusalem ochocientas treinta y dos personas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 30, 'El año veintitrés de Nabucodonosor, trasportó Nabuzaradán capitán de la guardia, setecientas cuarenta y cinco personas de los Judíos: todas las personas fueron cuatro mil seiscientas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 31, 'Y acaeció que en el año treinta y siete de la cautividad de Joachîn rey de Judá, en el mes duodécimo, á los veinticinco del mes, Evil-merodach, rey de Babilonia, en el año primero de su reinado, alzó la cabeza de Joachîn rey de Judá y sacólo de la casa de la cárcel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 32, 'Y habló con él amigablemente, é hizo poner su silla sobre las sillas de los reyes que estaban con él en Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 33, 'Hízole mudar también los vestidos de su prisión, y comía pan delante de él siempre todos los días de su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JER', 'Jeremías', 52, 34, 'Y continuamente se le daba ración por el rey de Babilonia, cada cosa en su día por todos los de su vida, hasta el día de su muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 1, '¡COMO está sentada sola la ciudad populosa! La grande entre las naciones se ha vuelto como viuda, La señora de provincias es hecha tributaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 2, 'Amargamente llora en la noche, y sus lágrimas en sus mejillas; No tiene quien la consuele de todos sus amadores: Todos sus amigos le faltaron, volviéronsele enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 3, 'Fuése Judá, a causa de la aflicción y de la grandeza de servidumbre; Ella moró entre las gentes, y no halló descanso: Todos sus perseguidores la alcanzaron entre estrechuras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 4, 'Las calzadas de Sión tienen luto, porque no hay quien venga á las solemnidades; Todas sus puertas están asoladas, sus sacerdotes gimen, Sus vírgenes afligidas, y ella tiene amargura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 5, 'Sus enemigos han sido hechos cabeza, sus aborrecedores fueron prosperados; Porque Jehová la afligió por la multitud de sus rebeliones: Sus niños fueron en cautividad delante del enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 6, 'Fuése de la hija de Sión toda su hermosura: Sus príncipes fueron como ciervos que no hallan pasto, Y anduvieron sin fortaleza delante del perseguidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 7, 'Jerusalem, cuando cayó su pueblo en mano del enemigo y no hubo quien le ayudase, Se acordó de los días de su aflicción, y de sus rebeliones, Y de todas sus cosas deseables que tuvo desde los tiempos antiguos: Miráronla los enemigos, y escarnecieron de sus sábados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 8, 'Pecado cometió Jerusalem; por lo cual ella ha sido removida: Todos los que la honraban la han menospreciado, porque vieron su vergüenza; Y ella suspira, y se vuelve atrás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 9, 'Sus inmundicias en sus faldas; no se acordó de su postrimería: Por tanto ella ha descendido maravillosamente, no tiene consolador. Mira, oh Jehová, mi aflicción, porque el enemigo se ha engrandecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 10, 'Extendió su mano el enemigo á todas sus cosas preciosas; Y ella ha visto entrar en su santuario las gentes, De las cuales mandaste que no entrasen en tu congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 11, 'Todo su pueblo buscó su pan suspirando; Dieron por la comida todas sus cosas preciosas, para entretener la vida. Mira, oh Jehová, y ve que estoy abatida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 12, '¿No os conmueve á cuantos pasáis por el camino? Mirad, y ved si hay dolor como mi dolor que me ha venido; Porque Jehová me ha angustiado en el día de la ira de su furor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 13, 'Desde lo alto envió fuego en mis huesos, el cual se enseñoreó: Ha extendido red a mis pies, tornóme atrás, Púsome asolada, y que siempre tenga dolor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 14, 'El yugo de mis rebeliones está ligado por su mano, Enlazadas han subido sobre mi cerviz: ha hecho caer mis fuerzas: Hame entregado el Señor en sus manos, contra quienes no podré levantarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 15, 'El Señor ha hollado todos mis fuertes en medio de mí; Llamó contra mí compañía para quebrantar mis mancebos: Como lagar ha pisado el Señor á la virgen hija de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 16, 'Por esta causa yo lloro; mis ojos, mis ojos fluyen aguas; Porque se alejó de mí consolador que dé reposo á mi alma: Mis hijos son destruídos, porque el enemigo prevaleció.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 17, 'Sión extendió sus manos, no tiene quien la consuele; Jehová dió mandamiento contra Jacob, que sus enemigos lo cercasen: Jerusalem fué en abominación entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 18, 'Jehová es justo; que yo contra su boca me rebelé. Oid ahora, pueblos todos, y ved mi dolor: Mis vírgenes y mis mancebos fueron en cautiverio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 19, 'Dí voces á mis amadores, mas ellos me han engañado; Mis sacerdotes y mis ancianos en la ciudad perecieron, Buscando comida para sí con que entretener su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 20, 'Mira, oh Jehová, que estoy atribulada: mis entrañas rugen, Mi corazón está trastornado en medio de mí; porque me rebelé desaforadamente: De fuera deshijó el cuchillo, de dentro parece una muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 21, 'Oyeron que gemía, y no hay consolador para mí: Todos mis enemigos han oído mi mal, se han holgado de que tú lo hiciste. Harás venir el día que has anunciado, y serán como yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 1, 22, 'Entre delante de ti toda su maldad, Y haz con ellos como hiciste conmigo por todas mis rebeliones: Porque muchos son mis suspiros, y mi corazón está doloroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 1, '¡COMO oscureció el Señor en su furor a la hija de Sión! Derribó del cielo á la tierra la hermosura de Israel, Y no se acordó del estrado de sus pies en el día de su ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 2, 'Destruyó el Señor, y no perdonó; Destruyó en su furor todas las tiendas de Jacob: Echó por tierra las fortalezas de la hija de Judá, Deslustró el reino y sus príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 3, 'Cortó con el furor de su ira todo el cuerno de Israel; Hizo volver atrás su diestra delante del enemigo; Y encendióse en Jacob como llama de fuego que ha devorado en contorno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 4, 'Entesó su arco como enemigo, afirmó su mano derecha como adversario, Y mató toda cosa hermosa á la vista: En la tienda de la hija de Sión derramó como fuego su enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 5, 'Fué el Señor como enemigo, destruyó a Israel; Destruyó todos sus palacios, disipó sus fortalezas: Y multiplicó en la hija de Judá la tristeza y lamento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 6, 'Y quitó su tienda como de un huerto, Destruyó el lugar de su congregación: Jehová ha hecho olvidar en Sión solemnidades y sábados, Y ha desechado en el furor de su ira rey y sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 7, 'Desechó el Señor su altar, menospreció su santuario, Ha entregado en mano del enemigo los muros de sus palacios: Dieron grita en la casa de Jehová como en día de fiesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 8, 'Jehová determinó destruir el muro de la hija de Sión; Extendió el cordel, no retrajo su mano de destruir: Hizo pues, se lamentara el antemuro y el muro; fueron destruídos juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 9, 'Sus puertas fueron echadas por tierra, destruyó y quebrantó sus cerrojos: Su rey y sus príncipes están entre las gentes donde no hay ley; Sus profetas tampoco hallaron visión de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 10, 'Sentáronse en tierra, callaron los ancianos de la hija de Sión; Echaron polvo sobre sus cabezas, ciñéronse de saco; Las vírgenes de Jerusalem bajaron sus cabezas a tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 11, 'Mis ojos desfallecieron de lágrimas, rugieron mis entrañas, Mi hígado se derramó por tierra por el quebrantamiento de la hija de mi pueblo, Cuando desfallecía el niño y el que mamaba, en las plazas de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 12, 'Decían a sus madres: ¿Dónde está el trigo y el vino? Desfallecían como heridos en las calles de la ciudad, Derramando sus almas en el regazo de sus madres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 13, '¿Qué testigo te traeré, ó á quién te haré semejante, hija de Jerusalem? ¿A quién te compararé para consolarte, oh virgen hija de Sión? Porque grande es tu quebrantamiento como la mar: ¿quién te medicinará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 14, 'Tus profetas vieron para ti vanidad y locura; Y no descubrieron tu pecado para estorbar tu cautiverio, Sino que te predicaron vanas profecías y extravíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 15, 'Todos los que pasaban por el camino, batieron las manos sobre ti; Silbaron, y movieron sus cabezas sobre la hija de Jerusalem, diciendo: ¿Es ésta la ciudad que decían de perfecta hermosura, el gozo de toda la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 16, 'Todos tus enemigos abrieron sobre ti su boca, Silbaron, y rechinaron los dientes; dijeron: Devoremos: Cierto éste es el día que esperábamos; lo hemos hallado, vímoslo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 17, 'Jehová ha hecho lo que tenía determinado, Ha cumplido su palabra que él había mandado desde tiempo antiguo: Destruyó, y no perdonó; Y alegró sobre ti al enemigo, Y enalteció el cuerno de tus adversarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 18, 'El corazón de ellos clamaba al Señor: Oh muro de la hija de Sión, echa lágrimas como un arroyo día y noche; No descanses, ni cesen las niñas de tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 19, 'Levántate, da voces en la noche, en el principio de las velas; Derrama como agua tu corazón ante la presencia del Señor; Alza tus manos á él por la vida de tus pequeñitos, Que desfallecen de hambre en las entradas de todas las calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 20, 'Mira, oh Jehová, y considera á quién has hecho así. ¿Han de comer las mujeres su fruto, los pequeñitos de sus crías? ¿Han de ser muertos en el santuario del Señor el sacerdote y el profeta?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 21, 'Niños y viejos yacían por tierra en las calles; Mis vírgenes y mis mancebos cayeron a cuchillo: Mataste en el día de tu furor, degollaste, no perdonaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 2, 22, 'Has llamado, como a día de solemnidad, mis temores de todas partes; Y en el día del furor de Jehová no hubo quien escapase ni quedase vivo: Los que crié y mantuve, mi enemigo los acabó');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 1, 'YO soy el hombre que ha visto aflicción en la vara de su enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 2, 'Guióme y llevóme en tinieblas, mas no en luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 3, 'Ciertamente contra mí volvió y revolvió su mano todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 4, 'Hizo envejecer mi carne y mi piel; quebrantó mis huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 5, 'Edificó contra mí, y cercóme de tósigo y de trabajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 6, 'Asentóme en oscuridades, como los ya muertos de mucho tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 7, 'Cercóme por todos lados, y no puedo salir; agravó mis grillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 8, 'Aun cuando clamé y dí voces, cerro los oídos a mi oración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 9, 'Cercó mis caminos con piedra tajada, torció mis senderos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 10, 'Como oso que acecha fué para mí, como león en escondrijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 11, 'Torció mis caminos, y depedazóme; tornóme asolado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 12, 'Su arco entesó, y púsome como blanco a la saeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 13, 'Hizo entrar en mis riñones las saetas de su aljaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 14, 'Fuí escarnio á todo mi pueblo, canción de ellos todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 15, 'Hartóme de amarguras, embriagóme de ajenjos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 16, 'Quebróme los dientes con cascajo, cubrióme de ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 17, 'Y mi alma se alejó de la paz, olvidéme del bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 18, 'Y dije: Pereció mi fortaleza, y mi esperanza de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 19, 'Acuérdate de mi aflicción y de mi abatimiento, del ajenjo y de la hiel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 20, 'Tendrálo aún en memoria mi alma, porque en mí está humillada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 21, 'Esto reduciré á mi corazón, por lo cual esperaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 22, 'Es por la misericordia de Jehová que no somos consumidos, porque nunca decayeron sus misericordias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 23, 'Nuevas son cada mañana; grande es tu fidelidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 24, 'Mi parte es Jehová, dijo mi alma; por tanto en él esperaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 25, 'Bueno es Jehová á los que en él esperan, al alma que le buscare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 26, 'Bueno es esperar callando en la salud de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 27, 'Bueno es al hombre, si llevare el yugo desde su mocedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 28, 'Sentaráse solo, y callará, porque lo llevó sobre sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 29, 'Pondrá su boca en el polvo, por si quizá hay esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 30, 'Dará la mejilla al que le hiriere; hartaráse de afrenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 31, 'Porque el Señor no desechará para siempre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 32, 'Antes si afligiere, también se compadecerá según la multitud de sus misericordias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 33, 'Porque no aflige ni congoja de su corazón á los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 34, 'Desmenuzar bajo de sus pies todos los encarcelados de la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 35, 'Hacer apartar el derecho del hombre ante la presencia del Altísimo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 36, 'Trastornar al hombre en su causa, el Señor no lo sabe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 37, '¿Quién será aquel que diga, que vino algo que el Señor no mandó?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 38, '¿De la boca del Altísimo no saldrá malo y bueno?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 39, '¿Por qué murmura el hombre viviente, el hombre en su pecado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 40, 'Escudriñemos nuestros caminos, y busquemos, y volvámonos a Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 41, 'Levantemos nuestros corazones con las manos a Dios en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 42, 'Nosotros nos hemos rebelado, y fuimos desleales; tú no perdonaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 43, 'Desplegaste la ira, y nos perseguiste; mataste, no perdonaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 44, 'Te cubriste de nube, porque no pasase la oración nuestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 45, 'Raedura y abominación nos tornaste en medio de los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 46, 'Todos nuestros enemigos abrieron sobre nosotros su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 47, 'Temor y lazo fué para nosotros, asolamiento y quebrantamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 48, 'Ríos de aguas echan mis ojos, por el quebrantamiento de la hija de mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 49, 'Mis ojos destilan, y no cesan, porque no hay alivio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 50, 'Hasta que Jehová mire y vea desde los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 51, 'Mis ojos contristaron mi alma, por todas las hijas de mi ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 52, 'Mis enemigos me dieron caza como á ave, sin por qué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 53, 'Ataron mi vida en mazmorra, pusieron piedra sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 54, 'Aguas de avenida vinieron sobre mi cabeza; yo dije: Muerto soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 55, 'Invoqué tu nombre, oh Jehová, desde la cárcel profunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 56, 'Oiste mi voz; no escondas tu oído á mi clamor, para mi respiro');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 57, 'Acercástete el día que te invoqué: dijiste: No temas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 58, 'Abogaste, Señor, la causa de mi alma; redimiste mi vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 59, 'Tú has visto, oh Jehová, mi agravio; defiende mi causa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 60, 'Tú has visto toda su venganza; todos sus pensamientos contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 61, 'Tú has oído el oprobio de ellos, oh Jehová, todas sus maquinaciones contra mí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 62, 'Los dichos de los que contra mí se levantaron, y su designio contra mí todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 63, 'Su sentarse, y su levantarse mira: yo soy su canción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 64, 'Dales el pago, oh Jehová, según la obra de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 65, 'Dales ansia de corazón, tu maldición á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 3, 66, 'Persíguelos en tu furor, y quebrántalos de debajo de los cielos, oh Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 1, '¡COMO se ha oscurecido el oro! ¡Cómo el buen oro se ha demudado! Las piedras del santuario están esparcidas por las encrucijadas de todas las calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 2, 'Los hijos de Sión, preciados y estimados más que el oro puro, ¡Cómo son tenidos por vasos de barro, obra de manos de alfarero!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 3, 'Aun los monstruos marinos sacan la teta, dan de mamar a sus chiquitos: La hija de mi pueblo es cruel, como los avestruces en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 4, 'La lengua del niño de teta, de sed se pegó á su paladar: Los chiquitos pidieron pan, y no hubo quien se lo partiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 5, 'Los que comían delicadamente, asolados fueron en las calles; Los que se criaron en carmesí, abrazaron los estercoleros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 6, 'Y aumentóse la iniquidad de la hija de mi pueblo más que el pecado de Sodoma, Que fué trastornada en un momento, y no asentaron sobre ella compañías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 7, 'Sus Nazareos fueron blancos más que la nieve, más lustrosos que la leche. Su compostura más rubicunda que los rubíes, más bellos que el zafiro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 8, 'Oscura más que la negrura es la forma de ellos; no los conocen por las calles: Su piel está pegada á sus huesos, seca como un palo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 9, 'Más dichosos fueron los muertos á cuchillo que los muertos del hambre; Porque éstos murieron poco á poco por falta de los frutos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 10, 'Las manos de las mujeres piadosas cocieron á sus hijos; Fuéronles comida en el quebrantamiento de la hija de mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 11, 'Cumplió Jehová su enojo, derramó el ardor de su ira; Y encendió fuego en Sión, que consumió sus fundamentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 12, 'Nunca los reyes de la tierra, ni todos los que habitan en el mundo, Creyeron que el enemigo y el adversario entrara por las puertas de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 13, 'Es por los pecados de sus profetas, por las maldades de sus sacerdotes, Que derramaron en medio de ella la sangre de los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 14, 'Titubearon como ciegos en las calles, fueron contaminados en sangre, De modo que no pudiesen tocar á sus vestiduras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 15, 'Apartaos ¡inmundos!, les gritaban, Apartaos, apartaos, no toquéis. Cuando huyeron y fueron dispersos, dijeron entre las gentes: Nunca más morarán aquí');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 16, 'La ira de Jehová los apartó, no los mirará más: No respetaron la faz de los sacerdotes, ni tuvieron compasión de los viejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 17, 'Aun nos han desfallecido nuestros ojos tras nuestro vano socorro: En nuestra esperanza aguardamos gente que no puede salvar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 18, 'Cazaron nuestro pasos, que no anduviésemos por nuestras calles: Acercóse nuestro fin, cumpliéronse nuestros días; porque nuestro fin vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 19, 'Ligeros fueron nuestros perseguidores más que las águilas del cielo: Sobre los montes nos persiguieron, en el desierto nos pusieron emboscada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 20, 'El resuello de nuestras narices, el ungido de Jehová, De quien habíamos dicho: A su sombra tendremos vida entre las gentes: fué preso en sus hoyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 21, 'Gózate y alégrate, hija de Edom, la que habitas en tierra de Hus: Aun hasta ti pasará el cáliz; embriagarte has, y vomitarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 4, 22, 'Cumplido es tu castigo, oh hija de Sión: Nunca más te hará trasportar. Visitará tu iniquidad, oh hija de Edom; Descubrirá tus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 1, 'ACUÉRDATE, oh Jehová, de lo que nos ha sucedido: Ve y mira nuestro oprobio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 2, 'Nuestra heredad se ha vuelto á extraños, Nuestras casas á forasteros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 3, 'Huérfanos somos sin padre, Nuestras madres como viudas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 4, 'Nuestra agua bebemos por dinero; Nuestra leña por precio compramos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 5, 'Persecución padecemos sobre nuestra cerviz: Nos cansamos, y no hay para nosotros reposo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 6, 'Al Egipcio y al Asirio dimos la mano, para saciarnos de pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 7, 'Nuestros padres pecaron, y son muertos; Y nosotros llevamos sus castigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 8, 'Siervos se enseñorearon de nosotros; No hubo quien de su mano nos librase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 9, 'Con peligro de nuestras vidas traíamos nuestro pan Delante del cuchillo del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 10, 'Nuestra piel se ennegreció como un horno A causa del ardor del hambre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 11, 'Violaron á las mujeres en Sión, A las vírgenes en las ciudades de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 12, 'A los príncipes colgaron por su mano; No respetaron el rostro de los viejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 13, 'Llevaron los mozos á moler, Y los muchachos desfallecieron en la leña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 14, 'Los ancianos cesaron de la puerta, Los mancebos de sus canciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 15, 'Cesó el gozo de nuestro corazón; Nuestro corro se tornó en luto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 16, 'Cayó la corona de nuestra cabeza: ¡Ay ahora de nosotros! porque pecamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 17, 'Por esto fué entristecido nuestro corazón, Por esto se entenebrecieron nuestro ojos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 18, 'Por el monte de Sión que está asolado; Zorras andan en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 19, 'Mas tú, Jehová, permanecerás para siempre: Tu trono de generación en generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 20, '¿Por qué te olvidarás para siempre de nosotros, Y nos dejarás por largos días?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 21, 'Vuélvenos, oh Jehová, á ti, y nos volveremos: Renueva nuestros días como al principio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LAM', 'Lamentaciones', 5, 22, 'Porque repeliendo nos has desechado; Te has airado contra nosotros en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 1, 'Y FUÉ que á los treinta años, en el mes cuarto, á cinco del mes, estando yo en medio de los trasportados junto al río de Chebar, los cielos se abrieron, y vi visiones de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 2, 'A los cinco del mes, que fué en el quinto año de la transmigración del rey Joachîn,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 3, 'Fué palabra de Jehová á Ezequiel sacerdote, hijo de Buzi, en la tierra de los Caldeos, junto al río de Chebar; fué allí sobre él la mano de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 4, 'Y miré, y he aquí un viento tempestuoso venía del aquilón, una gran nube, con un fuego envolvente, y en derredor suyo un resplandor, y en medio del fuego una cosa que parecía como de ámbar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 5, 'Y en medio de ella, figura de cuatro animales. Y este era su parecer; había en ellos semejanza de hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 6, 'Y cada uno tenía cuatro rostros, y cuatro alas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 7, 'Y los pies de ellos eran derechos, y la planta de sus pies como la planta de pie de becerro; y centelleaban á manera de bronce muy bruñido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 8, 'Y debajo de sus alas, á sus cuatro lados, tenían manos de hombre; y sus rostros y sus alas por los cuatro lados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 9, 'Con las alas se juntaban el uno al otro. No se volvían cuando andaban; cada uno caminaba en derecho de su rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 10, 'Y la figura de sus rostros era rostro de hombre; y rostro de león á la parte derecha en los cuatro; y á la izquierda rostro de buey en los cuatro; asimismo había en los cuatro rostro de águila.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 11, 'Tales eran sus rostros; y tenían sus alas extendidas por encima, cada uno dos, las cuales se juntaban; y las otras dos cubrían sus cuerpos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 12, 'Y cada uno caminaba en derecho de su rostro: hacia donde el espíritu era que anduviesen, andaban; cuando andaban, no se volvían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 13, 'Cuanto á la semejanza de los animales, su parecer era como de carbones de fuego encendidos, como parecer de hachones encendidos: discurría entre los animales; y el fuego resplandecía, y del fuego salían relámpagos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 14, 'Y los animales corrían y tornaban á semejanza de relámpagos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 15, 'Y estando yo mirando los animales, he aquí una rueda en la tierra junto á los animales, á sus cuatro caras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 16, 'Y el parecer de las ruedas y su obra semejábase al color del topacio. Y las cuatro tenían una misma semejanza: su apariencia y su obra como rueda en medio de rueda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 17, 'Cuando andaban, se movían sobre sus cuatro costados: no se volvían cuando andaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 18, 'Y sus cercos eran altos y espantosos, y llenos de ojos alrededor en las cuatro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 19, 'Y cuando los animales andaban, las ruedas andaban junto á ellos: y cuando los animales se levantaban de la tierra, las ruedas se levantaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 20, 'Hacia donde el espíritu era que anduviesen, andaban; hacia donde era el espíritu que anduviesen, las ruedas también se levantaban tras ellos; porque el espíritu de los animales estaba en las ruedas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 21, 'Cuando ellos andaban, andaban ellas; y cuando ellos se paraban, se paraban ellas; asimismo cuando se levantaban de la tierra, las ruedas se levantaban tras ellos; porque el espíritu de los animales estaba en las ruedas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 22, 'Y sobre las cabezas de cada animal aparecía expansión á manera de cristal maravilloso, extendido encima sobre sus cabezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 23, 'Y debajo de la expansión estaban las alas de ellos derechas la una á la otra; á cada uno dos, y otras dos con que se cubrían sus cuerpos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 24, 'Y oí el sonido de sus alas cuando andaban, como sonido de muchas aguas, como la voz del Omnipotente, como ruido de muchedumbre, como la voz de un ejército. Cuando se paraban, aflojaban sus alas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 25, 'Y cuando se paraban y aflojaban sus alas, oíase voz de arriba de la expansión que había sobre sus cabezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 26, 'Y sobre la expansión que había sobre sus cabezas, veíase la figura de un trono y que parecía de piedra de zafiro; y sobre la figura del trono había una semejanza que parecía de hombre sentado sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 27, 'Y vi apariencia como de ámbar, como apariencia de fuego dentro de ella en contorno, por el aspecto de sus lomos para arriba; y desde sus lomos para abajo, vi que parecía como fuego, y que tenía resplandor alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 1, 28, 'Cual parece el arco del cielo que está en las nubes el día que llueve, así era el parecer del resplandor alrededor. Esta fué la visión de la semejanza de la gloria de Jehová. Y luego que yo la hube visto, caí sobre mi rostro, y oí voz de uno que hablaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 1, 'Y DIJOME: Hijo del hombre, está sobre tus pies, y hablaré contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 2, 'Y entró espíritu en mí luego que me habló, y afirmóme sobre mis pies, y oía al que me hablaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 3, 'Y díjome: Hijo del hombre, yo te envío á los hijos de Israel, á gentes rebeldes que se rebelaron contra mí: ellos y sus padres se han rebelado contra mí hasta este mismo día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 4, 'Yo pues te envío á hijos de duro rostro y de empedernido corazón; y les dirás: Así ha dicho el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 5, 'Acaso ellos escuchen; y si no escucharen, (porque son una rebelde familia,) siempre conocerán que hubo profeta entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 6, 'Y tú, hijo del hombre, no temas de ellos, ni tengas miedo de sus palabras, aunque te hallas entre zarzas y espinas, y tú moras con escorpiones: no tengas miedo de sus palabras, ni temas delante de ellos, porque son casa rebelde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 7, 'Les hablarás pues mis palabras, escuchen ó dejen de escuchar; porque son muy rebeldes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 8, 'Mas tú, hijo del hombre, oye lo que yo te hablo; no seas tú rebelde como la casa rebelde: abre tu boca, y come lo que yo te doy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 9, 'Y miré, y he aquí una mano me fué enviada, y en ella había un rollo de libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 2, 10, 'Y extendiólo delante de mí, y estaba escrito delante y detrás: y había escritas en él endechas, y lamentación, y ayes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 1, 'Y DIJOME: Hijo del hombre, come lo que hallares; come este rollo, y ve y habla á la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 2, 'Y abrí mi boca, é hízome comer aquel rollo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 3, 'Y díjome: Hijo del hombre, haz á tu vientre que coma, é hinche tus entrañas de este rollo que yo te doy. Y comílo, y fué en mi boca dulce como miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 4, 'Díjome luego: Hijo del hombre, ve y entra á la casa de Israel, y habla á ellos con mis palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 5, 'Porque no eres enviado á pueblo de habla profunda ni de lengua difícil, sino á la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 6, 'No á muchos pueblos de profunda habla ni de lengua difícil, cuyas palabras no entiendas; y si á ellos te enviara, ellos te oyeran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 7, 'Mas la casa de Israel no te querrán oir, porque no me quieren oír á mí: porque toda la casa de Israel son tiesos de frente, y duros de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 8, 'He aquí he hecho yo tu rostro fuerte contra los rostros de ellos, y tu frente fuerte contra su frente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 9, 'Como diamante, más fuerte que pedernal he hecho tu frente; no los temas, ni tengas miedo delante de ellos, porque es casa rebelde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 10, 'Y díjome: Hijo del hombre, toma en tu corazón todas mis palabras que yo te hablaré, y oye con tus oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 11, 'Y ve, y entra á los trasportados, á los hijos de tu pueblo, y les hablarás y les dirás: Así ha dicho el Señor Jehová; escuchen, ó dejen de escuchar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 12, 'Y levantóme el espíritu, y oí detrás de mí una voz de grande estruendo, que decía: Bendita sea la gloria de Jehová desde su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 13, 'Oí también el sonido de las alas de los animales que se juntaban la una con la otra, y el sonido de las ruedas delante de ellos, y sonido de grande estruendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 14, 'Levantóme pues el espíritu, y me tomó; y fuí en amargura, en la indignación de mi espíritu: mas la mano de Jehová era fuerte sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 15, 'Y vine á los trasportados en Telabib, que moraban junto al río de Chebar, y asenté donde ellos estaban asentados, y allí permanecí siete días atónito entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 16, 'Y aconteció que al cabo de los siete días fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 17, 'Hijo del hombre, yo te he puesto por atalaya á la casa de Israel: oirás pues tú la palabra de mi boca, y amonestarlos has de mi parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 18, 'Cuando yo dijere al impío: De cierto morirás: y tú no le amonestares, ni le hablares, para que el impío sea apercibido de su mal camino, á fin de que viva, el impío morirá por su maldad, mas su sangre demandaré de tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 19, 'Y si tú amonestares al impío, y él no se convirtiere de su impiedad, y de su mal camino, él morirá por su maldad, y tú habrás librado tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 20, 'Y cuando el justo se apartare de su justicia, é hiciere maldad, y pusiere yo tropiezo delante de él, él morirá, porque tú no le amonestaste; en su pecado morirá, y sus justicias que había hecho no vendrán en memoria; mas su sangre demandaré de tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 21, 'Y si al justo amonestares para que el justo no peque, y no pecare, de cierto vivirá, porque fué amonestado; y tú habrás librado tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 22, 'Y fué allí la mano de Jehová sobre mí, y díjome: Levántate, y sal al campo, y allí hablaré contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 23, 'Y levantéme, y salí al campo: y he aquí que allí estaba la gloria de Jehová, como la gloria que había visto junto al río de Chebar: y caí sobre mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 24, 'Entonces entró espíritu en mí, y afirmóme sobre mis pies, y hablóme, y díjome: Entra, y enciérrate dentro de tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 25, 'Y tú, oh hijo del hombre, he aquí que pondrán sobre ti cuerdas, y con ellas te ligarán, y no saldrás entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 26, 'Y haré se pegue tu lengua á tu paladar, y estarás mudo, y no serás á ellos varón que reprende: porque son casa rebelde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 3, 27, 'Mas cuando yo te hubiere hablado, abriré tu boca, y les dirás: Así ha dicho el Señor Jehová: El que oye, oiga; y el que cesa, cese: porque casa rebelde son.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 1, 'Y TU, hijo del hombre, tómate un adobe, y ponlo delante de tí, y diseña sobre él la ciudad de Jerusalem:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 2, 'Y pondrás contra ella cerco, y edificarás contra ella fortaleza, y sacarás contra ella baluarte, y asentarás delante de ella campo, y pondrás contra ella arietes alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 3, 'Tómate también una plancha de hierro, y ponla en lugar de muro de hierro entre ti y la ciudad: afirmarás luego tu rostro contra ella, y será en lugar de cerco, y la sitiarás. Es señal á la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 4, 'Y tú dormirás sobre tu lado izquierdo, y pondrás sobre él la maldad de la casa de Israel: el número de los días que dormirás sobre él, llevarás sobre ti la maldad de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 5, 'Yo te he dado los años de su maldad por el número de los días, trescientos y noventa días: y llevarás la maldad de la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 6, 'Y cumplidos estos, dormirás sobre tu lado derecho segunda vez, y llevarás la maldad de la casa de Judá cuarenta días: día por año, día por año te lo he dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 7, 'Y al cerco de Jerusalem afirmarás tu rostro, y descubierto tu brazo, profetizarás contra ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 8, 'Y he aquí he puesto sobre ti cuerdas, y no te tornarás del un tu lado al otro lado, hasta que hayas cumplido los días de tu cerco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 9, 'Y tú toma para ti trigo, y cebada, y habas, y lentejas, y mijo, y avena, y ponlo en una vasija, y hazte pan de ello el número de los días que durmieres sobre tu lado: trescientos y noventa días comerás de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 10, 'Y la comida que has de comer será por peso de veinte siclos al día: de tiempo á tiempo lo comerás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 11, 'Y beberás el agua por medida, la sexta parte de un hin: de tiempo á tiempo beberás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 12, 'Y comerás pan de cebada cocido debajo de la ceniza; y lo cocerás á vista de ellos con los estiércoles que salen del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 13, 'Y dijo Jehová: Así comerán los hijos de Israel su pan inmundo, entre las gentes á donde los lanzaré yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 14, 'Y dije: ¡Ah Señor Jehová! he aquí que mi alma no es inmunda, ni nunca desde mi mocedad hasta este tiempo comí cosa mortecina ni despedazada, ni nunca en mi boca entró carne inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 15, 'Y respondióme: He aquí te doy estiércoles de bueyes en lugar de los estiércoles de hombre, y dispondrás tu pan con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 16, 'Díjome luego: Hijo del hombre, he aquí quebrantaré el sostén del pan en Jerusalem, y comerán el pan por peso, y con angustia; y beberán el agua por medida, y con espanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 4, 17, 'Porque les faltará el pan y el agua, y se espantarán los unos con los otros, y se consumirán por su maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 1, 'Y TU, hijo del hombre, tómate un cuchillo agudo, una navaja de barbero toma, y hazla pasar sobre tu cabeza y tu barba: tómate después un peso de balanza, y reparte los pelos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 2, 'Una tercera parte quemarás con fuego en medio de la ciudad, cuando se cumplieren los días del cerco, y tomarás una tercera parte, y herirás con cuchillo alrededor de ella; y una tercera parte esparcirás al viento, y yo desenvainaré espada en pos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 3, 'Tomarás también de allí unos pocos por cuenta, y los atarás en el canto de tu ropa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 4, 'Y tomarás otra vez de ellos, y los echarás en mitad del fuego, y en el fuego los quemarás: de allí saldrá el fuego en toda la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 5, 'Así ha dicho el Señor Jehová: Esta es Jerusalem: púsela en medio de las gentes y de las tierras alrededor de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 6, 'Y ella mudó mis juicios y mis ordenanzas en impiedad más que las gentes, y más que las tierras que están alrededor de ella; porque desecharon mis juicios y mis mandamientos, y no anduvieron en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 7, 'Por tanto, así ha dicho Jehová: ¿Por haberos multiplicado más que á las gentes que están alrededor de vosotros, no habéis andado en mis mandamientos, ni habéis guardado mis leyes? Ni aun según las leyes de las gentes que están alrededor de vosotros habéis hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 8, 'Así pues ha dicho el Señor Jehová: He aquí yo contra ti; si, yo, y haré juicios en medio de ti á los ojos de las naciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 9, 'Y haré en ti lo que nunca hice, ni jamás haré cosa semejante, á causa de todas tus abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 10, 'Por eso los padres comerán á los hijos en medio de ti, y los hijos comerán á sus padres; y haré en ti juicios, y esparciré á todos vientos todo tu residuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 11, 'Por tanto, vivo yo, dice el Señor Jehová, ciertamente por haber violado mi santuario con todas tus abominaciones, te quebrantaré yo también: mi ojo no perdonará, ni tampoco tendré yo misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 12, 'Una tercera parte de ti morirá de pestilencia, y de hambre será consumida en medio de ti; y una tercera parte caerá á cuchillo alrededor de ti; y una tercera parte esparciré á todos los vientos, y tras ellos desenvainaré espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 13, 'Y cumpliráse mi furor, y haré que repose en ellos mi enojo, y tomaré satisfacción: y sabrán que yo Jehová he hablado en mi celo, cuando habré cumplido en ellos mi enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 14, 'Y te tornaré en desierto y en oprobio entre las gentes que están alrededor de ti, á los ojos de todo transeunte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 15, 'Y serás oprobio, y escarnio, y escarmiento, y espanto á las gentes que están alrededor de ti, cuando yo hiciere en ti juicios en furor é indignación, y en reprensiones de ira. Yo Jehová he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 16, 'Cuando arrojare yo sobre ellos las perniciosas saetas del hambre, que serán para destrucción, las cuales enviaré para destruiros, entonces aumentaré el hambre sobre vosotros, y quebrantaré entre vosotros el arrimo del pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 5, 17, 'Enviaré pues sobre vosotros hambre, y malas bestias que te destruyan; y pestilencia y sangre pasarán por ti; y meteré sobre ti cuchillo. Yo Jehová he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 2, 'Hijo del hombre, pon tu rostro hacia los montes de Israel, y profetiza contra ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 3, 'Y dirás: Montes de Israel, oid palabra del Señor Jehová: Así ha dicho el Señor Jehová á los montes y dicho el Señor Jehová á los montes y á los collados, á los arroyos y á los valles: He aquí que yo, yo haré venir sobre vosotros cuchillo, y destruiré vuestros altos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 4, 'Y vuestros altares serán asolados, y vuestras imágenes del sol serán quebradas: y haré que caigan vuestros muertos delante de vuestros ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 5, 'Y pondré los cuerpos muertos de los hijos de Israel delante de sus ídolos; y vuestros huesos esparciré en derredor de vuestros altares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 6, 'En todas vuestras habitaciones las ciudades serán desiertas, y los altos serán asolados, para que sean asolados y se hagan desiertos vuestros altares; y quebrados serán vuestros ídolos, y cesarán; y vuestras imágenes del sol serán destruídas, y vuestras obras serán desechas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 7, 'Y los muertos caerán en medio de vosotros; y sabréis que soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 8, 'Mas dejaré que haya de vosotros quien escape del cuchillo entre las gentes, cuando fuereis esparcidos por las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 9, 'Y los que de vosotros escaparen, se acordarán de mí entre las gentes entre las cuales serán cautivos: porque yo me quebranté á causa de su corazón fornicario, que se apartó de mí, y á causa de sus ojos, que fornicaron tras sus ídolos: y se avergonzarán de sí mismos, á causa de los males que hicieron en todas sus abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 10, 'Y sabrán que yo soy Jehová: no en vano dije que les había de hacer este mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 11, 'Así ha dicho el Señor Jehová: Hiere con tu mano, y huella con tu pie, y di: ¡Ay de los males de la casa de Israel por todas las abominaciones! porque con cuchillo, y con hambre, y con pestilencia caerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 12, 'El que estuviere lejos, morirá de pestilencia; y el que estuviere cerca caerá á cuchillo; y el que quedare, y fuere cercado, morirá de hambre: así cumpliré en ellos mi enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 13, 'Y sabréis que yo soy Jehová, cuando sus muertos estarán en medio de sus ídolos, en derredor de sus altares, en todo collado alto, y en todas las cumbres de los montes, y debajo de todo árbol sombrío, y debajo de toda encina espesa, lugares donde dieron olor suave á todos sus ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 6, 14, 'Y extenderé mi mano sobre ellos, y tornaré la tierra asolada y desierta, más que el desierto hacia Diblath, en todas sus habitaciones: y conocerán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 2, 'Y tú, hijo del hombre, así ha dicho el Señor Jehová á la tierra de Israel: El fin, el fin viene sobre los cuatro cantones de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 3, 'Ahora será el fin sobre ti, y enviaré sobre ti mi furor, y te juzgaré según tus caminos; y pondré sobre ti todas tus abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 4, 'Y mi ojo no te perdonará, ni tendré misericordia; antes pondré sobre ti tus caminos, y en medio de ti estarán tus abominaciones; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 5, 'Así ha dicho el Señor Jehová: Un mal, he aquí que viene un mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 6, 'Viene el fin, el fin viene: hase despertado contra ti; he aquí que viene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 7, 'La mañana viene para ti, oh morador de la tierra; el tiempo viene, cercano está el día; día de alboroto, y no de alegría sobre los montes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 8, 'Ahora presto derramaré mi ira sobre ti, y cumpliré en ti mi furor, y te juzgaré según tus caminos; y pondré sobre ti tus abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 9, 'Y mi ojo no perdonará, ni tendré misericordia: según tus caminos pondré sobre ti, y en medio de ti serán tus abominaciones; y sabréis que yo Jehová soy el que hiero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 10, 'He aquí el día, he aquí que viene: ha salido la mañana; florecido ha la vara, ha reverdecido la soberbia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 11, 'La violencia se ha levantado en vara de impiedad; ninguno quedará de ellos, ni de su multitud, ni uno de los suyos; ni habrá quien de ellos se lamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 12, 'El tiempo es venido, acercóse el día: el que compra, no se huelgue, y el que vende, no llore: porque la ira está sobre toda su multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 13, 'Porque el que vende no tornará á lo vendido, aunque queden vivos: porque la visión sobre toda su multitud no será cancelada; y ninguno podrá, á causa de su iniquidad, amparar su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 14, 'Tocarán trompeta, y aparejarán todas las cosas, y no habrá quien vaya á la batalla: porque mi ira está sobre toda su multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 15, 'De fuera cuchillo, de dentro pestilencia y hambre: el que estuviere en el campo morirá á cuchillo; y al que estuviere en la ciudad, consumirálo hambre y pestilencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 16, 'Y los que escaparen de ellos, huirán y estarán sobre los montes como palomas de los valles, gimiendo todos cada uno por su iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 17, 'Todas manos serán descoyuntadas, y declinarán como aguas todas rodillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 18, 'Ceñirse han también de sacos, y cubrirálos temblor; y en todo rostro habrá confusión, y en todas sus cabezas peladura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 19, 'Arrojarán su plata por las calles, y su oro será desechado; su plata ni su oro, no podrá librarlos en el día del furor de Jehová; no saciarán su alma, ni henchirán sus entrañas: porque ha sido tropiezo para su maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 20, 'Por cuanto la gloria de su ornamento pusieron en soberbia, é hicieron en ella imágenes de sus abominaciones, de sus estatuas: por eso se la torné á ellos en alejamiento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 21, 'Y en mano de extraños la entregué para ser saqueada, y en despojo á los impíos de la tierra, y la contaminarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 22, 'Y apartaré de ellos mi rostro, y violarán mi lugar secreto; pues entrarán en él destruidores, y le profanarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 23, 'Haz una cadena: porque la tierra está llena de juicios de sangres, y la ciudad está llena de violencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 24, 'Traeré por tanto los más malos de las naciones, los cuales poseerán sus casas; y haré cesar la soberbia de los poderosos, y sus santuarios serán profanados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 25, 'Destrucción viene; y buscarán la paz, y no la habrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 26, 'Quebrantamiento vendrá sobre quebrantamiento, y rumor será sobre rumor; y buscarán respuesta del profeta, mas la ley perecerá del sacerdote, y el consejo de los ancianos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 7, 27, 'El rey se enlutará, y el príncipe se vestirá de asolamiento, y las manos del pueblo de la tierra serán conturbadas: según su camino haré con ellos, y con los juicios de ellos los juzgaré; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 1, 'Y ACONTECIO en el sexto año, en el mes sexto, á los cinco del mes, que estaba yo sentado en mi casa, y los ancianos de Judá estaban sentados delante de mí, y allí cayó sobre mí la mano del Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 2, 'Y miré, y he aquí una semejanza que parecía de fuego: desde donde parecían sus lomos para abajo, fuego; y desde sus lomos arriba parecía como resplandor, como la vista de ámbar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 3, 'Y aquella semejanza extendió la mano, y tomóme por las guedejas de mi cabeza; y el espíritu me alzó entre el cielo y la tierra, y llevóme en visiones de Dios á Jerusalem, á la entrada de la puerta de adentro que mira hacia el aquilón, donde estaba la habitación de la imagen del celo, la que hacía celar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 4, 'Y he aquí allí estaba la gloria del Dios de Israel, como la visión que yo había visto en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 5, 'Y díjome: Hijo del hombre, alza ahora tus ojos hacia el lado del aquilón. Y alcé mis ojos hacia el lado del aquilón, y he aquí al aquilón, junto á la puerta del altar, la imagen del celo en la entrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 6, 'Díjome entonces: Hijo del hombre, ¿no ves lo que éstos hacen, las grandes abominaciones que la casa de Israel hace aquí, para alejarme de mi santuario? Mas vuélvete aún, y verás abominaciones mayores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 7, 'Y llevóme á la entrada del atrio, y miré, y he aquí en la pared un agujero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 8, 'Y díjome: Hijo del hombre, cava ahora en la pared. Y cavé en la pared, y he aquí una puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 9, 'Díjome luego: Entra, y ve las malvadas abominaciones que éstos hacen allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 10, 'Entré pues, y miré, y he aquí imágenes de todas serpientes, y animales de abominación, y todos los ídolos de la casa de Israel, que estaban pintados en la pared alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 11, 'Y delante de ellos estaban setenta varones de los ancianos de la casa de Israel, y Jaazanías hijo de Saphán estaba en medio de ellos, cada uno con su incensario en su mano; y del sahumerio subía espesura de niebla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 12, 'Y me dijo: Hijo del hombre, ¿has visto las cosas que los ancianos de la casa de Israel hacen en tinieblas, cada uno en sus cámaras pintadas? porque dicen ellos: No nos ve Jehová; Jehová ha dejado la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 13, 'Díjome después: Vuélvete aún, verás abominaciones mayores que hacen éstos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 14, 'Y llevóme á la entrada de la puerta de la casa de Jehová, que está al aquilón; y he aquí mujeres que estaban allí sentadas endechando á Tammuz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 15, 'Luego me dijo: ¿No ves, hijo del hombre? Vuélvete aún, verás abominaciones mayores que éstas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 16, 'Y metióme en el atrio de adentro de la casa de Jehová: y he aquí junto á la entrada del templo de Jehová, entre la entrada y el altar, como veinticinco varones, sus espaldas vueltas al templo de Jehová y sus rostros al oriente, y encorvábanse al nacimiento del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 17, 'Y díjome: ¿No has visto, hijo del hombre? ¿Es cosa liviana para la casa de Judá hacer las abominaciones que hacen aquí? Después que han llenado la tierra de maldad, y se tornaron á irritarme, he aquí que ponen hedor á mis narices.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 8, 18, 'Pues también yo haré en mi furor; no perdonará mi ojo, ni tendré misericordia, y gritarán á mis oídos con gran voz, y no los oiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 1, 'Y CLAMO en mis oídos con gran voz, diciendo: Los visitadores de la ciudad han llegado, y cada uno trae en su mano su instrumento para destruir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 2, 'Y he aquí que seis varones venían del camino de la puerta de arriba que está vuelta al aquilón, y cada uno traía en su mano su instrumento para destruir. Y entre ellos había un varón vestido de lienzos, el cual traía á su cintura una escribanía de escribano; y entrados, paráronse junto al altar de bronce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 3, 'Y la gloria del Dios de Israel se alzó de sobre el querubín sobre el cual había estado, al umbral de la casa: y llamó Jehová al varón vestido de lienzos, que tenía á su cintura la escribanía de escribano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 4, 'Y díjole Jehová: Pasa por medio de la ciudad, por medio de Jerusalem, y pon una señal en la frente á los hombres que gimen y que claman á causa de todas las abominaciones que se hacen en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 5, 'Y á los otros dijo á mis oídos: Pasad por la ciudad en pos de él, y herid; no perdone vuestro ojo, ni tengáis misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 6, 'Matad viejos, mozos y vírgenes, niños y mujeres, hasta que no quede ninguno: mas á todo aquel sobre el cual hubiere señal, no llegaréis; y habéis de comenzar desde mi santuario. Comenzaron pues desde los varones ancianos que estaban delante del templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 7, 'Y díjoles: Contaminad la casa, y henchid los atrios de muertos: salid. Y salieron, é hirieron en la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 8, 'Y aconteció que, habiéndolos herido, yo quedé y postréme sobre mi rostro, y clamé, y dije: ¡Ah, Señor Jehová! ¿has de destruir todo el resto de Israel derramando tu furor sobre Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 9, 'Y díjome: La maldad de la casa de Israel y de Judá es grande sobremanera, pues la tierra está llena de sangres, y la ciudad está llena de perversidad: porque han dicho: Dejado ha Jehová la tierra, y Jehová no ve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 10, 'Así pues, yo, mi ojo no perdonará, ni tendré misericordia: el camino de ellos tornaré sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 9, 11, 'Y he aquí que el varón vestido de lienzos, que tenía la escribanía á su cintura, respondió una palabra diciendo: Hecho he conforme á todo lo que me mandaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 1, 'Y MIRÉ, y he aquí en la expansión que había sobre la cabeza de los querubines como una piedra de zafiro, que parecía como semejanza de un trono que se mostró sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 2, 'Y habló al varón vestido de lienzos, y díjole: Entra en medio de la ruedas debajo de los querubines, é hinche tus manos carbones encendidos de entre los querubines, y derrama sobre la ciudad. Y entró á vista mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 3, 'Y los querubines estaban á la mano derecha de la casa cuando este varón entró; y la nube henchía el atrio de adentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 4, 'Y la gloria de Jehová se levantó del querubín al umbral de la puerta; y la casa fué llena de la nube, y el atrio se llenó del resplandor de la gloria de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 5, 'Y el estruendo de las alas de los querubines se oía hasta el atrio de afuera, como la voz del Dios Omnipotente cuando habla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 6, 'Y aconteció que, como mandó al varón vestido de lienzos, diciendo: Toma fuego de entre las ruedas, de entre los querubines, él entró, y paróse entre las ruedas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 7, 'Y un querubín extendió su mano de entre los querubines al fuego que estaba entre los querubines, y tomó, y puso en las palmas del que estaba vestido de lienzos, el cual lo tomó y salióse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 8, 'Y apareció en los querubines la figura de una mano humana debajo de sus alas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 9, 'Y miré, y he aquí cuatro ruedas junto á los querubines, junto á cada querubín una rueda; y el aspecto de las ruedas era como el de piedra de Tarsis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 10, 'Cuanto al parecer de ellas, las cuatro eran de una forma, como si estuviera una en medio de otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 11, 'Cuando andaban, sobre sus cuatro costados andaban: no se tornaban cuando andaban, sino que al lugar adonde se volvía el primero, en pos de él iban; ni se tornaban cuando andaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 12, 'Y toda su carne, y sus costillas, y sus manos, y sus alas, y las ruedas, lleno estaba de ojos alrededor en sus cuatro ruedas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 13, 'A las ruedas, oyéndolo yo, se les gritaba: ¡Rueda!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 14, 'Y cada uno tenía cuatro rostros. El primer rostro era de querubín; el segundo rostro, de hombre; el tercer rostro, de león; el cuarto rostro, de águila.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 15, 'Y levantáronse los querubines; este es el animal que vi en el río de Chebar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 16, 'Y cuando andaban los querubines, andaban las ruedas junto con ellos; y cuando los querubines alzaban sus alas para levantarse de la tierra, las ruedas también no se volvían de junto á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 17, 'Cuando se paraban ellos, parábanse ellas, y cuando ellos se alzaban, alzábanse con ellos: porque el espíritu de los animales estaba en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 18, 'Y la gloria de Jehová se salió de sobre el umbral de la casa, y paró sobre los querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 19, 'Y alzando los querubines sus alas, levantáronse de la tierra delante de mis ojos: cuando ellos salieron, también las ruedas al lado de ellos: y paráronse á la entrada de la puerta oriental de la casa de Jehová, y la gloria del Dios de Israel estaba arriba sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 20, 'Este era el animal que vi debajo del Dios de Israel en el río de Chebar; y conocí que eran querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 21, 'Cada uno tenía cuatro rostros, y cada uno cuatro alas, y figuras de manos humanas debajo de sus alas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 10, 22, 'Y la figura de sus rostros era la de los rostros que vi junto al río de Chebar, su mismo parecer y su ser; cada uno caminaba en derecho de su rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 1, 'Y EL espíritu me elevó, y metióme por la puerta oriental de la casa de Jehová, la cual mira hacia el oriente: y he aquí á la entrada de la puerta veinticinco varones, entre los cuales vi á Jaazanías hijo de Azur, y á Pelatías hijo de Benaías, príncipes del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 2, 'Y díjome: Hijo del hombre, estos son los hombres que maquinan perversidad, y dan en esta ciudad mal consejo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 3, 'Los cuales dicen: No será tan presto: edifiquemos casas: ésta será la caldera, y nosotros la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 4, 'Por tanto profetiza contra ellos, profetiza, hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 5, 'Y cayó sobre mí el espíritu de Jehová, y díjome: Di: Así ha dicho Jehová: Así habéis hablado, oh casa de Israel, y las cosas que suben á vuestro espíritu, yo las he entendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 6, 'Habéis multiplicado vuestros muertos en esta ciudad, y habéis henchido de muertos sus calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 7, 'Por tanto, así ha dicho el Señor Jehová: Vuestros muertos que habéis puesto en medio de ella, ellos son la carne, y ella es la caldera; mas yo os sacaré á vosotros de en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 8, 'Cuchillo habéis temido, y cuchillo traeré sobre vosotros, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 9, 'Y os sacaré de en medio de ella, y os entregaré en manos de extraños, y yo haré juicios en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 10, 'A cuchillo caeréis; en el término de Israel os juzgaré, y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 11, 'Esta no os será por caldera, ni vosotros seréis en medio de ella la carne: en el término de Israel os tengo de juzgar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 12, 'Y sabréis que yo soy Jehová: porque no habéis andado en mis ordenanzas, ni habéis hecho mis juicios, sino según los juicios de las gentes que están en vuestros alrededores habéis hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 13, 'Y aconteció que, estando yo profetizando, Pelatías hijo de Benaías murió. Entonces caí sobre mi rostro, y clamé con grande voz, y dije: ¡Ah, Señor Jehová! ¿harás tú consumación del resto de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 14, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 15, 'Hijo del hombre, tus hermanos, tus hermanos, los hombres de tu parentesco y toda la casa de Israel, toda ella son aquellos á quienes dijeron los moradores de Jerusalem: Alejaos de Jehová; á nosotros es dada la tierra en posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 16, 'Por tanto di: Así ha dicho el Señor Jehová: Aunque los he echado lejos entre las gentes, y los he esparcido por las tierras, con todo eso les seré por un pequeño santuario en las tierras á donde llegaren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 17, 'Di por tanto: Así ha dicho el Señor Jehová: Yo os recogeré de los pueblos, y os allegaré de las tierras en las cuales estáis esparcidos, y os daré la tierra de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 18, 'Y vendrán allá, y quitarán de ella todas su torpezas, y todas sus abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 19, 'Y darles he un corazón, y espíritu nuevo daré en sus entrañas; y quitaré el corazón de piedra de su carne, y daréles corazón de carne;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 20, 'Para que anden en mis ordenanzas, y guarden mis juicios y los cumplan, y me sean por pueblo, y yo sea á ellos por Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 21, 'Mas á aquellos cuyo corazón anda tras el deseo de sus torpezas y de sus abominaciones, yo tornaré su camino sobre sus cabezas, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 22, 'Después alzaron los querubines sus alas, y las ruedas en pos de ellos; y la gloria del Dios de Israel estaba sobre ellos encima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 23, 'Y la gloria de Jehová se fué de en medio de la ciudad, y paró sobre el monte que está al oriente de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 24, 'Luego me levantó el espíritu, y volvióme á llevar en visión del espíritu de Dios á la tierra de los Caldeos, á los trasportados. Y partióse de mí la visión que había visto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 11, 25, 'Y hablé á los trasportados todas las palabras de Jehová que él me había mostrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 2, 'Hijo del hombre, tú habitas en medio de casa rebelde, los cuales tienen ojos para ver, y no ven, tienen oídos para oir, y no oyen; porque son casa rebelde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 3, 'Por tanto tú, hijo del hombre, hazte aparejos de marcha, y pártete de día delante de sus ojos; y te pasarás de tu lugar á otro lugar á vista de ellos, por si tal vez atienden, porque son casa rebelde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 4, 'Y sacarás tus aparejos, como aparejos de partida, de día delante de sus ojos: mas tú saldrás por la tarde á vista de ellos, como quien sale para partirse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 5, 'Delante de sus ojos horadarás la pared, y saldrás por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 6, 'Delante de sus ojos los llevarás sobre tus hombros, de noche los sacarás; cubrirás tu rostro, y no mirarás la tierra: porque en señal te he dado á la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 7, 'Y yo hice así como me fué mandado: saqué mis aparejos de día, como aparejos de partida, y á la tarde horadé la pared á mano; salí de noche, y llevélos sobre los hombros á vista de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 8, 'Y fué á mi palabra de Jehová por la mañana, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 9, 'Hijo del hombre, ¿no te ha dicho la casa de Israel, aquella casa rebelde: ¿Qué haces?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 10, 'Diles: Así ha dicho el Señor Jehová: Al príncipe en Jerusalem es esta carga, y á toda la casa de Israel que está en medio de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 11, 'Diles: Yo soy vuestra señal: como yo hice, así les harán á ellos: al pasar á otro país irán en cautiverio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 12, 'Y al príncipe que está en medio de ellos llevarán á cuestas de noche, y saldrán; horadarán la pared para sacarlo por ella; cubrirá su rostro para no ver con sus ojos la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 13, 'Mas yo extenderé mi red sobre él, y será preso en mi malla, y harélo llevar á Babilonia, á tierra de Caldeos; mas no la verá, y allá morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 14, 'Y á todos los que estuvieren alrededor de él para su ayuda, y á todas sus compañías esparciré á todo viento, y desenvainaré espada en pos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 15, 'Y sabrán que yo soy Jehová, cuando los esparciere entre las gentes, y los derramare por la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 16, 'Y haré que de ellos queden pocos en número, del cuchillo, y del hambre, y de la pestilencia, para que cuenten todas sus abominaciones entre las gentes adonde llegaren; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 17, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 18, 'Hijo del hombre, come tu pan con temblor, y bebe tu agua con estremecimiento y con anhelo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 19, 'Y dirás al pueblo de la tierra: Así ha dicho el Señor Jehová sobre los moradores de Jerusalem, y sobre la tierra de Israel: Su pan comerán con temor, y con espanto beberán su agua; porque su tierra será asolada de su multitud, por la maldad de todos los que en ella moran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 20, 'Y las ciudades habitadas serán asoladas, y la tierra será desierta; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 21, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 22, 'Hijo del hombre, ¿qué refrán es este que tenéis vosotros en la tierra de Israel, diciendo: Prolongarse han los días, y perecerá toda visión?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 23, 'Diles por tanto: Así ha dicho el Señor Jehová: Haré cesar este refrán, y no repetirán más este dicho en Israel. Diles pues: Se han acercado aquellos días, y la palabra de toda visión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 24, 'Porque no habrá más alguna visión vana, ni habrá adivinación de lisonjeros en medio de la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 25, 'Porque yo Jehová hablaré; cumpliráse la palabra que yo hablaré; no se dilatará más: antes en vuestros días, oh casa rebelde, hablaré palabra, y cumpliréla, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 26, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 27, 'Hijo del hombre, he aquí que los de la casa de Israel dicen: La visión que éste ve es para muchos días, y para lejanos tiempos profetiza éste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 12, 28, 'Diles por tanto: Así ha dicho el Señor Jehová: No se dilatarán más todas mis palabras: cumpliráse la palabra que yo hablaré, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 2, 'Hijo del hombre, profetiza contra los profetas de Israel que profetizan, y di á los que profetizan de su corazón: Oid palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 3, 'Así ha dicho el Señor Jehová: ¡Ay de los profetas insensatos, que andan en pos de su propio espíritu, y nada vieron!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 4, 'Como zorras en los desiertos fueron tus profetas, oh Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 5, 'No habéis subido á los portillos, ni echasteis vallado en la casa de Israel, estando en la batalla en el día de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 6, 'Vieron vanidad y adivinación de mentira. Dicen: Ha dicho Jehová; y Jehová no los envió: y hacen esperar que se confirme la palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 7, '¿No habéis visto visión vana, y no habéis dicho adivinación de mentira, por cuanto decís, Dijo Jehová; no habiendo yo hablado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 8, 'Por tanto, así ha dicho el Señor Jehová: por cuanto vosotros habéis hablado vanidad, y habéis visto mentira, por tanto, he aquí yo contra vosotros, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 9, 'Y será mi mano contra los profetas que ven vanidad, y adivinan mentira: no serán en la congregación de mi pueblo, ni serán escritos en el libro de la casa de Israel, ni á la tierra de Israel volverán; y sabréis que yo soy el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 10, 'Por tanto, y por cuanto engañaron á mi pueblo, diciendo, Paz, no habiendo paz; y el uno edificaba la pared, y he aquí que los otros la encostraban con lodo suelto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 11, 'Di á los encostradores con lodo suelto, que caerá; vendrá lluvia inundante, y daré piedras de granizo que la hagan caer, y viento tempestuoso la romperá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 12, 'Y he aquí, cuando la pared habrá caído, no os dirán: ¿Dónde está la embarradura con que encostrasteis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 13, 'Por tanto, así ha dicho el Señor Jehová: Y haré que la rompa viento tempestuoso con mi ira, y lluvia inundante vendrá con mi furor, y piedras de granizo con enojo para consumir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 14, 'Así desbarataré la pared que vosotros encostrasteis con lodo suelto, y echaréla á tierra, y será descubierto su cimiento, y caerá, y seréis consumidos en medio de ella; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 15, 'Cumpliré así mi furor en la pared y en los que la encostraron con lodo suelto; y os diré: No existe la pared, ni aquellos que la encostraron,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 16, 'Los profetas de Israel que profetizan á Jerusalem, y ven para ella visión de paz, no habiendo paz, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 17, 'Y tú, hijo del hombre, pon tu rostro á las hijas de tu pueblo que profetizan de su corazón, y profetiza contra ellas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 18, 'Y di: Así ha dicho el Señor Jehová: ¡Ay de aquellas que cosen almohadillas á todos codos de manos, y hacen veletes sobre la cabeza de toda edad para cazar las almas! ¿Habéis de cazar las almas de mi pueblo, para mantener así vuestra propia vida?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 19, '¿Y habéis de profanarme entre mi pueblo por puñados de cebada y por pedazos de pan, matando las almas que no mueren, y dando vida á las almas que no vivirán, mintiendo á mi pueblo que escucha la mentira?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 20, 'Por tanto, así ha dicho el Señor Jehová: He aquí yo contra vuestras almohadillas, con que cazáis ahí las almas volando; yo las arrancaré de vuestros brazos, y dejaré las almas, las almas que cazáis volando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 21, 'Romperé asimismo vuestro veletes, y libraré mi pueblo de vuestra mano, y no estarán más en vuestra mano para caza; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 22, 'Por cuanto entristecisteis con mentira el corazón del justo, al cual yo no entristecí, y esforzasteis las manos del impío, para que no se apartase de su mal camino, infundiéndole ánimo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 13, 23, 'Por tanto no veréis vanidad, ni más adivinaréis adivinación; y libraré mi pueblo de vuestra mano; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 1, 'Y VINIERON á mí algunos de los ancianos de Israel, y sentáronse delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 2, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 3, 'Hijo del hombre, estos hombres han puesto sus ídolos en su corazón, y establecido el tropiezo de su maldad delante de su rostro: ¿acaso he de ser yo verdaderamente consultado por ellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 4, 'Háblales por tanto, y diles: Así ha dicho el Señor Jehová: Cualquier hombre de la casa de Israel que hubiere puesto sus ídolos en su corazón, y establecido el tropiezo de su maldad delante de su rostro, y viniere al profeta, yo Jehová responderé al que viniere en la multitud de sus ídolos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 5, 'Para tomar á la casa de Israel en su corazón, que se han apartado de mí todos ellos en sus ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 6, 'Por tanto di á la casa de Israel: Así dice el Señor Jehová: Convertíos, y volveos de vuestros ídolos, y apartad vuestro rostro de todas vuestras abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 7, 'Porque cualquier hombre de la casa de Israel, y de los extranjeros que moran en Israel, que se hubiere apartado de andar en pos de mí, y hubiere puesto sus ídolos en su corazón, y establecido delante de su rostro el tropiezo de su maldad, y viniere al profeta para preguntarle por mí, yo Jehová le responderé por mí mismo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 8, 'Y pondré mi rostro contra aquel hombre, y le pondré por señal y por fábula, y yo lo cortaré de entre mi pueblo; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 9, 'Y el profeta, cuando fuere engañado y hablare palabra, yo Jehová engañé al tal profeta; y extenderé mi mano sobre él, y raeréle de en medio de mi pueblo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 10, 'Y llevarán su maldad: como la maldad del que pregunta, así será la maldad del profeta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 11, 'Para que no yerren más la casa de Israel de en pos de mí: ni más se contaminen en todas sus rebeliones, y me sean por pueblo, y yo les sea por Dios, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 12, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 13, 'Hijo del hombre, cuando la tierra pecare contra mí rebelándose pérfidamente, y extendiere yo mi mano sobre ella, y le quebrantare el arrimo del pan, y enviare en ella hambre, y talare de ella hombres y bestias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 14, 'Si estuvieren en medio de ella estos tres varones, Noé, Daniel, y Job, ellos por su justicia librarán su vida, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 15, 'Y si hiciere pasar malas bestias por la tierra, y la asolaren, y fuere desolada que no haya quien pase á causa de las bestias,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 16, 'Y estos tres varones estuvieren en medio de ella, vivo yo, dice el Señor Jehová, ni á sus hijos ni á sus hijas librarán; ellos solos serán libres, y la tierra será asolada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 17, 'O si yo trajere espada sobre la tierra, y dijere: Espada, pasa por la tierra; é hiciere talar de ella hombres y bestias,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 18, 'Y estos tres varones estuvieren en medio de ella, vivo yo, dice el Señor Jehová, no librarán sus hijos ni sus hijas; ellos solos serán libres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 19, 'O si pestilencia enviare sobre esa tierra, y derramare mi ira sobre ella en sangre, para talar de ella hombres y bestias,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 20, 'Y estuvieren en medio de ella Noé, Daniel, y Job, vivo yo, dice el Señor Jehová, no librarán hijo ni hija; ellos por su justicia librarán su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 21, 'Por lo cual así ha dicho el Señor Jehová: ¿Cuánto más, si mis cuatro malos juicios, espada, y hambre, y mala bestia, y pestilencia, enviare contra Jerusalem, para talar de ella hombres y bestias?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 22, 'Sin embargo, he aquí quedarán en ella algunos residuos, hijos é hijas, que serán llevados fuera: he aquí que ellos entrarán á vosotros, y veréis su camino y sus hechos; y tomaréis consolación del mal que hice venir sobre Jerusalem, de todas las cosas que traje sobre ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 14, 23, 'Y consolaros han cuando viereis su camino y sus hechos, y conoceréis que no sin causa hice todo lo que habré hecho en ella, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 15, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 15, 2, 'Hijo del hombre, ¿qué es el palo de la vid más que todo palo? ¿qué es el sarmiento entre los maderos del bosque?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 15, 3, '¿Tomarán de él madera para hacer alguna obra? ¿tomarán de él una estaca para colgar de ella algún vaso?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 15, 4, 'He aquí, que es puesto en el fuego para ser consumido; sus dos cabos consumió el fuego, y la parte del medio se quemó; ¿aprovechará para obra alguna?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 15, 5, 'He aquí que cuando estaba entero no era para obra alguna: ¿cuánto menos después que el fuego lo hubiere consumido, y fuere quemado? ¿será más para alguna obra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 15, 6, 'Por tanto, así ha dicho el Señor Jehová: Como el palo de la vid entre los maderos del bosque, el cual dí al fuego para que lo consuma, así haré á los moradores de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 15, 7, 'Y pondré mi rostro contra ellos; de fuego salieron, y fuego los consumirá; y sabréis que yo soy Jehová, cuando pusiere mi rostro contra ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 15, 8, 'Y tornaré la tierra en asolamiento, por cuanto cometieron prevaricación, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 2, 'Hijo del hombre, notifica á Jerusalem sus abominaciones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 3, 'Y di: Así ha dicho el Señor Jehová sobre Jerusalem: Tu habitación y tu raza fué de la tierra de Canaán; tu padre Amorrheo, y tu madre Hethea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 4, 'Y cuanto á tu nacimiento, el día que naciste no fué cortado tu ombligo, ni fuiste lavada con aguas para atemperarte, ni salada con sal, ni fuiste envuelta con fajas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 5, 'No hubo ojo que se compadeciese de ti, para hacerte algo de esto, teniendo de ti misericordia; sino que fuiste echada sobre la haz del campo, con menosprecio de tu vida, en el día que naciste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 6, 'Y yo pasé junto á ti, y te vi sucia en tus sangres, y díjete: En tus sangres, vive; vive, díjete, en tus sangres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 7, 'En millares como la hierba del campo te puse, y fuiste aumentada y engrandecida, y viniste á ser adornada grandemente; los pechos te crecieron, y tu pelo brotó; mas tú estabas desnuda y descubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 8, 'Y pasé yo junto á ti, y te miré, y he aquí que tu tiempo era tiempo de amores; y extendí mi manto sobre ti, y cubrí tu desnudez; y díte juramento, y entré en concierto contigo, dice el Señor Jehová, y fuiste mía:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 9, 'Y te lavé con agua, y lavé tus sangres de encima de ti, y ungíte con aceite;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 10, 'Y te vestí de bordado, y te calcé de tejón, y ceñíte de lino, y te vestí de seda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 11, 'Y te atavíe con ornamentos, y puse ajorcas en tus brazos, y collar á tu cuello;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 12, 'Y puse joyas sobre tus narices, y zarcillos en tus orejas, y diadema de hermosura en tu cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 13, 'Y fuiste adornada de oro y de plata, y tu vestido fué lino, y seda, y bordado; comiste flor de harina de trigo, y miel, y aceite; y fuiste hermoseada en extremo, y has prosperado hasta reinar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 14, 'Y salióte nombradía entre las gentes á causa de tu hermosura; porque era perfecta, á causa de mi hermosura que yo puse sobre ti, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 15, 'Mas confiaste en tu hermosura, y fornicaste á causa de tu nombradía, y derramaste tus fornicaciones á cuantos pasaron; suya eras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 16, 'Y tomaste de tus vestidos, e hicístete diversos altos lugares, y fornicaste en ellos: cosa semejante no vendrá, ni será así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 17, 'Tomaste asimismo los vasos de tu hermosura de mi oro y de mi plata, que yo te había dado, é hicístete imágenes de hombre, y fornicaste con ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 18, 'Y tomaste tus vestidos de diversos colores, y cubrístelas; y mi aceite y mi perfume pusiste delante de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 19, 'Mi pan también, que yo te había dado, la flor de la harina, y el aceite, y la miel, con que yo te mantuve, pusiste delante de ellas para olor suave; y fué así, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 20, 'Demás de esto, tomaste tus hijos y tus hijas que me habías engendrado, y los sacrificaste á ellas para consumación. ¿Es poco, esto de tus fornicaciones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 21, 'Y sacrificaste mis hijos, y dístelos á ellas para que los hiciesen pasar por el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 22, 'Y con todas tus abominaciones y tus fornicaciones no te has acordado de los días de tu mocedad, cuando estabas desnuda y descubierta, cuando estabas envuelta en tu sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 23, 'Y fué que después de toda tu maldad (¡ay, ay de ti! dice el Señor Jehová,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 24, 'Edificástete alto, y te hiciste altar en todas las plazas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 25, 'En toda cabeza de camino edificaste tu altar, y tornaste abominable tu hermosura, y abriste tus piernas á cuantos pasaban, y multiplicaste tus fornicaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 26, 'Y fornicaste con los hijos de Egipto, tus vecinos, de grandes carnes; y aumentaste tus fornicaciones para enojarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 27, 'Por tanto, he aquí que yo extendí sobre ti mi mano, y disminuí tu provisión ordinaria, y te entregué á la voluntad de las hijas de los Filisteos que te aborrecen, las cuales se avergüenzan de tu camino deshonesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 28, 'Fornicaste también con los hijos de Assur por no haberte hartado; y fornicaste con ellos, y tampoco te hartaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 29, 'Multiplicaste asimismo tu fornicación en la tierra de Canaán y de los Caldeos: ni tampoco con esto te hartaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 30, '¡Cuán inconstante es tu corazón, dice el Señor Jehová, habiendo hecho todas estas cosas, obras de una poderosa ramera,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 31, 'Edificando tus altares en cabeza de todo camino, y haciendo tus altares en todas las plazas! Y no fuiste semejante á ramera, menospreciando el salario,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 32, 'Sino como mujer adúltera, por cuanto que en lugar de su marido recibe á ajenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 33, 'A todas las rameras dan dones; mas tú diste tus dones á todos tus enamorados; y les diste presentes, porque entrasen á ti de todas partes por tus fornicaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 34, 'Y ha sido en ti al contrario de las mujeres en tus fornicaciones, ni nunca después de ti será así fornicado; porque en dar tú dones, y no ser dados dones á ti, ha sido al contrario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 35, 'Por tanto, ramera, oye palabra de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 36, 'Así ha dicho el Señor Jehová: Por cuanto han sido descubiertas tus vergüenzas, y tu confusión ha sido manifestada á tus enamorados en tus fornicaciones; y á los ídolos de tus abominaciones, y en la sangre de tus hijos, los cuales les diste;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 37, 'Por tanto, he aquí que yo junto todos tus enamorados con los cuales tomaste placer, y todos los que amaste, con todos los que aborreciste; y reunirélos contra ti alrededor, y descubriréles tu vergüenza, y verán toda tu torpeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 38, 'Y yo te juzgaré por las leyes de las adúlteras, y de las que derraman sangre; y te daré en sangre de ira y de celo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 39, 'Y te entregaré en mano de ellos: y destruirán tu alto, y derribarán tus altares, y te harán desnudar de tus ropas, y se llevarán los vasos de tu gloria, y te dejarán desnuda y descubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 40, 'Y harán subir contra ti reunión de gente, y te apedrearán con piedras, y te atravesarán con sus espadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 41, 'Y quemarán tus casas á fuego, y harán en ti juicios á ojos de muchas mujeres; y hacerte he cesar de ser ramera, ni tampoco darás más don.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 42, 'Y haré reposar mi ira sobre ti, y apartaráse de ti mi celo, y descansaré de más enojarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 43, 'Por cuanto no te acordaste de los días de tu mocedad, y me provocaste á ira en todo esto, por eso, he aquí yo también he tornado tu camino sobre tu cabeza, dice el Señor Jehová; pues ni aun has pensado sobre todas tus abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 44, 'He aquí que todo proverbista hará de ti proverbio, diciendo: Como la madre, tal su hija.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 45, 'Hija de tu madre eres tú, que desechó á su marido y á sus hijos; y hermana de tus hermanas eres tú, que desecharon á sus maridos y á sus hijos: vuestra madre fué Hethea, y vuestro padre Amorrheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 46, 'Y tu hermana mayor es Samaria con su hijas, la cual habita á tu mano izquierda; y tu hermana la menor que tú es Sodoma con sus hijas, la cual habita á tu mano derecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 47, 'Y aun no anduviste en sus caminos, ni hiciste según sus abominaciones; antes, como si esto fuera poco y muy poco, te corrompiste más que ellas en todos tus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 48, 'Vivo yo, dice el Señor Jehová, Sodoma tu hermana, con sus hijas, no ha hecho como hiciste tú y tus hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 49, 'He aquí que esta fué la maldad de Sodoma tu hermana: soberbia, hartura de pan, y abundancia de ociosidad tuvo ella y sus hijas; y no corroboró la mano del afligido y del menesteroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 50, 'Y ensoberbeciéronse, é hicieron abominación delante de mí, y quitélas como vi bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 51, 'Y Samaria no cometió ni la mitad de tus pecados; porque tú multiplicaste tus abominaciones más que ellas, y has justificado á tus hermanas con todas tus abominaciones que hiciste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 52, 'Tú también, que juzgaste á tus hermanas, lleva tu vergüenza en tus pecados que hiciste más abominables que ellas: más justas son que tú: avergüénzate pues tú también, y lleva tu confusión, pues que has justificado á tus hermanas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 53, 'Yo pues haré tornar sus cautivos, los cautivos de Sodoma y de sus hijas, y los cautivos de Samaria y de sus hijas, y los cautivos de tus cautiverios entre ellas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 54, 'Para que tú lleves tu confusión, y te avergüences de todo lo que has hecho, siéndoles tú motivo de consuelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 55, 'Y tus hermanas, Sodoma con sus hijas y Samaria con sus hijas, volverán á su primer estado; tú también y tus hijas volveréis á vuestro primer estado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 56, 'Sodoma, tu hermana, no fué nombrada en tu boca en el tiempo de tus soberbias,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 57, 'Antes que tu maldad se descubriese, como en el tiempo de la vergüenza de las hijas de Siria y de todas las hijas de los Filisteos alrededor, que te menosprecian en contorno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 58, 'Tú has llevado tu enormidad y tus abominaciones, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 59, 'Empero así ha dicho el Señor Jehová: ¿Haré yo contigo como tú hiciste, que menospreciaste el juramento para invalidar el pacto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 60, 'Antes yo tendré memoria de mi pacto que concerté contigo en los días de tu mocedad, y te confirmaré un pacto sempiterno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 61, 'Y acordarte has de tus caminos y te avergonzarás, cuando recibirás á tus hermanas, las mayores que tú con las menores que tú, las cuales yo te daré por hijas, mas no por tu pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 62, 'Y confirmaré mi pacto contigo, y sabrás que yo soy Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 16, 63, 'Para que te acuerdes, y te avergüences, y nunca más abras la boca á causa de tu vergüenza, cuando me aplacare para contigo de todo lo que hiciste, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 2, 'Hijo del hombre, propón una figura, y compón una parábola á la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 3, 'Y dirás: Así ha dicho el Señor Jehová: Una grande águila, de grandes alas y de largos miembros, llena de plumas de diversos colores, vino al Líbano, y tomó el cogollo del cedro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 4, 'Arrancó el principal de sus renuevos, y llevólo á la tierra de mercaderes, y púsolo en la ciudad de los negociantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 5, 'Tomó también de la simiente de la tierra, y púsola en un campo bueno para sembrar, plantóla junto á grandes aguas, púsola como un sauce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 6, 'Y brotó, é hízose una vid de mucha rama, baja de estatura, que sus ramas la miraban, y sus raíces estaban debajo de ella: así que se hizo una vid, y arrojó sarmientos, y echó mugrones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 7, 'Y fué otra grande águila, de grandes alas y de muchas plumas; y he aquí que esta vid juntó cerca de ella sus raíces, y extendió hacia ella sus ramos, para ser regada por ella por los surcos de su plantío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 8, 'En un buen campo, junto á muchas aguas fué plantada, para que hiciese ramos y llevase fruto, y para que fuese vid robusta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 9, 'Di: Así ha dicho el Señor Jehová: ¿Será prosperada? ¿No arrancará sus raíces, y destruirá su fruto, y secaráse? Todas las hojas de su lozanía secará, y no con gran brazo, ni con mucha gente, arrancándola de sus raíces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 10, 'Y he aquí que plantada está ella, ¿será prosperada? ¿No se secará del todo cuando el viento solano la tocare? En los surcos de su verdor se secará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 11, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 12, 'Di ahora á la casa rebelde: ¿No habéis entendido qué significan estas cosas? Diles: He aquí que el rey de Babilonia vino á Jerusalem, y tomó tu rey y sus príncipes, y llevólos consigo á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 13, 'Tomó también de la simiente del reino, é hizo con él alianza, y trájole á juramento; y tomó los fuertes de la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 14, 'Para que el reino fuese abatido y no se levantase, sino que guardase su alianza y estuviese en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 15, 'Rebelóse empero contra él enviando sus embajadores á Egipto, para que le diese caballos y mucha gente. ¿Será prosperado, escapará, el que estas cosas hizo? ¿y el que rompió la alianza, podrá huir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 16, 'Vivo yo, dice el Señor Jehová, que morirá en medio de Babilonia, en el lugar del rey que le hizo reinar, cuyo juramento menospreció, y cuya alianza con él hecha rompió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 17, 'Y no con grande ejército, ni con mucha compañía hará con él Faraón en la batalla, cuando funden baluarte y edifiquen bastiones para cortar muchas vidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 18, 'Pues menospreció el juramento, para invalidar el concierto cuando he aquí que había dado su mano, é hizo todas estas cosas, no escapará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 19, 'Por tanto, así ha dicho el Señor Jehová: Vivo yo, que el juramento mío que menospreció, y mi concierto que ha invalidado, tornaré sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 20, 'Y extenderé sobre él mi red, y será preso en mi malla; y hacerlo he venir á Babilonia, y allí estaré á juicio con él, por su prevaricación con que contra mí se ha rebelado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 21, 'Y todos sus fugitivos con todos sus escuadrones caerán á cuchillo, y los que quedaren serán esparcidos á todo viento; y sabréis que yo Jehová he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 22, 'Así ha dicho el Señor Jehová: Y tomaré yo del cogollo de aquel alto cedro, y pondrélo; del principal de sus renuevos cortaré un tallo, y plantarlo he yo sobre el monte alto y sublime;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 23, 'En el monte alto de Israel lo plantaré, y alzará ramos, y llevará fruto, y haráse magnífico cedro; y habitarán debajo de él todas las aves, toda cosa que vuela habitará á la sombra de sus ramos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 17, 24, 'Y sabrán todos los árboles del campo que yo Jehová abatí el árbol sublime, levanté el árbol bajo, hice secar el árbol verde, é hice reverdecer el árbol seco. Yo Jehová hablé é hice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 2, '¿Qué pensáis vosotros, vosotros que usáis este refrán sobre la tierra de Israel, diciendo: Los padres comieron el agraz, y los dientes de los hijos tienen la dentera?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 3, 'Vivo yo, dice el Señor Jehová, que nunca más tendréis por qué usar este refrán en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 4, 'He aquí que todas las almas son mías; como el alma del padre, así el alma del hijo es mía; el alma que pecare, esa morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 5, 'Y el hombre que fuere justo, é hiciere juicio y justicia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 6, 'Que no comiere sobre los montes, ni alzare sus ojos á los ídolos de la casa de Israel, ni violare la mujer de su prójimo, ni llegare á la mujer menstruosa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 7, 'Ni oprimiere á ninguno; al deudor tornare su prenda, no cometiere robo, diere de su pan al hambriento, y cubriere al desnudo con vestido,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 8, 'No diere á logro, ni recibiere aumento; de la maldad retrajere su mano, é hiciere juicio de verdad entre hombre y hombre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 9, 'En mis ordenanzas caminare, y guardare mis derechos para hacer verdad, éste es justo: éste vivirá, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 10, 'Mas si engendrare hijo ladrón, derramador de sangre, ó que haga alguna cosa de éstas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 11, 'Y que no haga las otras; antes comiere sobre los montes, ó violare la mujer de su prójimo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 12, 'Al pobre y menesteroso oprimiere, cometiere robos, no tornare la prenda, ó alzare sus ojos á los ídolos, é hiciere abominación,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 13, 'Diere á usura, y recibiere aumento: ¿vivirá éste? No vivirá. Todas estas abominaciones hizo; de cierto morirá; su sangre será sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 14, 'Pero si éste engrendrare hijo, el cual viere todos los pecados que su padre hizo, y viéndolos no hiciere según ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 15, 'No comiere sobre los montes, ni alzare sus ojos á los ídolos de la casa de Israel; la mujer de su prójimo no violare,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 16, 'Ni oprimiere á nadie; la prenda no empeñare, ni cometiere robos; al hambriento diere de su pan, y cubriere de vestido al desnudo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 17, 'Apartare su mano del pobre, usura ni aumento no recibiere; hiciere mis derechos, y anduviere en mis ordenanzas, éste no morirá por la maldad de su padre; de cierto vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 18, 'Su padre, por cuanto hizo agravio, despojó violentamente al hermano, é hizo en medio de su pueblo lo que no es bueno, he aquí que él morirá por su maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 19, 'Y si dijereis: ¿Por qué el hijo no llevará por el pecado de su padre? Porque el hijo hizo juicio y justicia, guardó todas mis ordenanzas, y las hizo, de cierto vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 20, 'El alma que pecare, esa morirá: el hijo no llevará por el pecado del padre, ni el padre llevará por el pecado del hijo: la justicia del justo será sobre él, y la impiedad el impío será sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 21, 'Mas el impío, si se apartare de todos sus pecados que hizo, y guardare todas mis ordenanzas, é hiciere juicio y justicia, de cierto vivirá; no morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 22, 'Todas sus rebeliones que cometió, no le serán recordadas: en su justicia que hizo vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 23, '¿Quiero yo la muerte del impío? dice el Señor Jehová. ¿No vivirá, si se apartare de sus caminos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 24, 'Mas si el justo se apartare de su justicia, y cometiere maldad, é hiciere conforme á todas las abominaciones que el impío hizo; ¿vivirá él? Todas las justicias que hizo no vendrán en memoria; por su rebelión con que prevaricó, y por su pecado que cometió, por ello morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 25, 'Y si dijereis: No es derecho el camino del Señor: oid ahora, casa de Israel: ¿No es derecho mi camino? ¿no son vuestros caminos torcidos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 26, 'Apartándose el justo de su justicia, y haciendo iniquidad, él morirá por ello: por su iniquidad que hizo, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 27, 'Y apartándose el impío de su impiedad que hizo, y haciendo juicio y justicia, hará vivir su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 28, 'Porque miró, y apartóse de todas sus prevaricaciones que hizo, de cierto vivirá, no morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 29, 'Si aun dijere la casa de Israel: No es derecho el camino del Señor: ¿No son derechos mis caminos, casa de Israel? Cierto, vuestros caminos no son derechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 30, 'Por tanto, yo os juzgaré á cada uno según sus caminos, oh casa de Israel, dice el Señor Jehová. Convertíos, y volveos de todas vuestras iniquidades; y no os será la iniquidad causa de ruina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 31, 'Echad de vosotros todas vuestras iniquidades con que habéis prevaricado, y haceos corazón nuevo y espíritu nuevo. ¿Y por qué moriréis, casa de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 18, 32, 'Que no quiero la muerte del que muere, dice el Señor Jehová, convertíos pues, y viviréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 1, 'Y TU levanta endecha sobre los príncipes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 2, 'Y dirás: ¡Cómo se echó entre los leones tu madre la leona! entre los leoncillos crió sus cachorros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 3, 'E hizo subir uno de sus cachorros: vino á ser leoncillo, y aprendió á prender presa, y á devorar hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 4, 'Y las gentes oyeron de él: fué tomado con el lazo de ellas, y lleváronlo con grillos á la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 5, 'Y viendo ella que había esperado mucho tiempo, y que se perdía su esperanza, tomó otro de sus cachorros, y púsolo por leoncillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 6, 'Y él andaba entre los leones; hízose leoncillo, aprendió á hacer presa, devoró hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 7, 'Y conoció sus viudas, y asoló sus ciudades; y la tierra fué asolada, y su abundancia, á la voz de su bramido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 8, 'Y dieron sobre él las gentes de las provincias de su alrededor, y extendieron sobre él su red; fué preso en su hoyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 9, 'Y pusiéronlo en cárcel con cadenas, y lleváronlo al rey de Babilonia; metiéronlo en fortalezas, para que su voz no se oyese más sobre los montes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 10, 'Tu madre fué como una vid en tu sangre, plantada junto á las aguas, haciendo fruto y echando vástagos á causa de las muchas aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 11, 'Y ella tuvo varas fuertes para cetros de señores; y levantóse su estatura por encima entre las ramas, y fué vista en su altura, y con la multitud de sus sarmientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 12, 'Empero fué arrancada con ira, derribada en tierra, y viento solano secó su fruto; fueron quebradas y secáronse sus varas fuertes; consumiólas el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 13, 'Y ahora está plantada en el desierto, en tierra de sequedad y de aridez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 19, 14, 'Y ha salido fuego de la vara de sus ramos, ha consumido su fruto, y no ha quedado en ella vara fuerte, cetro para enseñorear. Endecha es esta, y de endecha servirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 1, 'Y ACONTECIO en el año séptimo, en el mes quinto, á los diez del mes, que vinieron algunos de los ancianos de Israel á consultar á Jehová, y sentáronse delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 2, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 3, 'Hijo del hombre, habla á los ancianos de Israel, y diles: Así ha dicho el Señor Jehová: ¿A consultarme venís vosotros? Vivo yo, que yo no os responderé, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 4, '¿Quieres tú juzgarlos? ¿los quieres juzgar tú, hijo del hombre? Notifícales las abominaciones de sus padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 5, 'Y diles: Así ha dicho el Señor Jehová: El día que escogí á Israel, y que alcé mi mano por la simiente de la casa de Jacob, y que fuí conocido de ellos en la tierra de Egipto, cuando alcé mi mano á ellos, diciendo: Yo soy Jehová vuestro Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 6, 'Aquel día que les alcé mi mano, que los sacaría de la tierra de Egipto á la tierra que les había proveído, que fluye leche y miel, la cual es la más hermosa de todas las tierras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 7, 'Entonces les dije: Cada uno eche de sí cada uno de las abominaciones de sus ojos, y no os contaminéis en los ídolos de Egipto. Yo soy Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 8, 'Mas ellos se rebelaron contra mí, y no quisieron obedecerme: no echó de sí cada uno las abominaciones de sus ojos, ni dejaron los ídolos de Egipto; y dije que derramaría mi ira sobre ellos, para cumplir mi enojo en ellos en medio de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 9, 'Con todo, á causa de mi nombre, porque no se infamase en los ojos de las gentes en medio de las cuales estaban, en cuyos ojos fuí conocido de ellos, hice para sacarlos de tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 10, 'Saquélos pues de la tierra de Egipto, y trájelos al desierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 11, 'Y díles mis ordenanzas, y declaréles mis derechos, los cuales el hombre que los hiciere, vivirá en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 12, 'Y díles también mis sábados que fuesen por señal entre mí y ellos, para que supiesen que yo soy Jehová que los santifico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 13, 'Mas rebeláronse contra mí la casa de Israel en el desierto; no anduvieron en mis ordenanzas, y desecharon mis derechos, los cuales el hombre que los hiciere, vivirá en ellos; y mis sábados profanaron en gran manera; dije, por tanto, que había de derramar sobre ellos mi ira en el desierto para consumirlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 14, 'Pero en atención á mi nombre hice porque no se infamase á la vista de la gentes, delante de cuyos ojos los saqué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 15, 'Y también yo les alcé mi mano en el desierto, que no los metería en la tierra que les dí, que fluye leche y miel, la cual es la más hermosa de todas las tierras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 16, 'Porque desecharon mis derechos, y no anduvieron en mis ordenanzas, y mis sábados profanaron: porque tras sus ídolos iba su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 17, 'Con todo los perdonó mi ojo, no matándolos, ni los consumí en el desierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 18, 'Antes dije en el desierto á sus hijos: No andéis en las ordenanzas de vuestros padres, ni guardéis sus leyes, ni os contaminéis en sus ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 19, 'Yo soy Jehová vuestro Dios; andad en mis ordenanzas, y guardad mis derechos, y ponedlos por obra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 20, 'Y santificad mis sábados, y sean por señal entre mí y vosotros, para que sepáis que yo soy Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 21, 'Y los hijos se rebelaron contra mí: no anduvieron en mis ordenanzas, ni guardaron mis derechos para ponerlos por obra, los cuales el hombre que los cumpliere, vivirá en ellos; profanaron mis sábados. Dije entonces que derramaría mi ira sobre ellos, para cumplir mi enojo en ellos en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 22, 'Mas retraje mi mano, y en atención á mi nombre hice porque no se infamase á vista de las gentes, delante de cuyos ojos los saqué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 23, 'Y también les alcé yo mi mano en el desierto, que los esparciría entre las gentes, y que los aventaría por las tierras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 24, 'Porque no pusieron por obra mis derechos, y desecharon mis ordenanzas, y profanaron mis sábados, y tras los ídolos de sus padres se les fueron sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 25, 'Por eso yo también les dí ordenanzas no buenas, y derechos por los cuales no viviesen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 26, 'Y contaminélos en sus ofrendas cuando hacían pasar por el fuego todo primogénito, para que los desolase, á fin de que supiesen que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 27, 'Por tanto, hijo del hombre, habla á la casa de Israel, y diles: Así ha dicho el Señor Jehová: Aun en esto me afrentaron vuestros padres cuando cometieron contra mí rebelión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 28, 'Porque yo los metí en la tierra sobre la cual había alzado mi mano que les había de dar, y miraron á todo collado alto, y á todo árbol espeso, y allí sacrificaron sus víctimas, y allí presentaron la irritación de sus ofrendas, allí pusieron también él olor de su suavidad, y allí derramaron sus libaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 29, 'Y yo les dije: ¿Qué es ese alto adonde vosotros vais? Y fué llamado su nombre Bamah hasta el día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 30, 'Di, pues, á la casa de Israel: Así ha dicho el Señor Jehová: ¿No os contamináis vosotros á la manera de vuestros padres, y fornicáis tras sus abominaciones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 31, 'Porque ofreciendo vuestras ofrendas, haciendo pasar vuestros hijos por el fuego, os habéis contaminado con todos vuestros ídolos hasta hoy: ¿y he de responderos yo, casa de Israel? Vivo yo, dice el Señor Jehová, que no os responderé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 32, 'Y no ha de ser lo que habéis pensado. Porque vosotros decís: Seamos como las gentes, como las familias de las naciones, sirviendo á la madera y á la piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 33, 'Vivo yo, dice el Señor Jehová, que con mano fuerte, y brazo extendido, y enojo derramado, tengo de reinar sobre vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 34, 'Y os sacaré de entre los pueblos, y os juntaré de las tierras en que estáis esparcidos, con mano fuerte, y brazo extendido, y enojo derramado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 35, 'Y os he de traer al desierto de pueblos, y allí litigaré con vosotros cara á cara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 36, 'Como litigué con vuestros padres en el desierto de la tierra de Egipto, así litigaré con vosotros, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 37, 'Y os haré pasar bajo de vara y os traeré en vínculo de concierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 38, 'Y apartaré de entre vosotros los rebeldes, y los que se rebelaron contra mí: de la tierra de sus destierros los sacaré, y á la tierra de Israel no vendrán; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 39, 'Y vosotros, oh casa de Israel, así ha dicho el Señor Jehová: Andad cada uno tras sus ídolos, y servidles, pues que á mí no me obedecéis; y no profanéis más mi santo nombre con vuestras ofrendas, y con vuestros ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 40, 'Empero en mi santo monte, en el alto monte de Israel, dice el Señor Jehová, allí me servirá toda la casa de Israel, toda ella en la tierra: allí los querré, y allí demandaré vuestras ofrendas, y las primicias de vuestros dones, con todas vuestras cosas consagradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 41, 'En olor de suavidad os aceptaré, cuando os hubiere sacado de entre los pueblos, y os hubiere juntado de las tierras en que estáis esparcidos; y seré santificado en vosotros á los ojos de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 42, 'Y sabréis que yo soy Jehová, cuando os hubiere metido en la tierra de Israel, en la tierra por la cual alcé mi mano que la daría á vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 43, 'Y allí os acordaréis de vuestros caminos, y de todos vuestros hechos en que os contaminasteis; y seréis confusos en vuestra misma presencia por todos vuestros pecados que cometisteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 44, 'Y sabréis que yo soy Jehová cuando hiciere con vosotros por amor de mi nombre, no según vuestros caminos malos, ni según vuestras perversas obras, oh casa de Israel, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 45, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 46, 'Hijo del hombre, pon tu rostro hacia el mediodía, y derrama tu palabra hacia la parte austral, y profetiza contra el bosque del campo del mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 47, 'Y dirás al bosque del mediodía: Oye palabra de Jehová: Así ha dicho el Señor Jehová: He aquí que yo enciendo en ti fuego, el cual consumirá en ti todo árbol verde, y todo árbol seco: no se apagará la llama del fuego; y serán quemados en ella todos rostros, desde el mediodía hasta el norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 48, 'Y verá toda carne que yo Jehová lo encendí; no se apagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 20, 49, 'Y dije: ¡Ah, Señor Jehová! ellos dicen de mí: ¿No profiere éste parábolas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 2, 'Hijo del hombre, pon tu rostro contra Jerusalem, y derrama palabra sobre los santuarios, y profetiza sobre la tierra de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 3, 'Y dirás á la tierra de Israel: Así ha dicho Jehová: He aquí, que yo contra ti, y sacaré mi espada de su vaina, y talaré de ti al justo y al impío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 4, 'Y por cuanto he de talar de ti al justo y al impío, por tanto, mi espada saldrá de su vaina contra toda carne, desde el mediodía hasta el aquilón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 5, 'Y sabrá toda carne que yo Jehová saqué mi espada de su vaina; no volverá más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 6, 'Y tú, hijo del hombre, gime con quebrantamiento de lomos, y con amargura; gime delante de los ojos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 7, 'Y será, que cuando te dijeren: ¿Por qué gimes tú? dirás: Por la fama que viene; y todo corazón se desleirá, y todas manos se debilitarán, y angustiaráse todo espíritu, y todas rodillas se irán en aguas: he aquí que viene, y hacerse ha, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 8, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 9, 'Hijo del hombre, profetiza, y di: Así ha dicho el Señor Jehová: Di: La espada, la espada está afilada, y aun acicalada;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 10, 'Para degollar víctimas está afilada, acicalada está para que relumbre. ¿Hemos de alegrarnos? A la vara de mi hijo viene menospreciando todo árbol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 11, 'Y dióla á acicalar para tenerla á mano: la espada está afilada, y acicalada está ella, para entregralo en mano del matador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 12, 'Clama y aúlla, oh hijo del hombre; porque ésta será sobre mi pueblo, será ella sobre todos los príncipes de Israel. Temores de espada serán á mi pueblo: por tanto, hiere el muslo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 13, 'Porque está probado. ¿Y qué, si la espada desprecia aun el cetro? El no será más, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 14, 'Tú pues, hijo del hombre, profetiza y bate una mano con otra, y dóblese la espada la tercera vez, la espada de muertos: ésta es espada de gran matanza que los penetrará,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 15, 'Para que el corazón desmaye, y los estragos se multipliquen: en todas las puertas de ellos he puesto espanto de espada. ¡Ah! dispuesta está para que relumbre, y aderezada para degollar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 16, 'Ponte á una parte, ponte á la diestra, ó ponte á la siniestra, hacia donde tu rostro se determinare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 17, 'Y yo también batiré mi mano con mi mano, y haré reposar mi ira. Yo Jehová he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 18, 'Y fué á mí palabra de Jehova, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 19, 'Y tú, hijo del hombre, señálate dos caminos por donde venga la espada del rey de Babilonia: de una misma tierra salgan ambos: y echa mano á la suerte: en el principio del camino de la ciudad lo harás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 20, 'El camino señalarás por donde venga la espada á Rabba de los hijos de Ammón, y á Judá contra Jerusalem la fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 21, 'Porque el rey de Babilonia se paró en una encrucijada, al principio de dos caminos, para tomar adivinación: acicaló saetas, consultó en ídolos, miró el hígado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 22, 'La adivinación fué á su mano derecha, sobre Jerusalem, para poner capitanes, para abrir la boca á la matanza, para levantar la voz en grito, para poner ingenios contra las puertas, para fundar baluarte, y edificar fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 23, 'Y seráles como adivinación mentirosa en sus ojos, por estar juramentados con juramento á ellos: mas él trae á la memoria la maldad, para prenderlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 24, 'Por tanto, así ha dicho el Señor Jehová: Por cuanto habéis hecho venir en memoria vuestras maldades, manifestando vuestras traiciones, y descubriendo vuestros pecados en todas vuestras obras; por cuanto habéis venido en memoria, seréis tomados á mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 25, 'Y tú, profano é impío príncipe de Israel, cuyo día vino en el tiempo de la consumación de la maldad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 26, 'Así ha dicho el Señor Jehová: Depón la tiara, quita la corona: ésta no será más ésta: al bajo alzaré, y al alto abatiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 27, 'Del revés, del revés, del revés la tornaré; y no será ésta más, hasta que venga aquel cuyo es el derecho, y se la entregaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 28, 'Y tú, hijo del hombre, profetiza, y di: Así ha dicho el Señor Jehová sobre los hijos de Ammón, y su oprobio. Dirás pues: La espada, la espada está desenvainada para degollar; acicalada para consumir con resplandor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 29, 'Te profetizan vanidad, adivínante mentira, para entregarte con los cuellos de los malos sentenciados á muerte, cuyo día vino en tiempo de la consumación de la maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 30, '¿Tornaréla á su vaina? En el lugar donde te criaste, en la tierra donde has vivido, te tengo de juzgar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 31, 'Y derramaré sobre ti mi ira: el fuego de mi enojo haré encender sobre ti, y te entregaré en mano de hombres temerarios, artífices de destrucción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 21, 32, 'Del fuego serás para ser consumido; tu sangre será en medio de la tierra; no habrá más memoria de ti: porque yo Jehová he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 2, 'Y tú, hijo del hombre, ¿no juzgarás tú, no juzgarás tú á la ciudad derramadora de sangre, y le mostrarás todas sus abominaciones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 3, 'Dirás, pues: Así ha dicho el Señor Jehová: ¡Ciudad derramadora de sangre en medio de sí, para que venga su hora, y que hizo ídolos contra sí misma para contaminarse!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 4, 'En tu sangre que derramaste has pecado, y te has contaminado en tus ídolos que hiciste; y has hecho acercar tus días, y has llegado á tus años: por tanto te he dado en oprobio á las gentes, y en escarnio á todas las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 5, 'Las que están cerca, y las que están lejos de ti, se reirán de ti, amancillada de fama, y de grande turbación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 6, 'He aquí que los príncipes de Israel, cada uno según su poder, fueron en ti para derramar sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 7, 'Al padre y á la madre despreciaron en ti: al extranjero trataron con calumnia en medio de ti: al huérfano y á la viuda despojaron en ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 8, 'Mis santuarios menospreciaste, y mis sábados has profanado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 9, 'Calumniadores hubo en ti para derramar sangre; y sobre los montes comieron en ti: hicieron en medio de ti suciedades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 10, 'La desnudez del padre descubrieron en ti; la inmunda de menstruo forzaron en ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 11, 'Y cada uno hizo abominación con la mujer de su prójimo; y cada uno contaminó su nuera torpemente; y cada uno forzó en ti á su hermana, hija de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 12, 'Precio recibieron en ti para derramar sangre; usura y logro tomaste, y á tus prójimos defraudaste con violencia: olvidástete de mí, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 13, 'Y he aquí, que herí mi mano á causa de tu avaricia que cometiste, y á causa de tus sangres que fueron en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 14, '¿Estará firme tu corazón? ¿tus manos serán fuertes en los días que obraré yo contra ti? Yo Jehová he hablado, y harélo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 15, 'Y yo te esparciré por las gentes, y te aventaré por las tierras; y haré fenecer de ti tu inmundicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 16, 'Y tomarás heredad en ti á los ojos de las gentes; y sabrás que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 17, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 18, 'Hijo del hombre, la casa de Israel se me ha tornado en escoria: todos ellos son metal, y estaño, y hierro, y plomo, en medio del horno; escorias de plata se tornaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 19, 'Por tanto, así ha dicho el Señor Jehová: Por cuanto todos vosotros os habéis tornado en escorias, por tanto, he aquí que yo os junto en medio de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 20, 'Como quien junta plata y metal y hierro y plomo y estaño en medio del horno, para encender fuego en él para fundir; así os juntaré en mi furor y en mi ira, y haré reposar, y os fundiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 21, 'Yo os juntaré y soplaré sobre vosotros en el fuego de mi furor, y en medio de él seréis fundidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 22, 'Como se funde la plata en medio del horno, así seréis fundidos en medio de él; y sabréis que yo Jehová habré derramado mi enojo sobre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 23, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 24, 'Hijo del hombre, di á ella: Tú no eres tierra limpia, ni rociada con lluvia en el día del furor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 25, 'La conjuración de sus profetas en medio de ella, como león bramando que arrebata presa: devoraron almas, tomaron haciendas y honra, aumentaron sus viudas en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 26, 'Sus sacerdotes violentaron mi ley, y contaminaron mis santuarios: entre lo santo y lo profano no hicieron diferencia, ni distinguieron entre inmundo y limpio; y de mis sábados escondieron sus ojos, y yo era profanado en medio de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 27, 'Sus príncipes en medio de ella como lobos que arrebataban presa, derramando sangre, para destruir las almas, para pábulo de su avaricia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 28, 'Y sus profetas revocaban con lodo suelto, profetizándoles vanidad, y adivinándoles mentira, diciendo: Así ha dicho el Señor Jehová; y Jehová no había hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 29, 'El pueblo de la tierra usaba de opresión, y cometía robo, y al afligido y menesteroso hacían violencia, y al extranjero oprimían sin derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 30, 'Y busqué de ellos hombre que hiciese vallado y que se pusiese al portillo delante de mí por la tierra, para que yo no la destruyese; y no lo hallé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 22, 31, 'Por tanto derramé sobre ellos mi ira; con el fuego de mi ira los consumí: torné el camino de ellos sobre su cabeza, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 2, 'Hijo del hombre, hubo dos mujeres, hijas de una madre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 3, 'Las cuales fornicaron en Egipto; en sus mocedades fornicaron. Allí fueron apretados sus pechos, y allí fueron estrujados los pechos de su virginidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 4, 'Y llamábanse, la mayor, Aholah, y su hermana, Aholibah; las cuales fueron mías, y parieron hijos é hijas. Y llamáronse, Samaria, Aholah; y Jerusalem, Aholibah.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 5, 'Y Aholah cometió fornicación en mi poder: y prendóse de sus amantes, los Asirios sus vecinos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 6, 'Vestidos de cárdeno, capitanes y príncipes, mancebos todos de codiciar, caballeros que andaban á caballo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 7, 'Y puso sus fornicaciones con ellos, con todos los más escogidos de los hijos de los Asirios, y con todos aquellos de quienes se enamoró: contaminóse con todos los ídolos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 8, 'Y no dejó sus fornicaciones de Egipto: porque con ella se echaron en su mocedad, y ellos comprimieron los pechos de su virginidad, y derramaron sobre ella su fornicación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 9, 'Por lo cual la entregué en mano de sus amantes, en mano de los hijos de los Asirios, de quienes se había enamorado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 10, 'Ellos descubrieron sus vergüenzas, tomaron sus hijos y sus hijas, y á ella mataron á cuchillo: y vino á ser de nombre entre las mujeres, pues en ella hicieron juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 11, 'Y viólo su hermana Aholibah, y estragó su amor más que ella; y sus fornicaciones, más que las fornicaciones de su hermana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 12, 'Enamoróse de los hijos de los Asirios, sus vecinos, capitanes y príncipes, vestidos en perfección, caballeros que andaban á caballo, todos ellos mancebos de codiciar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 13, 'Y vi que se había contaminado: un camino era el de ambas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 14, 'Y aumentó sus fornicaciones: pues cuando vió hombres pintados en la pared, imágenes de Caldeos pintadas de color,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 15, 'Ceñidos de talabartes por sus lomos, y tiaras pintadas en sus cabezas, teniendo todos ellos parecer de capitanes, á la manera de los hombres de Babilonia, nacidos en tierra de Caldeos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 16, 'Enamoróse de ellos en viéndolos, y envióles mensajeros á la tierra de los Caldeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 17, 'Y entraron á ella los hombres de Babilonia á la cama de los amores, y contamináronla con su fornicación; y ella también se contaminó con ellos, y su deseo se hartó de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 18, 'Así hizo patentes sus fornicaciones, y descubrió sus vergüenzas: por lo cual mi alma se hartó de ella, como se había ya hartado mi alma de su hermana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 19, 'Aun multiplicó sus fornicaciones trayendo en memoria los días de su mocedad, en los cuales había fornicado en la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 20, 'Y enamoróse de sus rufianes, cuya carne es como carne de asnos, y cuyo flujo como flujo de caballos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 21, 'Así tornaste á la memoria la suciedad de tu mocedad, cuando comprimieron tus pechos en Egipto por los pechos de tu mocedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 22, 'Por tanto, Aholibah, así ha dicho el Señor Jehová: He aquí que yo despierto tus amantes contra ti, de los cuales se hartó tu deseo, y yo les haré venir contra ti en derredor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 23, 'Los de Babilonia, y todos los Caldeos, mayordomos, y príncipes, y capitanes, todos los de Asiria con ellos: mancebos todos ellos de codiciar, capitanes y príncipes, nobles y principales, que montan á caballo todos ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 24, 'Y vendrán sobre ti carros, carretas, y ruedas, y multitud de pueblos. Escudos, y paveses, y capacetes pondrán contra ti en derredor; y yo daré el juicio delante de ellos, y por sus leyes te juzgarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 25, 'Y pondré mi celo contra ti, y obrarán contigo con furor; quitarte han tu nariz y tus orejas; y lo que te quedare caerá á cuchillo. Ellos tomarán tus hijos y tus hijas, y tu residuo será consumido por el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 26, 'Y te desnudarán de tus vestidos, y tomarán los vasos de tu gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 27, 'Y haré cesar de ti tu suciedad, y tu fornicación de la tierra de Egipto: ni más levantarás á ellos tus ojos, ni nunca más te acordarás de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 28, 'Porque así ha dicho el Señor Jehová: He aquí, yo te entrego en mano de aquellos que tú aborreciste, en mano de aquellos de los cuales se hartó tu deseo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 29, 'Los cuales obrarán contigo con odio, y tomarán todo lo que tú trabajaste, y te dejarán desnuda y descubierta: y descubriráse la torpeza de tus fornicaciones, y tu suciedad, y tus fornicaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 30, 'Estas cosas se harán contigo, porque fornicaste en pos de las gentes, con las cuales te contaminaste en sus ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 31, 'En el camino de tu hermana anduviste: yo pues pondré su cáliz en tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 32, 'Así ha dicho el Señor Jehová: Beberás el hondo y ancho cáliz de tu hermana; de ti se mofarán las gentes, y te escarnecerán: de grande cabida es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 33, 'Serás llena de embriaguez y de dolor por el cáliz de soledad y de asolamiento, por el cáliz de tu hermana Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 34, 'Lo beberás pues, y lo agotarás, y quebrarás sus tiestos; y tus pechos arrancarás; porque yo he hablado, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 35, 'Por tanto, así ha dicho el Señor Jehová: Por cuanto te has olvidado de mí, y me has echado tras tus espaldas, por eso, lleva tú también tu suciedad y tus fornicaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 36, 'Y díjome Jehová: Hijo del hombre, ¿no juzgarás tú á Aholah, y á Aholibah, y les denunciarás sus abominaciones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 37, 'Porque han adulterado, y hay sangre en sus manos, y han fornicado con sus ídolos; y aun sus hijos que me habían engendrado, hicieron pasar por el fuego, quemándolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 38, 'Aun esto más me hicieron: contaminaron mi santuario en aquel día, y profanaron mis sábados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 39, 'Pues habiendo sacrificado sus hijos á sus ídolos, entrábanse en mi santuario el mismo día para contaminarlo: y he aquí, así hicieron en medio de mi casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 40, 'Y cuanto más, que enviaron por hombres que vienen de lejos, á los cuales había sido enviado mensajero: y he aquí vinieron; y por amor de ellos te lavaste, y alcoholaste tus ojos, y te ataviaste con adornos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 41, 'Y te sentaste sobre suntuoso estrado, y fué adornada mesa delante de él, y sobre ella pusiste mi perfume y mi óleo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 42, 'Y oyóse en ella voz de compañía en holganza: y con los varones fueron traídos de la gente común los Sabeos del desierto; y pusieron manillas sobre sus manos, y coronas de gloria sobre sus cabezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 43, 'Y dije á la envejecida en adulterios: Sus prostituciones cumplirán ellos ahora, y ella con ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 44, 'Porque han venido á ella como quien viene á mujer ramera: así vinieron á Aholah y á Aholibah, mujeres depravadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 45, 'Por tanto, hombres justos las juzgarán por la ley de las adúlteras, y por la ley de las que derraman sangre: porque son adúlteras, y sangre hay en sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 46, 'Por lo que así ha dicho el Señor Jehová: Yo haré subir contra ellas compañías, las entregaré á turbación y á rapiña:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 47, 'Y la compañía de gentes las apedreará con piedras, y las acuchillará con sus espadas: matarán á sus hijos y á sus hijas, y sus casas consumirán con fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 48, 'Y haré cesar la depravación de la tierra, y escarmentarán todas las mujeres, y no harán según vuestra torpeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 23, 49, 'Y sobre vosotras pondrán vuestra obscenidad, y llevaréis los pecados de vuestros ídolos; y sabréis que yo soy el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 1, 'Y FUÉ á mí palabra de Jehová en el noveno año, en el mes décimo, á los diez del mes, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 2, 'Hijo del hombre, escríbete el nombre de este día: el rey de Babilonia se puso sobre Jerusalem este mismo día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 3, 'Y habla á la casa de rebelión por parábola, y diles: Así ha dicho el Señor Jehová: Pon una olla, ponla, y echa también en ella agua:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 4, 'Junta sus piezas en ella; todas buenas piezas, pierna y espalda; hínchela de huesos escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 5, 'Toma una oveja escogida; y también enciende los huesos debajo de ella; haz que hierva bien; coced también sus huesos dentro de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 6, 'Pues así ha dicho el Señor Jehová: ¡Ay de la ciudad de sangres, de la olla no espumada, y cuya espuma no salió de ella! Por sus piezas, por sus piezas sácala; no caiga sobre ella suerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 7, 'Porque su sangre fué en medio de ella: sobre una piedra alisada la puso; no la derramó sobre la tierra para que fuese cubierta con polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 8, 'Habiendo, pues, hecho subir la ira para hacer venganza, yo pondré su sangre sobre la dura piedra, para que no sea cubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 9, 'Por tanto, así ha dicho el Señor Jehová: ¡Ay de la ciudad de sangres! Pues también haré yo gran hoguera,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 10, 'Multiplicando la leña, encendiendo el fuego, para consumir la carne, y hacer la salsa; y los huesos serán quemados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 11, 'Asentando después la olla vacía sobre sus brasas, para que se caldee, y se queme su fondo, y se funda en ella su suciedad, y se consuma su espuma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 12, 'En fraude se cansó, y no salió de ella su mucha espuma. En fuego será su espuma consumida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 13, 'En tu suciedad perversa padecerás: porque te limpié, y tú no te limpiaste de tu suciedad: nunca más te limpiarás, hasta que yo haga reposar mi ira sobre ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 14, 'Yo Jehová he hablado; vendrá, y harélo. No me tornaré atrás, ni tendré misericordia, ni me arrepentiré: según tus caminos y tus obras te juzgarán, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 15, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 16, 'Hijo del hombre, he aquí que yo te quito de golpe el deseo de tus ojos: no endeches, ni llores, ni corran tus lágrimas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 17, 'Reprime el suspirar, no hagas luto de mortuorios: ata tu bonete sobre ti, y pon tus zapatos en tus pies, y no te cubras con rebozo, ni comas pan de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 18, 'Y hablé al pueblo por la mañana, y á la tarde murió mi mujer: y á la mañana hice como me fué mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 19, 'Y díjome el pueblo: ¿No nos enseñarás qué nos significan estas cosas que tú haces?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 20, 'Y yo les dije: Palabra de Jehová fué á mí, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 21, 'Di á la casa de Israel: Así ha dicho el Señor Dios: He aquí yo profano mi santuario, la gloria de vuestra fortaleza, el deseo de vuestros ojos, y el regalo de vuestra alma: vuestros hijos y vuestras hijas que dejasteis, caerán á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 22, 'Y haréis de la manera que yo hice: no os cubriréis con rebozo, ni comeréis pan de hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 23, 'Y vuestros bonetes estarán sobre vuestras cabezas, y vuestros zapatos en vuestros pies: no endecharéis ni lloraréis, sino que os consumiréis á causa de vuestras maldades, y gemiréis unos con otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 24, 'Ezequiel pues os será por señal; según todas las cosas que él hizo, haréis: en viniendo esto, entonces sabréis que yo soy el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 25, 'Y tú, hijo del hombre, el día que yo quitaré de ellos su fortaleza, el gozo de su gloria, el deseo de sus ojos, y el cuidado de sus almas, sus hijos y sus hijas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 26, 'Este día vendrá á ti un escapado para traer las nuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 24, 27, 'En aquel día se abrirá tu boca para hablar con el escapado, y hablarás, y no estarás más mudo; y les serás por señal, y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 2, 'Hijo del hombre, pon tu rostro hacia los hijos de Ammón, y profetiza sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 3, 'Y dirás á los hijos de Ammón: Oid palabra del Señor Jehová: Así ha dicho el Señor Jehová: Por cuanto dijiste ¡Ea! acerca de mi santuario que fué profanado, y sobre la tierra de Israel que fué asolada, y sobre la casa de Judá, porque fueron en cautiverio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 4, 'Por tanto, he aquí, yo te entrego á los Orientales por heredad, y pondrán en ti sus apriscos, y colocarán en ti sus tiendas: ellos comerán tus sementeras, y beberán tu leche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 5, 'Y pondré á Rabba por habitación de camellos, y á los hijos de Ammón por majada de ovejas; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 6, 'Porque así ha dicho el Señor Jehová: Por cuanto tú batiste tus manos, y pateaste, y te gozaste del alma en todo tu menosprecio sobre la tierra de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 7, 'Por tanto, he aquí yo extenderé mi mano sobre ti, y te entregaré á las gentes para ser saqueada; y yo te cortaré de entre los pueblos, y te destruiré de entre las tierras: te raeré; y sabrás que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 8, 'Así ha dicho el Señor Jehová: Por cuanto dijo Moab y Seir: He aquí la casa de Judá es como todas las gentes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 9, 'Por tanto, he aquí yo abro el lado de Moab desde las ciudades, desde sus ciudades que están en su confín, las tierras deseables de Beth-jesi-moth, y Baal-meón, y Chîriathaim,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 10, 'A los hijos del oriente contra los hijos de Ammón; y entregaréla por heredad para que no haya más memoria de los hijos de Ammón entre las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 11, 'También en Moab haré juicios; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 12, 'Así ha dicho el Señor Jehová: Por lo que hizo Edom tomando venganza de la casa de Judá, pues delinquieron en extremo, y se vengaron de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 13, 'Por tanto, así ha dicho el Señor Jehová: Yo también extenderé mi mano sobre Edom, y talaré de ella hombres y bestias, y la asolaré: desde Temán y Dedán caerán á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 14, 'Y pondré mi venganza en Edom por la mano de mi pueblo Israel; y harán en Edom según mi enojo y según mi ira: y conocerán mi venganza, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 15, 'Así ha dicho el Señor Jehová: Por lo que hicieron los Palestinos con venganza, cuando se vengaron con despecho de ánimo, destruyendo por antiguas enemistades;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 16, 'Por tanto, así ha dicho Jehová: He aquí yo extiendo mi mano sobre los Palestinos, y talaré los Ceretheos, y destruiré el resto de la ribera de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 25, 17, 'Y haré en ellos grandes venganzas con reprensiones de ira; y sabrán que yo soy Jehová, cuando diere mi venganza en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 1, 'Y ACONTECIO en el undécimo año, en el primero del mes, que fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 2, 'Hijo del hombre, por cuanto dijo Tiro sobre Jerusalem: Ea, bien: quebrantada es la que era puerta de las naciones: á mí se volvió: seré llena; ella desierta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 3, 'Por tanto, así ha dicho el Señor Jehová: He aquí yo contra ti, oh Tiro, y haré subir contra ti muchas gentes, como la mar hace subir sus ondas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 4, 'Y demolerán los muros de Tiro, y derribarán sus torres: y raeré de ella su polvo, y la dejaré como una peña lisa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 5, 'Tendedero de redes será en medio de la mar, porque yo he hablado, dice el Señor Jehová: y será saqueada de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 6, 'Y sus hijas que están en el campo, serán muertas á cuchillo; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 7, 'Porque así ha dicho el Señor Jehová: He aquí que del aquilón traigo yo contra Tiro á Nabucodonosor, rey de Babilonia, rey de reyes, con caballos, y carros, y caballeros, y compañías, y mucho pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 8, 'Tus hijas que están en el campo matará á cuchillo; y pondrá contra ti ingenios, y fundará contra ti baluarte, y afirmará contra ti escudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 9, 'Y pondrá contra ella arietes, contra tus muros, y tus torres destruirá con sus martillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 10, 'Por la multitud de sus caballos te cubrirá el polvo de ellos: con el estruendo de los caballeros, y de las ruedas, y de los carros, temblarán tus muros, cuando entrare por tus puertas como por portillos de ciudad destruída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 11, 'Con las uñas de sus caballos hollará todas tus calles; á tu pueblo matará á cuchillo, y las estatuas de tu fortaleza caerán á tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 12, 'Y robarán tus riquezas, y saquearán tus mercaderías: y arruinarán tus muros, y tus casas preciosas destruirán; y pondrán tus piedras y tu madera y tu polvo en medio de las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 13, 'Y haré cesar el estrépito de tus canciones, y no se oirá más el son de tus vihuelas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 14, 'Y te pondré como una peña lisa: tendedero de redes serás; ni nunca más serás edificada: porque yo Jehová he hablado, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 15, 'Así ha dicho el Señor Jehová á Tiro: ¿No se estremecerán las islas al estruendo de tu caída, cuando gritarán los heridos, cuando se hará la matanza en medio de ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 16, 'Entonces todos los príncipes de la mar descenderán de sus sillas, y se quitarán sus mantos, y desnudarán sus bordadas ropas: de espanto se vestirán, sentaránse sobre la tierra, y temblarán á cada momento, y estarán sobre ti atónitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 17, 'Y levantarán sobre ti endechas, y te dirán: ¿Cómo pereciste tú, poblada en los mares, ciudad que fué alabada, que fué fuerte en la mar, ella y sus habitantes, que ponían su espanto á todos sus moradores?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 18, 'Ahora se estremecerán las islas en el día de tu caída, sí, las islas que están en la mar se espantarán de tu éxito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 19, 'Porque así ha dicho el Señor Jehová: Yo te tornaré ciudad asolada, como las ciudades que no se habitan; haré subir sobre ti el abismo, y las muchas aguas te cubrirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 20, 'Y te haré descender con los que descienden al sepulcro, con el pueblo del siglo: y te pondré en lo más bajo de la tierra, como los desiertos antiguos, con los que descienden al sepulcro, para que nunca más seas poblada; y yo daré gloria en la tierra de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 26, 21, 'Yo te tornaré en espanto, y no serás: y serás buscada, y nunca más serás hallada, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 2, 'Y tú, hijo del hombre, levanta endechas sobre Tiro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 3, 'Y dirás á Tiro, que está asentada á las entradas de la mar, mercadera de los pueblos de muchas islas: Así ha dicho el Señor Jehová: Tiro, tú has dicho: Yo soy de perfecta hermosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 4, 'En el corazón de las mares están tus términos: los que te edificaron completaron tu belleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 5, 'De hayas del monte Senir te fabricaron todas las tillas: tomaron cedros del Líbano para hacerte el mástil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 6, 'De castaños de Basán hicieron tus remos: compañía de Asirios hicieron tus bancos de marfil de las islas de Chittim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 7, 'De fino lino bordado de Egipto fué tu cortina, para que te sirviese de vela; de cárdeno y grana de las islas de Elisah fué tu pabellón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 8, 'Los moradores de Sidón y de Arvad fueron tus remeros: tus sabios, oh Tiro, estaban en ti; ellos fueron tus pilotos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 9, 'Los ancianos de Gebal y sus sabios repararon tus hendiduras: todas las galeras de la mar y los remeros de ellas fueron en ti para negociar tus negocios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 10, 'Persas y Lidios, y los de Phut, fueron en tu ejército tus hombres de guerra: escudos y capacetes colgaron en ti; ellos te dieron tu honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 11, 'Y los hijos de Arvad con tu ejército estuvieron sobre tus muros alrededor, y los Gammadeos en tus torres: sus escudos colgaron sobre tus muros alrededor; ellos completaron tu hermosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 12, 'Tarsis tu mercadera á causa de la multitud de todas riquezas en plata, hierro, estaño, y plomo, dió en tus ferias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 13, 'Grecia, Tubal, y Mesec, tus mercaderes, con hombres y con vasos de metal, dieron en tus ferias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 14, 'De la casa de Togarma, caballos y caballeros y mulos, dieron en tu mercado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 15, 'Los hijos de Dedán eran tus negociantes: muchas islas tomaban mercadería de tu mano; cuernos de marfil y pavos te dieron en presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 16, 'Siria fué tu mercadera por la multitud de tus labores: con perlas, y púrpura, y vestidos bordados, y linos finos, y corales, y rubíes, dió en tus ferias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 17, 'Judá, y la tierra de Israel, eran tus mercaderes: con trigos de Minith, y pannah, y miel, y aceite, y resina, dieron en tu mercado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 18, 'Damasco, tu mercadera por la multitud de tus labores, por la abundancia de todas riquezas, con vino de Helbón, y lana blanca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 19, 'Asimismo Dan y el errante Javán dieron en tus ferias, para negociar en tu mercado de hierro labrado, mirra destilada, y caña aromática.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 20, 'Dedán fué tu mercadera con paños preciosos para carros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 21, 'Arabia y todos los príncipes de Cedar, mercaderes de tu mano en corderos, y carneros, y machos cabríos: en estas cosas fueron tus mercaderes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 22, 'Los mercaderes de Seba y de Raama fueron tus mercaderes: con lo principal de toda especiería, y toda piedra preciosa, y oro, dieron en tus ferias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 23, 'Harán, y Canneh, y Edén, los mercaderes de Seba, de Asiria, y Chilmad, contigo contrataban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 24, 'Estos tus mercaderes negociaban contigo en varias cosas: en mantos de jacinto, y bordados, y en cajas de ropas preciosas, enlazadas con cordones, y en madera de cedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 25, 'Las naves de Tarsis, tus cuadrillas, fueron en tu negociación: y fuiste llena, y fuiste multiplicada en gran manera en medio de los mares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 26, 'En muchas aguas te engolfaron tus remeros: viento solano te quebrantó en medio de los mares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 27, 'Tus riquezas, y tus mercaderías, y tu negociación, tus remeros, y tus pilotos, los reparadores de tus hendiduras, y los agentes de tus negocios, y todos tus hombres de guerra que hay en ti, con toda tu compañía que en medio de ti se halla, caerán en medio de los mares el día de tu caída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 28, 'Al estrépito de las voces de tus marineros temblarán los arrabales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 29, 'Y descenderán de sus naves todos los que toman remo; remeros, y todos los pilotos de la mar se pararán en tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 30, 'Y harán oir su voz sobre ti, y gritarán amargamente, y echarán polvo sobre sus cabezas, y se revolcarán en la ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 31, 'Y haránse por ti calva, y se ceñirán de sacos, y endecharán por ti endechas amargas, con amargura de alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 32, 'Y levantarán sobre ti endechas en sus lamentaciones, y endecharán sobre ti diciendo: ¿Quién como Tiro, como la destruída en medio de la mar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 33, 'Cuando tus mercaderías salían de las naves, hartabas muchos pueblos: los reyes de la tierra enriqueciste con la multitud de tus riquezas y de tus contrataciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 34, 'En el tiempo que serás quebrantada de los mares en los profundos de las aguas, tu comercio y toda tu compañía caerán en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 35, 'Todos los moradores de las islas se maravillarán sobre ti, y sus reyes temblarán de espanto: inmutaránse en sus rostros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 27, 36, 'Los mercaderes en los pueblos silbarán sobre ti: vendrás á ser espanto, y dejarás de ser para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 2, 'Hijo del hombre, di al príncipe de Tiro: Así ha dicho el Señor Jehová: Por cuanto se enalteció tu corazón y dijiste: Yo soy un dios; en la silla de Dios estoy sentado en medio de los mares (siendo tú hombre y no Dios); y has puesto tu corazón como corazón de Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 3, 'He aquí que tú eres más sabio que Daniel; no hay secreto que te sea oculto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 4, 'Con tu sabiduría y con tu prudencia te has juntado riquezas, y has adquirido oro y plata en tus tesoros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 5, 'Con la grandeza de tu sabiduría en tu contratación has multiplicado tus riquezas; y á causa de tus riquezas se ha enaltecido tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 6, 'Por tanto, así ha dicho el Señor Jehová: Por cuanto pusiste tu corazón como corazón de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 7, 'Por tanto, he aquí yo traigo sobre ti extraños, los fuertes de las gentes, que desenvainarán su espadas contra la hermosura de tu sabiduría, y ensuciarán tu esplendor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 8, 'A la huesa te harán descender, y morirás de las muertes de los que mueren en medio de los mares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 9, '¿Hablarás delante de tu matador, diciendo: Yo soy Dios? Tú, hombre eres, y no Dios, en la mano de tu matador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 10, 'De muerte de incircuncisos morirás por mano de extraños: porque yo he hablado, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 11, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 12, 'Hijo del hombre, levanta endechas sobre el rey de Tiro, y dile: Así ha dicho el Señor Jehová: Tú echas el sello á la proporción, lleno de sabiduría, y acabado de hermosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 13, 'En Edén, en el huerto de Dios estuviste: toda piedra preciosa fué tu vestidura; el sardio, topacio, diamante, crisólito, onique, y berilo, el zafiro, carbunclo, y esmeralda, y oro, los primores de tus tamboriles y pífanos estuvieron apercibidos para ti en el día de tu creación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 14, 'Tú, querubín grande, cubridor: y yo te puse; en el santo monte de Dios estuviste; en medio de piedras de fuego has andado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 15, 'Perfecto eras en todos tus caminos desde el día que fuiste criado, hasta que se halló en ti maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 16, 'A causa de la multitud de tu contratación fuiste lleno de iniquidad, y pecaste: por lo que yo te eché del monte de Dios, y te arrojé de entre las piedras del fuego, oh querubín cubridor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 17, 'Enaltecióse tu corazón á causa de tu hermosura, corrompiste tu sabiduría á causa de tu resplandor: yo te arrojaré por tierra; delante de los reyes te pondré para que miren en ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 18, 'Con la multitud de tus maldades, y con la iniquidad de tu contratación ensuciaste tu santuario: yo pues saqué fuego de en medio de ti, el cual te consumió, y púsete en ceniza sobre la tierra á los ojos de todos los que te miran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 19, 'Todos los que te conocieron de entre los pueblos, se maravillarán sobre ti: en espanto serás, y para siempre dejarás de ser.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 20, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 21, 'Hijo del hombre, pon tu rostro hacia Sidón, y profetiza contra ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 22, 'Y dirás: Así ha dicho el Señor Jehová: He aquí yo contra ti, oh Sidón, y en medio de ti seré glorificado: y sabrán que yo soy Jehová, cuando hiciere en ella juicios, y en ella me santificare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 23, 'Y enviaré á ella pestilencia y sangre en sus plazas; y caerán muertos en medio de ella; con espada contra ella alrededor; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 24, 'Y nunca más será á la casa de Israel espino que le punce, ni espanto que le dé dolor, en todos los alrededores de los que los menosprecian; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 25, 'Así ha dicho el Señor Jehová: Cuando juntaré la casa de Israel de los pueblos entre los cuales están esparcidos, entonces me santificaré en ellos á los ojos de las gentes, y habitarán en su tierra, la cual dí á mi siervo Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 28, 26, 'Y habitarán en ella seguros, y edificarán casas, y plantarán viñas, y habitarán confiadamente, cuando yo haré juicios en todos los que los despojan en sus alrededores; y sabrán que yo soy Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 1, 'EN el año décimo, en el mes décimo, á los doce del mes, fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 2, 'Hijo del hombre, pon tu rostro contra Faraón rey de Egipto, y profetiza contra él y contra todo Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 3, 'Habla, y di: Así ha dicho el Señor Jehová: He aquí yo contra ti, Faraón rey de Egipto, el gran dragón que yace en medio de sus ríos, el cual dijo: Mío es mi río, y yo me lo hice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 4, 'Yo pues, pondré anzuelos en tus mejillas, y pegaré los peces de tus ríos á tus escamas, y te sacaré de en medio de tus ríos, y todos los peces de tus ríos saldrán pegados á tus escamas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 5, 'Y dejaréte en el desierto, á ti y á todos los peces de tus ríos: sobre la haz del campo caerás; no serás recogido, ni serás juntado: á las bestias de la tierra y á las aves del cielo te he dado por comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 6, 'Y sabrán todos los moradores de Egipto que yo soy Jehová, por cuanto fueron bordón de caña á la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 7, 'Cuando te tomaron con la mano, te quebraste, y les rompiste todo el hombro: y cuando se recostaron sobre ti, te quebraste, y los deslomaste enteramente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 8, 'Por tanto, así ha dicho el Señor Jehová: He aquí que yo traigo contra ti espada, y talaré de ti hombres y bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 9, 'Y la tierra de Egipto será asolada y desierta: y sabrán que yo soy Jehová: porque dijo: Mi río, y yo lo hice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 10, 'Por tanto, he aquí yo contra ti, y contra tus ríos; y pondré la tierra de Egipto en asolamientos de la soledad del desierto, desde Migdol hasta Seveneh, hasta el término de Etiopía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 11, 'No pasará por ella pie de hombre, ni pie de bestia pasará por ella; ni será habitada por cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 12, 'Y pondré á la tierra de Egipto en soledad entre las tierras asoladas, y sus ciudades entre las ciudades destruidas estarán asoladas por cuarenta años: y esparciré á Egipto entre las gentes, y aventarélos por las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 13, 'Porque así ha dicho el Señor Jehová: Al fin de cuarenta años juntaré á Egipto de los pueblos entre los cuales fueren esparcidos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 14, 'Y tornaré á traer los cautivos de Egipto, y los volveré á la tierra de Patros, á la tierra de su habitación; y allí serán un reino bajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 15, 'En comparación de los otros reinos será humilde; ni más se alzará sobre las gentes: porque yo los disminuiré, para que no se enseñoreen en las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 16, 'Y no será más á la casa de Israel por confianza, que haga acordar el pecado, mirando en pos de ellos; y sabrán que yo soy el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 17, 'Y aconteció en el año veinte y siete, en el mes primero, al primero del mes, que fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 18, 'Hijo del hombre, Nabucodonosor rey de Babilonia hizo á su ejército prestar grande servicio contra Tiro. Toda cabeza se encalveció, y pelóse todo hombro; y ni para él ni para su ejército hubo paga de Tiro, por el servicio que prestó contra ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 19, 'Por tanto, así ha dicho el Señor Jehová: He aquí que yo doy á Nabucodonosor, rey de Babilonia, la tierra de Egipto; y él tomará su multitud, y cogerá sus despojos, y arrebatará su presa, y habrá paga para su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 20, 'Por su trabajo con que sirvió contra ella le he dado la tierra de Egipto: porque trabajaron por mí, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 29, 21, 'En aquel tiempo haré reverdecer el cuerno á la casa de Israel, y te daré apertura de boca en medio de ellos; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 2, 'Hijo del hombre, profetiza, y di: Así ha dicho el Señor Jehová: Aullad: ¡Ay del día!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 3, 'Porque cerca está el día, cerca está el día del Señor; día de nublado, día de las gentes será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 4, 'Y vendrá espada á Egipto, y habrá miedo en Etiopía, cuando caerán heridos en Egipto; y tomarán su multitud, y serán destruídos sus fundamentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 5, 'Etiopía, y Libia, y Lidia, y todo el conjunto de pueblo, y Chûb, y los hijos de la tierra de la liga, caerán con ellos á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 6, 'Así ha dicho Jehová: También caerán los que sostienen á Egipto, y la altivez de su fortaleza caerá: desde Migdol hasta Seveneh caerán en él á cuchillo, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 7, 'Y serán asolados entre las tierras asoladas, y sus ciudades serán entre las ciudades desiertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 8, 'Y sabrán que yo soy Jehová, cuando pusiere fuego á Egipto, y fueren quebrantados todos sus ayudadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 9, 'En aquel tiempo saldrán mensajeros de delante de mí en navíos, á espantar á Etiopía la confiada, y tendrán espanto como en el día de Egipto: porque he aquí viene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 10, 'Así ha dicho el Señor Jehová: Haré cesar la multitud de Egipto por mano de Nabucodonosor, rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 11, 'El, y con él su pueblo, los más fuertes de las gentes, serán traídos á destruir la tierra: y desenvainarán sus espadas sobre Egipto, y henchirán la tierra de muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 12, 'Y secaré los ríos, y entregaré la tierra en manos de malos, y destruiré la tierra y su plenitud por mano de extranjeros: yo Jehová he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 13, 'Así ha dicho el Señor Jehová: Destruiré también las imágenes, y haré cesar los ídolos de Memphis; y no habrá más príncipe de la tierra de Egipto, y en la tierra de Egipto pondré temor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 14, 'Y asolaré á Patros, y pondré fuego á Zoán, y haré juicios en No.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 15, 'Y derramaré mi ira sobre Sin, fortaleza de Egipto, y talaré la multitud de No.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 16, 'Y pondré fuego á Egipto; Sin tendrá gran dolor, y No será destrozada, y Memphis tendrá continuas angustias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 17, 'Los mancebos de Avén y de Pibeseth caerán á cuchillo; y ellas irán en cautiverio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 18, 'Y en Tehaphnes será cerrado el día, cuando quebrantaré yo allí las barras de Egipto, y cesará en ella la soberbia de su fortaleza: nublado la cubrirá, y los moradores de sus aldeas irán en cautiverio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 19, 'Haré pues juicios en Egipto y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 20, 'Y aconteció en el año undécimo, en el mes primero, á los siete del mes, que fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 21, 'Hijo del hombre, quebrantado he el brazo de Faraón rey de Egipto; y he aquí que no ha sido vendado poniéndo le medicinas, poniéndole faja para ligarlo, á fin de vigorizarle para que pueda tener espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 22, 'Por tanto, así ha dicho el Señor Jehová: Heme aquí contra Faraón rey de Egipto, y quebraré sus brazos, el fuerte y el fracturado, y haré que la espada se le caiga de la mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 23, 'Y esparciré los Egipcios entre las gentes, y aventarélos por las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 24, 'Y fortificaré los brazos del rey de Babilonia, y pondré mi espada en su mano; mas quebraré los brazos de Faraón, y delante de aquél gemirá con gemidos de herido de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 25, 'Fortificaré pues los brazos del rey de Babilonia, y los brazos de Faraón caerán; y sabrán que yo soy Jehová, cuando yo pusiere mi espada en la mano del rey de Babilonia, y él la extendiere sobre la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 30, 26, 'Y esparciré los Egipcios entre las gentes, y los aventaré por las tierras; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 1, 'Y ACONTECIO en el año undécimo, en el mes tercero, al primero del mes, que fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 2, 'Hijo del hombre, di á Faraón rey de Egipto, y á su pueblo: ¿A quién te comparaste en tu grandeza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 3, 'He aquí era el Asirio cedro en el Líbano, hermoso en ramas, y umbroso con sus ramos, y de grande altura, y su copa estaba entre densas ramas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 4, 'Las aguas lo hicieron crecer, encumbrólo el abismo: sus ríos iban alrededor de su pie, y á todos los árboles del campo enviaba sus corrientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 5, 'Por tanto, se encumbró su altura sobre todos los árboles del campo, y multiplicáronse sus ramos, y á causa de las muchas aguas se alargaron sus ramas que había echado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 6, 'En sus ramas hacían nido todas las aves del cielo, y debajo de su ramaje parían todas las bestias del campo, y á su sombra habitaban muchas gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 7, 'Hízose, pues, hermoso en su grandeza con la extensión de sus ramas; porque su raíz estaba junto á muchas aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 8, 'Los cedros no lo cubrieron en el huerto de Dios: las hayas no fueron semejantes á sus ramas, ni los castaños fueron semejantes á sus ramos: ningún árbol en el huerto de Dios fué semejante á él en su hermosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 9, 'Hícelo hermoso con la multitud de sus ramas; y todos los árboles de Edén, que estaban en el huerto de Dios, tuvieron de él envidia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 10, 'Por tanto, así dijo el Señor Jehová: Por cuanto te encumbraste en altura, y puso su cumbre entre densas ramas, y su corazón se elevó con su altura,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 11, 'Yo lo entregaré en mano del fuerte de las gentes, que de cierto le manejará: por su impiedad lo he arrojado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 12, 'Y le cortarán extraños, los fuertes de las gentes, y lo abandonarán: sus ramas caerán sobre los montes y por todos los valles, y por todas las arroyadas de la tierra serán quebrados sus ramos; é iránse de su sombra todos los pueblos de la tierra, y lo dejarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 13, 'Sobre su ruina habitarán todas las aves del cielo, y sobre su ramas estarán todas las bestias del campo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 14, 'Para que no se eleven en su altura los árboles todos de las aguas, ni levanten su cumbre entre las espesuras, ni en sus ramas se paren por su altura todos los que beben aguas: porque todos serán entregados á muerte, á la tierra baja, en medio de los hijos de los hombres, con los que descienden á la huesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 15, 'Así ha dicho el Señor Jehová: El día que descendió á la sepultura, hice hacer luto, hice cubrir por él el abismo, y detuve sus ríos, y las muchas aguas fueron detenidas: y al Líbano cubrí de tinieblas por él, y todos los árboles del campo se desmayaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 16, 'Del estruendo de su caída hice temblar las gentes, cuando les hice descender á la fosa con todos los que descienden á la sepultura; y todos los árboles de Edén escogidos, y los mejores del Líbano, todos los que beben aguas, tomaron consolación en la tierra baja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 17, 'También ellos descendieron con él á la fosa, con los muertos á cuchillo, los que fueron su brazo, los que estuvieron á su sombra en medio de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 31, 18, '¿A quién te has comparado así en gloria y en grandeza entre los árboles de Edén? Pues derrribado serás con los árboles de Edén en la tierra baja: entre los incircuncisos yacerás, con los muertos á cuchillo. Este es Faraón y todo su pueblo, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 1, 'Y ACONTECIO en el año duodécimo, en el mes duodécimo, al primero del mes, que fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 2, 'Hijo del hombre, levanta endechas sobre Faraón rey de Egipto, y dile: A leoncillo de gentes eres semejante, y eres como la ballena en los mares: que secabas tus ríos, y enturbiabas las aguas con tus pies, y hollabas sus riberas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 3, 'Así ha dicho el Señor Jehová: Yo extenderé sobre ti mi red con reunión de muchos pueblos, y te harán subir con mi esparavel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 4, 'Y te dejaré en tierra, te echaré sobre la haz del campo, y haré que se asienten sobre ti todas las aves del cielo, y hartaré de ti las bestias de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 5, 'Y pondré tus carnes sobre los montes, y henchiré los valles de tu altura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 6, 'Y regaré de tu sangre la tierra donde nadas, hasta los montes; y los arroyos se henchirán de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 7, 'Y cuando te habré muerto, cubriré los cielos, y haré entenebrecer sus estrellas: el sol cubriré con nublado, y la luna no hará resplandecer su luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 8, 'Todas las lumbreras de luz haré entenebrecer en el cielo por ti, y pondré tinieblas sobre tu tierra, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 9, 'Y entristeceré el corazón de muchos pueblos, cuando llevaré tu quebrantamiento sobre las gentes, por las tierras que no conociste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 10, 'Y haré atónitos sobre ti muchos pueblos, y sus reyes tendrán á causa de ti horror grande, cuando haré resplandecer mi espada delante de sus rostros, y todos se sobresaltarán en sus ánimos á cada momento en el día de tu caída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 11, 'Porque así ha dicho el Señor Jehová: La espada del rey de Babilonia vendrá sobre ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 12, 'Con espadas de fuertes haré caer tu pueblo; todos ellos serán los fuertes de las gentes: y destruirán la soberbia de Egipto, y toda su multitud será deshecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 13, 'Todas sus bestias destruiré de sobre las muchas aguas: ni más las enturbiará pie de hombre, ni uña de bestias las enturbiarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 14, 'Entonces haré asentarse sus aguas, y haré ir sus ríos como aceite, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 15, 'Cuando asolaré la tierra de Egipto, y la tierra fuere asolada de su plenitud, cuando heriré á todos los que en ella moran, sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 16, 'Esta es la endecha, y cantarla han: las hijas de las gentes la cantarán: endecharán sobre Egipto, y sobre toda su multitud, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 17, 'Y aconteció en el año duodécimo, á los quince del mes, que fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 18, 'Hijo del hombre, endecha sobre la multitud de Egipto, y despéñalo á él, y á las villas de las gentes fuertes, en la tierra de los profundos, con los que descienden á la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 19, 'Porque eres tan hermoso, desciende, y yace con los incircuncisos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 20, 'Entre los muertos á cuchillo caerán: al cuchillo es entregado: traedlo á él y á todos sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 21, 'De en medio del infierno hablarán á él los fuertes de los fuertes, con los que le ayudaron, que descendieron, y yacen con los incircuncisos muertos á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 22, 'Allí Assur con toda su gente: en derredor de él están sus sepulcros: todos ellos cayeron muertos á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 23, 'Sus sepulcros fueron puestos á los lados de la fosa, y su gente está por los alrededores de su sepulcro: todos ellos cayeron muertos á cuchillo, los cuales pusieron miedo en la tierra de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 24, 'Allí Elam, y toda su multitud por los alrededores de su sepulcro: todos ellos cayeron muertos á cuchillo, los cuales descendieron incircuncisos á los más profundos lugares de la tierra, porque pusieron su terror en la tierra de los vivientes, mas llevaron su confusión con los que descienden al sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 25, 'En medio de los muertos le pusieron cama con toda su multitud: á sus alrededores están sus sepulcros: todos ellos incircuncisos muertos á cuchillo, porque fué puesto su espanto en la tierra de los vivientes, mas llevaron su confusión con los que descienden al sepulcro: él fué puesto en medio de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 26, 'Allí Mesech, y Tubal, y toda su multitud: sus sepulcros en sus alrededores: todos ellos incircuncisos muertos á cuchillo, porque habían dado su terror en la tierra de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 27, 'Y no yacerán con los fuertes que cayeron de los incircuncisos, los cuales descendieron al sepulcro con sus armas de guerra, y pusieron sus espadas debajo de sus cabezas: mas sus pecados estarán sobre sus huesos, porque fueron terror de fuertes en la tierra de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 28, 'Tú pues serás quebrantado entre los incircuncisos, y yacerás con los muertos á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 29, 'Allí Idumea, sus reyes y todos sus príncipes, los cuales con su fortaleza fueron puestos con los muertos á cuchillo: ellos yacerán con los incircuncisos, y con los que descienden al sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 30, 'Allí los príncipes del aquilón, todos ellos, y todos los de Sidón, que con su terror descendieron con los muertos, avergonzados de su fortaleza, yacen también incircuncisos con los muertos á cuchillo, y llevaron su confusión con los que descienden al sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 31, 'A estos verá Faraón, y consolaráse sobre toda su multitud; Faraón muerto á cuchillo, y todo su ejército, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 32, 32, 'Porque yo puse mi terror en la tierra de los vivientes, también yacerá entre los incircuncisos con los muertos á cuchillo, Faraón y toda su multitud, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 2, 'Hijo del hombre, habla á los hijos de tu pueblo, y diles: Cuando trajere yo espada sobre la tierra, y el pueblo de la tierra tomare un hombre de sus términos, y se lo pusiere por atalaya,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 3, 'Y él viere venir la espada sobre la tierra, y tocare corneta, y avisare al pueblo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 4, 'Cualquiera que oyere el sonido de la corneta, y no se apercibiere, y viniendo la espada lo tomare, su sangre será sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 5, 'El sonido de la corneta oyó, y no se apercibió; su sangre será sobre él: mas el que se apercibiere, librará su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 6, 'Pero si el atalaya viere venir la espada, y no tocare la corneta, y el pueblo no se apercibiere, y viniendo la espada, tomare de él alguno; por causa de su pecado fué tomado, mas demandaré su sangre de mano del atalaya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 7, 'Tú pues, hijo del hombre, yo te he puesto por atalaya á la casa de Israel, y oirás la palabra de mi boca, y los apercibirás de mi parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 8, 'Diciendo yo al impío: Impío, de cierto morirás; si tú no hablares para que se guarde el impío de su camino, el impío morirá por su pecado, mas su sangre yo la demandaré de tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 9, 'Y si tú avisares al impío de su camino para que de él se aparte, y él no se apartare de su camino, por su pecado morirá él, y tú libraste tu vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 10, 'Tú pues, hijo del hombre, di á la casa de Israel: Vosotros habéis hablado así, diciendo: Nuestras rebeliones y nuestros pecados están sobre nosotros, y á causa de ellos somos consumidos: ¿cómo pues viviremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 11, 'Diles: Vivo yo, dice el Señor Jehová, que no quiero la muerte del impío, sino que se torne el impío de su camino, y que viva. Volveos, volveos de vuestros caminos: ¿y por qué moriréis, oh casa de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 12, 'Y tú, hijo del hombre, di á los hijos de tu pueblo: La justicia del justo no lo librará el día que se rebelare; y la impiedad del impío no le será estorbo el día que se volviere de su impiedad; y el justo no podrá vivir por su justicia el día que pecare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 13, 'Diciendo yo al justo: De cierto vivirá, y él confiado en su justicia hiciere iniquidad, todas sus justicias no vendrán en memoria, sino que morirá por su iniquidad que hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 14, 'Y diciendo yo al impío: De cierto morirás; si él se volviere de su pecado, é hiciere juicio y justicia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 15, 'Si el impío restituyere la prenda, devolviere lo que hubiere robado, caminare en las ordenanzas de la vida, no haciendo iniquidad, vivirá ciertamente y no morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 16, 'No se le recordará ninguno de sus pecados que había cometido: hizo juicio y justicia; vivirá ciertamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 17, 'Luego dirán los hijos de tu pueblo: No es recta la vía del Señor: la vía de ellos es la que no es recta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 18, 'Cuando el justo se apartare de su justicia, é hiciere iniquidad, morirá por ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 19, 'Y cuando el impío se apartare de su impiedad, é hiciere juicio y justicia, vivirá por ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 20, 'Y dijisteis: No es recta la vía del Señor. Yo os juzgaré, oh casa de Israel, á cada uno conforme á sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 21, 'Y aconteció en el año duodécimo de nuestro cautiverio, en el mes décimo, á los cinco del mes, que vino á mí un escapado de Jerusalem, diciendo: La ciudad ha sido herida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 22, 'Y la mano de Jehová había sido sobre mí la tarde antes que el escapado viniese, y había abierto mi boca, hasta que vino á mí por la mañana; y abrió mi boca, y no más estuve callado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 23, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 24, 'Hijo del hombre, los que habitan aquellos desiertos en la tierra de Israel, hablando dicen: Abraham era uno, y poseyó la tierra: pues nosotros somos muchos; á nosotros es dada la tierra en posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 25, 'Por tanto, diles: Así dicho el Señor Jehová: ¿Con sangre comeréis, y á vuestros ídolos alzaréis vuestros ojos, y sangre derramaréis, y poseeréis vosotros la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 26, 'Estuvisteis sobre vuestras espadas, hicisteis abominación, y contaminasteis cada cual la mujer de su prójimo: ¿y habréis de poseer la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 27, 'Les dirás así: Así ha dicho el Señor Jehová: Vivo yo, que los que están en aquellos asolamientos caerán á cuchillo, y al que está sobre la haz del campo entregaré á las bestias que lo devoren; y los que están en las fortalezas y en las cuevas, de pestilencia morirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 28, 'Y pondré la tierra en desierto y en soledad, y cesará la soberbia de su fortaleza; y los montes de Israel serán asolados, que no haya quien pase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 29, 'Y sabrán que yo soy Jehová, cuando pusiere la tierra en soledad y desierto, por todas las abominaciones que han hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 30, 'Y tú, hijo del hombre, los hijos de tu pueblo se mofan de ti junto á las paredes y á las puertas de las casas, y habla el uno con el otro, cada uno con su hermano, diciendo: Venid ahora, y oid qué palabra sale de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 31, 'Y vendrán á ti como viene el pueblo, y se estarán delante de ti como mi pueblo, y oirán tus palabras, y no las pondrán por obra: antes hacen halagos con sus bocas, y el corazón de ellos anda en pos de su avaricia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 32, 'Y he aquí que tú eres á ellos como cantor de amores, gracioso de voz y que canta bien: y oirán tus palabras, mas no las pondrán por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 33, 33, 'Empero cuando ello viniere (he aquí viene) sabrán que hubo profeta entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 2, 'Hijo del hombre, profetiza contra los pastores de Israel; profetiza, y diles á los pastores: Así ha dicho el Señor Jehová: ¡Ay de los pastores de Israel, que se apacientan á sí mismos! ¿No apacientan los pastores los rebaños?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 3, 'Coméis la leche, y os vestís de la lana: la gruesa degolláis, no apacentáis las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 4, 'No corroborasteis las flacas, ni curasteis la enferma: no ligasteis la perniquebrada, ni tornasteis la amontada, ni buscasteis la perdida; sino que os habéis enseñoreado de ellas con dureza y con violencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 5, 'Y están derramadas por falta de pastor; y fueron para ser comidas de toda bestia del campo, y fueron esparcidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 6, 'Y anduvieron perdidas mis ovejas por todos los montes, y en todo collado alto: y en toda la haz de la tierra fueron derramadas mis ovejas, y no hubo quien buscase, ni quien requiriese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 7, 'Por tanto, pastores, oid palabra de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 8, 'Vivo yo, ha dicho el Señor Jehová, que por cuanto mi rebaño fué para ser robado, y mis ovejas fueron para ser comidas de toda bestia del campo, sin pastor; ni mis pastores buscaron mis ovejas, sino que los pastores se apacentaron á sí mismos, y no apacentaron mis ovejas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 9, 'Por tanto, oh pastores, oid palabra de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 10, 'Así ha dicho el Señor Jehová: He aquí, yo á los pastores; y requeriré mis ovejas de su mano, y haréles dejar de apacentar las ovejas: ni los pastores se apacentarán más á sí mismos; pues yo libraré mis ovejas de sus bocas, y no les serán más por comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 11, 'Porque así ha dicho el Señor Jehová: He aquí, yo, yo requeriré mis ovejas, y las reconoceré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 12, 'Como reconoce su rebaño el pastor el día que está en medio de sus ovejas esparcidas, así reconoceré mis ovejas, y las libraré de todos los lugares en que fueron esparcidas el día del nublado y de la oscuridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 13, 'Y yo las sacaré de los pueblos, y las juntaré de las tierras: y las meteré en su tierra, y las apacentaré en los montes de Israel por las riberas, y en todas las habitaciones del país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 14, 'En buenos pastos las apacentaré, y en los altos montes de Israel será su majada: allí dormirán en buena majada, y en pastos gruesos serán apacentadas sobre los montes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 15, 'Yo apacentaré mis ovejas, y yo les haré tener majada, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 16, 'Yo buscaré la perdida, y tornaré la amontada, y ligaré la perniquebrada, y corroboraré la enferma: mas á la gruesa y á la fuerte destruiré. Yo las apacentaré en juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 17, 'Mas vosotras, ovejas mías, así ha dicho el Señor Jehová: He aquí yo juzgo entre oveja y oveja, entre carneros y machos cabríos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 18, '¿Os es poco que comáis los buenos pastos, sino que holléis con vuestros pies lo que de vuestros pastos queda; y que bebiendo las aguas sentadas, holléis además con vuestros pies las que quedan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 19, 'Y mis ovejas comen lo hollado de vuestros pies, y beben lo que con vuestros pies habéis hollado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 20, 'Por tanto, así les dice el Señor Jehová: He aquí, yo, yo juzgaré entre la oveja gruesa y la oveja flaca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 21, 'Por cuanto rempujasteis con el lado y con el hombro, y acorneasteis con vuestros cuernos á todas las flacas, hasta que las esparcisteis fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 22, 'Yo salvaré á mis ovejas, y nunca más serán en rapiña; y juzgaré entre oveja y oveja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 23, 'Y despertaré sobre ellas un pastor, y él las apacentará; á mi siervo David: él las apacentará, y él les será por pastor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 24, 'Yo Jehová les seré por Dios, y mi siervo David príncipe en medio de ellos. Yo Jehová he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 25, 'Y estableceré con ellos pacto de paz, y haré cesar de la tierra las malas bestias; y habitarán en el desierto seguramente, y dormirán en los bosques.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 26, 'Y daré á ellas, y á los alrededores de mi collado, bendición; y haré descender la lluvia en su tiempo, lluvias de bendición serán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 27, 'Y el árbol del campo dará su fruto, y la tierra dará su fruto, y estarán sobre su tierra seguramente; y sabrán que yo soy Jehová, cuando quebrare las coyundas de su yugo, y los librare de mano de los que se sirven de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 28, 'Y no serán más presa de las gentes, ni las bestias de la tierra las devorarán; sino que habitarán seguramente, y no habrá quien espante;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 29, 'Y despertaréles una planta por nombre, y no más serán consumidos de hambre en la tierra, ni serán más avergonzados de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 30, 'Y sabrán que yo su Dios Jehová soy con ellos, y ellos son mi pueblo, la casa de Israel, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 34, 31, 'Y vosotras, ovejas mías, ovejas de mi pasto, hombres sois, y yo vuestro Dios, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 2, 'Hijo del hombre, pon tu rostro hacia el monte de Seir, y profetiza contra él,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 3, 'Y dile: Así ha dicho el Señor Jehová: He aquí yo contra ti, oh monte de Seir, y extenderé mi mano contra ti, y te pondré en asolamiento y en soledad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 4, 'A tus ciudades asolaré, y tú serás asolado; y sabrás que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 5, 'Por cuanto tuviste enemistades perpetuas, y esparciste los hijos de Israel á poder de espada en el tiempo de su aflicción, en el tiempo extremadamente malo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 6, 'Por tanto, vivo yo, dice el Señor Jehová, que á sangre te diputaré, y sangre te perseguirá: y pues la sangre no aborreciste, sangre te perseguirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 7, 'Y pondré al monte de Seir en asolamiento y en soledad, y cortaré de él pasante y volviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 8, 'Y henchiré sus montes de sus muertos: en tus collados, y en tus valles, y en todos tus arroyos, caerán ellos muertos á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 9, 'Yo te pondré en asolamientos perpetuos, y tus ciudades nunca más se restaurarán; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 10, 'Por cuanto dijiste: Las dos naciones y las dos tierras serán mías, y las poseeremos, estando allí Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 11, 'Por tanto, vivo yo, dice el Señor Jehová, yo haré conforme á tu ira, y conforme á tu celo con que procediste, á causa de tus enemistades con ellos: y seré conocido en ellos, cuando te juzgaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 12, 'Y sabrás que yo Jehová he oído todas tus injurias que proferiste contra los montes de Israel, diciendo: Destruídos son, nos son dados á devorar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 13, 'Y os engrandecisteis contra mí con vuestra boca, y multiplicasteis contra mí vuestras palabras. Yo lo oí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 14, 'Así ha dicho el Señor Jehová: Alegrándose toda la tierra, yo te haré soledad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 35, 15, 'Como te alegraste sobre la heredad de la casa de Israel, porque fué asolada, así te haré á ti: asolado será el monte de Seir, y toda Idumea, toda ella; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 1, 'Y TU, hijo del hombre, profetiza sobre los montes de Israel, y di: Montes de Israel, oid palabra de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 2, 'Así ha dicho el Señor Jehová: Por cuanto el enemigo dijo sobre vosotros: ¡Ea! también las alturas perpetuas nos han sido por heredad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 3, 'Profetiza por tanto, y di: Así ha dicho el Señor Jehová: Pues por cuanto asolándoos y tragándoos de todas partes, para que fueseis heredad á las otras gentes, se os ha hecho andar en boca de lenguas, y ser el oprobio de los pueblos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 4, 'Por tanto, montes de Israel, oid palabra del Señor Jehová: Así ha dicho el Señor Jehová á los montes y á los collados, á los arroyos y á los valles, á las ruinas y asolamientos, y á las ciudades desamparadas, que fueron puestas á saco y en escarnio á las otras gentes alrededor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 5, 'Por eso, así ha dicho el Señor Jehová: He hablado por cierto en el fuego de mi celo contra las demás gentes, y contra toda Idumea, que se disputaron mi tierra por heredad con alegría de todo corazón, con enconamiento de ánimo, para que sus expelidos fuesen presa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 6, 'Por tanto, profetiza sobre la tierra de Israel, y di á los montes y á los collados, y á los arroyos y á los valles: Así ha dicho el Señor Jehová: He aquí, en mi celo y en mi furor he hablado, por cuanto habéis llevado el oprobio de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 7, 'Por lo cual así ha dicho el Señor Jehová: Yo he alzado mi mano, que las gentes que os están alrededor han de llevar su afrenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 8, 'Mas vosotros, oh montes de Israel, daréis vuestros ramos, y llevaréis vuestro fruto á mi pueblo Israel; porque cerca están para venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 9, 'Porque heme aquí á vosotros, y á vosotros me volveré, y seréis labrados y sembrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 10, 'Y haré multiplicar sobre vosotros hombres, á toda la casa de Israel, toda ella; y las ciudades han de ser habitadas, y serán edificadas las ruinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 11, 'Y multiplicaré sobre vosotros hombres y bestias, y serán multiplicados y crecerán: y os haré morar como solíais antiguamente, y os haré más bien que en vuestros principios; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 12, 'Y haré andar hombres sobre vosotros, á mi pueblo Israel; y te poseerán, y les serás por heredad, y nunca más les matarás los hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 13, 'Así ha dicho el Señor Jehová: Por cuanto dicen de vosotros: Comedora de hombres, y matadora de los hijos de tus gentes has sido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 14, 'Por tanto, no devorarás más hombres, y nunca más matarás los hijos á tus gentes, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 15, 'Y nunca más te haré oir injuria de gentes, ni más llevarás denuestos de pueblos, ni harás más morir los hijos á tus gentes, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 16, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 17, 'Hijo del hombre, morando en su tierra la casa de Israel, la contaminaron con sus caminos y con sus obras: como inmundicia de menstruosa fué su camino delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 18, 'Y derramé mi ira sobre ellos por las sangres que derramaron sobre la tierra; porque con sus ídolos la contaminaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 19, 'Y esparcílos por las gentes, y fueron aventados por las tierras: conforme á sus caminos y conforme á sus obras los juzgué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 20, 'Y entrados á las gentes á donde fueron, profanaron mi santo nombre, diciéndose de ellos: Estos son pueblo de Jehová, y de su tierra de él han salido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 21, 'Y he tenido lástima en atención á mi santo nombre, el cual profanó la casa de Israel entre las gentes á donde fueron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 22, 'Por tanto, di á la casa de Israel: Así ha dicho el Señor Jehová: No lo hago por vosotros, oh casa de Israel, sino por causa de mi santo nombre, el cual profanasteis vosotros entre las gentes á donde habéis llegado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 23, 'Y santificaré mi grande nombre profanado entre las gentes, el cual profanasteis vosotros en medio de ellas; y sabrán las gentes que yo soy Jehová, dice el Señor Jehová, cuando fuere santificado en vosotros delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 24, 'Y yo os tomaré de las gentes, y os juntaré de todas las tierras, y os traeré á vuestro país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 25, 'Y esparciré sobre vosotros agua limpia, y seréis limpiados de todas vuestras inmundicias; y de todos vuestros ídolos os limpiaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 26, 'Y os daré corazón nuevo, y pondré espíritu nuevo dentro de vosotros; y quitaré de vuestra carne el corazón de piedra, y os daré corazón de carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 27, 'Y pondré dentro de vosotros mi espíritu, y haré que andéis en mis mandamientos, y guardéis mis derechos, y los pongáis por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 28, 'Y habitaréis en la tierra que dí á vuestros padres; y vosotros me seréis por pueblo, y yo seré á vosotros por Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 29, 'Y os guardaré de todas vuestras inmundicias; y llamaré al trigo, y lo multiplicaré, y no os daré hambre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 30, 'Multiplicaré asimismo el fruto de los árboles, y el fruto de los campos, porque nunca más recibáis oprobio de hambre entre las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 31, 'Y os acordaréis de vuestros malos caminos, y de vuestras obras que no fueron buenas; y os avergonzaréis de vosotros mismos por vuestras iniquidades, y por vuestras abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 32, 'No lo hago por vosotros, dice el Señor Jehová, séaos notorio: avergonzaos y confundíos de vuestras iniquidades, casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 33, 'Así ha dicho el Señor Jehová: El día que os limpiaré de todas vuestras iniquidades, haré también habitar las ciudades, y las asoladas serán edificadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 34, 'Y la tierra asolada será labrada, en lugar de haber sido asolada en ojos de todos los que pasaron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 35, 'Los cuales dijeron: Esta tierra asolada fué como huerto de Edén; y estas ciudades desiertas y asoladas y arruinadas, fortalecidas estuvieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 36, 'Y las gentes que fueron dejadas en vuestros alrededores, sabrán que yo edifiqué las derribadas, y planté las asoladas: yo Jehová he hablado, y harélo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 37, 'Así ha dicho el Señor Jehová: Aun seré solicitado de la casa de Israel, para hacerles esto: multiplicarélos de hombres á modo de rebaños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 36, 38, 'Como las ovejas santas, como las ovejas de Jerusalem en sus solemnidades, así las ciudades desiertas serán llenas de rebaños de hombres; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 1, 'Y LA mano de Jehová fué sobre mí, y sacóme en espíritu de Jehová, y púsome en medio de un campo que estaba lleno de huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 2, 'E hízome pasar cerca de ellos por todo alrededor: y he aquí que eran muy muchos sobre la haz del campo, y por cierto secos en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 3, 'Y díjome: Hijo del hombre, ¿vivirán estos huesos? Y dije: Señor Jehová, tú lo sabes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 4, 'Díjome entonces: Profetiza sobre estos huesos, y diles: Huesos secos, oid palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 5, 'Así ha dicho el Señor Jehová á estos huesos: He aquí, yo hago entrar espíritu en vosotros, y viviréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 6, 'Y pondré nervios sobre vosotros, y haré subir sobre vosotros carne, y os cubriré de piel, y pondré en vosotros espíritu, y viviréis; y sabréis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 7, 'Profeticé pues, como me fué mandado; y hubo un ruido mientras yo profetizaba, y he aquí un temblor, y los huesos se llegaron cada hueso á su hueso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 8, 'Y miré, y he aquí nervios sobre ellos, y la carne subió, y la piel cubrío por encima de ellos: mas no había en ellos espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 9, 'Y díjome: Profetiza al espíritu, profetiza, hijo del hombre, y di al espíritu: Así ha dicho el Señor Jehová: Espíritu, ven de los cuatro vientos, y sopla sobre estos muertos, y vivirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 10, 'Y profeticé como me había mandado, y entró espíritu en ellos, y vivieron, y estuvieron sobre sus pies, un ejército grande en extremo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 11, 'Díjome luego: Hijo del hombre, todos estos huesos son la casa de Israel. He aquí, ellos dicen: Nuestros huesos se secaron, y pereció nuestra esperanza, y somos del todo talados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 12, 'Por tanto profetiza, y diles: Así ha dicho el Señor Jehová: He aquí, yo abro vuestros sepulcros, pueblo mío, y os haré subir de vuestras sepulturas, y os traeré á la tierra de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 13, 'Y sabréis que yo soy Jehová, cuando abriere vuestros sepulcros, y os sacare de vuestras sepulturas, pueblo mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 14, 'Y pondré mi espíritu en vosotros, y viviréis, y os haré reposar sobre vuestra tierra; y sabréis que yo Jehová hablé, y lo hice, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 15, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 16, 'Tú, hijo del hombre, tómate ahora un palo, y escribe en él: A Judá, y á los hijos de Israel sus compañeros. Toma después otro palo, y escribe en él: A José, palo de Ephraim, y á toda la casa de Israel sus compañeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 17, 'Júntalos luego el uno con el otro, para que sean en uno, y serán uno en tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 18, 'Y cuando te hablaren los hijos de tu pueblo, diciendo: ¿No nos enseñarás qué te propones con eso?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 19, 'Diles: Así ha dicho el Señor Jehová: He aquí, yo tomo el palo de José que está en la mano de Ephraim, y á las tribus de Israel sus compañeros, y pondrélos con él, con el palo de Judá, y harélos un palo, y serán uno en mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 20, 'Y los palos sobre que escribieres, estarán en tu mano delante de sus ojos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 21, 'Y les dirás: Así ha dicho el Señor Jehová: He aquí, yo tomo á los hijos de Israel de entre las gentes á las cuales fueron, y los juntaré de todas partes, y los traeré á su tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 22, 'Y los haré una nación en la tierra, en los montes de Israel; y un rey será á todos ellos por rey: y nunca más serán dos naciones, ni nunca más serán divididos en dos reinos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 23, 'Ni más se contaminarán con sus ídolos, y con sus abominaciones, y con todas sus rebeliones: y los salvaré de todas sus habitaciones en las cuales pecaron, y los limpiaré; y me serán por pueblo, y yo á ellos por Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 24, 'Y mi siervo David será rey sobre ellos, y á todos ellos será un pastor: y andarán en mis derechos, y mis ordenanzas guardarán, y las pondrán por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 25, 'Y habitarán en la tierra que dí á mi siervo Jacob, en la cual habitaron vuestros padres, en ella habitarán ellos, y sus hijos, y los hijos de sus hijos para siempre; y mi siervo David les será príncipe para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 26, 'Y concertaré con ellos pacto de paz, perpetuo pacto será con ellos: y los asentaré, y los multiplicaré, y pondré mi santuario entre ellos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 27, 'Y estará en ellos mi tabernáculo, y seré á ellos por Dios, y ellos me serán por pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 37, 28, 'Y sabrán las gentes que yo Jehová santifico á Israel, estando mi santuario entre ellos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 1, 'Y FUÉ á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 2, 'Hijo del hombre, pon tu rostro contra Gog en tierra de Magog, príncipe de la cabecera de Mesech y Tubal, y profetiza sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 3, 'Y di: Así ha dicho el Señor Jehová: He aquí, yo á ti, oh Gog, príncipe de la cabecera de Mesech y Tubal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 4, 'Y yo te quebrantaré, y pondré anzuelos en tus quijadas, y te sacaré á ti, y á todo tu ejército, caballos y caballeros, vestidos de todo todos ellos, grande multitud con paveses y escudos, teniendo todos ellos espadas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 5, 'Persia, y Etiopía, y Libia con ellos; todos ellos con escudos y almetes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 6, 'Gomer, y todas sus compañías; la casa de Togarma, á los lados del norte, y todas sus compañías; pueblos muchos contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 7, 'Aparéjate, y apercíbete, tú, y toda tu multitud que se ha reunido á ti, y séles por guarda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 8, 'De aquí á muchos días serás tú visitado: al cabo de años vendrás á la tierra salvada de la espada, recogida de muchos pueblos, á los montes de Israel, que siempre fueron para asolamiento: mas fué sacada de las naciones, y todos ellos morarán confiadamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 9, 'Y subirás tú, vendrás como tempestad; como nublado para cubrir la tierra serás tú, y todas tus compañías, y muchos pueblos contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 10, 'Así ha dicho el Señor Jehová: Y será en aquel día, que subirán palabras en tu corazón, y concebirás mal pensamiento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 11, 'Y dirás: Subiré contra tierra de aldeas, iré á gentes reposadas, y que habitan confiadamente: todos ellos habitan sin muros, no tienen cerrojos ni puertas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 12, 'Para arrebatar despojos y para tomar presa; para tornar tu mano sobre las tierras desiertas ya pobladas, y sobre el pueblo recogido de las gentes, que se hace de ganados y posesiones, que mora en el ombligo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 13, 'Seba, y Dedán, y los mercaderes de Tarsis, y todos sus leoncillos, te dirán: ¿Has venido á arrebatar despojos? ¿has reunido tu multitud para tomar presa, para quitar plata y oro, para tomar ganados y posesiones, para tomar grandes despojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 14, 'Por tanto profetiza, hijo del hombre, y di á Gog: Así ha dicho el Señor Jehová: En aquel tiempo, cuando mi pueblo Israel habitará seguramente, ¿no lo sabrás tú?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 15, 'Y vendrás de tu lugar, de las partes del norte, tú y muchos pueblos contigo, todos ellos á caballo, grande reunión y poderoso ejército:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 16, 'Y subirás contra mi pueblo Israel como nublado para cubrir la tierra; será al cabo de los días: y te traeré sobre mi tierra, para que las gentes me conozcan, cuando fuere santificado en ti, oh Gog, delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 17, 'Así ha dicho el Señor Jehová: ¿No eres tú aquél de quien hablé yo en tiempos pasados por mis siervos los profetas de Israel, los cuales profetizaron en aquellos tiempos que yo te había de traer sobre ellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 18, 'Y será en aquel tiempo, cuando vendrá Gog contra la tierra de Israel, dijo el Señor Jehová, que subirá mi ira en mi enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 19, 'Porque he hablado en mi celo, y en el fuego de mi ira: Que en aquel tiempo habrá gran temblor sobre la tierra de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 20, 'Que los peces de la mar, y las aves del cielo, y las bestias del campo, y toda serpiente que anda arrastrando sobre la tierra, y todos los hombres que están sobre la haz de la tierra, temblarán á mi presencia; y se arruinarán los montes, y los vallados caerán, y todo muro caerá á tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 21, 'Y en todos mis montes llamaré contra él espada, dice el Señor Jehová: la espada de cada cual será contra su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 22, 'Y yo litigaré con él con pestilencia y con sangre; y haré llover sobre él, y sobre sus compañías, y sobre los muchos pueblos que están con él, impetuosa lluvia, y piedras de granizo, fuego y azufre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 38, 23, 'Y seré engrandecido y santificado, y seré conocido en ojos de muchas gentes; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 1, 'TU pues, hijo del hombre, profetiza contra Gog, y di: Así ha dicho el Señor Jehová: He aquí yo contra ti, oh Gog, príncipe de la cabecera de Mesech y Tubal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 2, 'Y te quebrantaré, y te sextaré, y te haré subir de las partes del norte, y te traeré sobre los montes de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 3, 'Y sacaré tu arco de tu mano izquierda, y derribaré tus saetas de tu mano derecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 4, 'Sobre los montes de Israel caerás tú, y todas tus compañías, y los pueblos que fueron contigo: á toda ave y á toda cosa que vuela, y á las bestias del campo, te he dado por comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 5, 'Sobre la haz del campo caerás: porque yo he hablado, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 6, 'Y enviaré fuego sobre Magog, y sobre los que moran seguramente en las islas; y sabrán que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 7, 'Y haré notorio mi santo nombre en medio de mi pueblo Israel, y nunca más dejaré amancillar mi santo nombre; y sabrán las gentes que yo soy Jehová, el Santo en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 8, 'He aquí, vino y fué, dice el Señor Jehová: este es el día del cual he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 9, 'Y los moradores de las ciudades de Israel saldrán, y encenderán y quemarán armas, y escudos, y paveses, arcos y saetas, y bastones de mano, y lanzas: y las quemarán en fuego por siete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 10, 'Y no traerán leña del campo, ni cortarán de los bosques, sino que quemarán las armas en el fuego: y despojarán á sus despojadores, y robarán á los que los robaron, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 11, 'Y será en aquel tiempo, que yo daré á Gog lugar para sepultura allí en Israel, el valle de los que pasan al oriente de la mar, y obstruirá el paso á los transeuntes, pues allí enterrarán á Gog y á toda su multitud: y lo llamarán, El valle de Hamón-gog.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 12, 'Y la casa de Israel los estará enterrando por siete meses, para limpiar la tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 13, 'Enterrarlos ha todo el pueblo de la tierra: y será para ellos célebre el día que yo fuere glorificado, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 14, 'Y tomarán hombres de jornal, los cuales vayan por el país con los que viajaren, para enterrar á los que quedaron sobre la haz de la tierra, á fin de limpiarla: al cabo de siete meses harán el reconocimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 15, 'Y pasarán los que irán por el país, y el que viere los huesos de algún hombre, edificará junto á ellos un mojón, hasta que los entierren los sepultureros en el valle de Hamón-gog.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 16, 'Y también el nombre de la ciudad será Hamonah: y limpiarán la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 17, 'Y tú, hijo del hombre, así ha dicho el Señor Jehová: Di á las aves, á todo volátil, y á toda bestia del campo: Juntaos, y venid; reuníos de todas partes á mí víctima que os sacrifico, un sacrificio grande sobre los montes de Israel, y comeréis carne y beberéis sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 18, 'Comeréis carne de fuertes, y beberéis sangre de príncipes de la tierra; de carneros, de corderos, de machos de cabrío, de bueyes, de toros, engordados todos en Basán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 19, 'Y comeréis gordura hasta hartaros y beberéis hasta embriagaros sangre, de mi sacrificio que yo os sacrifiqué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 20, 'Y os hartaréis sobre mi mesa, de caballos, y de caballeros fuertes, y de todos hombres de guerra, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 21, 'Y pondré mi gloria entre las gentes, y todas las gentes verán mi juicio que habré hecho, y mi mano que sobre ellos puse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 22, 'Y de aquel día en adelante sabrá la casa de Israel que yo soy Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 23, 'Y sabrán las gentes que la casa de Israel fué llevada cautiva por su pecado; por cuanto se rebelaron contra mí, y yo escondí de ellos mi rostro, y entreguélos en mano de sus enemigos, y cayeron todos á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 24, 'Conforme á su inmundicia y conforme á sus rebeliones hice con ellos: y de ellos escondí mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 25, 'Por tanto, así ha dicho el Señor Jehová: Ahora volveré la cautividad de Jacob, y tendré misericordia de toda la casa de Israel, y celaré por mi santo nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 26, 'Y ellos sentirán su vergüenza, y toda su rebelión con que prevaricaron contra mí, cuando habitaren en su tierra seguramente, y no habrá quien los espante;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 27, 'Cuando los volveré de los pueblos, y los juntaré de las tierras de sus enemigos, y fuere santificado en ellos en ojos de muchas gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 28, 'Y sabrán que yo soy Jehová su Dios, cuando después de haberlos hecho pasar á las gentes, los juntaré sobre su tierra, sin dejar más allá ninguno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 39, 29, 'Ni esconderé más de ellos mi rostro; porque habré derramado de mi espíritu sobre la casa de Israel, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 1, 'EN el año veinticinco de nuestro cautiverio, al principio del año, á los diez del mes, á los catorce años después que la ciudad fué herida, en aquel mismo día fué sobre mí la mano de Jehová, y llevóme allá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 2, 'En visiones de Dios me llevó á la tierra de Israel, y púsome sobre un monte muy alto, sobre el cual había como edificio de una ciudad al mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 3, 'Y llevóme allí, y he aquí un varón, cuyo aspecto era como aspecto de metal, y tenía un cordel de lino en su mano, y una caña de medir: y él estaba á la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 4, 'Y hablóme aquel varón, diciendo: Hijo del hombre, mira con tus ojos, y oye con tus oídos, y pon tu corazón á todas las cosas que te muestro; porque para que yo te las mostrase eres traído aquí. Cuenta todo lo que ves á la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 5, 'Y he aquí, un muro fuera de la casa: y la caña de medir que aquel varón tenía en la mano, era de seis codos, de á codo y palmo: y midió la anchura del edificio de una caña, y la altura, de otra caña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 6, 'Después vino á la puerta que daba cara hacia el oriente, y subió por sus gradas, y midió el un poste de la puerta, de una caña en anchura, y el otro poste de otra caña en ancho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 7, 'Y cada cámara tenía una caña de largo, y una caña de ancho; y entre las cámaras había cinco codos en ancho; y cada poste de la puerta junto á la entrada de la puerta por dentro, una caña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 8, 'Midió asimismo la entrada de la puerta por de dentro, una caña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 9, 'Midió luego la entrada del portal, de ocho codos, y sus postes de dos codos; y la puerta del portal estaba por de dentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 10, 'Y la puerta de hacia el oriente tenía tres cámaras de cada parte, todas tres de una medida: también de una medida los portales de cada parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 11, 'Y midió la anchura de la entrada de la puerta, de diez codos; la longitud del portal de trece codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 12, 'Y el espacio de delante de las cámaras, de un codo de la una parte, y de otro codo de la otra; y cada cámara tenía seis codos de una parte, y seis codos de otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 13, 'Y midió la puerta desde el techo de la una cámara hasta el techo de la otra, veinticinco codos de anchura, puerta contra puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 14, 'E hizo los postes de sesenta codos, cada poste del atrio y del portal por todo alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 15, 'Y desde la delantera de la puerta de la entrada hasta la delantera de la entrada de la puerta de dentro, cincuenta codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 16, 'Y había ventanas estrechas en las cámaras, y en sus portales por de dentro de la puerta alrededor, y asimismo en los corredores; y las ventanas estaban alrededor por de dentro; y en cada poste había palmas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 17, 'Llevóme luego al atrio exterior, y he aquí, había cámaras, y solado hecho al atrio en derredor: treinta cámaras había alrededor en aquel atrio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 18, 'Y el solado al lado de las puertas, en proporción á la longitud de los portales, era el solado más bajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 19, 'Y midió la anchura desde la delantera de la puerta de abajo hasta la delantera del atrio interior por de fuera, de cien codos hacia el oriente y el norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 20, 'Y de la puerta que estaba hacia el norte en el atrio exterior, midió su longitud y su anchura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 21, 'Y sus cámaras eran tres de una parte, y tres de otra, y sus postes y sus arcos eran como la medida de la puerta primera: cincuenta codos su longitud, y veinticinco su anchura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 22, 'Y sus ventanas, y sus arcos, y sus palmas, eran conforme á la medida de la puerta que estaba hacia el oriente; y subían á ella por siete gradas; y delante de ellas estaban sus arcos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 23, 'Y la puerta del atrio interior estaba enfrente de la puerta al norte; y así al oriente: y midió de puerta á puerta cien codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 24, 'Llevóme después hacia el mediodía, y he aquí una puerta hacia el mediodía: y midió sus portales y sus arcos conforme á estas medidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 25, 'Y tenía sus ventanas y sus arcos alrededor, como las ventanas: la longitud era de cincuenta codos, y la anchura de veinticinco codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 26, 'Y sus gradas eran de siete peldaños, con sus arcos delante de ellas; y tenía palmas, una de una parte, y otra de la otra, en sus postes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 27, 'Y había puerta de hacia el mediodía del atrio interior: y midió de puerta á puerta hacia el mediodía cien codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 28, 'Metióme después en el atrio de adentro á la puerta del mediodía, y midió la puerta del mediodía conforme á estas medidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 29, 'Y sus cámaras, y sus postes y sus arcos, eran conforme á estas medidas; y tenía sus ventanas y sus arcos alrededor: la longitud era de cincuenta codos, y de veinticinco codos la anchura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 30, 'Y los arcos alrededor eran de veinticinco codos de largo, y cinco codos de ancho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 31, 'Y sus arcos caían afuera al atrio, con palmas en sus postes; y sus gradas eran de ocho escalones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 32, 'Y llevóme al atrio interior hacia el oriente, y midió la puerta conforme á estas medidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 33, 'Y eran sus cámaras, y sus postes, y sus arcos, conforme á estas medidas: y tenía sus ventanas y sus arcos alrededor: la longitud era de cincuenta codos, y la anchura de veinticinco codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 34, 'Y sus arcos caían afuera al atrio, con palmas en sus postes de una parte y otra: y sus gradas eran de ocho escalones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 35, 'Llevóme luego á la puerta del norte, y midió conforme á estas medidas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 36, 'Sus cámaras, y sus postes, y sus arcos, y sus ventanas alrededor: la longitud era de cincuenta codos, y de veinticinco codos el ancho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 37, 'Y sus postes caían fuera al atrio, con palmas á cada uno de sus postes de una parte y otra: y sus gradas eran de ocho peldaños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 38, 'Y había allí una cámara, y su puerta con postes de portales; allí lavarán el holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 39, 'Y en la entrada de la puerta había dos mesas de la una parte, y otras dos de la otra, para degollar sobre ellas el holocausto, y la expiación, y el sacrificio por el pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 40, 'Y al lado por de fuera de las gradas, á la entrada de la puerta del norte, había dos mesas; y al otro lado que estaba á la entrada de la puerta, dos mesas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 41, 'Cuatro mesas de la una parte, y cuatro mesas de la otra parte al lado de la puerta; ocho mesas, sobre las cuales degollarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 42, 'Y las cuatro mesas para el holocausto eran de piedras labradas, de un codo y medio de longitud, y codo y medio de ancho, y de altura de un codo: sobre éstas pondrán las herramientas con que degollarán el holocausto y el sacrificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 43, 'Y dentro, ganchos de un palmo, dispuestos por todo alrededor; y sobre las mesas la carne de la ofrenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 44, 'Y fuera de la puerta interior, en el atrio de adentro que estaba al lado de la puerta del norte, estaban las cámaras de los cantores, las cuales miraban hacia el mediodía: una estaba al lado de la puerta del oriente que miraba hacia el norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 45, 'Y díjome: Esta cámara que mira hacia el mediodía es de los sacerdotes que tienen la guarda del templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 46, 'Y la cámara que mira hacia el norte es de los sacerdotes que tienen la guarda del altar: estos son los hijos de Sadoc, los cuales son llamados de los hijos de Leví al Señor, para ministrarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 47, 'Y midió el atrio, cien codos de longitud, y la anchura de cien codos cuadrados; y el altar estaba delante de la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 48, 'Y llevóme al pórtico del templo, y midió cada poste del pórtico, cinco codos de una parte, y cinco codos de otra; y la anchura de la puerta tres codos de una parte, y tres codos de otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 40, 49, 'La longitud del pórtico veinte codos, y la anchura once codos, al cual subían por gradas: y había columnas junto á los postes, una de un lado, y otra de otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 1, 'METIOME luego en el templo, y midió los postes, siendo el ancho seis codos de una parte, y seis codos de otra, que era la anchura del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 2, 'Y la anchura de la puerta era de diez codos; y los lados de la puerta, de cinco codos de una parte, y cinco de otra. Y midió su longitud de cuarenta codos, y la anchura de veinte codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 3, 'Y pasó al interior, y midió cada poste de la puerta de dos codos; y la puerta de seis codos; y la anchura de la entrada de siete codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 4, 'Midió también su longitud, de veinte codos, y la anchura de veinte codos, delante del templo: y díjome: Este es el lugar santísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 5, 'Después midió el muro de la casa, de seis codos; y de cuatro codos la anchura de las cámaras, en torno de la casa alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 6, 'Y las cámaras eran cámara sobre cámara, treinta y tres por orden; y entraban modillones en la pared de la casa alrededor, sobre los que las cámaras estribasen, y no estribasen en la pared de la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 7, 'Y había mayor anchura y vuelta en las cámaras á lo más alto; el caracol de la casa subía muy alto alrededor por de dentro de la casa: por tanto la casa tenía más anchura arriba; y de la cámara baja se subía á la alta por la del medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 8, 'Y miré la altura de la casa alrededor: los cimientos de las cámaras eran una caña entera de seis codos de grandor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 9, 'Y la anchura de la pared de afuera de las cámaras era de cinco codos, y el espacio que quedaba de las cámaras de la casa por de dentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 10, 'Y entre las cámaras había anchura de veinte codos por todos lados alrededor de la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 11, 'Y la puerta de cada cámara salía al espacio que quedaba; una puerta hacia el norte, y otra puerta hacia el mediodía: y la anchura del espacio que quedaba era de cinco codos por todo alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 12, 'Y el edificio que estaba delante del apartamiento al lado de hacia el occidente era de setenta codos; y la pared del edificio, de cinco codos de anchura alrededor, y noventa codos de largo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 13, 'Y midió la casa, cien codos de largo: y el apartamiento, y el edificio, y sus paredes, de longitud de cien codos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 14, 'Y la anchura de la delantera de la casa, y del apartamiento al oriente, de cien codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 15, 'Y midió la longitud del edificio que estaba delante del apartamiento que había detrás de él, y las cámaras de una parte y otra, cien codos; y el templo de dentro, y los portales del atrio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 16, 'Los umbrales, y las ventanas estrechas, y las cámaras, tres en derredor á la parte delantera, todo cubierto de madera alrededor desde el suelo hasta las ventanas; y las ventanas también cubiertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 17, 'Encima de sobre la puerta, y hasta la casa de dentro, y de fuera, y por toda la pared en derredor de dentro y por de fuera, tomó medidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 18, 'Y estaba labrada con querubines y palmas: entre querubín y querubín una palma: y cada querubín tenía dos rostros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 19, 'Un rostro de hombre hacia la palma de la una parte, y rostro de león hacia la palma de la otra parte, por toda la casa alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 20, 'Desde el suelo hasta encima de la puerta había labrados querubines y palmas, y por toda la pared del templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 21, 'Cada poste del templo era cuadrado, y la delantera del santuario era como la otra delantera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 22, 'La altura del altar de madera era de tres codos, y su longitud de dos codos; y sus esquinas, y su superficie, y sus paredes, eran de madera. Y díjome: Esta es la mesa que está delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 23, 'Y el templo y el santuario tenían dos portadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 24, 'Y en cada portada había dos puertas, dos puertas que se volvían: dos puertas en la una portada, y otras dos en la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 25, 'Y en las puertas del templo había labrados de querubines y palmas, así como estaban hechos en las paredes, y grueso madero sobre la delantera de la entrada por de fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 41, 26, 'Y había ventanas estrechas, y palmas de una y otra parte por los lados de la entrada, y de la casa, y por las vigas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 1, 'SACOME luego al atrio de afuera hacia el norte, y llevóme á la cámara que estaba delante del espacio que quedaba enfrente del edificio de hacia el norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 2, 'Por delante de la puerta del norte su longitud era de cien codos, y la anchura de cincuenta codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 3, 'Frente á los veinte codos que había en el atrio de adentro, y enfrente del solado que había en al atrio exterior, estaban las cámaras, las unas enfrente de las otras en tres pisos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 4, 'Y delante de las cámaras había un corredor de diez codos de ancho á la parte de adentro, con viaje de un codo; y sus puertas hacia el norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 5, 'Y las cámaras más altas eran más estrechas; porque las galerías quitaban de ellas más que de las bajas y de las de en medio del edificio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 6, 'Porque estaban en tres pisos, y no tenían columnas como las columnas de los atrios: por tanto, eran más estrechas que las de abajo y las del medio desde el suelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 7, 'Y el muro que estaba afuera enfrente de las cámaras, hacia el atrio exterior delante de las cámaras, tenía cincuenta codos de largo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 8, 'Porque la longitud de las cámaras del atrio de afuera era de cincuenta codos: y delante de la fachada del templo había cien codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 9, 'Y debajo de las cámaras estaba la entrada al lado oriental, para entrar en él desde el atrio de afuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 10, 'A lo largo del muro del atrio hacia el oriente, enfrente de la lonja, y delante del edificio, había cámaras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 11, 'Y el corredor que había delante de ellas era semejante al de las cámaras que estaban hacia el norte, conforme á su longitud, asimismo su anchura, y todas sus salidas; conforme á sus puertas, y conforme á sus entradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 12, 'Y conforme á las puertas de las cámaras que estaban hacia el mediodía, tenía una puerta al principio del camino, del camino delante del muro hacia el oriente á los que entran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 13, 'Y díjome: Las cámaras del norte y las del mediodía, que están delante de la lonja, son cámaras santas, en las cuales los sacerdotes que se acercan á Jehová comerán las santas ofrendas: allí pondrán las ofrendas santas, y el presente, y la expiación, y el sacrificio por el pecado: porque el lugar es santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 14, 'Cuando los sacerdotes entraren, no saldrán del lugar santo al atrio de afuera, sino que allí dejarán sus vestimentas con que ministrarán, porque son santas; y vestiránse otros vestidos, y así se allegarán á lo que es del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 15, 'Y luego que acabó las medidas de la casa de adentro, sacóme por el camino de la puerta que miraba hacia el oriente, y midiólo todo alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 16, 'Midió el lado oriental con la caña de medir, quinientas cañas de la caña de medir en derredor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 17, 'Midió al lado del norte, quinientas cañas de la caña de medir alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 18, 'Midió al lado del mediodía, quinientas cañas de la caña de medir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 19, 'Rodeó al lado del occidente, y midió quinientas cañas de la caña de medir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 42, 20, 'A los cuatro lados lo midió: tuvo el muro todo alrededor quinientas cañas de longitud, y quinientas cañas de anchura, para hacer separación entre el santuario y el lugar profano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 1, 'LLEVOME luego á la puerta, á la puerta que mira hacia el oriente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 2, 'Y he aquí la gloria del Dios de Israel, que venía de hacia el oriente; y su sonido era como el sonido de muchas aguas, y la tierra resplandecía á causa de su gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 3, 'Y la visión que vi era como la visión, como aquella visión que vi cuando vine para destruir la ciudad: y las visiones eran como la visión que vi junto al río de Chebar; y caí sobre mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 4, 'Y la gloria de Jehová entró en la casa por la vía de la puerta que daba cara al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 5, 'Y alzóme el espíritu, y metióme en el atrio de adentro; y he aquí que la gloria de Jehová hinchió la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 6, 'Y oí uno que me hablaba desde la casa: y un varón estaba junto á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 7, 'Y díjome: Hijo del hombre, este es el lugar de mi asiento, y el lugar de las plantas de mis pies, en el cual habitaré entre los hijos de Israel para siempre: y nunca más contaminará la casa de Israel mi santo nombre, ni ellos ni sus reyes, con sus fornicaciones, y con los cuerpos muertos de sus reyes en sus altares:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 8, 'Y poniendo ellos su umbral junto á mi umbral, y su poste junto á mi poste, y no más que pared entre mí y ellos, contaminaron mi santo nombre con sus abominaciones que hicieron: consumílos por tanto en mi furor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 9, 'Ahora echarán lejos de mí su fornicación, y los cuerpos muertos de sus reyes, y habitaré en medio de ellos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 10, 'Tú, hijo del hombre, muestra á la casa de Israel esta casa, y avergüéncense de sus pecados, y midan la traza de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 11, 'Y si se avergonzaren de todo lo que han hecho, hazles entender la figura de la casa, y su traza, y sus salidas y sus entradas, y todas sus formas, y todas sus descripciones, y todas sus configuraciones, y todas sus leyes: y descríbelo delante de sus ojos, para que guarden toda su forma, y todas sus reglas, y las pongan por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 12, 'Esta es la ley de la casa: Sobre fcfc término alrededor será santísimo. He aquí que esta es la ley de la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 13, 'Y estas son las medidas del altar por codos (el codo de á codo y palmo). El seno, de un codo, y de un codo el ancho; y su remate por su borde alrededor, de un palmo. Este será el fondo alto del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 14, 'Y desde el seno de sobre el suelo hasta el lugar de abajo, dos codos, y la anchura de un codo: y desde el lugar menor hasta el lugar mayor, cuatro codos, y la anchura de un codo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 15, 'Y el altar, de cuatro codos, y encima del altar, cuatro cuernos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 16, 'Y el altar tenía doce codos de largo, y doce de ancho, cuadrado á sus cuatro lados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 17, 'Y el área, de catorce codos de longitud y catorce de anchura en sus cuatro lados, y de medio codo el borde alrededor: y el seno de un codo por todos lados; y sus gradas estaban al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 18, 'Y díjome: Hijo del hombre, así ha dicho el Señor Jehová: Estas son las ordenanzas del altar el día en que será hecho, para ofrecer sobre él holocausto, y para esparcir sobre él sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 19, 'Darás á los sacerdotes Levitas que son del linaje de Sadoc, que se allegan á mí, dice el Señor Jehová, para ministrarme, un becerro de la vacada para expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 20, 'Y tomarás de su sangre, y pondrás en los cuatro cuernos del altar, y en las cuatro esquinas del área, y en el borde alrededor: así lo limpiarás y purificarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 21, 'Tomarás luego el becerro de la expiación, y lo quemarás conforme á la ley de la casa, fuera del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 22, 'Y al segundo día ofrecerás un macho de cabrío sin defecto, para expiación; y purificarán el altar como lo purificaron con el becerro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 23, 'Cuando acabares de expiar, ofrecerás un becerro de la vacada sin defecto, y un carnero sin tacha de la manada:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 24, 'Y los ofrecerás delante de Jehová, y los sacerdotes echarán sal sobre ellos, y los ofrecerán en holocausto á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 25, 'Por siete días sacrificarán un macho cabrío cada día en expiación; asimismo sacrificarán el becerro de la vacada y un carnero sin tacha del rebaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 26, 'Por siete días expiarán el altar, y lo limpiarán, y ellos henchirán sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 43, 27, 'Y acabados estos días, al octavo día, y en adelante, sacrificarán los sacerdotes sobre el altar vuestros holocaustos y vuestros pacíficos; y me seréis aceptos, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 1, 'Y TORNOME hacia la puerta de afuera del santuario, la cual mira hacia el oriente; y estaba cerrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 2, 'Y díjome Jehová: Esta puerta ha de estar cerrada: no se abrirá, ni entrará por ella hombre, porque Jehová Dios de Israel entró por ella; estará por tanto cerrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 3, 'Para el príncipe; el príncipe, él se sentará en ella para comer pan delante de Jehová: por el camino de la entrada de la puerta entrará, y por el camino de ella saldrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 4, 'Y llevóme hacia la puerta del norte por delante de la casa, y miré, y he aquí, la gloria de Jehová había henchido la casa de Jehová: y caí sobre mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 5, 'Y díjome Jehová: Hijo del hombre, pon tu corazón, y mira con tus ojos, y oye con tus oídos todo lo que yo hablo contigo sobre todas las ordenanzas de la casa de Jehová, y todas sus leyes: y pon tu corazón á las entradas de la casa, y á todas las salidas del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 6, 'Y dirás á los rebeldes, á la casa de Israel: Así ha dicho el Señor Jehová: Básteos de todas vuestras abominaciones, oh casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 7, 'De haber vosotros traído extranjeros, incircuncisos de corazón é incircuncisos de carne, para estar en mi santuario, para contaminar mi casa; de haber ofrecido mi pan, la grosura y la sangre: é invalidaron mi pacto por todas vuestras abominaciones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 8, 'Y no guardasteis el ordenamiento de mis santificaciones, sino que os pusisteis guardas de mi ordenanza en mi santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 9, 'Así ha dicho el Señor Jehová: Ningún hijo de extranjero, incircunciso de corazón é incircunciso de carne, entrará en mi santuario, de todos los hijos de extranjeros que están entre los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 10, 'Y los Levitas que se apartaron lejos de mí cuando Israel erró, el cual se desvió de mí en pos de sus ídolos, llevarán su iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 11, 'Y serán ministros en mi santuario, porteros á las puertas de la casa, y sirvientes en la casa: ellos matarán el holocausto y la víctima al pueblo, y ellos estarán delante de ellos para servirles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 12, 'Por cuanto les sirvieron delante de sus ídolos, y fueron á la casa de Israel por tropezadero de maldad; por tanto, he alzado mi mano acerca de ellos, dice el Señor Jehová, que llevarán su iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 13, 'No serán allegados á mí para serme sacerdotes, ni se llegarán á ninguna de mis santificaciones; á las santidades de santidades; sino que llevarán su vergüenza, y sus abominaciones que hicieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 14, 'Pondrélos, pues, por guardas de la guarda de la casa en todo su servicio, y en todo lo que en ella hubiere de hacerse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 15, 'Mas los sacerdotes Levitas, hijos de Sadoc, que guardaron el ordenamiento de mi santuario, cuando los hijos de Israel se desviaron de mí, ellos serán allegados á mí para ministrarme, y delante de mí estarán para ofrecerme la grosura y la sangre, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 16, 'Esos entrarán en mi santuario, y ellos se allegarán á mi mesa para ministrarme, y guardarán mi ordenamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 17, 'Y será que cuando entraren por las puertas del atrio interior, se vestirán de vestimentas de lino: no asentará sobre ellos lana, cuando ministraren en las puertas del atrio de adentro, y en el interior.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 18, 'Tiaras de lino tendrán en sus cabezas, y pañetes de lino en sus lomos: no se ceñirán para sudar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 19, 'Y cuando salieren al atrio de afuera, al atrio de afuera al pueblo, se desnudarán de sus vestimentas con que ministraron, y las dejarán en las cámaras del santuario, y se vestirán de otros vestidos: así no santificarán el pueblo con sus vestimentas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 20, 'Y no raparán su cabeza, ni dejarán crecer el cabello; sino que lo recortarán trasquilando sus cabezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 21, 'Y ninguno de los sacerdotes beberá vino cuando hubieren de entrar en el atrio interior.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 22, 'Ni viuda, ni repudiada se tomarán por mujeres; sino que tomarán vírgenes del linaje de la casa de Israel, ó viuda que fuere viuda de sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 23, 'Y enseñarán á mi pueblo á hacer diferencia entre lo santo y lo profano, y les enseñarán á discernir entre lo limpio y lo no limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 24, 'Y en el pleito ellos estarán para juzgar; conforme á mis derechos lo juzgarán: y mis leyes y mis decretos guardarán en todas mis solemnidades, y santificarán mis sábados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 25, 'Y á hombre muerto no entrará para contaminarse; mas sobre padre, ó madre, ó hijo, ó hija, hermano, ó hermana que no haya tenido marido, se contaminará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 26, 'Y ffadespués de su purificación, le contarán siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 27, 'Y el día que entrare al santuario, al atrio de adentro, para ministrar en el santuario, ofrecerá su expiación, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 28, 'Y será á ellos por heredad: yo seré su heredad; y no les daréis posesión en Israel: yo soy su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 29, 'El presente, y la expiación, y el sacrificio por el pecado, comerán; y toda cosa dedicada en Israel, será de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 30, 'Y las primicias de todos los primeros de todo, y toda ofrenda de todo lo que se ofreciere de todas vuestras ofrendas, será de los sacerdotes: daréis asimismo las primicias de todas vuestras masas al sacerdote, para que haga reposar la bendición en vuestras casas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 44, 31, 'Ninguna cosa mortecina, ni desgarrada, así de aves como de animales, comerán los sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 1, 'Y CUANDO partiereis por suertes la tierra en heredad, apartaréis una suerte para Jehová que le consagréis en la tierra, de longitud de veinticinco mil cañas y diez mil de ancho: esto será santificado en todo su término alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 2, 'De esto serán para el santuario quinientas de longitud, y quinientas de ancho, en cuadro alrededor; y cincuenta codos en derredor para sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 3, 'Y de esta medida medirás en longitud veinticinco mil cañas, y en anchura diez mil, en lo cual estará el santuario, el santuario de santuarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 4, 'Lo consagrado de esta tierra será para los sacerdotes ministros del santuario, que se llegan para ministrar á Jehová: y seráles lugar para casas, y lugar santo para el santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 5, 'Asimismo veinticinco mil de longitud, y diez mil de anchura, lo cual será para los Levitas ministros de la casa, en posesión, con veinte cámaras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 6, 'Y para la posesión de la ciudad daréis cinco mil de anchura y veinticinco mil de longitud, delante de lo que se apartó para el santuario: será para toda la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 7, 'Y la parte del príncipe será junto al apartamiento del santuario, de la una parte y de la otra, y junto á la posesión de la ciudad, delante del apartamiento del santuario, y delante de la posesión de la ciudad, desde el rincón occidental hacia el occidente, hasta el rincón oriental hacia el oriente: y la longitud será de la una parte á la otra, desde el rincón del occidente hasta el rincón del oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 8, 'Esta tierra tendrá por posesión en Israel, y nunca más mis príncipes oprimirán á mi pueblo: y darán la tierra á la casa de Israel por sus tribus.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 9, 'Así ha dicho el Señor Jehová: Básteos, oh príncipes de Israel: dejad la violencia y la rapiña: haced juicio y justicia; quitad vuestras imposiciones de sobre mi pueblo, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 10, 'Peso de justicia, y epha de justicia, y bato de justicia, tendréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 11, 'El epha y el bato serán de una misma medida: que el bato tenga la décima parte del homer, y la décima parte del homer el epha: la medida de ellos será según el homer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 12, 'Y el siclo será de veinte geras: veinte siclos, con veinticinco siclos, y quince siclos, os serán una mina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 13, 'Esta será la ofrenda que ofreceréis: la sexta parte de un epha de homer del trigo, y la sexta parte de un epha de homer de la cebada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 14, 'Y la ordenanza del aceite será que ofreceréis un bato de aceite, que es la décima parte de un coro: diez batos harán un homer; porque diez batos son un homer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 15, 'Y una cordera de la manada de doscientas, de las gruesas de Israel, para sacrificio, y para holocausto y para pacíficos, para expiación por ellos, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 16, 'Todo el pueblo de la tierra será obligado á esta ofrenda para el príncipe de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 17, 'Mas del príncipe será el dar el holocausto, y el sacrificio, y la libación, en las solemnidades, y en las lunas nuevas, y en los sábados, y en todas las fiestas de la casa de Israel: él dispondrá la expiación, y el presente, y el holocausto, y los pacíficos, para expiar la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 18, 'Así ha dicho el Señor Jehová: El mes primero, al primero del mes, tomarás un becerro sin defecto de la vacada, y expiarás el santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 19, 'Y el sacerdote tomará de la sangre de la expiación, y pondrá sobre los postes de la casa, y sobre los cuatro ángulos del área del altar, y sobre los postes de las puertas del atrio de adentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 20, 'Así harás el séptimo del mes por los errados y engañados; y expiarás la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 21, 'El mes primero, á los catorce días del mes, tendréis la pascua, fiesta de siete días: comeráse pan sin levadura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 22, 'Y aquel día el príncipe sacrificará por sí, y por todo el pueblo de la tierra, un becerro por el pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 23, 'Y en los siete días de solemnidad hará holocausto á Jehová, siete becerros y siete carneros sin defecto, cada día de los siete días; y por el pecado un macho cabrío cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 24, 'Y con cada becerro ofrecerá presente de un epha, y con cada carnero un epha; y por cada epha un hin de aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 45, 25, 'En el mes séptimo, á los quince del mes, en la fiesta, hará como en estos siete días, cuanto á la expiación, y cuanto al holocausto, y cuanto al presente, y cuanto al aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 1, 'ASI ha dicho el Señor Jehová: La puerta del atrio de adentro que mira al oriente, estará cerrada los seis días de trabajo, y el día del sábado se abrirá: abriráse también el día de la nueva luna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 2, 'Y el príncipe entrará por el camino del portal de la puerta de afuera, y estará al umbral de la puerta, mientras los sacerdotes harán su holocausto y sus pacíficos, y adorará á la entrada de la puerta: después saldrá; mas no se cerrará la puerta hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 3, 'Asimismo adorará el pueblo de la tierra delante de Jehová, á la entrada de la puerta, en los sábados y en las nuevas lunas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 4, 'Y el holocausto que el príncipe ofrecerá á Jehová el día del sábado, será seis corderos sin defecto, y un carnero sin tacha:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 5, 'Y por presente un epha con cada carnero; y con cada cordero un presente, don de su mano, y un hin de aceite con el epha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 6, 'Mas el día de la nueva luna, un becerro sin tacha de la vacada, y seis corderos, y un carnero: deberán ser sin defecto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 7, 'Y hará presente de un epha con el becerro, y un epha con cada carnero: mas con los corderos, conforme á su facultad; y un hin de aceite por cada epha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 8, 'Y cuando el príncipe entrare, entrará por el camino del portal de la puerta: y por el mismo camino saldrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 9, 'Mas cuando el pueblo de la tierra entrare delante de Jehová en las fiestas, el que entrare por la puerta del norte, saldrá por la puerta del mediodía; y el que entrare por la puerta del mediodía, saldrá por la puerta del norte: no volverá por la puerta por donde entró, sino que saldrá por la de enfrente de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 10, 'Y el príncipe, cuando ellos entraren, él entrará en medio de ellos: y cuando ellos salieren, él saldrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 11, 'Y en las fiestas y en las solemnidades será el presente un epha con cada becerro, y un epha con cada carnero; y con los corderos, lo que le pareciere; y un hin de aceite con cada epha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 12, 'Mas cuando el príncipe libremente hiciere holocausto ó pacíficos á Jehová, abriránle la puerta que mira al oriente, y hará su holocausto y sus pacíficos, como hace en el día del sábado: después saldrá; y cerrarán la puerta después que saliere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 13, 'Y sacrificarás á Jehová cada día en holocausto un cordero de un año sin defecto, cada mañana lo sacrificarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 14, 'Y con él harás todas las mañanas presente de la sexta parte de un epha, y la tercera parte de un hin de aceite para mezclar con la flor de harina: presente para Jehová continuamente por estatuto perpetuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 15, 'Ofrecerán pues el cordero, y el presente y el aceite, todas las mañanas en holocausto continuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 16, 'Así ha dicho el Señor Jehová: Si el príncipe diere algún don de su heredad á alguno de sus hijos, será de ellos; posesión de ellos será por herencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 17, 'Mas si de su heredad diere don á alguno de sus siervos, será de él hasta el año de libertad, y volverá al príncipe; mas su herencia será de sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 18, 'Y el príncipe no tomará nada de la herencia del pueblo, por no defraudarlos de su posesión: de lo que él posee dará herencia á sus hijos; para que mi pueblo no sea echado cada uno de su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 19, 'Metióme después por la entrada que estaba hacia la puerta, á las cámaras santas de los sacerdotes, las cuales miraban al norte, y había allí un lugar á los lados del occidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 20, 'Y díjome: Este es el lugar donde los sacerdotes cocerán el sacrificio por el pecado y la expiación: allí cocerán el presente, por no sacarlo al atrio de afuera para santificar al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 21, 'Luego me sacó al atrio de afuera, y llevóme por los cuatro rincones del atrio; y en cada rincón había un patio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 22, 'En los cuatro rincones del atrio había patios juntos de cuarenta codos de longitud, y treinta de anchura: tenían una misma medida todos cuatro á los rincones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 23, 'Y había una pared alrededor de ellos, alrededor de todos cuatro, y chimeneas hechas abajo alrededor de las paredes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 46, 24, 'Y díjome: Estos son los aposentos de los cocineros, donde los servidores de la casa cocerán el sacrificio del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 1, 'HIZOME tornar luego á la entrada de la casa; y he aquí aguas que salían de debajo del umbral de la casa hacia el oriente: porque la fachada de la casa estaba al oriente: y las aguas descendían de debajo, hacia el lado derecho de la casa, al mediodía del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 2, 'Y sacóme por el camino de la puerta del norte, é hízome rodear por el camino fuera de la puerta, por de fuera al camino de la que mira al oriente: y he aquí las aguas que salían al lado derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 3, 'Y saliendo el varón hacia el oriente, tenía un cordel en su mano; y midió mil codos, é hízome pasar por las aguas hasta los tobillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 4, 'Y midió otros mil, é hízome pasar por las aguas hasta las rodillas. Midió luego otros mil, é hízome pasar por las aguas hasta los lomos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 5, 'Y midió otros mil, é iba ya el arroyo que yo no podía pasar: porque las aguas se habían alzado, y el arroyo no se podía pasar sino á nado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 6, 'Y díjome: ¿Has visto, hijo del hombre? Después me llevó, é hízome tornar por la ribera del arroyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 7, 'Y tornando yo, he aquí en la ribera del arroyo había árboles muy muchos de la una parte y de la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 8, 'Y díjome: Estas aguas salen á la región del oriente, y descenderán á la llanura, y entrarán en la mar: y entradas en la mar, recibirán sanidad las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 9, 'Y será que toda alma viviente que nadare por donde quiera que entraren estos dos arroyos, vivirá: y habrá muy muchos peces por haber entrado allá estas aguas, y recibirán sanidad; y vivirá todo lo que entrare en este arroyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 10, 'Y será que junto á él estarán pescadores; y desde En-gadi hasta En-eglaim será tendedero de redes: en su clase será su pescado como el pescado de la gran mar, mucho en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 11, 'Sus charcos y sus lagunas no se sanarán; quedarán para salinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 12, 'Y junto al arroyo, en su ribera de una parte y de otra, crecerá todo árbol de comer: su hoja nunca caerá, ni faltará su fruto: á sus meses madurará, porque sus aguas salen del santuario: y su fruto será para comer, y su hoja para medicina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 13, 'Así ha dicho el Señor Jehová: Este es el término en que partiréis la tierra en heredad entre las doce tribus de Israel: José dos partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 14, 'Y la heredaréis así los unos como los otros: por ella alcé mi mano que la había de dar á vuestros padres: por tanto, esta tierra os caerá en heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 15, 'Y este será el término de la tierra hacia la parte del norte; desde la gran mar, camino de Hethlon viniendo á Sedad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 16, 'Hamath, Berotha, Sibrahim, que está entre el término de Damasco y el término de Hamath; Haser-hatticon, que es el término de Hauran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 17, 'Y será el término del norte desde la mar de Haser-enon al término de Damasco al norte, y al término de Hamath al lado del norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 18, 'Al lado del oriente, por medio de Hauran y de Damasco, y de Galaad, y de la tierra de Israel, al Jordán: esto mediréis de término hasta la mar del oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 19, 'Y al lado del mediodía, hacia el mediodía, desde Tamar hasta las aguas de las rencillas; desde Cades y el arroyo hasta la gran mar: y esto será el lado austral, al mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 20, 'Y al lado del occidente la gran mar será el término hasta en derecho para venir á Hamath: este será el lado del occidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 21, 'Partiréis, pues, esta tierra entre vosotros por las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 22, 'Y será que echaréis sobre ella suertes por herencia para vosotros, y para los extranjeros que peregrinan entre vosotros, que entre vosotros han engendrado hijos: y los tendréis como naturales entre los hijos de Israel; echarán suertes con vosotros para heredarse entre las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 47, 23, 'Y será que en la tribu en que peregrinare el extranjero, allí le daréis su heredad, ha dicho el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 1, 'Y ESTOS son los nombres de las tribus: Desde la extremidad septentrional por la vía de Hethlon viniendo á Hamath, Haser-enon, al término de Damasco, al norte, al término de Hamath: tendrá Dan una parte, siendo sus extremidades al oriente y al occidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 2, 'Y junto al término de Dan, desde la parte del oriente hasta la parte de la mar, Aser una parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 3, 'Y junto al término de Aser, desde el lado oriental hasta la parte de la mar, Nephtalí, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 4, 'Y junto al término de Nephtalí, desde la parte del oriente hasta la parte de la mar, Manasés, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 5, 'Y junto al término de Manasés, desde la parte del oriente hasta la parte de la mar, Ephraim, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 6, 'Y junto al término de Ephraim, desde la parte del oriente hasta la parte de la mar, Rubén, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 7, 'Y junto al término de Rubén, desde la parte del oriente hasta la parte de la mar, Judá, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 8, 'Y junto al término de Judá, desde la parte del oriente hasta la parte de la mar, será la suerte que apartaréis de veinticinco mil cañas de anchura, y de longitud como cualquiera de las otras partes es á saber, desde la parte del oriente hasta la parte de la mar; y el santuario estará en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 9, 'La suerte que apartaréis para Jehová, será de longitud de veinticinco mil cañas, y de diez mil de ancho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 10, 'Y allí será la suerte santa de los sacerdotes, de veinticinco mil cañas al norte, y de diez mil de anchura al occidente, y de diez mil de ancho al oriente, y de veinticinco mil de longitud al mediodía: y el santuario de Jehová estará en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 11, 'Los sacerdotes santificados de los hijos de Sadoc, que guardaron mi observancia, que no erraron cuando erraron los hijos de Israel, como erraron los Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 12, 'Ellos tendrán por suerte, apartada en la partición de la tierra, la parte santísima, junto al término de los Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 13, 'Y la de los Levitas, al lado del término de los sacerdotes, será de veinticinco mil cañas de longitud, y de diez mil de anchura: toda la longitud de veinticinco mil, y la anchura de diez mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 14, 'No venderán de ello, ni permutarán, ni traspasarán las primicias de la tierra: porque es cosa consagrada á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 15, 'Y las cinco mil cañas de anchura que quedan de las veinticinco mil, serán profanas, para la ciudad, para habitación y para ejido; y la ciudad estará en medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 16, 'Y estas serán sus medidas: á la parte del norte cuatro mil y quinientas cañas, y á la parte del mediodía cuatro mil y quinientas, y á la parte del oriente cuatro mil y quinientas, y á la parte del occidente cuatro mil y quinientas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 17, 'Y el ejido de la ciudad será al norte de doscientas y cincuenta cañas, y al mediodía de doscientas y cincuenta, y al oriente de doscientas y cincuenta, y de doscientas y cincuenta al occidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 18, 'Y lo que quedare de longitud delante de la suerte santa, diez mil cañas al oriente y diez mil al occidente, que será lo que quedará de la suerte santa, será para sembrar para los que sirven á la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 19, 'Y los que servirán á la ciudad, serán de todas las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 20, 'Todo el apartado de veinticinco mil cañas por veinticinco mil en cuadro, apartaréis por suerte para el santuario, y para la posesión de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 21, 'Y del príncipe será lo que quedare de la una parte y de la otra de la suerte santa, y de la posesión de la ciudad, es á saber, delante de las veinticinco mil cañas de la suerte hasta el término oriental, y al occidente delante de las veinticinco mil hasta el término occidental, delante de las partes dichas será del príncipe: y suerte santa será; y el santuario de la casa estará en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 22, 'Y desde la posesión de los Levitas, y desde la posesión de la ciudad, en medio estará lo que pertenecerá al príncipe. Entre el término de Judá y el término de Benjamín estará la suerte del príncipe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 23, 'Cuanto á las demás tribus, desde la parte del oriente hasta la parte de la mar, tendrá Benjamín una parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 24, 'Y junto al término de Benjamín, desde la parte del oriente hasta la parte de la mar, Simeón, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 25, 'Y junto al término de Simeón, desde la parte del oriente hasta la parte de la mar, Issachâr, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 26, 'Y junto al término de Issachâr, desde la parte del oriente hasta la parte de la mar, Zabulón, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 27, 'Y junto al término de Zabulón, desde la parte del oriente hasta la parte de la mar, Gad, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 28, 'Y junto al término de Gad, á la parte del austro, al mediodía, será el término desde Tamar hasta las aguas de las rencillas, y desde Cades y el arroyo hasta la gran mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 29, 'Esta es la tierra que partiréis por suertes en heredad á las tribus de Israel, y estas son sus porciones, ha dicho el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 30, 'Y estas son las salidas de la ciudad á la parte del norte, cuatro mil y quinientas cañas por medida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 31, 'Y las puertas de la ciudad serán según los nombres de las tribus de Israel: tres puertas al norte: la puerta de Rubén, una; la puerta de Judá, otra; la puerta de Leví, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 32, 'Y á la parte del oriente cuatro mil y quinientas cañas, y tres puertas: la puerta de José, una; la puerta de Benjamín, otra; la puerta de Dan, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 33, 'Y á la parte del mediodía, cuatro mil y quinientas cañas por medida, y tres puertas: la puerta de Simeón, una; la puerta de Issachâr, otra; la puerta de Zabulón, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 34, 'Y á la parte del occidente cuatro mil y quinientas cañas, y sus tres puertas: la puerta de Gad, una; la puerta de Aser, otra; la puerta de Nephtalí, otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZK', 'Ezequiel', 48, 35, 'En derredor tendrá dieciocho mil cañas. Y el nombre de la ciudad desde aquel día será JEHOVA SHAMMA.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 1, 'EN el año tercero del reinado de Joacim rey de Judá, vino Nabucodonosor rey de Babilonia á Jerusalem, y cercóla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 2, 'Y el Señor entregó en sus manos á Joacim rey de Judá, y parte de los vasos de la casa de Dios, y trájolos á tierra de Sinar, á la casa de su dios: y metió los vasos en la casa del tesoro de su dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 3, 'Y dijo el rey á Aspenaz, príncipe de sus eunucos, que trajese de los hijos de Israel, del linaje real de los príncipes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 4, 'Muchachos en quienes no hubiese tacha alguna, y de buen parecer, y enseñados en toda sabiduría, y sabios en ciencia, y de buen entendimiento, é idóneos para estar en el palacio del rey; y que les enseñase las letras y la lengua de los Caldeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 5, 'Y señalóles el rey ración para cada día de la ración de la comida del rey, y del vino de su beber: que los criase tres años, para que al fin de ellos estuviesen delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 6, 'Y fueron entre ellos, de los hijos de Judá, Daniel, Ananías, Misael y Azarías:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 7, 'A los cuales el príncipe de los eunucos puso nombres: y puso á Daniel, Beltsasar; y á Ananías, Sadrach; y á Misael, Mesach; y á Azarías, Abed-nego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 8, 'Y Daniel propuso en su corazón de no contaminarse en la ración de la comida del rey, ni en el vino de su beber: pidió por tanto al príncipe de los eunucos de no contaminarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 9, '(Y puso Dios á Daniel en gracia y en buena voluntad con el príncipe de los eunucos.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 10, 'Y dijo el príncipe de los eunucos á Daniel: Tengo temor de mi señor el rey, que señaló vuestra comida y vuestra bebida; pues luego que él habrá visto vuestros rostros más tristes que los de los muchachos que son semejantes á vosotros, condenaréis para con el rey mi cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 11, 'Entonces dijo Daniel á Melsar, que estaba puesto por el príncipe de los eunucos sobre Daniel, Ananías, Misael, y Azarías:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 12, 'Prueba, te ruego, tus siervos diez días, y dennos legumbres á comer, y agua á beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 13, 'Parezcan luego delante de ti nuestros rostros, y los rostros de los muchachos que comen de la ración de la comida del rey; y según que vieres, harás con tus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 14, 'Consintió pues con ellos en esto, y probó con ellos diez días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 15, 'Y al cabo de los diez días pareció el rostro de ellos mejor y más nutrido de carne, que los otros muchachos que comían de la ración de comida del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 16, 'Así fué que Melsar tomaba la ración de la comida de ellos, y el vino de su beber, y dábales legumbres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 17, 'Y á estos cuatro muchachos dióles Dios conocimiento é inteligencia en todas letras y ciencia: mas Daniel tuvo entendimiento en toda visión y sueños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 18, 'Pasados pues los días al fin de los cuales había dicho el rey que los trajesen, el príncipe de los eunucos los trajo delante de Nabucodonosor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 19, 'Y el rey habló con ellos, y no fué hallado entre todos ellos otro como Daniel, Ananías, Misael, y Azarías: y así estuvieron delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 20, 'Y en todo negocio de sabiduría é inteligencia que el rey les demandó, hallólos diez veces mejores que todos los magos y astrólogos que había en todo su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 1, 21, 'Y fué Daniel hasta el año primero del rey Ciro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 1, 'Y EN el segundo año del reinado de Nabucodonosor, soñó Nabucodonosor sueños, y perturbóse su espíritu, y su sueño se huyó de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 2, 'Y mandó el rey llamar magos, astrólogos, y encantadores, y Caldeos, para que mostrasen al rey sus sueños. Vinieron pues, y se presentaron delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 3, 'Y el rey les dijo: He soñado un sueño, y mi espíritu se ha perturbado por saber del sueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 4, 'Entonces hablaron los Caldeos al rey en lengua aramea: Rey, para siempre vive: di el sueño á tus siervos, y mostraremos la declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 5, 'Respondió el rey y dijo á los Caldeos: El negocio se me fué: si no me mostráis el sueño y su declaración, seréis hechos cuartos, y vuestras casas serán puestas por muladares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 6, 'Y si mostrareis el sueño y su declaración, recibiréis de mí dones y mercedes y grande honra: por tanto, mostradme el sueño y su declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 7, 'Respondieron la segunda vez, y dijeron: Diga el rey el sueño á sus siervos, y mostraremos su declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 8, 'El rey respondió, y dijo: Yo conozco ciertamente que vosotros ponéis dilaciones, porque veis que el negocio se me ha ido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 9, 'Si no me mostráis el sueño, una sola sentencia será de vosotros. Ciertamente preparáis respuesta mentirosa y perversa que decir delante de mí, entre tanto que se muda el tiempo: por tanto, decidme el sueño, para que yo entienda que me podéis mostrar su declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 10, 'Los Caldeos respondieron delante del rey, y dijeron: No hay hombre sobre la tierra que pueda declarar el negocio del rey: demás de esto, ningún rey, príncipe, ni señor, preguntó cosa semejante á ningún mago, ni astrólogo, ni Caldeo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 11, 'Finalmente, el negocio que el rey demanda, es singular, ni hay quien lo pueda declarar delante del rey, salvo los dioses cuya morada no es con la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 12, 'Por esto el rey con ira y con grande enojo, mandó que matasen á todos los sabios de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 13, 'Y publicóse el mandamiento, y los sabios eran llevados á la muerte; y buscaron á Daniel y á sus compañeros para matarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 14, 'Entonces Daniel habló avisada y prudentemente á Arioch, capitán de los de la guarda del rey, que había salido para matar los sabios de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 15, 'Habló y dijo á Arioch capitán del rey: ¿Qué es la causa que este mandamiento se publica de parte del rey tan apresuradamente? Entonces Arioch declaró el negocio á Daniel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 16, 'Y Daniel entró, y pidió al rey que le diese tiempo, y que él mostraría al rey la declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 17, 'Fuése luego Daniel á su casa, y declaró el negocio á Ananías, Misael, y Azarías, sus compañeros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 18, 'Para demandar misericordias del Dios del cielo sobre este misterio, y que Daniel y sus compañeros no pereciesen con los otros sabios de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 19, 'Entonces el arcano fué revelado á Daniel en visión de noche; por lo cual bendijo Daniel al Dios del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 20, 'Y Daniel habló, y dijo: Sea bendito el nombre de Dios de siglo hasta siglo: porque suya es la sabiduría y la fortaleza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 21, 'Y él es el que muda los tiempos y las oportunidades: quita reyes, y pone reyes: da la sabiduría á los sabios, y la ciencia á los entendidos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 22, 'El revela lo profundo y lo escondido: conoce lo que está en tinieblas, y la luz mora con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 23, 'A ti, oh Dios de mis padres, confieso y te alabo, que me diste sabiduría y fortaleza, y ahora me enseñaste lo que te pedimos; pues nos has enseñado el negocio del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 24, 'Después de esto Daniel entró á Arioch, al cual el rey había puesto para matar á los sabios de Babilonia; fué, y díjole así: No mates á los sabios de Babilonia: llévame delante del rey, que yo mostraré al rey la declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 25, 'Entonces Arioch llevó prestamente á Daniel delante del rey, y díjole así: Un varón de los trasportados de Judá he hallado, el cual declarará al rey la interpretación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 26, 'Respondió el rey, y dijo á Daniel, al cual llamaban Beltsasar: ¿Podrás tú hacerme entender el sueño que vi, y su declaración?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 27, 'Daniel respondió delante del rey, y dijo: El misterio que el rey demanda, ni sabios, ni astrólogos, ni magos, ni adivinos lo pueden enseñar al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 28, 'Mas hay un Dios en los cielos, el cual revela los misterios, y él ha hecho saber al rey Nabucodonosor lo que ha de acontecer á cabo de días. Tu sueño, y las visiones de tu cabeza sobre tu cama, es esto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 29, 'Tú, oh rey, en tu cama subieron tus pensamientos por saber lo que había de ser en lo por venir; y el que revela los misterios te mostró lo que ha de ser.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 30, 'Y á mí ha sido revelado este misterio, no por sabiduría que en mí haya, más que en todos los vivientes, sino para que yo notifique al rey la declaración, y que entiendieses los pensamientos de tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 31, 'Tú, oh rey, veías, y he aquí una grande imagen. Esta imagen, que era muy grande, y cuya gloria era muy sublime, estaba en pie delante de ti, y su aspecto era terrible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 32, 'La cabeza de esta imagen era de fino oro; sus pechos y sus brazos, de plata; su vientre y sus muslos, de metal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 33, 'Sus piernas de hierro; sus pies, en parte de hierro, y en parte de barro cocido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 34, 'Estabas mirando, hasta que una piedra fué cortada, no con mano, la cual hirió á la imagen en sus pies de hierro y de barro cocido, y los desmenuzó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 35, 'Entonces fué también desmenuzado el hierro, el barro cocido, el metal, la plata y el oro, y se tornaron como tamo de las eras del verano: y levantólos el viento, y nunca más se les halló lugar. Mas la piedra que hirió á la imagen, fué hecha un gran monte, que hinchió toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 36, 'Este es el sueño: la declaración de él diremos también en presencia del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 37, 'Tú, oh rey, eres rey de reyes; porque el Dios del cielo te ha dado reino, potencia, y fortaleza, y majestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 38, 'Y todo lo que habitan hijos de hombres, bestias del campo, y aves del cielo, él ha entregado en tu mano, y te ha hecho enseñorear sobre todo: tú eres aquella cabeza de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 39, 'Y después de ti se levantará otro reino menor que tú; y otro tercer reino de metal, el cual se enseñoreará de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 40, 'Y el reino cuarto será fuerte como hierro; y como el hierro desmenuza y doma todas las cosas, y como el hierro que quebranta todas estas cosas, desmenuzará y quebrantará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 41, 'Y lo que viste de los pies y los dedos, en parte de barro cocido de alfarero, y en parte de hierro, el reino será dividido; mas habrá en él algo de fortaleza de hierro, según que viste el hierro mezclado con el tiesto de barro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 42, 'Y por ser los dedos de los pies en parte de hierro, y en parte de barro cocido, en parte será el reino fuerte, y en parte será frágil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 43, 'Cuanto á aquello que viste, el hierro mezclado con tiesto de barro, mezclaránse con simiente humana, mas no se pegarán el uno con el otro, como el hierro no se mistura con el tiesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 44, 'Y en los días de estos reyes, levantará el Dios del cielo un reino que nunca jamás se corromperá: y no será dejado á otro pueblo este reino; el cual desmenuzará y consumirá todos estos reinos, y él permanecerá para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 45, 'De la manera que viste que del monte fué cortada una piedra, no con manos, la cual desmenuzó al hierro, al metal, al tiesto, á la plata, y al oro; el gran Dios ha mostrado al rey lo que ha de acontecer en lo por venir: y el sueño es verdadero, y fiel su declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 46, 'Entonces el rey Nabucodonosor cayó sobre su rostro, y humillóse á Daniel, y mandó que le sacrificasen presentes y perfumes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 47, 'El rey habló á Daniel, y dijo: Ciertamente que el Dios vuestro es Dios de dioses, y el Señor de los reyes, y el descubridor de los misterios, pues pudiste revelar este arcano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 48, 'Entonces el rey engrandeció á Daniel, y le dió muchos y grandes dones, y púsolo por gobernador de toda la provincia de Babilonia, y por príncipe de los gobernadores sobre todos los sabios de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 2, 49, 'Y Daniel solicitó del rey, y él puso sobre los negocios de la provincia de Babilonia á Sadrach, Mesach, y Abed-nego: y Daniel estaba á la puerta del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 1, 'EL rey Nabucodonosor hizo una estatua de oro, la altura de la cual era de sesenta codos, su anchura de seis codos: levantóla en el campo de Dura, en la provincia de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 2, 'Y envió el rey Nabucodonosor á juntar los grandes, los asistentes y capitanes, oidores, receptores, los del consejo, presidentes, y á todos los gobernadores de las provincias, para que viniesen á la dedicación de la estatua que el rey Nabucodonosor había levantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 3, 'Fueron pues reunidos los grandes, los asistentes y capitanes, los oidores, receptores, los del consejo, los presidentes, y todos los gobernadores de las provincias, á la dedicación de la estatua que el rey Nabucodonosor había levantado: y estaban en pie delante de la estatua que había levantado el rey Nabucodonosor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 4, 'Y el pregonero pregonaba en alta voz: Mándase á vosotros, oh pueblos, naciones, y lenguas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 5, 'En oyendo el son de la bocina, del pífano, del tamboril, del arpa, del salterio, de la zampoña, y de todo instrumento músico, os postraréis y adoraréis la estatua de oro que el rey Nabucodonosor ha levantado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 6, 'Y cualquiera que no se postrare y adorare, en la misma hora será echado dentro de un horno de fuego ardiendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 7, 'Por lo cual, en oyendo todos los pueblos el son de la bocina, del pífano, del tamboril, del arpa, del salterio, de la zampoña, y de todo instrumento músico, todos los pueblos, naciones, y lenguas, se postraron, y adoraron la estatua de oro que el rey Nabucodonosor había levantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 8, 'Por esto en el mismo tiempo algunos varones Caldeos se llegaron, y denunciaron de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 9, 'Hablando y diciendo al rey Nabucodonosor: Rey, para siempre vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 10, 'Tú, oh rey, pusiste ley que todo hombre en oyendo el son de la bocina, del pífano, del tamboril, del arpa, del salterio, de la zampoña, y de todo instrumento músico, se postrase y adorase la estatua de oro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 11, 'Y el que no se postrase y adorase, fuese echado dentro de un horno de fuego ardiendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 12, 'Hay unos varones Judíos, los cuales pusiste tú sobre los negocios de la provincia de Babilonia; Sadrach, Mesach, y Abed-nego: estos varones, oh rey, no han hecho cuenta de ti; no adoran tus dioses, no adoran la estatua de oro que tú levantaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 13, 'Entonces Nabucodonosor dijo con ira y con enojo que trajesen á Sadrach, Mesach, y Abed-nego. Al punto fueron traídos estos varones delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 14, 'Habló Nabucodonosor, y díjoles: ¿Es verdad Sadrach, Mesach, y Abed-nego, que vosotros no honráis á mi dios, ni adoráis la estatua de oro que he levantado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 15, 'Ahora pues, ¿estáis prestos para que en oyendo el son de la bocina, del pífano, del tamboril, del arpa, del salterio, de la zampoña, y de todo instrumento músico, os postréis, y adoréis la estatua que he hecho? Porque si no la adorareis, en la misma hora seréis echados en medio de un horno de fuego ardiendo: ¿y qué dios será aquel que os libre de mis manos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 16, 'Sadrach, Mesach, y Abed-nego respondieron y dijeron al rey Nabucodonosor: no cuidamos de responderte sobre este negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 17, 'He aquí nuestro Dios á quien honramos, puede librarnos del horno de fuego ardiendo; y de tu mano, oh rey, nos librará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 18, 'Y si no, sepas, oh rey, que tu dios no adoraremos, ni tampoco honraremos la estatua que has levantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 19, 'Entonces Nabucodonosor fué lleno de ira, y demudóse la figura de su rostro sobre Sadrach, Mesach, y Abed-nego: así habló, y ordenó que el horno se encendiese siete veces tanto de lo que cada vez solía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 20, 'Y mandó á hombres muy vigorosos que tenía en su ejército, que atasen á Sadrach, Mesach, y Abed-nego, para echarlos en el horno de fuego ardiendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 21, 'Entonces estos varones fueron atados con sus mantos, y sus calzas, y sus turbantes, y sus vestidos, y fueron echados dentro del horno de fuego ardiendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 22, 'Y porque la palabra del rey daba priesa, y había procurado que se encendiese mucho, la llama del fuego mató á aquellos que habían alzado á Sadrach, Mesach, y Abed-nego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 23, 'Y estos tres varones, Sadrach, Mesach, y Abed-nego, cayeron atados dentro del horno de fuego ardiendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 24, 'Entonces el rey Nabucodonosor se espantó, y levantóse apriesa, y habló, y dijo á los de su consejo: ¿No echaron tres varones atados dentro del fuego? Ellos respondieron y dijeron al rey: Es verdad, oh rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 25, 'Respondió él y dijo: He aquí que yo veo cuatro varones sueltos, que se pasean en medio del fuego, y ningún daño hay en ellos: y el parecer del cuarto es semejante á hijo de los dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 26, 'Entonces Nabucodonosor se acercó á la puerta del horno de fuego ardiendo, y habló y dijo: Sadrach, Mesach, y Abed-nego, siervos del alto Dios, salid y venid. Entonces Sadrach, Mesach, y Abed-nego, salieron de en medio del fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 27, 'Y juntáronse los grandes, los gobernadores, los capitanes, y los del consejo del rey, para mirar estos varones, como el fuego no se enseñoreó de sus cuerpos, ni cabello de sus cabezas fué quemado, ni sus ropas se mudaron, ni olor de fuego había pasado por ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 28, 'Nabucodonosor habló y dijo: Bendito el Dios de ellos, de Sadrach, Mesach, y Abed-nego, que envió su ángel, y libró sus siervos que esperaron en él, y el mandamiento del rey mudaron, y entregaron sus cuerpos antes que sirviesen ni adorasen otro dios que su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 29, 'Por mí pues se pone decreto, que todo pueblo, nación, ó lengua, que dijere blasfemia contra el Dios de Sadrach, Mesach, y Abed-nego, sea descuartizado, y su casa sea puesta por muladar; por cuanto no hay dios que pueda librar como éste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 3, 30, 'Entonces el rey engrandeció á Sadrach, Mesach, y Abed-nego en la provincia de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 1, 'NABUCODONOSOR rey, á todos los pueblos, naciones, y lenguas, que moran en toda la tierra: Paz os sea multiplicada:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 2, 'Las señales y milagros que el alto Dios ha hecho conmigo, conviene que yo las publique.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 3, '¡Cuán grandes son sus señales, y cuán potentes sus maravillas! Su reino, reino sempiterno, y su señorío hasta generación y generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 4, 'Yo Nabucodonosor estaba quieto en mi casa, y floreciente en mi palacio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 5, 'Vi un sueño que me espantó, y las imaginaciones y visiones de mi cabeza me turbaron en mi cama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 6, 'Por lo cual yo puse mandamiento para hacer venir delante de mí todos los sabios de Babilonia, que me mostrasen la declaración del sueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 7, 'Y vinieron magos, astrólogos, Caldeos, y adivinos: y dije el sueño delante de ellos, mas nunca me mostraron su declaración;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 8, 'Hasta tanto que entró delante de mí Daniel, cuyo nombre es Beltsasar, como el nombre de mi dios, y en el cual hay espíritu de los dioses santos, y dije el sueño delante de él, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 9, 'Beltsasar, príncipe de los magos, ya que he entendido que hay en ti espíritu de los dioses santos, y que ningún misterio se te esconde, exprésame las visiones de mi sueño que he visto, y su declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 10, 'Aquestas las visiones de mi cabeza en mi cama: Parecíame que veía un árbol en medio de la tierra, cuya altura era grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 11, 'Crecía este árbol, y hacíase fuerte, y su altura llegaba hasta el cielo, y su vista hasta el cabo de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 12, 'Su copa era hermosa, y su fruto en abundancia, y para todos había en él mantenimiento. Debajo de él se ponían á la sombra las bestias del campo, y en sus ramas hacían morada las aves del cielo, y manteníase de él toda carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 13, 'Veía en las visiones de mi cabeza en mi cama, y he aquí que un vigilante y santo descendía del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 14, 'Y clamaba fuertemente y decía así: Cortad el árbol, y desmochad sus ramas, derribad su copa, y derramad su fruto: váyanse las bestias que están debajo de él, y las aves de sus ramas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 15, 'Mas la cepa de sus raíces dejaréis en la tierra, y con atadura de hierro y de metal entre la hierba del campo; y sea mojado con el rocío del cielo, y su parte con las bestias en la hierba de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 16, 'Su corazón sea mudado de corazón de hombre, y séale dado corazón de bestia, y pasen sobre él siete tiempos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 17, 'La sentencia es por decreto de los vigilantes, y por dicho de los santos la demanda: para que conozcan los vivientes que el Altísimo se enseñorea del reino de los hombres, y que á quien él quiere lo da, y constituye sobre él al más bajo de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 18, 'Yo el rey Nabucodonosor he visto este sueño. Tú pues, Beltsasar, dirás la declaración de él, porque todos los sabios de mi reino nunca pudieron mostrarme su interpretación: mas tú puedes, porque hay en ti espíritu de los dioses santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 19, 'Entonces Daniel, cuyo nombre era Beltsasar, estuvo callando casi una hora, y sus pensamientos lo espantaban: El rey habló, y dijo: Beltsasar, el sueño ni su declaración no te espante. Respondió Beltsasar, y dijo: Señor mío, el sueño sea para tus enemigos, y su declaración para los que mal te quieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 20, 'El árbol que viste, que crecía y se hacía fuerte, y que su altura llegaba hasta el cielo, y su vista por toda la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 21, 'Y cuya copa era hermosa, y su fruto en abundancia, y que para todos había mantenimiento en él; debajo del cual moraban las bestias del campo, y en sus ramas habitaban las aves del cielo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 22, 'Tú mismo eres, oh rey, que creciste, y te hiciste fuerte, pues creció tu grandeza, y ha llegado hasta el cielo, y tu señorío hasta el cabo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 23, 'Y cuanto á lo que vió el rey, un vigilante y santo que descendía del cielo, y decía: Cortad el árbol y destruidlo: mas la cepa de sus raíces dejaréis en la tierra, y con atadura de hierro y de metal en la hierba del campo; y sea mojado con el rocío del cielo, y su parte sea con las bestias del campo, hasta que pasen sobre él siete tiempos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 24, 'Esta es la declaración, oh rey, y la sentencia del Altísimo, que ha venido sobre el rey mi señor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 25, 'Que te echarán de entre los hombres, y con las bestias del campo será tu morada, y con hierba del campo te apacentarán como á los bueyes, y con rocío del cielo serás bañado; y siete tiempos pasarán sobre ti, hasta que entiendas que el Altísimo se enseñorea en el reino de los hombres, y que á quien él quisiere lo dará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 26, 'Y lo que dijeron, que dejasen en la tierra la cepa de las raíces del mismo árbol, significa que tu reino se te quedará firme, luego que entiendas que el señorío es en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 27, 'Por tanto, oh rey, aprueba mi consejo, y redime tus pecados con justicia, y tus iniquidades con misericordias para con los pobres; que tal vez será eso una prolongación de tu tranquilidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 28, 'Todo aquesto vino sobre el rey Nabucodonosor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 29, 'A cabo de doce meses, andándose paseando sobre el palacio del reino de Babilonia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 30, 'Habló el rey, y dijo: ¿No es ésta la gran Babilonia, que yo edifiqué para casa del reino, con la fuerza de mi poder, y para gloria de mi grandeza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 31, 'Aun estaba la palabra en la boca del rey, cuando cae una voz del cielo: A ti dicen, rey Nabucodonosor; el reino es traspasado de ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 32, 'Y de entre los hombres te echan, y con las bestias del campo será tu morada, y como á los bueyes te apacentarán: y siete tiempos pasarán sobre ti, hasta que conozcas que el Altísimo se enseñorea en el reino de los hombres, y á quien él quisiere lo da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 33, 'En la misma hora se cumplió la palabra sobre Nabucodonosor, y fué echado de entre los hombres; y comía hierba como los bueyes, y su cuerpo se bañaba con el rocío del cielo, hasta que su pelo creció como de águila, y sus uñas como de aves.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 34, 'Mas al fin del tiempo yo Nabucodonosor alcé mis ojos al cielo, y mi sentido me fué vuelto; y bendije al Altísimo, y alabé y glorifiqué al que vive para siempre; porque su señorío es sempiterno, y su reino por todas las edades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 35, 'Y todos los moradores de la tierra por nada son contados: y en el ejército del cielo, y en los habitantes de la tierra, hace según su voluntad: ni hay quien estorbe su mano, y le diga: ¿Qué haces?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 36, 'En el mismo tiempo mi sentido me fué vuelto, y la majestad de mi reino, mi dignidad y mi grandeza volvieron á mí, y mis gobernadores y mis grandes me buscaron; y fuí restituído á mi reino, y mayor grandeza me fué añadida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 4, 37, 'Ahora yo Nabucodonosor alabo, engrandezco y glorifico al Rey del cielo, porque todas sus obras son verdad, y sus caminos juicio; y humillar puede á los que andan con soberbia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 1, 'EL rey Belsasar hizo un gran banquete á mil de sus príncipes, y en presencia de los mil bebía vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 2, 'Belsasar, con el gusto del vino, mandó que trajesen los vasos de oro y de plata que Nabucodonosor su padre había traído del templo de Jerusalem; para que bebiesen con ellos el rey y sus príncipes, sus mujeres y sus concubinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 3, 'Entonces fueron traídos los vasos de oro que habían traído del templo de la casa de Dios que estaba en Jerusalem, y bebieron con ellos el rey y sus príncipes, sus mujeres y sus concubinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 4, 'Bebieron vino, y alabaron á los dioses de oro y de plata, de metal, de hierro, de madera, y de piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 5, 'En aquella misma hora salieron unos dedos de mano de hombre, y escribían delante del candelero sobre lo encalado de la pared del palacio real, y el rey veía la palma de la mano que escribía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 6, 'Entonces el rey se demudó de su color, y sus pensamientos lo turbaron, y desatáronse las ceñiduras de sus lomos, y sus rodillas se batían la una con la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 7, 'El rey clamó en alta voz que hiciesen venir magos, Caldeos, y adivinos. Habló el rey, y dijo á los sabios de Babilonia: Cualquiera que leyere esta escritura, y me mostrare su declaración, será vestido de púrpura, y tendrá collar de oro á su cuello; y en el reino se enseñoreará el tercero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 8, 'Entonces fueron introducidos todos los sabios del rey, y no pudieron leer la escritura, ni mostrar al rey su declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 9, 'Entonces el rey Belsasar fué muy turbado, y se le mudaron sus colores y alteráronse sus príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 10, 'La reina, por las palabras del rey y de sus príncipes, entró á la sala del banquete. Y habló la reina, y dijo: Rey, para siempre vive, no te asombren tus pensamientos, ni tus colores se demuden:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 11, 'En tu reino hay un varón, en el cual mora el espíritu de los dioses santos; y en los días de tu padre se halló en él luz é inteligencia y sabiduría, como ciencia de los dioses: al cual el rey Nabucodonosor, tu padre, el rey tu padre constituyó príncipe sobre todos los magos, astrólogos, Caldeos, y adivinos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 12, 'Por cuanto fué hallado en él mayor espíritu, y ciencia, y entendimiento, interpretando sueños, y declarando preguntas, y deshaciendo dudas, es á saber, en Daniel; al cual el rey puso por nombre Beltsasar. Llámese pues ahora á Daniel, y él mostrará la declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 13, 'Entonces Daniel fué traído delante del rey. Y habló el rey, y dijo á Daniel: ¿Eres tú aquel Daniel de los hijos de la cautividad de Judá, que mi padre trajo de Judea?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 14, 'Yo he oído de ti que el espíritu de los dioses santos está en ti, y que en ti se halló luz, y entendimiento y mayor sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 15, 'Y ahora fueron traídos delante de mí, sabios, astrólogos, que leyesen esta escritura, y me mostrasen su interpretación: pero no han podido mostrar la declaración del negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 16, 'Yo pues he oído de ti que puedes declarar las dudas, y desatar dificultades. Si ahora pudieres leer esta escritura, y mostrarme su interpretación, serás vestido de púrpura, y collar de oro tendrás en tu cuello, y en el reino serás el tercer señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 17, 'Entonces Daniel respondió, y dijo delante del rey: Tus dones sean para ti, y tus presentes dalos á otro. La escritura yo la leeré al rey, y le mostraré la declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 18, 'El altísimo Dios, oh rey, dió á Nabucodonosor tu padre el reino, y la grandeza, y la gloria, y la honra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 19, 'Y por la grandeza que le dió, todos los pueblos, naciones, y lenguas, temblaban y temían delante de él. Los que él quería mataba, y daba vida á los que quería: engrandecía á los que quería, y á los que quería humillaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 20, 'Mas cuando su corazón se ensoberbeció, y su espíritu se endureció en altivez, fué depuesto del trono de su reino, y traspasaron de él la gloria:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 21, 'Y fué echado de entre los hijos de los hombres; y su corazón fué puesto con las bestias, y con los asnos monteses fué su morada. Hierba le hicieron comer, como á buey, y su cuerpo fué bañado con el rocío del cielo, hasta que conoció que el altísimo Dios se enseñorea del reino de los hombres, y que pondrá sobre él al que quisiere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 22, 'Y tú, su hijo Belsasar, no has humillado tu corazón, sabiendo todo esto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 23, 'Antes contra el Señor del cielo te has ensoberbecido, é hiciste traer delante de ti los vasos de su casa, y tú y tus príncipes, tus mujeres y tus concubinas, bebisteis vino en ellos: demás de esto, á dioses de plata y de oro, de metal, de hierro, de madera, y de piedra, que ni ven, ni oyen, ni saben, diste alabanza: y al Dios en cuya mano está tu vida, y cuyos son todos tus caminos, nunca honraste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 24, 'Entonces de su presencia fué enviada la palma de la mano que esculpió esta escritura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 25, 'Y la escritura que esculpió es: MENE, MENE, TEKEL, UPHARSIN.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 26, 'La declaración del negocio es: MENE: Contó Dios tu reino, y halo rematado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 27, 'TEKEL: Pesado has sido en balanza, y fuiste hallado falto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 28, 'PERES: Tu reino fué rompido, y es dado á Medos y Persas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 29, 'Entonces, mandándolo Belsasar, vistieron á Daniel de púrpura, y en su cuello fué puesto un collar de oro, y pregonaron de él que fuese el tercer señor en el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 30, 'La misma noche fué muerto Belsasar, rey de los Caldeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 5, 31, 'Y Darío de Media tomó el reino, siendo de sesenta y dos años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 1, 'PARECIO bien á Darío constituir sobre el reino ciento veinte gobernadores, que estuviesen en todo el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 2, 'Y sobre ellos tres presidentes, de los cuales Daniel era el uno, á quienes estos gobernadores diesen cuenta, porque el rey no recibiese daño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 3, 'Pero el mismo Daniel era superior á estos gobernadores y presidentes, porque había en él más abundancia de espíritu: y el rey pensaba de ponerlo sobre todo el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 4, 'Entonces los presidentes y gobernadores buscaban ocasiones contra Daniel por parte del reino; mas no podían hallar alguna ocasión ó falta, porque él era fiel, y ningún vicio ni falta fué en él hallado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 5, 'Entonces dijeron aquellos hombres: No hallaremos contra este Daniel ocasión alguna, si no la hallamos contra él en la ley de su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 6, 'Entonces estos gobernadores y presidentes se juntaron delante del rey, y le dijeron así: Rey Darío, para siempre vive:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 7, 'Todos los presidentes del reino, magistrados, gobernadores, grandes y capitanes, han acordado por consejo promulgar un real edicto, y confirmarlo, que cualquiera que demandare petición de cualquier dios ú hombre en el espacio de treinta días, sino de ti, oh rey, sea echado en el foso de los leones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 8, 'Ahora, oh rey, confirma el edicto, y firma la escritura, para que no se pueda mudar, conforme á la ley de Media y de Persia, la cual no se revoca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 9, 'Firmó pues el rey Darío la escritura y el edicto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 10, 'Y Daniel, cuando supo que la escritura estaba firmada, entróse en su casa, y abiertas las ventanas de su cámara que estaban hacia Jerusalem, hincábase de rodillas tres veces al día, y oraba, y confesaba delante de su Dios, como lo solía hacer antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 11, 'Entonces se juntaron aquellos hombres, y hallaron á Daniel orando y rogando delante de su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 12, 'Llegáronse luego, y hablaron delante del rey acerca del edicto real: ¿No has confirmado edicto que cualquiera que pidiere á cualquier dios ú hombre en el espacio de treinta días, excepto á ti, oh rey, fuese echado en el foso de los leones? Respondió el rey y dijo: Verdad es, conforme á la ley de Media y de Persia, la cual no se abroga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 13, 'Entonces respondieron y dijeron delante del rey: Daniel que es de los hijos de la cautividad de los Judíos, no ha hecho cuenta de ti, oh rey, ni del edicto que confirmaste; antes tres veces al día hace su petición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 14, 'El rey entonces, oyendo el negocio, pesóle en gran manera, y sobre Daniel puso cuidado para librarlo; y hasta puestas del sol trabajó para librarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 15, 'Empero aquellos hombres se reunieron cerca del rey, y dijeron al rey: Sepas, oh rey, que es ley de Media y de Persia, que ningún decreto ú ordenanza que el rey confirmare pueda mudarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 16, 'Entonces el rey mandó, y trajeron á Daniel, y echáronle en el foso de los leones. Y hablando el rey dijo á Daniel: El Dios tuyo, á quien tú continuamente sirves, él te libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 17, 'Y fué traída una piedra, y puesta sobre la puerta del foso, la cual selló el rey con su anillo, y con el anillo de sus príncipes, porque el acuerdo acerca de Daniel no se mudase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 18, 'Fuése luego el rey á su palacio, y acostóse ayuno; ni instrumentos de música fueron traídos delante de él, y se le fué el sueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 19, 'El rey, por tanto, se levantó muy de mañana, y fué apriesa al foso de los leones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 20, 'Y llegándose cerca del foso llamó á voces á Daniel con voz triste: y hablando el rey dijo á Daniel: Daniel, siervo del Dios viviente, el Dios tuyo, á quien tú continuamente sirves ¿te ha podido librar de los leones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 21, 'Entonces habló Daniel con el rey: oh rey, para siempre vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 22, 'El Dios mío envió su ángel, el cual cerró la boca de los leones, para que no me hiciesen mal: porque delante de él se halló en mí justicia: y aun delante de ti, oh rey, yo no he hecho lo que no debiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 23, 'Entonces se alegró el rey en gran manera á causa de él, y mandó sacar á Daniel del foso: y fué Daniel sacado del foso, y ninguna lesión se halló en él, porque creyó en su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 24, 'Y mandándolo el rey fueron traídos aquellos hombres que habían acusado á Daniel, y fueron echados en el foso de los leones, ellos, sus hijos, y sus mujeres; y aun no habían llegado al suelo del foso, cuando los leones se apoderaron de ellos, y quebrantaron todos sus huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 25, 'Entonces el rey Darío escribió á todos los pueblos, naciones, y lenguas, que habitan en toda la tierra: Paz os sea multiplicada:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 26, 'De parte mía es puesta ordenanza, que en todo el señorío de mi reino todos teman y tiemblen de la presencia del Dios de Daniel: porque él es el Dios viviente y permanente por todos los siglos, y su reino tal que no será desecho, y su señorío hasta el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 27, 'Que salva y libra, y hace señales y maravillas en el cielo y en la tierra; el cual libró á Daniel del poder de los leones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 6, 28, 'Y este Daniel fué prosperado durante el reinado de Darío, y durante el reinado de Ciro, Persa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 1, 'EN el primer año de Belsasar rey de Babilonia, vió Daniel un sueño y visiones de su cabeza en su cama: luego escribió el sueño, y notó la suma de los negocios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 2, 'Habló Daniel y dijo: Veía yo en mi visión de noche, y he aquí que los cuatro vientos del cielo combatían en la gran mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 3, 'Y cuatro bestias grandes, diferentes la una de la otra, subían de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 4, 'La primera era como león, y tenía alas de águila. Yo estaba mirando hasta tanto que sus alas fueron arrancadas, y fué quitada de la tierra; y púsose enhiesta sobre los pies á manera de hombre, y fuéle dado corazón de hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 5, 'Y he aquí otra segunda bestia, semejante á un oso, la cual se puso al un lado, y tenía en su boca tres costillas entre sus dientes; y fuéle dicho así: Levántate, traga carne mucha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 6, 'Después de esto yo miraba, y he aquí otra, semejante á un tigre, y tenía cuatro alas de ave en sus espaldas: tenía también esta bestia cuatro cabezas; y fuéle dada potestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 7, 'Después de esto miraba yo en las visiones de la noche, y he aquí la cuarta bestia, espantosa y terrible, y en grande manera fuerte; la cual tenía unos dientes grandes de hierro: devoraba y desmenuzaba, y las sobras hollaba con sus pies: y era muy diferente de todas las bestias que habían sido antes de ella, y tenía diez cuernos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 8, 'Estando yo contemplando los cuernos, he aquí que otro cuerno pequeño subía entre ellos, y delante de él fueron arrancados tres cuernos de los primeros; y he aquí, en este cuerno había ojos como ojos de hombre, y una boca que hablaba grandezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 9, 'Estuve mirando hasta que fueron puestas sillas: y un Anciano de grande edad se sentó, cuyo vestido era blanco como la nieve, y el pelo de su cabeza como lana limpia; su silla llama de fuego, sus ruedas fuego ardiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 10, 'Un río de fuego procedía y salía de delante de él: millares de millares le servían, y millones de millones asistían delante de él: el Juez se sentó, y los libros se abrieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 11, 'Yo entonces miraba á causa de la voz de las grandes palabras que hablaba el cuerno; miraba hasta tanto que mataron la bestia, y su cuerpo fué deshecho, y entregado para ser quemado en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 12, 'Habían también quitado á las otras bestias su señorío, y les había sido dada prolongación de vida hasta cierto tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 13, 'Miraba yo en la visión de la noche, y he aquí en las nubes del cielo como un hijo de hombre que venía, y llegó hasta el Anciano de grande edad, é hiciéronle llegar delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 14, 'Y fuéle dado señorío, y gloria, y reino; y todos los pueblos, naciones y lenguas le sirvieron; su señorío, señorío eterno, que no será transitorio, y su reino que no se corromperá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 15, 'Mi espíritu fué turbado, yo Daniel, en medio de mi cuerpo, y las visiones de mi cabeza me asombraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 16, 'Lleguéme á uno de los que asistían, y preguntéle la verdad acerca de todo esto. Y hablóme, y declaróme la interpretación de las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 17, 'Estas grandes bestias, las cuales son cuatro, cuatro reyes son, que se levantarán en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 18, 'Después tomarán el reino los santos del Altísimo, y poseerán el reino hasta el siglo, y hasta el siglo de los siglos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 19, 'Entonces tuve deseo de saber la verdad acerca de la cuarta bestia, que tan diferente era de todas las otras, espantosa en gran manera, que tenía dientes de hierro, y sus uñas de metal, que devoraba y desmenuzaba, y las sobras hollaba con sus pies:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 20, 'Asimismo acerca de los diez cuernos que tenía en su cabeza, y del otro que había subido, de delante del cual habían caído tres: y este mismo cuerno tenía ojos, y boca que hablaba grandezas, y su parecer mayor que el de sus compañeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 21, 'Y veía yo que este cuerno hacía guerra contra los santos, y los vencía,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 22, 'Hasta tanto que vino el Anciano de grande edad, y se dió el juicio á los santos del Altísimo; y vino el tiempo, y los santos poseyeron el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 23, 'Dijo así: La cuarta bestia será un cuarto reino en la tierra, el cual será más grande que todos los otros reinos, y á toda la tierra devorará, y la hollará, y la despedazará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 24, 'Y los diez cuernos significan que de aquel reino se levantarán diez reyes; y tras ellos se levantará otro, el cual será mayor que los primeros, y á tres reyes derribará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 25, 'Y hablará palabras contra el Altísimo, y á los santos del Altísimo quebrantará, y pensará en mudar los tiempos y la ley: y entregados serán en su mano hasta tiempo, y tiempos, y el medio de un tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 26, 'Empero se sentará el juez, y quitaránle su señorío, para que sea destruído y arruinado hasta el extremo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 27, 'Y que el reino, y el señorío, y la majestad de los reinos debajo de todo el cielo, sea dado al pueblo de los santos del Altísimo; cuyo reino es reino eterno, y todos los señoríos le servirán y obedecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 7, 28, 'Hasta aquí fué el fin de la plática. Yo Daniel, mucho me turbaron mis pensamientos, y mi rostro se me mudó: mas guardé en mi corazón el negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 1, 'EN el año tercero del reinado del rey Belsasar, me apareció una visión á mí, Daniel, después de aquella que me había aparecido antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 2, 'Vi en visión, (y aconteció cuando vi, que yo estaba en Susán, que es cabecera del reino en la provincia de Persia;) vi pues en visión, estando junto al río Ulai,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 3, 'Y alcé mis ojos, y miré, y he aquí un carnero que estaba delante del río, el cual tenía dos cuernos: y aunque eran altos, el uno era más alto que el otro; y el más alto subió á la postre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 4, 'Vi que el carnero hería con los cuernos al poniente, al norte, y al mediodía, y que ninguna bestia podía parar delante de él, ni había quien escapase de su mano: y hacía conforme á su voluntad, y engrandecíase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 5, 'Y estando yo considerando, he aquí un macho de cabrío venía de la parte del poniente sobre la haz de toda la tierra, el cual no tocaba la tierra: y tenía aquel macho de cabrío un cuerno notable entre sus ojos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 6, 'Y vino hasta el carnero que tenía los dos cuernos, al cual había yo visto que estaba delante del río, y corrió contra él con la ira de su fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 7, 'Y vilo que llegó junto al carnero, y levantóse contra él, é hiriólo, y quebró sus dos cuernos, porque en el carnero no había fuerzas para parar delante de él: derribólo por tanto en tierra, y hollólo; ni hubo quien librase al carnero de su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 8, 'Y engrandecióse en gran manera el macho de cabrío; y estando en su mayor fuerza, aquel gran cuerno fué quebrado, y en su lugar subieron otros cuatro maravillosos hacia los cuatro vientos del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 9, 'Y del uno de ellos salió un cuerno pequeño, el cual creció mucho al mediodía, y al oriente, y hacia la tierra deseable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 10, 'Y engrandecióse hasta el ejército del cielo; y parte del ejército y de las estrellas echó por tierra, y las holló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 11, 'Aun contra el príncipe de la fortaleza se engrandeció, y por él fué quitado el continuo sacrificio, y el lugar de su santuario fué echado por tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 12, 'Y el ejército fué le entregado á causa de la prevaricación sobre el continuo sacrificio: y echó por tierra la verdad, é hizo cuanto quiso, y sucedióle prósperamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 13, 'Y oí un santo que hablaba; y otro de los santos dijo á aquél que hablaba: ¿Hasta cuándo durará la visión del continuo sacrificio, y la prevaricación asoladora que pone el santuario y el ejército para ser hollados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 14, 'Y él me dijo: Hasta dos mil y trescientos días de tarde y mañana; y el santuario será purificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 15, 'Y acaeció que estando yo Daniel considerando la visión, y buscando su inteligencia, he aquí, como una semejanza de hombre se puso delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 16, 'Y oí una voz de hombre entre las riberas de Ulai, que gritó y dijo: Gabriel, enseña la visión á éste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 17, 'Vino luego cerca de donde yo estaba; y con su venida me asombré, y caí sobre mi rostro. Empero él me dijo: Entiende, hijo del hombre, porque al tiempo se cumplirá la visión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 18, 'Y estando él hablando conmigo, caí dormido en tierra sobre mi rostro: y él me tocó, é hízome estar en pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 19, 'Y dijo: He aquí yo te enseñaré lo ha de venir en el fin de la ira: porque al tiempo se cumplirá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 20, 'Aquel carnero que viste, que tenía cuernos, son los reyes de Media y de Persia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 21, 'Y el macho cabrío es el rey de Javán: y el cuerno grande que tenía entre sus ojos es el rey primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 22, 'Y que fué quebrado y sucedieron cuatro en su lugar, significa que cuatro reinos sucederán de la nación, mas no en la fortaleza de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 23, 'Y al cabo del imperio de éstos, cuando se cumplirán los prevaricadores, levantaráse un rey altivo de rostro, y entendido en dudas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 24, 'Y su poder se fortalecerá, mas no con fuerza suya, y destruirá maravillosamente, y prosperará; y hará arbitrariamente, y destruirá fuertes y al pueblo de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 25, 'Y con su sagacidad hará prosperar el engaño en su mano; y en su corazón se engrandecerá, y con paz destruirá á muchos: y contra el príncipe de los príncipes se levantará; mas sin mano será quebrantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 26, 'Y la visión de la tarde y la mañana que está dicha, es verdadera: y tú guarda la visión, porque es para muchos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 8, 27, 'Y yo Daniel fuí quebrantado, y estuve enfermo algunos días: y cuando convalecí, hice el negocio del rey; mas estaba espantado acerca de la visión, y no había quien la entendiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 1, 'EN el año primero de Darío hijo de Assuero, de la nación de los Medos, el cual fué puesto por rey sobre el reino de los Caldeos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 2, 'En el año primero de su reinado, yo Daniel miré atentamente en los libros el número de los años, del cual habló Jehová al profeta Jeremías, que había de concluir la asolación de Jerusalem en setenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 3, 'Y volví mi rostro al Señor Dios, buscándole en oración y ruego, en ayuno, y cilicio, y ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 4, 'Y oré á Jehová mi Dios, y confesé, y dije: Ahora Señor, Dios grande, digno de ser temido, que guardas el pacto y la misericordia con los que te aman y guardan tus mandamientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 5, 'Hemos pecado, hemos hecho iniquidad, hemos obrado impíamente, y hemos sido rebeldes, y nos hemos apartado de tus mandamientos y de tus juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 6, 'No hemos obedecido á tus siervos los profetas, que en tu nombre hablaron á nuestros reyes, y á nuestros príncipes, á nuestros padres, y á todo el pueblo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 7, 'Tuya es, Señor, la justicia, y nuestra la confusión de rostro, como en el día de hoy á todo hombre de Judá, y á los moradores de Jerusalem, y á todo Israel, á los de cerca y á los de lejos, en todas las tierras á donde los has echado á causa de su rebelión con que contra ti se rebelaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 8, 'Oh Jehová, nuestra es la confusión de rostro, de nuestros reyes, de nuestros príncipes, y de nuestros padres; porque contra ti pecamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 9, 'De Jehová nuestro Dios es el tener misericordia, y el perdonar, aunque contra él nos hemos rebelado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 10, 'Y no obedecimos á la voz de Jehová nuestro Dios, para andar en sus leyes, las cuales puso él delante de nosotros por mano de sus siervos los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 11, 'Y todo Israel traspasó tu ley apartándose para no oir tu voz: por lo cual ha fluído sobre nosotros la maldición, y el juramento que está escrito en la ley de Moisés, siervo de Dios; porque contra él pecamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 12, 'Y él ha verificado su palabra que habló sobre nosotros, y sobre nuestros jueces que nos gobernaron, trayendo sobre nosotros tan grande mal; que nunca fué hecho debajo del cielo como el que fué hecho en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 13, 'Según está escrito en la ley de Moisés, todo aqueste mal vino sobre nosotros: y no hemos rogado á la faz de Jehová nuestro Dios, para convertirnos de nuestras maldades, y entender tu verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 14, 'Veló por tanto Jehová sobre el mal, y trájolo sobre nosotros; porque justo es Jehová nuestro Dios en todas sus obras que hizo, porque no obedecimos á su voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 15, 'Ahora pues, Señor Dios nuestro, que sacaste tu pueblo de la tierra de Egipto con mano poderosa, y te hiciste nombre cual en este día; hemos pecado, impíamente hemos hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 16, 'Oh Señor, según todas tus justicias, apártese ahora tu ira y tu furor de sobre tu ciudad Jerusalem, tu santo monte: porque á causa de nuestros pecados, y por la maldad de nuestros padres, Jerusalem y tu pueblo dados son en oprobio á todos en derredor nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 17, 'Ahora pues, Dios nuestro, oye la oración de tu siervo, y sus ruegos, y haz que tu rostro resplandezca sobre tu santuario asolado, por amor del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 18, 'Inclina, oh Dios mío, tu oído, y oye; abre tus ojos, y mira nuestros asolamientos, y la ciudad sobre la cual es llamado tu nombre: porque no derramamos nuestros ruegos ante tu acatamiento confiados en nuestras justicias, sino en tus muchas miseraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 19, 'Oye, Señor; oh Señor, perdona; presta oído, Señor, y haz; no pongas dilación, por amor de ti mismo, Dios mío: porque tu nombre es llamado sobre tu ciudad y sobre tu pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 20, 'Aun estaba hablando, y orando, y confesando mi pecado y el pecado de mi pueblo Israel, y derramaba mi ruego delante de Jehová mi Dios por el monte santo de mi Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 21, 'Aun estaba hablando en oración, y aquel varón Gabriel, al cual había visto en visión al principio, volando con presteza, me tocó como á la hora del sacrificio de la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 22, 'É hízome entender, y habló conmigo, y dijo: Daniel, ahora he salido para hacerte entender la declaración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 23, 'Al principio de tus ruegos salió la palabra, y yo he venido para enseñártela, porque tú eres varón de deseos. Entiende pues la palabra, y entiende la visión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 24, 'Setenta semanas están determinadas sobre tu pueblo y sobre tu santa ciudad, para acabar la prevaricación, y concluir el pecado, y expiar la iniquidad; y para traer la justicia de los siglos, y sellar la visión y la profecía, y ungir al Santo de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 25, 'Sepas pues y entiendas, que desde la salida de la palabra para restaurar y edificar á Jerusalem hasta el Mesías Príncipe, habrá siete semanas, y sesenta y dos semanas; tornaráse á edificar la plaza y el muro en tiempos angustiosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 26, 'Y después de las sesenta y dos semanas se quitará la vida al Mesías, y no por sí: y el pueblo de un príncipe que ha de venir, destruirá á la ciudad y el santuario; con inundación será el fin de ella, y hasta el fin de la guerra será talada con asolamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 9, 27, 'Y en otra semana confirmará el pacto á muchos, y á la mitad de la semana hará cesar el sacrificio y la ofrenda: después con la muchedumbre de las abominaciones será el desolar, y esto hasta una entera consumación; y derramaráse la ya determinada sobre el pueblo asolado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 1, 'EN el tercer año de Ciro rey de Persia, fué revelada palabra á Daniel, cuyo nombre era Beltsasar; y la palabra era verdadera, mas el tiempo fijado era largo: él empero comprendió la palabra, y tuvo inteligencia en la visión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 2, 'En aquellos días yo Daniel me contristé por espacio de tres semanas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 3, 'No comí pan delicado, ni entró carne ni vino en mi boca, ni me unté con ungüento, hasta que se cumplieron tres semanas de días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 4, 'Y á los veinte y cuatro días del mes primero estaba yo á la orilla del gran río Hiddekel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 5, 'Y alzando mis ojos miré, y he aquí un varón vestido de lienzos, y ceñidos sus lomos de oro de Uphaz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 6, 'Y su cuerpo era como piedra de Tarsis, y su rostro parecía un relámpago, y sus ojos como antorchas de fuego, y sus brazos y sus pies como de color de metal resplandeciente, y la voz de sus palabras como la voz de ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 7, 'Y sólo yo, Daniel, vi aquella visión, y no la vieron los hombres que estaban conmigo; sino que cayó sobre ellos un gran temor, y huyeron, y escondiéronse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 8, 'Quedé pues yo solo, y vi esta gran visión, y no quedó en mí esfuerzo; antes mi fuerza se me trocó en desmayo, sin retener vigor alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 9, 'Empero oí la voz de sus palabras: y oyendo la voz de sus palabras, estaba yo adormecido sobre mi rostro, y mi rostro en tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 10, 'Y, he aquí, una mano me tocó, é hizo que me moviese sobre mis rodillas, y sobre las palmas de mis manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 11, 'Y díjome: Daniel, varón de deseos, está atento á las palabras que te hablaré, y levántate sobre tus pies; porque á ti he sido enviado ahora. Y estando hablando conmigo esto, yo estaba temblando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 12, 'Y díjome: Daniel, no temas: porque desde el primer día que diste tu corazón á entender, y á afligirte en la presencia de tu Dios, fueron oídas tus palabras; y á causa de tus palabras yo soy venido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 13, 'Mas el príncipe del reino de Persia se puso contra mí veintiún días: y he aquí, Miguel, uno de los principales príncipes, vino para ayudarme, y yo quedé allí con los reyes de Persia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 14, 'Soy pues venido para hacerte saber lo que ha de venir á tu pueblo en los postreros días; porque la visión es aún para días;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 15, 'Y estando hablando conmigo semejantes palabras, puse mis ojos en tierra, y enmudecí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 16, 'Mas he aquí, como una semejanza de hijo de hombre tocó mis labios. Entonces abrí mi boca, y hablé, y dije á aquel que estaba delante de mí: Señor mío, con la visión se revolvieron mis dolores sobre mí, y no me quedó fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 17, '¿Cómo pues podrá el siervo de mi señor hablar con este mi señor? porque al instante me faltó la fuerza, y no me ha quedado aliento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 18, 'Y aquella como semejanza de hombre me tocó otra vez, y me confortó;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 19, 'Y díjome: Varón de deseos, no temas: paz á ti; ten buen ánimo, y aliéntate. Y hablando él conmigo cobré yo vigor, y dije: Hable mi señor, porque me has fortalecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 20, 'Y dijo: ¿Sabes por qué he venido á ti? Porque luego tengo de volver para pelear con el príncipe de los Persas; y en saliendo yo, luego viene el príncipe de Grecia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 10, 21, 'Empero yo te declararé lo que está escrito en la escritura de verdad: y ninguno hay que se esfuerce conmigo en estas cosas, sino Miguel vuestro príncipe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 1, 'Y EN el año primero de Darío el de Media, yo estuve para animarlo y fortalecerlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 2, 'Y ahora yo te mostraré la verdad. He aquí que aun habrá tres reyes en Persia, y el cuarto se hará de grandes riquezas más que todos; y fortificándose con sus riquezas, despertará á todos contra el reino de Javán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 3, 'Levantaráse luego un rey valiente, el cual se enseñoreará sobre gran dominio, y hará su voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 4, 'Pero cuando estará enseñoreado, será quebrantado su reino, y repartido por los cuatro vientos del cielo; y no á sus descendientes, ni según el señorío con que él se enseñoreó: porque su reino será arrancado, y para otros fuera de aquellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 5, 'Y haráse fuerte el rey del mediodía: mas uno de los príncipes de aquél le sobrepujará, y se hará poderoso; su señorío será grande señorío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 6, 'Y al cabo de años se concertarán, y la hija del rey del mediodía vendrá al rey del norte para hacer los conciertos. Empero ella no podrá retener la fuerza del brazo: ni permanecerá él, ni su brazo; porque será entregada ella, y los que la habían traído, asimismo su hijo, y los que estaban de parte de ella en aquel tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 7, 'Mas del renuevo de sus raíces se levantará uno sobre su silla, y vendrá con ejército, y entrará en la fortaleza del rey del norte, y hará en ellos á su arbitrio, y predominará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 8, 'Y aun los dioses de ellos, con sus príncipes, con sus vasos preciosos de plata y de oro, llevará cautivos á Egipto: y por años se mantendrá él contra el rey del norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 9, 'Así entrará en el reino el rey del mediodía, y volverá á su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 10, 'Mas los hijos de aquél se airarán y reunirán multitud de grandes ejércitos: y vendrá á gran priesa, é inundará, y pasará, y tornará, y llegará con ira hasta su fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 11, 'Por lo cual se enfurecerá el rey del mediodía, y saldrá, y peleará con el mismo rey del norte; y pondrá en campo gran multitud, y toda aquella multitud será entregada en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 12, 'Y la multitud se ensoberbecerá, elevaráse su corazón, y derribará muchos millares; mas no prevalecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 13, 'Y el rey del norte volverá á poner en campo mayor multitud que primero, y á cabo del tiempo de años vendrá á gran priesa con grande ejército y con muchas riquezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 14, 'Y en aquellos tiempos se levantarán muchos contra el rey del mediodía; é hijos de disipadores de tu pueblo se levantarán para confirmar la profecía, y caerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 15, 'Vendrá pues el rey del norte, y fundará baluartes, y tomará la ciudad fuerte; y los brazos del mediodía no podrán permanecer, ni su pueblo escogido, ni habrá fortaleza que pueda resistir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 16, 'Y el que vendrá contra él, hará á su voluntad, ni habrá quien se le pueda parar delante; y estará en la tierra deseable, la cual será consumida en su poder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 17, 'Pondrá luego su rostro para venir con el poder de todo su reino; y hará con aquél cosas rectas, y darále una hija de mujeres para trastornarla: mas no estará ni será por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 18, 'Volverá después su rostro á las islas, y tomará muchas; mas un príncipe le hará parar su afrenta, y aun tornará sobre él su oprobio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 19, 'Luego volverá su rostro á las fortalezas de su tierra: mas tropezará y caerá, y no parecerá más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 20, 'Entonces sucederá en su silla uno que hará pasar exactor por la gloria del reino; mas en pocos días será quebrantado, no en enojo, ni en batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 21, 'Y sucederá en su lugar un vil, al cual no darán la honra del reino: vendrá empero con paz, y tomará el reino con halagos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 22, 'Y con los brazos de inundación serán inundados delante de él, y serán quebrantados; y aun también el príncipe del pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 23, 'Y después de los conciertos con él, él hará engaño, y subirá, y saldrá vencedor con poca gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 24, 'Estando la provincia en paz y en abundancia, entrará y hará lo que no hicieron sus padres, ni los padres de sus padres; presa, y despojos, y riquezas repartirá á sus soldados; y contra las fortalezas formará sus designios: y esto por tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 25, 'Y despertará sus fuerzas y su corazón contra el rey del mediodía con grande ejército: y el rey del mediodía se moverá á la guerra con grande y muy fuerte ejército; mas no prevalecerá, porque le harán traición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 26, 'Aun los que comerán su pan, le quebrantarán; y su ejército será destruído, y caerán muchos muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 27, 'Y el corazón de estos dos reyes será para hacer mal, y en una misma mesa tratarán mentira: mas no servirá de nada, porque el plazo aun no es llegado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 28, 'Y volveráse á su tierra con grande riqueza, y su corazón será contra el pacto santo: hará pues, y volveráse á su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 29, 'Al tiempo señalado tornará al mediodía; mas no será la postrera venida como la primera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 30, 'Porque vendrán contra él naves de Chîttim, y él se contristará, y se volverá, y enojaráse contra el pacto santo, y hará: volveráse pues, y pensará en los que habrán desamparado el santo pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 31, 'Y serán puestos brazos de su parte; y contaminarán el santuario de fortaleza, y quitarán el continuo sacrificio, y pondrán la abominación espantosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 32, 'Y con lisonjas hará pecar á los violadores del pacto: mas el pueblo que conoce á su Dios, se esforzará, y hará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 33, 'Y los sabios del pueblo darán sabiduría á muchos: y caerán á cuchillo y á fuego, en cautividad y despojo, por días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 34, 'Y en su caer serán ayudados de pequeño socorro: y muchos se juntarán á ellos con lisonjas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 35, 'Y algunos de los sabios caerán para ser purgados, y limpiados, y emblanquecidos, hasta el tiempo determinado: porque aun para esto hay plazo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 36, 'Y el rey hará á su voluntad; y se ensoberbecerá, y se engrandecerá sobre todo dios: y contra el Dios de los dioses hablará maravillas, y será prosperado, hasta que sea consumada la ira: porque hecha está determinación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 37, 'Y del Dios de sus padres no se cuidará, ni del amor de las mujeres: ni se cuidará de dios alguno, porque sobre todo se engrandecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 38, 'Mas honrará en su lugar al dios Mauzim, dios que sus padres no conocieron: honrarálo con oro, y plata, y piedras preciosas, y con cosas de gran precio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 39, 'Y con el dios ajeno que conocerá, hará á los baluartes de Mauzim crecer en gloria: y harálos enseñorear sobre muchos, y por interés repartirá la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 40, 'Empero al cabo del tiempo el rey del mediodía se acorneará con él; y el rey del norte levantará contra él como tempestad, con carros y gente de á caballo, y muchos navíos; y entrará por las tierras, é inundará, y pasará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 41, 'Y vendrá á la tierra deseable, y muchas provincias caerán; mas éstas escaparán de su mano: Edom, y Moab, y lo primero de los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 42, 'Asimismo extenderá su mano á las otras tierras, y no escapará el país de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 43, 'Y se apoderará de los tesoros de oro y plata, y de todas las cosas preciosas de Egipto, de Libia, y Etiopía por donde pasará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 44, 'Mas nuevas de oriente y del norte lo espantarán; y saldrá con grande ira para destruir y matar muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 11, 45, 'Y plantará la tiendas de su palacio entre los mares, en el monte deseable del santuario; y vendrá hasta su fin, y no tendrá quien le ayude.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 1, 'Y EN aquel tiempo se levantará Miguel, el gran príncipe que está por los hijos de tu pueblo; y será tiempo de angustia, cual nunca fué después que hubo gente hasta entonces: mas en aquel tiempo será libertado tu pueblo, todos los que se hallaren escritos en el libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 2, 'Y muchos de los que duermen en el polvo de la tierra serán despertados, unos para vida eterna, y otros para vergüenza y confusión perpetua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 3, 'Y los entendidos resplandecerán como el resplandor del firmamento; y los que enseñan á justicia la multitud, como las estrellas á perpetua eternidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 4, 'Tú empero Daniel, cierra las palabras y sella el libro hasta el tiempo del fin: pasarán muchos, y multiplicaráse la ciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 5, 'Y yo, Daniel, miré, y he aquí otros dos que estaban, el uno de esta parte á la orilla del río, y el otro de la otra parte á la orilla del río.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 6, 'Y dijo uno al varón vestido de lienzos, que estaba sobre las aguas del río: ¿Cuándo será el fin de estas maravillas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 7, 'Y oía al varón vestido de lienzos, que estaba sobre las aguas del río, el cual alzó su diestra y su siniestra al cielo, y juró por el Viviente en los siglos, que será por tiempo, tiempos, y la mitad. Y cuando se acabare el esparcimiento del escuadrón del pueblo santo, todas estas cosas serán cumplidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 8, 'Y yo oí, mas no entendí. Y dije: Señor mío, ¿qué será el cumplimiento de estas cosas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 9, 'Y dijo: Anda, Daniel, que estas palabras están cerradas y selladas hasta el tiempo del cumplimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 10, 'Muchos serán limpios, y emblanquecidos, y purificados; mas los impíos obrarán impíamente, y ninguno de los impíos entenderá, pero entenderán los entendidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 11, 'Y desde el tiempo que fuere quitado el continuo sacrificio hasta la abominación espantosa, habrá mil doscientos y noventa días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 12, 'Bienaventurado el que esperare, y llegare hasta mil trescientos treinta y cinco días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DAN', 'Daniel', 12, 13, 'Y tú irás al fin, y reposarás, y te levantarás en tu suerte al fin de los días.');
